/**
 * 校验所有列是否超出 MySQL InnoDB 行大小限制（65535 字节）。
 * utf8mb4 下 VARCHAR(N) 最大占用 N*4+2 字节。
 */
private void validateRowSizeLimit(List<ExcelColumnDefResp> columns) {
    // 系统列开销：BIGINT(8) + VARCHAR(50)(202) + DATETIME(5) + VARCHAR(100)(402) + DATETIME(5) ≈ 622
    long totalBytes = 622;

    // DDL 中 VARCHAR 长度上限（与 ExcelDynamicTableServiceImpl 保持一致）
    final long MAX_VARCHAR_LEN = 500;

    for (ExcelColumnDefResp col : columns) {
        ExcelColumnType type = ExcelColumnType.fromFrontCode(col.getDataType());
        totalBytes += switch (type) {
            case LONG -> 8;
            case DOUBLE -> 8;
            case DATETIME -> 5;
            // VARCHAR(N) utf8mb4: max N*4 + 2 bytes length prefix
            case STRING, LINK -> MAX_VARCHAR_LEN * 4L + 2;
        };
    }

    if (totalBytes > 65535) {
        long varcharCount = columns.stream()
                .filter(c -> {
                    ExcelColumnType t = ExcelColumnType.fromFrontCode(c.getDataType());
                    return t == ExcelColumnType.STRING || t == ExcelColumnType.STRING;
                })
                .count();
        throw new RuntimeException("Excel列数过多（" + columns.size() + "列），超出MySQL单行65535字节存储上限，"
                + "请减少列数后重新上传。当前预估行大小约" + totalBytes + "字节");
    }
}

/**
     * 根据 VARCHAR 列数量动态计算安全长度上限，确保不超出 MySQL 65535 字节行大小限制。
     * utf8mb4 下 VARCHAR(N) 最大占用 N*4+2 字节。
     */
    private long computeMaxVarcharLength(List<ExcelColumnDefReq> columns) {
        long varcharCount = columns.stream()
                .filter(c -> {
                    ExcelColumnType t = ExcelColumnType.fromFrontCode(c.getDataType());
                    return t == ExcelColumnType.STRING || t == ExcelColumnType.LINK;
                }).count();
        if (varcharCount == 0) return 500;

        // 系统列开销 ≈ 622 字节，留 1000 字节安全余量
        long available = 65535 - 622 - 1000;
        long maxPerColumn = available / varcharCount - 2;  // 减去 2 字节长度前缀
        maxPerColumn /= 4;  // utf8mb4 每字符最多 4 字节
        return Math.min(maxPerColumn, 500);
    }

