private void evictOldSessionsForCurrentLogin(String tenantId, Long userId, String userCode, String currentDeviceId,
                                                 DeviceLoginConfigVO loginConfig) {
        if (StrUtil.hasBlank(tenantId, userCode, currentDeviceId)
                || loginConfig == null
                || !Boolean.TRUE.equals(loginConfig.getEnabled())
                || ObjectUtil.isNull(loginConfig.getMaxDevicesCount())
                || loginConfig.getMaxDevicesCount() <= 0) {
            return;
        }
        Integer maxDevicesCount = loginConfig.getMaxDevicesCount();
        try {
            // 同设备重复登录时先清掉旧会话，避免重复设备占用名额
            kickoutOldSessionOfSameDevice(tenantId, userCode, currentDeviceId);

            LambdaQueryWrapper<UserDeviceSession> activeWrapper = new LambdaQueryWrapper<>();
            activeWrapper.eq(UserDeviceSession::getUserId, userId)
                    .eq(UserDeviceSession::getTenantId, tenantId)
                    .eq(UserDeviceSession::getSessionStatus, DeviceSessionStatusEnum.ACTIVE.getCode())
                    .eq(UserDeviceSession::getLoginStatus, DeviceLoginStatusEnum.SUCCESS.getCode())
                    .orderByAsc(UserDeviceSession::getLastActivityTime)
                    .orderByAsc(UserDeviceSession::getLoginTime)
                    .orderByAsc(UserDeviceSession::getId);
            List<UserDeviceSession> activeSessions = userDeviceSessionMapper.selectList(activeWrapper);
            if (CollUtil.isEmpty(activeSessions)) {
                return;
            }

            int overflow = activeSessions.size() - maxDevicesCount + 1;
            if (overflow <= 0) {
                return;
            }

            int kicked = 0;
            Set<String> kickedDeviceIds = new HashSet<>();
            for (UserDeviceSession session : activeSessions) {
                if (kicked >= overflow) {
                    break;
                }
                String deviceId = session.getDeviceId();
                if (StrUtil.isBlank(deviceId)
                        || StrUtil.equals(deviceId, currentDeviceId)
                        || kickedDeviceIds.contains(deviceId)) {
                    continue;
                }
                userDeviceService.forceLogoutDevice(deviceId, tenantId, userCode);
                kickedDeviceIds.add(deviceId);
                kicked++;
            }
        } catch (Exception e) {
            log.warn("登录前淘汰旧设备会话异常，登录继续: {}", e.getMessage(), e);
        }
    }

    /**
     * 检查账号是否已被锁定
     * @param loginConfig
     * @param tenantId
     * @param userCode
     * @param account
     */
    private void checkLoginPasswordLocked(DeviceLoginConfigVO loginConfig, String tenantId, String userCode, String account) {
        if (!isLoginPasswordErrorLimitEnabled(loginConfig) || StrUtil.isBlank(tenantId) || StrUtil.isBlank(userCode)) {
            return;
        }
        String lockKey = buildLoginPasswordLockKey(tenantId, userCode);
        Boolean hasLock = stringRedisTemplate.hasKey(lockKey);
        if (!Boolean.TRUE.equals(hasLock)) {
            return;
        }
        Long expireSeconds = stringRedisTemplate.getExpire(lockKey, TimeUnit.SECONDS);
        if (expireSeconds == null || expireSeconds <= 0) {
            stringRedisTemplate.delete(lockKey);
            return;
        }
        long remainMinutes = resolveRemainMinutes(expireSeconds);
        long startLockTime = resolveLockStartTime(loginConfig, lockKey, expireSeconds);
        long lockTime = resolveLockMinutes(loginConfig, remainMinutes);
        throw new LoginLimitException(account, lockTime, startLockTime);
    }

    private void handleLoginPasswordError(DeviceLoginConfigVO loginConfig, String tenantId, String userCode, String account) {
        if (!isLoginPasswordErrorLimitEnabled(loginConfig) || StrUtil.isBlank(tenantId) || StrUtil.isBlank(userCode)) {
            return;
        }
        Integer maxCount = loginConfig.getLoginPasswordErrorMaxCount();
        Integer lockMinutes = loginConfig.getLoginPasswordErrorLockMinutes();
        if (maxCount == null || maxCount <= 0 || lockMinutes == null || lockMinutes <= 0) {
            log.warn("登录次数限制配置无效: tenantId={}, userCode={}, maxCount={}, lockMinutes={}", tenantId, userCode, maxCount, lockMinutes);
            return;
        }
        String countKey = buildLoginPasswordFailCountKey(tenantId, userCode);
        Long failCount = stringRedisTemplate.opsForValue().increment(countKey);
        if (failCount != null && failCount == 1L) {
            // stringRedisTemplate.expire(countKey, lockMinutes, TimeUnit.MINUTES);
            // LOGIN_PWD_ERROR_WINDOW_MINUTES 时间内 登录密码错误 多少次，短暂封号
            stringRedisTemplate.expire(countKey, LOGIN_PWD_ERROR_WINDOW_MINUTES, TimeUnit.MINUTES);
        }
        if (failCount != null && failCount > maxCount) {
            // 如果后面需求要求冷却时间后仅有一次的登录机会，则不使用delete方式，而是将failCount值减一
            stringRedisTemplate.delete(countKey);
            String lockKey = buildLoginPasswordLockKey(tenantId, userCode);
            long startLockTime = System.currentTimeMillis();
            stringRedisTemplate.opsForValue().set(lockKey, String.valueOf(startLockTime), lockMinutes, TimeUnit.MINUTES);
            throw new LoginLimitException(account, lockMinutes.longValue(), startLockTime);
        }
    }

    /**
     * 清除所有限制状态
     * @param tenantId
     * @param userCode
     */
    private void clearLoginPasswordLimitCache(String tenantId, String userCode) {
        if (StrUtil.isBlank(tenantId) || StrUtil.isBlank(userCode)) {
            return;
        }
        stringRedisTemplate.delete(buildLoginPasswordFailCountKey(tenantId, userCode));
        stringRedisTemplate.delete(buildLoginPasswordLockKey(tenantId, userCode));
    }

    private boolean isLoginPasswordErrorLimitEnabled(DeviceLoginConfigVO loginConfig) {
        return loginConfig != null && Boolean.TRUE.equals(loginConfig.getEnableLoginPasswordErrorLimit());
    }

    private String buildLoginPasswordFailCountKey(String tenantId, String userCode) {
        return LOGIN_PASSWORD_FAIL_COUNT_CACHE_PREFIX + tenantId + ":" + userCode;
    }

    private String buildLoginPasswordLockKey(String tenantId, String userCode) {
        return LOGIN_PASSWORD_LOCK_CACHE_PREFIX + tenantId + ":" + userCode;
    }

    private long resolveRemainMinutes(long expireSeconds) {
        long remainMinutes = (long) Math.ceil(expireSeconds / 60.0);
        return Math.max(remainMinutes, 1L);
    }

    private long resolveLockMinutes(DeviceLoginConfigVO loginConfig, long remainMinutes) {
        Integer lockMinutes = loginConfig != null ? loginConfig.getLoginPasswordErrorLockMinutes() : null;
        if (lockMinutes != null && lockMinutes > 0) {
            return lockMinutes.longValue();
        }
        return remainMinutes;
    }

    private long resolveLockStartTime(DeviceLoginConfigVO loginConfig, String lockKey, long expireSeconds) {
        String lockValue = stringRedisTemplate.opsForValue().get(lockKey);
        if (StrUtil.isNotBlank(lockValue)) {
            try {
                return Long.parseLong(lockValue);
            } catch (NumberFormatException ignore) {
                return System.currentTimeMillis();
            }
        }
        Integer lockMinutes = loginConfig != null ? loginConfig.getLoginPasswordErrorLockMinutes() : null;
        if (lockMinutes != null && lockMinutes > 0) {
            long totalSeconds = lockMinutes * 60L;
            long usedSeconds = Math.max(totalSeconds - expireSeconds, 0L);
            return System.currentTimeMillis() - usedSeconds * 1000L;
        }
        return System.currentTimeMillis();
    }

    private String buildLoginLockMessage(String account, long remainMinutes) {
        String accountInfo = StrUtil.isBlank(account) ? "当前账号" : account;
        return String.format("账号登录失败次数过多，暂时冻结账号%s%s分钟，请稍后重试", accountInfo, remainMinutes);
    }

    /**
     * 记录设备会话信息
     */
    private void recordDeviceSession(SysUserInfo sysUserInfo, String deviceFingerprint,
            HttpServletRequest request, String token) {
        try {
            String clientIp = DeviceFingerprintUtil.extractClientIp(request);
            String userAgent = JakartaServletUtil.getHeader(request, "User-Agent", "UTF-8");

            // 检测设备信息
            LoginDeviceInfoDTO deviceInfo = new LoginDeviceInfoDTO();
            deviceInfo.setDeviceId(deviceFingerprint);
            try {
                deviceInfo = DeviceDetectionUtil.detectDevice(userAgent, deviceInfo);
            } catch (Exception e) {
                log.warn("设备信息检测异常，使用默认值: {}", e.getMessage());
                deviceInfo.setDeviceType("未知");
                deviceInfo.setOsType("未知");
                deviceInfo.setBrowser("未知");
                deviceInfo.setBrowserVersion("未知");
            }

            // 创建设备会话
            UserDeviceSession deviceSession = userDeviceService.createSession(
                    sysUserInfo,
                    sysUserInfo.getTenantId(),
                    deviceInfo,
                    token,
                    clientIp);

        } catch (Exception e) {
            log.error("记录设备会话异常: {}", e.getMessage(), e);
        }
    }

    /**
     * 踢出同设备的旧会话，防止重复登录
     * @param tenantId 租户ID
     * @param userCode 用户Code
     * @param deviceFingerprint 设备指纹
     */
    private void kickoutOldSessionOfSameDevice(String tenantId, String userCode, String deviceFingerprint) {
        try {
            // 1. 查询该用户该设备上所有 ACTIVE 的会话
            LambdaQueryWrapper<UserDeviceSession> queryWrapper = new LambdaQueryWrapper<>();
            queryWrapper.eq(UserDeviceSession::getUserCode, userCode)
                    .eq(UserDeviceSession::getTenantId, tenantId)
                    .eq(UserDeviceSession::getDeviceId, deviceFingerprint)
                    .eq(UserDeviceSession::getSessionStatus, DeviceSessionStatusEnum.ACTIVE.getCode())
                    .eq(UserDeviceSession::getLoginStatus, DeviceLoginStatusEnum.SUCCESS.getCode());

            List<UserDeviceSession> oldSessions = userDeviceSessionMapper.selectList(queryWrapper);

            if (oldSessions == null || oldSessions.isEmpty()) {
                log.debug("未找到需要踢出的旧会话: userCode={}, deviceId={}", userCode, deviceFingerprint);
                return;
            }

            // 2. 踢出旧会话
            for (UserDeviceSession oldSession : oldSessions) {
                try {
                    // 2.1 通过 SaToken 踢出
                    if (oldSession.getToken() != null) {
                        StpUtil.kickout(userCode, deviceFingerprint);
                    }

                    // 2.2 更新数据库状态
                    UserDeviceSession updateSession = new UserDeviceSession();
                    updateSession.setSessionStatus(DeviceSessionStatusEnum.OFFLINE.getCode());
                    updateSession.setLogoutReason(LogoutTypeEnum.DUPLICATE_LOGIN.getCode());
                    updateSession.setLogoutTime(LocalDateTime.now());
                    updateSession.setModifiedTime(LocalDateTime.now());

                    LambdaUpdateWrapper<UserDeviceSession> updateWrapper = new LambdaUpdateWrapper<>();
                    updateWrapper.eq(UserDeviceSession::getId, oldSession.getId());

                    userDeviceSessionMapper.update(updateSession, updateWrapper);

                    log.info("旧会话已踢出: userCode={}, deviceId={}, sessionId={}, reason=DUPLICATE_LOGIN",
                             userCode, deviceFingerprint, oldSession.getId());

                } catch (Exception e) {
                    log.warn("踢出旧会话失败: sessionId={}, error={}", oldSession.getId(), e.getMessage(), e);
