/**
 * Atomix命令-接口API
 *
 * @author <a href="xiaoymin@foxmail.com">xiaoymin@foxmail.com</a>
 * 2026/2/4 20:15
 * @since ais-server
 */
@Slf4j
@AllArgsConstructor
@Tag(name = "Atomix命令")
@RestController
@RequestMapping("/kb/atomix")
public class AtomixController {

    private static final String EDIT_UNSUPPORTED_OPERATION = "unsupported_operation";
    private static final String EDIT_INVALID_PATCH = "invalid_patch";
    private static final Pattern EDIT_PREFIX_PATTERN = Pattern.compile("(?is)^\\s*kb\\s+edit(\\s+.*)?$");
    private static final Pattern WRITE_PREFIX_PATTERN = Pattern.compile("(?is)^\\s*kb\\s+write(\\s+.*)?$");

    final AtomixCommandExecutor atomixCommandExecutor;
    final AtomixCommandLogMessageProducer atomixCommandLogMessageProducer;
    final AtomixPageChangePublisher atomixPageChangePublisher;

    /**
     * 执行Atomix命令
     *
     * @param executeReq 命令执行请求
     * @return 命令执行结果
     */
    @Operation(summary = "执行Atomix命令")
    @PostMapping("/execute")
    public Result<AtomixCommandExecuteResp> execute(@Valid @RequestBody AtomixCommandExecuteReq executeReq) {
        log.info("执行Atomix命令,API:{},command:{}", "/kb/atomix/execute", executeReq.getCommand());
        Assert.isTrue(StrUtil.isNotBlank(executeReq.getCommand()), "command不能为空");
        String normalizedCommand = normalizeWriteContentCommand(StrUtil.trim(executeReq.getCommand()));
        long startTime = System.currentTimeMillis();
        CommandResult<?> commandResult = null;
        AtomixCommandExecuteResp resp = null;
        Exception exception = null;
        try {
            if (isHelpCommand(normalizedCommand)) {
                resp = buildHelpResp();
                return Result.data(resp);
            }
            AtomixCommandExecuteResp editPrecheck = preValidateEditCommand(normalizedCommand);
            if (editPrecheck != null) {
                resp = editPrecheck;
                return new Result<>(ErrorCodeEnum.CUSTOM_FAIL.getCode(), ErrorCodeEnum.CUSTOM_FAIL.getMsg(), resp);
            }
            commandResult = atomixCommandExecutor.execute(normalizedCommand);
            resp = AtomixCommandExecuteResp.from(commandResult);
            if (commandResult == null || !commandResult.isSuccess()) {
                return new Result<>(ErrorCodeEnum.CUSTOM_FAIL.getCode(), ErrorCodeEnum.CUSTOM_FAIL.getMsg(), resp);
            }
            try {
                atomixPageChangePublisher.publish(resp, normalizedCommand);
            } catch (Exception e) {
                log.warn("发送Atomix页面变更事件失败: {}", e.getMessage(), e);
            }
            return Result.data(resp);
        } catch (Exception e) {
            exception = e;
            throw e;
        } finally {
            long costTime = System.currentTimeMillis() - startTime;
            try {
                SysUserInfo currentUser = UserContextHolder.getCurrentUser();
                HttpServletRequest request = ThreadLocalHolder.getHttpServletRequest();
                AtomixCommandLogMessage message = new AtomixCommandLogMessage();
                message.setCode(IdUtil.getSnowflakeNextIdStr());
                message.setTenantId(currentUser.getTenantId());
                message.setUserCode(currentUser.getCode());
                message.setUserName(resolveUserName(currentUser));
                message.setCommandText(normalizedCommand);
                message.setCommandName(resolveCommandName(commandResult, normalizedCommand));
                message.setRequestSource(resolveRequestSource(request));
                message.setRequestPath(request != null ? request.getRequestURI() : StrUtil.EMPTY);
                message.setRequestMethod(request != null ? request.getMethod() : StrUtil.EMPTY);
                message.setClientIp(request != null ? JakartaServletUtil.getClientIP(request) : StrUtil.EMPTY);
                message.setUserAgent(request != null ? StrUtil.blankToDefault(request.getHeader("User-Agent"), StrUtil.EMPTY) : StrUtil.EMPTY);
                message.setSuccessFlag(resp != null && Boolean.TRUE.equals(resp.getSuccess()) && exception == null ? 1 : 0);
                message.setCostTime(costTime);
                message.setResponseData(resolveResponseData(resp));
                if (resp != null && Boolean.FALSE.equals(resp.getSuccess())) {
                    message.setErrorCode(resp.getErrorCode());
                    message.setErrorMessage(resp.getErrorMessage());
                }
                if (exception != null && StrUtil.isBlank(message.getErrorMessage())) {
                    message.setErrorMessage(exception.getMessage());
                }
                message.setCreateTimeMillis(System.currentTimeMillis());
                atomixCommandLogMessageProducer.send(message);
            } catch (Exception e) {
                log.warn("发送Atomix命令日志MQ消息失败: {}", e.getMessage(), e);
            }
        }
    }

    private String resolveCommandName(CommandResult<?> commandResult, String commandText) {
        if (commandResult != null && StrUtil.isNotBlank(commandResult.getCommand())) {
            return commandResult.getCommand();
        }
        if (StrUtil.isBlank(commandText)) {
            return StrUtil.EMPTY;
        }
        String[] parts = StrUtil.splitToArray(commandText.trim(), ' ');
        if (parts.length == 0) {
            return StrUtil.EMPTY;
        }
        if (parts.length > 1 && StrUtil.equalsIgnoreCase(parts[0], "kb")) {
            return parts[1];
        }
        return parts[0];
    }

    private String resolveRequestSource(HttpServletRequest request) {
        if (request == null) {
            return StrUtil.EMPTY;
        }
        String origin = request.getHeader("Origin");
        if (StrUtil.isNotBlank(origin)) {
            return origin;
        }
        String referer = request.getHeader("Referer");
        return StrUtil.blankToDefault(referer, StrUtil.EMPTY);
    }

    private String resolveResponseData(AtomixCommandExecuteResp resp) {
        if (resp == null) {
            return StrUtil.EMPTY;
        }
        StringBuilder builder = new StringBuilder(128);
        builder.append("{\"success\":").append(Boolean.TRUE.equals(resp.getSuccess()));
        builder.append(",\"command\":\"").append(StrUtil.nullToDefault(resp.getCommand(), StrUtil.EMPTY)).append("\"");
        if (StrUtil.isNotBlank(resp.getErrorCode())) {
            builder.append(",\"errorCode\":\"").append(resp.getErrorCode()).append("\"");
        }
        if (StrUtil.isNotBlank(resp.getErrorMessage())) {
            builder.append(",\"errorMessage\":\"").append(resp.getErrorMessage()).append("\"");
        }
        Object data = resp.getData();
        if (data != null) {
            builder.append(",\"dataType\":\"").append(data.getClass().getSimpleName()).append("\"");
            builder.append(",\"data\":\"").append(StrUtil.toString(data)).append("\"");
        }
        builder.append('}');
        String result = builder.toString();
        if (result.length() > 2000) {
            return result.substring(0, 2000);
        }
        return result;
    }

    private boolean isHelpCommand(String command) {
        if (StrUtil.isBlank(command)) {
            return false;
        }
        String normalized = command.trim().replaceAll("\\s+", " ").toLowerCase();
        return "kb --help".equals(normalized)
                || "kb -h".equals(normalized)
                || "kb help".equals(normalized);
    }

    static String normalizeWriteContentCommand(String command) {
        if (StrUtil.isBlank(command) || !WRITE_PREFIX_PATTERN.matcher(command).matches()) {
            return command;
        }
        int contentTokenStart = findContentTokenStart(command);
        if (contentTokenStart < 0) {
            return command;
        }
        int contentTokenEnd = findTokenEnd(command, contentTokenStart);
        String contentToken = command.substring(contentTokenStart, contentTokenEnd);
        int contentStart;
        if (StrUtil.equalsIgnoreCase(contentToken, "--content")) {
            contentStart = skipWhitespace(command, contentTokenEnd);
            if (contentStart >= command.length() || isQuote(command.charAt(contentStart))) {
                return command;
            }
            return command.substring(0, contentStart) + quoteCommandArgument(command.substring(contentStart));
        }
        String prefix = "--content=";
        if (StrUtil.startWithIgnoreCase(contentToken, prefix)) {
            contentStart = contentTokenStart + prefix.length();
            if (contentStart >= command.length() || isQuote(command.charAt(contentStart))) {
                return command;
            }
            return command.substring(0, contentStart) + quoteCommandArgument(command.substring(contentStart));
        }
        return command;
    }

    private static int findContentTokenStart(String command) {
        int index = 0;
        while (index < command.length()) {
            index = skipWhitespace(command, index);
            if (index >= command.length()) {
                return -1;
            }
            int tokenEnd = findTokenEnd(command, index);
            String token = command.substring(index, tokenEnd);
            if (StrUtil.equalsIgnoreCase(token, "--content") || StrUtil.startWithIgnoreCase(token, "--content=")) {
                return index;
            }
            index = tokenEnd;
        }
        return -1;
    }

    private static int skipWhitespace(String command, int index) {
        int current = index;
        while (current < command.length() && Character.isWhitespace(command.charAt(current))) {
            current++;
        }
        return current;
    }

    private static int findTokenEnd(String command, int tokenStart) {
        char quote = 0;
        boolean escaped = false;
        for (int i = tokenStart; i < command.length(); i++) {
            char ch = command.charAt(i);
            if (escaped) {
                escaped = false;
                continue;
            }
            if (ch == '\\') {
                escaped = true;
                continue;
            }
            if (quote != 0) {
                if (ch == quote) {
                    quote = 0;
                }
                continue;
            }
            if (isQuote(ch)) {
                quote = ch;
                continue;
            }
            if (Character.isWhitespace(ch)) {
                return i;
            }
        }
        return command.length();
    }

    private static boolean isQuote(char ch) {
        return ch == '\'' || ch == '"';
    }

    private static String quoteCommandArgument(String value) {
        StringBuilder builder = new StringBuilder(value.length() + 2);
        builder.append('"');
        for (int i = 0; i < value.length(); i++) {
            char ch = value.charAt(i);
            if (ch == '\\' || ch == '"') {
                builder.append('\\');
            }
            builder.append(ch);
        }
        builder.append('"');
        return builder.toString();
    }

    private AtomixCommandExecuteResp buildHelpResp() {
        Map<String, Object> payload = new LinkedHashMap<>();
        payload.put("outputContent", String.join("\n", List.of(
