        resp.setOperationSource(StrUtil.EMPTY);
        resp.setOperationTarget(null);
        return resp;
    }

    private AtomixCommandExecuteResp preValidateEditCommand(String command) {
        if (StrUtil.isBlank(command) || !EDIT_PREFIX_PATTERN.matcher(command).matches()) {
            return null;
        }
        String patchBody = extractPatchBody(command);
        if (StrUtil.isBlank(patchBody)) {
            return null;
        }
        String normalizedPatch = patchBody.replace("\r\n", "\n").replace('\r', '\n');
        if (containsUnsupportedDirective(normalizedPatch)) {
            return buildEditErrorResp(EDIT_UNSUPPORTED_OPERATION, "unsupported operation", "operation", "Delete/Move");
        }
        if (hasSecondChunkMissingHeader(normalizedPatch)) {
            return buildEditErrorResp(EDIT_INVALID_PATCH,
                    "second and subsequent hunks must start with @@",
                    "reason",
                    "missing_hunk_header");
        }
        return null;
    }

    private String extractPatchBody(String command) {
        List<String> tokens = CommandLineTokenizer.tokenize(command);
        if (tokens == null || tokens.isEmpty()) {
            return null;
        }
        for (int i = 0; i < tokens.size(); i++) {
            String token = tokens.get(i);
            if (StrUtil.isBlank(token)) {
                continue;
            }
            if (StrUtil.startWithIgnoreCase(token, "--patch=")) {
                return token.substring("--patch=".length());
            }
            if (StrUtil.equalsIgnoreCase(token, "--patch") && i + 1 < tokens.size()) {
                return tokens.get(i + 1);
            }
        }
        return null;
    }

    private boolean containsUnsupportedDirective(String patchBody) {
        String lower = patchBody.toLowerCase();
        return lower.contains("*** delete file") || lower.contains("*** move to");
    }

    private boolean hasSecondChunkMissingHeader(String patchBody) {
        if (!patchBody.contains("*** Update File")) {
            return false;
        }
        String[] lines = patchBody.split("\n", -1);
        int begin = findLine(lines, "*** Begin Patch");
        int end = findLine(lines, "*** End Patch");
        if (begin < 0 || end <= begin) {
            return false;
        }
        boolean firstHunkStarted = false;
        boolean afterBlankLine = false;
        for (int i = begin + 1; i < end; i++) {
            String line = lines[i];
            String trimmed = line.trim();
            if (StrUtil.startWith(trimmed, "*** Update File")) {
                continue;
            }
            if (trimmed.startsWith("@@")) {
                firstHunkStarted = true;
                afterBlankLine = false;
                continue;
            }
            if (line.isEmpty()) {
                if (firstHunkStarted) {
                    afterBlankLine = true;
                }
                continue;
            }
            if (!isPatchBodyLine(line)) {
                continue;
            }
            if (!firstHunkStarted) {
                firstHunkStarted = true;
                afterBlankLine = false;
                continue;
            }
            if (afterBlankLine) {
                return true;
            }
            afterBlankLine = false;
        }
        return false;
    }

    private boolean isPatchBodyLine(String line) {
        return line.startsWith("+") || line.startsWith("-") || line.startsWith(" ");
    }

    private int findLine(String[] lines, String marker) {
        for (int i = 0; i < lines.length; i++) {
            if (StrUtil.equals(lines[i].trim(), marker)) {
                return i;
            }
        }
        return -1;
    }

    private AtomixCommandExecuteResp buildEditErrorResp(String code, String message, String detailKey, String detailValue) {
        AtomixCommandExecuteResp resp = new AtomixCommandExecuteResp();
        resp.setSuccess(Boolean.FALSE);
        resp.setCommand("edit");
        resp.setErrorCode(code);
        resp.setErrorMessage(message);
        Map<String, Object> details = new LinkedHashMap<>();
        if (StrUtil.isNotBlank(detailKey)) {
            details.put(detailKey, detailValue);
        }
        resp.setErrorDetails(details

