    private EmbeddingQueueCapacityAcquireResult fallbackAcquire(Integer elementId, Long fileSize) {
        String fieldKey = String.valueOf(elementId);
        try {
            cleanupExpiredReservations();
            Object existing = stringRedisTemplate.opsForHash().get(PENDING_FILE_HASH_KEY, fieldKey);
            if (existing != null) {
                refreshFileExpire(fieldKey);
                refreshTtl();
                log.info("文件向量化容量降级模式检测到已有占用，跳过重复提交，elementId:{}, fileSize:{}, currentPending:{}",
                        elementId, readable(fileSize), currentPendingReadable());
                return EmbeddingQueueCapacityAcquireResult.ALREADY_RESERVED;
            }
            long current = currentPendingBytes();
            long maxBytes = properties.getMaxPendingBytes();
            if (fileSize > maxBytes) {
                refreshTtl();
                log.info("文件向量化容量单文件超过上限，停止提交，elementId:{}, fileSize:{}, maxPendingBytes:{}",
                        elementId, readable(fileSize), readable(maxBytes));
                return EmbeddingQueueCapacityAcquireResult.LIMIT_EXCEEDED;
            }
            if (current + fileSize > maxBytes && current > 0) {
                refreshTtl();
                log.info("文件向量化容量降级模式达到上限，停止本轮提交，elementId:{}, fileSize:{}, currentPending:{}, maxPendingBytes:{}",
                        elementId, readable(fileSize), readable(current), readable(maxBytes));
                return EmbeddingQueueCapacityAcquireResult.LIMIT_EXCEEDED;
            }
            Boolean reserved = stringRedisTemplate.opsForHash().putIfAbsent(PENDING_FILE_HASH_KEY, fieldKey, String.valueOf(fileSize));
            if (Boolean.FALSE.equals(reserved)) {
                refreshFileExpire(fieldKey);
                refreshTtl();
                log.info("文件向量化容量降级模式检测到并发占用，跳过重复提交，elementId:{}, fileSize:{}, currentPending:{}",
                        elementId, readable(fileSize), currentPendingReadable());
                return EmbeddingQueueCapacityAcquireResult.ALREADY_RESERVED;
            }
            Long pending = stringRedisTemplate.opsForValue().increment(PENDING_BYTES_KEY, fileSize);
            if (pending == null) {
                stringRedisTemplate.opsForHash().delete(PENDING_FILE_HASH_KEY, fieldKey);
                stringRedisTemplate.opsForZSet().remove(PENDING_FILE_EXPIRE_ZSET_KEY, fieldKey);
                log.warn("文件向量化容量降级模式占用失败，elementId:{}, fileSize:{}", elementId, fileSize);
                return EmbeddingQueueCapacityAcquireResult.SKIPPED;
            }
            refreshFileExpire(fieldKey);
            refreshTtl();
            if (pending > properties.getMaxPendingBytes()) {
                stringRedisTemplate.opsForHash().delete(PENDING_FILE_HASH_KEY, fieldKey);
                stringRedisTemplate.opsForZSet().remove(PENDING_FILE_EXPIRE_ZSET_KEY, fieldKey);
                Long rollback = stringRedisTemplate.opsForValue().decrement(PENDING_BYTES_KEY, fileSize);
                refreshTtl();
                log.warn("文件向量化容量降级模式发生并发超限回滚，elementId:{}, fileSize:{}, currentPending:{}",
                        elementId, readable(fileSize), readable(normalizePending(rollback)));
                return EmbeddingQueueCapacityAcquireResult.LIMIT_EXCEEDED;
            }
            log.info("文件向量化容量降级模式占用成功，elementId:{}, fileSize:{}, currentPending:{}, maxPendingBytes:{}, ttlSeconds:{}",
                    elementId, readable(fileSize), readable(pending), readable(properties.getMaxPendingBytes()), properties.getTtlSeconds());
            return EmbeddingQueueCapacityAcquireResult.ACQUIRED;
        } catch (Exception e) {
            log.error("文件向量化容量降级模式执行失败，跳过本次限制，elementId:{}, fileSize:{}, error:{}",
                    elementId, readable(fileSize), e.getMessage(), e);
            return EmbeddingQueueCapacityAcquireResult.SKIPPED;
        }
    }

