                refreshTtl();
            }
            log.info("文件向量化容量降级模式释放完成，elementId:{}, releaseBytes:{}, currentPending:{}, ttlSeconds:{}",
                    elementId, readable(releaseBytes), readable(normalizedPending), properties.getTtlSeconds());
        } catch (Exception e) {
            log.error("文件向量化容量降级模式释放失败，elementId:{}, error:{}", elementId, e.getMessage(), e);
        }
    }

    private List<String> redisKeys() {
        return List.of(PENDING_BYTES_KEY, PENDING_FILE_HASH_KEY, PENDING_FILE_EXPIRE_ZSET_KEY);
    }

    private void refreshTtl() {
        long ttlSeconds = properties.getTtlSeconds();
        stringRedisTemplate.expire(PENDING_BYTES_KEY, ttlSeconds, TimeUnit.SECONDS);
        stringRedisTemplate.expire(PENDING_FILE_HASH_KEY, ttlSeconds, TimeUnit.SECONDS);
        stringRedisTemplate.expire(PENDING_FILE_EXPIRE_ZSET_KEY, ttlSeconds, TimeUnit.SECONDS);
    }

    private void refreshFileExpire(String fieldKey) {
        long expireAt = System.currentTimeMillis() + TimeUnit.SECONDS.toMillis(properties.getTtlSeconds());
        stringRedisTemplate.opsForZSet().add(PENDING_FILE_EXPIRE_ZSET_KEY, fieldKey, expireAt);
    }

    private void cleanupExpiredReservations() {
        long now = System.currentTimeMillis();
        Long current = stringRedisTemplate.execute(CLEANUP_SCRIPT, redisKeys(),
                String.valueOf(properties.getTtlSeconds()), String.valueOf(now));
        if (current != null) {
            log.info("文件向量化容量过期占用清理完成，currentPending:{}", readable(current));
        }
    }

