        LambdaQueryWrapper<BusinessTable> lambdaQueryWrapper = Wrappers.lambdaQuery(BusinessTable.class).eq(BusinessTable::getTenantId, tenantId);
        lambdaQueryWrapper.eq(StrUtil.isNotBlank(businessTableQueryReq.getContainerId()), BusinessTable::getContainerId, businessTableQueryReq.getContainerId());
        if (StrUtil.isNotBlank(businessTableQueryReq.getBelongDs())) {
            lambdaQueryWrapper.eq(BusinessTable::getBelongDs, businessTableQueryReq.getBelongDs());
        }
        if (StrUtil.isNotBlank(businessTableQueryReq.getType())) {
            lambdaQueryWrapper.eq(BusinessTable::getType, businessTableQueryReq.getType());
        }
        if (StrUtil.isNotBlank(businessTableQueryReq.getName())) {
            lambdaQueryWrapper.and(s -> s.like(BusinessTable::getName, businessTableQueryReq.getName()).or(l -> l.like(BusinessTable::getDescription, businessTableQueryReq.getName())));
        }
        lambdaQueryWrapper.orderByDesc(BusinessTable::getCreateTime);
        List<BusinessTable> businessTableInfos = businessTableMapper.selectList(lambdaQueryWrapper);
        List<BusinessTableResp> businessTableRespInfos = new ArrayList<>();
        long count = businessTablePageNo.getTotal();
