    @Override
    public Result<DataSQLResp> preview(Integer tableId, Integer pageNo, Integer pageSize) {
        BusinessTable businessTable = businessTableMapper.selectById(tableId);
        Assert.notNull(businessTable, "system.common.request.invalid");
        SysUserInfo sysUser = UserContextHolder.getCurrentUser();
        Assert.isTrue(StrUtil.equalsIgnoreCase(sysUser.getTenantId(), businessTable.getTenantId()), "system.common.request.invalid");

        // STRUCTURED 类型（Excel动态表）直接走 JdbcTemplate 查询主库
        if (MapSyncNodeType.STRUCTURED.name().equals(businessTable.getType())) {
            return previewWithJdbc(businessTable, sysUser.getTenantId(), pageNo, pageSize);
        }

        KnowledgeTableTypes tableTypes = KnowledgeTableTypes.of(businessTable.getType());
        String sql = businessTable.getSqlSource();
        if (tableTypes == KnowledgeTableTypes.TABLE) {
            sql = "select * from " + businessTable.getName();
        }
        Optional<BusinessDataSource> dataSourceOptional = businessDataSourceService.queryInfoByCode(businessTable.getBelongDs(), sysUser.getTenantId());
        if (dataSourceOptional.isEmpty()) {
            throw new RuntimeException("system.common.request.invalid");
        }
        return businessDatasourceDynamicService.executeQuery(dataSourceOptional.get().getId(), sql, pageNo, pageSize);
    }

    private Result<DataSQLResp> previewWithJdbc(BusinessTable businessTable, String tenantId, int pageNo, int pageSize) {
        String physicalName = businessTable.getDbName();
        int offset = (pageNo - 1) * pageSize;
        List<Map<String, Object>> data = jdbcTemplate.queryForList(
                "SELECT * FROM `" + physicalName + "` WHERE `_tenant_id` = ? ORDER BY `_id` DESC LIMIT ? OFFSET ?",
                tenantId, pageSize, offset);
