        resp.setSql("select * from " + physicalName);
        resp.setData(data);
        return Result.data(resp);
    }

    /**
     * 更新数据表记录
     * @param businessTableUpdateReq 更新数据表条件Vo
     * @return 是否更新成功
     */
    @Transactional(rollbackFor = Exception.class)
    @Override
    public Result<String> update(BusinessTableUpdateReq businessTableUpdateReq) {
        log.info("根据主键id修改数据表数据,Vo:{}", businessTableUpdateReq.toString());
        BusinessTable record = businessTableMapper.selectById(businessTableUpdateReq.getId());
        Assert.notNull(record, "请求数据非法");
        SysUserInfo sysUser = UserContextHolder.getCurrentUser();
        Assert.isTrue(StrUtil.equalsIgnoreCase(sysUser.getTenantId(), record.getTenantId()), "请求数据非法");
        List<BusinessColumn> columns = businessColumnService.listColumns(record);
        // 校验表信息是否修改了
        StringBuilder hexBuilder = new StringBuilder();
        hexBuilder.append(record.getName()).append(record.getDescription()).append(record.getRemark());
        for (BusinessColumn column : columns) {
            hexBuilder.append(column.getName()).append(":").append(column.getDescription());
        }
        String recordHex = DigestUtil.sha256Hex(hexBuilder.toString());
        BusinessTable businessTable = new BusinessTable();
        BeanUtils.copyProperties(businessTableUpdateReq, businessTable);
        businessTable.setModifierTime(LocalDateTime.now());
        String updateHex = businessTableUpdateReq.updateHex();
        boolean hexEquals = StrUtil.equalsIgnoreCase(recordHex, updateHex);
        if (!hexEquals) {
            // 数据发生了变动，需要重新发布。
            businessTable.setStatus(ProcessStatusEnum.UN_ISSUE.getCode());
        }
        int ret = businessTableMapper.updateById(businessTable);
        if (ret > 0) {
            // 校验文本是否修改了
            businessColumnService.updateColumns(record, businessTableUpdateReq.getColumns());
            if (!hexEquals) {
                knowledgeElementService.deleteByCode(sysUser.getTenantId(), businessTable.getContainerId(), CollUtil.newArrayList(record.getCode()));
            }
        }
        return ret > 0 ? Result.defaultSuccess("更新成功") : Result.error("更新失败");
    }

