    private BusinessTable buildBusinessTable(BusinessDataSource businessDataSource, String containerId, String tableName, String tenantId, SysUserInfo sysUser,
                                             DataBaseTable dataBaseTable, LocalDateTime now) {
        BusinessTable businessTable = new BusinessTable();
        businessTable.setContainerId(containerId);
        businessTable.setCode(IdUtil.getSnowflakeNextIdStr());
        businessTable.setName(tableName);
        businessTable.setDescription(dataBaseTable.getComment());
        businessTable.setDbName(businessDataSource.getDbName());
        businessTable.setBelongDs(businessDataSource.getCode());
        businessTable.setTenantId(tenantId);
        businessTable.setType(KnowledgeTableTypes.TABLE.name());
        businessTable.setStatus(ProcessStatusEnum.UN_ISSUE.getCode());
        businessTable.setModifierTime(now);
        businessTable.setCreateTime(now);
        businessTable.setCreator(sysUser.getCode());
        businessTable.setModifier(sysUser.getCode());
        businessTable.setSort(0);
        return businessTable;
    }

    private BusinessColumn buildBusinessColumn(DatabaseColumn column, BusinessTable table, Integer sort, LocalDateTime now) {
        BusinessColumn businessColumn = new BusinessColumn();
        businessColumn.setModifierTime(now);
        businessColumn.setCreateTime(now);
        businessColumn.setBelongDs(table.getBelongDs());
        businessColumn.setBelongTable(table.getCode());
        businessColumn.setCode(IdUtil.getSnowflakeNextIdStr());
        businessColumn.setTenantId(table.getTenantId());
        businessColumn.setDescription(column.getDescription());
        businessColumn.setName(column.getName());
        businessColumn.setDataType(column.getType());
        businessColumn.setDataLength(column.getDataLength());
        businessColumn.setDataPrecision(0);
        businessColumn.setPkStatus(column.getPrimaryKey());
        businessColumn.setNullable(column.getNullable());
        businessColumn.setSort(sort);
        businessColumn.setCreator(table.getCreator());
        businessColumn.setModifier(table.getModifier());
        return businessColumn;
    }

