    @Override
    public void abort(String messageId) {
        String key = CacheCns.CACHE_EMBEDDING_PROCESS_ABORT_PROCESS + messageId;
        stringRedisTemplate.opsForValue().set(key, CacheCns.CACHE_EMBEDDING_PROCESS_ABORT_STATUS, 2, TimeUnit.MINUTES);
    }

    @Override
    public ResponseBodyEmitter process(KnowledgeProcessReq processReq) {
        SseEmitter emitter = new SseEmitter(10 * 60 * 1000L);
        List<Integer> ids = this.listAvailableProcessElement(UserContextHolder.getTenantId(), processReq.getIds());
        if (CollUtil.isEmpty(ids)) {
            return emitter;
        }
        KnowledgeProcessContext processContext = KnowledgeProcessContext.of(ids, processReq.getMessageId());
        emitter.onTimeout(() -> {
            log.info("Process Timeout.");
            processContext.done();
        });
        emitter.onCompletion(() -> {
            log.info("Process Complete.");
            processContext.done();
        });
        emitter.onError((e) -> {
            log.error("Process Error.", e);
            processContext.done();
        });
        log.info("开始监听文件处理进度。available-ids:{}", ids);
        log.info("reqId:{}", processReq.getIds());
        RunUtils.execute(new KnowledgeLatchTask(emitter, processContext, stringRedisTemplate));
        return emitter;
    }

    @Override
    public void exchange(Integer dataId, Integer currentPage, Integer totalPage) {
        // 向量中阶段，切片进度映射到 0-80% 区间，给 EMBEDDED(80%) 和 SUCCESS(100%) 留出空间
        int pagePercent = totalPage > 0 ? currentPage * 100 / totalPage : 0;
        int percent = Math.min(pagePercent * 80 / 100, 80);
        updateProcessStatus(dataId, ProcessStatusEnum.EMBEDDING, percent);
    }

    @Override
    public void updateProcessStatus(Integer dataId, ProcessStatusEnum statusEnum) {
        updateProcessStatus(dataId, statusEnum, defaultPercent(statusEnum));
    }

    @Override
    public void updateProcessStatus(Integer dataId, ProcessStatusEnum statusEnum, Integer percent) {
        String key = CacheCns.CACHE_EMBEDDING_PROCESS_PROCESS + dataId;
        try {
            int statusCode = statusEnum.getCode();
            int p = percent != null ? percent : defaultPercent(statusEnum);
            String value = p + "," + statusCode;
            log.info("写入处理状态到Redis, dataId:{}, status:{}, percent:{}", dataId, statusCode, p);
            if (statusCode == ProcessStatusEnum.SUCCESS.getCode() || statusCode == ProcessStatusEnum.FAILURE.getCode()) {
                stringRedisTemplate.opsForValue().set(key, value, 10, TimeUnit.SECONDS);
            } else {
                stringRedisTemplate.opsForValue().set(key, value, 5, TimeUnit.MINUTES);
            }
        } catch (Exception e) {
            log.warn(e.getMessage(), e);
        }
    }

    private int defaultPercent(ProcessStatusEnum statusEnum) {
        return switch (statusEnum) {
            case INIT, DRAFT, UN_ISSUE, FAILURE -> 0;
            case CONVERT, CONVERT_SUCCESS -> 10;
            case PROCESSING -> 20;
            case EMBEDDING -> 40;
            case EMBEDDED -> 80;
            case SUCCESS -> 100;
            default -> 0;
        };

