    @Override
    public Result<Boolean> deleteByChunkId(String elementId, String referenceId) {
        Optional<SaasKnowledgeElement> saasKnowledgeElement = knowledgeElementService.queryInfoByCode(elementId);
        // 根据模型查询最大的token大小
        if (saasKnowledgeElement.isEmpty()){
            throw new IllegalArgumentException("文档不存在或已经被删除");
        }
        SaasKnowledgeElement element=saasKnowledgeElement.get();
        UniversalEmbeddingConfig  embeddingConfig=knowledgeElementEmbeddingQueryService.getEmbeddingConfigByContainerId(element.getContainerId());
        if (embeddingConfig==null){
            throw new IllegalArgumentException("嵌入模型配置不存在或者已经被删除,操作失败");
        }
        // 首先删除分片
        vectorIndexDelegate.clearChunk(VectorClearChunkReq.builder().dataId(element.getCode())
                .id(referenceId)
                .dims(embeddingConfig.getVectorDimension())
                .tenantId(element.getTenantId())
                .containerId(element.getContainerId()).build());
        return Result.data(Boolean.TRUE);
    }
    @Override
    public Result<Boolean> updateByChunkId(KnowledgeElementDetailUpdateReq req) {
        req.check();
        Optional<SaasKnowledgeElement> saasKnowledgeElement = knowledgeElementService.queryInfoByCode(req.getDataId());
        // 根据模型查询最大的token大小
        if (saasKnowledgeElement.isEmpty()){
            throw new IllegalArgumentException("文档不存在或已经被删除");
        }
        SaasKnowledgeElement element=saasKnowledgeElement.get();
        // 查询当前知识容器所归属的嵌入模型
        Optional<SaasKnowledgeConfigContainer>  knowledgeContainerOptional = saasKnowledgeConfigContainerService.queryInfoByContainerId(element.getContainerId());
        if (knowledgeContainerOptional.isEmpty()){
            throw new IllegalArgumentException("知识库配置不存在或者已经被删除");
        }
        SaasKnowledgeConfigContainer configContainer=knowledgeContainerOptional.get();
        // 获取模型参数配置
        Optional<UniversalEmbeddingConfig>  embeddingConfigOptional=modelProviderService.loadEmbedding(configContainer.getEmbeddingModel(),element.getTenantId());
        if (embeddingConfigOptional.isEmpty()){
            throw new IllegalArgumentException("嵌入模型配置不存在或者已经被删除,操作失败");
        }
        UniversalEmbeddingConfig embeddingConfig=embeddingConfigOptional.get();
        // 获取单行最大token数据
        if (StrUtil.length(req.getContent()) > embeddingConfig.getMaxTokensPerLine()) {
            throw new IllegalArgumentException("单个分片内容超过embedding模型上限(最大Token"+embeddingConfig.getMaxTokensPerLine()+")");
        }
        ChunkIdInfoReq chunkIdInfoReq=ChunkIdInfoReq.build(element.getTenantId(), element.getContainerId(), req.getReferenceId(), embeddingConfig.getVectorDimension());
        // 更新切片内容
        Optional<DataSetChunkInfo> chunkInfoOptional=vectorIndexDelegate.getChunkById(chunkIdInfoReq);
        if (chunkInfoOptional.isEmpty()){
            throw new IllegalArgumentException("切片不存在或者已经被删除");
        }
        // 开始生成嵌入embedding
        UniversalEmbeddingResponse embeddingResponse=embeddingVectorService.universalEmbedding(embeddingConfig,req.getContent());
        Assert.isTrue(embeddingResponse.isSuccess(), "生成嵌入失败:" + embeddingResponse.getErrorMessage());
        // 首先删除分片
        vectorIndexDelegate.clearChunk(VectorClearChunkReq.builder().dataId(req.getDataId())
                .id(req.getReferenceId())
                .dims(embeddingConfig.getVectorDimension())
                .tenantId(element.getTenantId())
                .containerId(element.getContainerId()).build());
        // 保存分片chunk
        DataSetChunkInfo chunkInfo= chunkInfoOptional.get();
        // 更新content字段和vector
        chunkInfo.setContent(req.getContent());
        chunkInfo.setVector(embeddingResponse.getFirstEmbedding());
        chunkInfo.getMetadata().put(PageMetaDataIndexField.FIELD_NAME_SUMMARY, req.getSummary());
        chunkInfo.getMetadata().put(PageMetaDataIndexField.FIELD_NAME_TAG, req.getTags());
        // 更新时间
        chunkInfo.setCreateTime(System.currentTimeMillis());
        // 存储回去,立即刷新索引数据可见性
        vectorIndexDelegate.saveChunks(List.of(chunkInfo),element.getTenantId(), VectorRefreshPolicy.IMMEDIATE);
        // 阻塞100ms，es是准实时系统，避免数据还没有刷新到底层索引，导致查询不可见的问题
        //ThreadUtil.sleep(RandomUtil.randomInt(10,100));
        return Result.data(Boolean.TRUE);
    }
    /**
     * 更新文件解析配置表记录
     * @param saasKnowledgeBaseConfigUpdateReq 更新文件配置表条件Vo
     * @return 是否更新成功
     */
    @Override
    @Transactional(rollbackFor = Exception.class)
    public Result<String> updateConfigElement(SaasKnowledgeConfigElementUpdateReq saasKnowledgeBaseConfigUpdateReq) {
        log.info("根据主键id修改文件配置表数据,Vo:{}", saasKnowledgeBaseConfigUpdateReq.toString());
        Assert.notBlank(saasKnowledgeBaseConfigUpdateReq.getElementId(), "文档id不能为空");
        Assert.notBlank(saasKnowledgeBaseConfigUpdateReq.getSplitMode(), "文档切分模式不能为空");
        Assert.notNull(saasKnowledgeBaseConfigUpdateReq.getMaxChunkSize(), "单个chunk最大切割size大小不能为空");
        Assert.notNull(saasKnowledgeBaseConfigUpdateReq.getOverlapSize(), "重叠块字符切割数量不能为空");
        Assert.isTrue(saasKnowledgeBaseConfigUpdateReq.getOverlapSize()< saasKnowledgeBaseConfigUpdateReq.getMaxChunkSize(), "重叠长度不能大于最大切割长度");
        Optional<SaasKnowledgeElement> saasKnowledgeElementOptional = knowledgeElementService.queryInfoByCode(saasKnowledgeBaseConfigUpdateReq.getElementId());
        if (saasKnowledgeElementOptional.isEmpty()){
            throw new IllegalArgumentException("当前文档不存在或者已经被删除");
        }
        // 校验模型的最大切割长度
        SaasKnowledgeElement element=saasKnowledgeElementOptional.get();
        knowledgeModelConfigService.checkEmbeddingInputToken(element.getContainerId(), saasKnowledgeBaseConfigUpdateReq.getMaxChunkSize());
        Integer processStatus = element.getProcessStatus();
        // 只有处理成功的才能修改
        if (Objects.equals(processStatus, ProcessStatusEnum.EMBEDDING.getCode()) ) {
            // 如果是待处理状态，直接修改
            throw new IllegalArgumentException("当前文档正在处理中,请稍后再试");
        }
        // Assert.isTrue(Objects.equals(processStatus, ProcessStatusEnum.SUCCESS.getCode()), "当前文档正在处理中,请稍后再试");
        SysUserInfo currentUser = UserContextHolder.getCurrentUser();
        SaasKnowledgeConfigElement saasKnowledgeBaseConfig = new SaasKnowledgeConfigElement();
        BeanUtils.copyProperties(saasKnowledgeBaseConfigUpdateReq, saasKnowledgeBaseConfig);
