    @Override
    public String buildTxt(List<SQLContextReq> contextReqList) {
        if (CollUtil.isEmpty(contextReqList)) {
            return StrUtil.EMPTY;
        }
        List<String> codes=contextReqList.stream().map(SQLContextReq::getCode).toList();
        List<BusinessTable> tables = businessTableService.listByCodes(codes);
        if (CollUtil.isEmpty(tables)) {
            return StrUtil.EMPTY;
        }
        Map<String,List<BusinessColumn>> tableColumnsMap=businessColumnService.mapByTables(tables);
        StringBuilder sb = new StringBuilder();
        for (BusinessTable table:tables){
            // 更新contextReqList中的数据
            for (SQLContextReq contextReq : contextReqList) {
                if (StrUtil.equalsIgnoreCase(contextReq.getCode(), table.getCode())) {
                    contextReq.setBusinessTable(table);
                    break;
                }
            }
            List<BusinessColumn> columns=tableColumnsMap.getOrDefault(table.getCode(),List.of());
            if (CollUtil.isEmpty(columns)){
                continue;
            }
            sb.append(SQLUtils.toTxt(table, columns)).append("\n");
        }
        return sb.toString();
    }

    @Override
    public String buildTxt(SQLContextReq contextReq) {
        Optional<BusinessTable> businessTableOptional = businessTableService.queryInfoByCode(contextReq.getTenantId(), contextReq.getCode());
        if (businessTableOptional.isEmpty()) {
            return StrUtil.EMPTY;
        }
        BusinessTable businessTable = businessTableOptional.get();
        contextReq.setBusinessTable(businessTable);
        List<BusinessColumn> columns = businessColumnService.listColumns(businessTable);
        return SQLUtils.toTxt(businessTable, columns);
    }

    @Override
    public String runSql(SQLContextReq sqlContextReq) {
        try {
            BusinessTable businessTable = sqlContextReq.getBusinessTable();

            // STRUCTURED 类型（Excel动态表）直接走 JdbcTemplate 查询主库
            if (MapSyncNodeType.STRUCTURED.name().equals(businessTable.getType())) {
                return runSqlWithJdbc(sqlContextReq);
            }

            Optional<BusinessDataSource> dataSourceOptional = businessDataSourceService.queryInfoByCode(businessTable.getBelongDs(), sqlContextReq.getTenantId());
            if (dataSourceOptional.isEmpty()) {
                return StrUtil.EMPTY;
            }
            BusinessDataSource dataSource = dataSourceOptional.get();
            // 这里大模型生成的SQL语句，有可能会存在多个SQL的情况，通过;进行分割，并且分批次执行获取总的结果
            List<String> sqlCollections = SQLUtils.extractSql(sqlContextReq.getSql());
            StringBuilder resultBuilder = new StringBuilder();
            for (String sql : sqlCollections) {
                if (StrUtil.isEmpty(sql)) {
                    continue;
                }
                try{
                    List<Map<String, Object>> maps = businessDatasourceDynamicService.executeSql(dataSource.getId(), sql, 1, 100);
                    // 拼装一个数据结果返回
                    resultBuilder.append(SQLUtils.rowDataText(sql, maps)).append("\n");
