                }
            }
            return resultBuilder.toString();
        } catch (Exception e) {
            log.error(e.getMessage(), e);
        }
        return StrUtil.EMPTY;
    }

    private String runSqlWithJdbc(SQLContextReq sqlContextReq) {
        List<String> sqlCollections = SQLUtils.extractSql(sqlContextReq.getSql());
        StringBuilder resultBuilder = new StringBuilder();
        for (String sql : sqlCollections) {
