                continue;
            }
            try {
                List<Map<String, Object>> maps = jdbcTemplate.queryForList(sql);
                resultBuilder.append(SQLUtils.rowDataText(sql, maps)).append("\n");
            } catch (Exception e) {
                log.error(e.getMessage(), e);
            }
        }
        return resultBuilder.toString();
    }

