            // 6. 调用安全接口并捕获响应
            String targetUrl = buildSecureTargetUrl();
            OkHttpClient client = createClient();
            RequestBody requestBody = RequestBody.create(GsonUtils.GSON.toJson(secureRequest), JSON_MEDIA_TYPE);
            Request request = new Request.Builder().url(targetUrl).post(requestBody)
                    .header("Accept", "application/json")
                    .header(FORWARD_REQUEST_HEADER, FORWARD_REQUEST_VALUE)
                    .build();

            log.info("安全转发并捕获响应, appId:{}, tenantId:{}, targetUrl:{}", appId, appInfo.getTenantId(), targetUrl);
            long begin = System.currentTimeMillis();
            try (Response upstream = client.newCall(request).execute()) {
                String responseBody = upstream.body() != null ? upstream.body().string() : "";
                log.info("安全转发完成, targetUrl:{}, status:{}, costMs:{}", targetUrl, upstream.code(), System.currentTimeMillis() - begin);
                return responseBody;
            }
        } catch (Exception e) {
            log.error("安全转发并捕获响应失败, appId:{}", appId, e);
            throw new RuntimeException("安全转发失败: " + e.getMessage(), e);
        }
    }

    /**
     * 简单转发（直接透传，目标环境跳过验证）
     */
    private void forwardSimple(ChatAppApiV1Completion v1Completion, HttpServletRequest request, HttpServletResponse response) {
        String targetUrl = buildTargetUrl();
        OkHttpClient client = createClient();
        RequestBody requestBody = RequestBody.create(GsonUtils.GSON.toJson(v1Completion), JSON_MEDIA_TYPE);
        Request.Builder builder = new Request.Builder().url(targetUrl).post(requestBody);
        copyRequestHeaders(request, builder);
        addForwardHeaders(builder, v1Completion);
        executeForward(targetUrl, client, builder.build(), response);
    }

    /**
     * 安全转发（AES-GCM 加密 AppInfo 和 Settings）
     */
    private void forwardSecure(ChatAppApiV1Completion v1Completion, HttpServletRequest request, HttpServletResponse response) {
