            String appKey = CacheCns.APP_CHAT_KEY + v1Completion.getMessageId() + ":" + v1Completion.getTimestamp();
            String appId = stringRedisTemplate.opsForValue().get(appKey);
            if (StrUtil.isBlank(appId)) {
                throw new IllegalStateException("转发请求未找到 appId, messageId:" + v1Completion.getMessageId());
            }

            // 2. 查询 AppInfo
            Optional<AppInfo> appInfoOptional = appInfoService.querySingleByAppId(appId);
            if (appInfoOptional.isEmpty()) {
                throw new IllegalStateException("转发请求未找到 AppInfo, appId:" + appId);
            }
            AppInfo appInfo = appInfoOptional.get();

            // 3. 查询 Settings
            PromptInfoResp settings = appSettingsService.queryInfoByAppId(
                    appInfo.getAppid(),
                    appInfo.getTenantId(),
