            SecureChatAppApiV1Completion.ForwardPayload payload = new SecureChatAppApiV1Completion.ForwardPayload();
            payload.setCompletion(v1Completion);
            payload.setSourceTenantId(appInfo.getTenantId());
            payload.setTargetTenantId(properties.getDefaultTenantId());
            payload.setSourceAppId(appId);
            payload.setStream(true);
            String encryptedPayload = AesGcmUtils.encrypt(objectMapper.writeValueAsString(payload), aesKey);

            // 7. 构建安全转发请求体
            SecureChatAppApiV1Completion secureRequest = new SecureChatAppApiV1Completion();
            secureRequest.setEncryptedAppInfo(encryptedAppInfo);
