@Slf4j
@AllArgsConstructor
@Service
public class ChannelQyWechatChatServiceImpl implements ChannelQyWechatChatService {

    final ChannelQyWechatService channelQyWechatService;
    final BotAgent botAgent;
    final ChannelQyWechatMessageService channelQyWechatMessageService;
    final AppChatContextBuilder appChatContextBuilder;
    final OpenApiChatForwardService openApiChatForwardService;

    @Override
    public WxCpXmlOutMessage chat(WxCpXmlMessage wxCpXmlMessage, Map<String, Object> map, WxCpService wxCpService) {
        log.info("企业微信回调Chat事件");
        String agentId = wxCpXmlMessage.getAgentId();
        // conversationId使用fromUserName
        String conversationId = wxCpXmlMessage.getFromUserName();
        String question = wxCpXmlMessage.getContent();
        if (StrUtil.isBlank(conversationId) || StrUtil.isBlank(question)) {
            log.info("conversationId或者question为空");
            return null;
        }
        Optional<AppQyWechatConfig> wechatConfigOptional = channelQyWechatService.getByCode(agentId);
        if (wechatConfigOptional.isEmpty()) {
            return null;
        }
        AppQyWechatConfig wechatConfig = wechatConfigOptional.get();

        // ZH_BOT 类型应用走安全转发到目标环境
        if (openApiChatForwardService.shouldForwardByAppId(wechatConfig.getAppid())) {
            return forwardToSecureEnv(wechatConfig, wxCpXmlMessage, wxCpService);
        }

        // 构建用户信息
        SysUserInfo sysUserInfo = new SysUserInfo();
        sysUserInfo.setCode(wxCpXmlMessage.getFromUserName());
        sysUserInfo.setTenantId(wechatConfig.getTenantId());
        // 复制给LocalContext上下文,在UserContextHolder中使用
        ThreadLocalHolder.setUser(sysUserInfo);
        // 构建问答信息
        AppChatDebugCompletion appChatDebugCompletion=new AppChatDebugCompletion();
        appChatDebugCompletion.setAppid(wechatConfig.getAppid());
        appChatDebugCompletion.setQuestion(question);
        appChatDebugCompletion.setConversationId(conversationId);
        appChatDebugCompletion.setPlatforms(Platforms.QY_WECHAT);
        appChatDebugCompletion.setStream(false);
        // integrations
        appChatDebugCompletion.setIntegrations(List.of(ChatIntegration.from(AgentIntegrations.INNER_INTENT),ChatIntegration.from(AgentIntegrations.INNER_SUBQUERY)));
        ChainContext chainContext = appChatContextBuilder.build(appChatDebugCompletion);
        BotCompletionResponse botCompletionResponse = botAgent.startSync(chainContext);
        String answer = botCompletionResponse.firstMessage();
        if (StrUtil.isBlank(answer)) {
            log.info("回答为空");
            return null;
        }
        // 判断内容是否超过2048个字节，如果超过，那么微信会自动截断，此时给一个临时的链接，让用户点击查看
        answer = channelQyWechatMessageService.truncateMessage(question, wechatConfig.getTenantId(), chainContext.getSessionConversation().getMessageId(), answer);
        // 构建微信主动发送的Markdown消息
        WxCpMessage wxCpMessage = WxCpMessage.MARKDOWN().agentId(NumberUtil.parseInt(wxCpXmlMessage.getAgentId()))
                .toUser(wxCpXmlMessage.getFromUserName())
                .content(answer).build();
        WxCpMessageService wxCpMessageService = new WxCpMessageServiceImpl(wxCpService);
        try {
            wxCpMessageService.send(wxCpMessage);
        } catch (WxErrorException e) {
            throw new RuntimeException(e);
        }
        // 直接返回null，不需要回复消息
        return null;
    }

    /**
     * ZH_BOT 类型应用：安全转发到目标环境并获取回复
     */
    private WxCpXmlOutMessage forwardToSecureEnv(AppQyWechatConfig wechatConfig, WxCpXmlMessage wxCpXmlMessage, WxCpService wxCpService) {
        String question = wxCpXmlMessage.getContent();
        String conversationId = wxCpXmlMessage.getFromUserName();

        // 构建转发请求
        ChatAppApiV1Completion v1Completion = new ChatAppApiV1Completion();
        v1Completion.setPrompt(question);
        v1Completion.setConversationId(conversationId);
        v1Completion.setMessageId(cn.hutool.core.util.IdUtil.getSnowflakeNextIdStr());
        v1Completion.setTimestamp(System.currentTimeMillis());

        // 安全转发到目标环境 securePath 接口
        String responseBody = openApiChatForwardService.forwardCompletionAndCapture(wechatConfig.getAppid(), v1Completion);

        // 解析响应获取回答
        String answer = parseAnswerFromResponse(responseBody);
        if (StrUtil.isBlank(answer)) {
            log.info("ZH_BOT转发回答为空, appId:{}", wechatConfig.getAppid());
            return null;
        }

        // 通过企微消息API主动发送
        WxCpMessage wxCpMessage = WxCpMessage.MARKDOWN().agentId(NumberUtil.parseInt(wxCpXmlMessage.getAgentId()))
                .toUser(wxCpXmlMessage.getFromUserName())
                .content(answer).build();
        WxCpMessageService wxCpMessageService = new WxCpMessageServiceImpl(wxCpService);
        try {
            wxCpMessageService.send(wxCpMessage);
        } catch (WxErrorException e) {
            throw new RuntimeException(e);
        }
        return null;
    }

