     */
    private String parseAnswerFromResponse(String responseBody) {
        if (StrUtil.isBlank(responseBody)) {
            return StrUtil.EMPTY;
        }
        try {
            com.google.gson.JsonObject json = GsonUtils.GSON.fromJson(responseBody, com.google.gson.JsonObject.class);
            if (json != null && json.has("choices")) {
                com.google.gson.JsonArray choices = json.getAsJsonArray("choices");
                if (choices != null && !choices.isEmpty()) {
                    com.google.gson.JsonObject firstChoice = choices.get(0).getAsJsonObject();
                    if (firstChoice.has("message")) {
                        com.google.gson.JsonObject message = firstChoice.getAsJsonObject("message");
                        if (message.has("content")) {
                            return message.get("content").getAsString();
                        }
                    }
                }
            }
        } catch (Exception e) {
            log.warn("解析转发响应失败, responseBody:{}", responseBody, e);
        }
        return StrUtil.EMPTY

