        log.info("文件上传-对话,api:{}", "/kb/chat/upload");
        long size = 0;
        for (MultipartFile multipartFile : multipartFiles) {
            size += multipartFile.getSize();
        }
        if (size > 500 * 1024 * 1024) {
            return Result.error("文件总大小不能超过500MB");
