core.util.StrUtil;
import cn.hutool.http.HttpUtil;
import com.torchv.application.knowledge.domain.embedding.pojo.UniversalDocumentParseConfig;
import com.torchv.application.knowledge.model.dto.queue.MessageFileConvertReq;
import com.torchv.infra.embedding.FileEmbeddingFacade;
import com.torchv.infra.embedding.engine.DocumentParseEngineService;
import com.torchv.infra.embedding.engine.ExternalParseResult;
import com.torchv.repository.chat.entity.SaasKnowledgeElement;
import com.torchv.repository.kb.entity.SaasKnowledgeConfigContainer;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Autowired;

import java.io.File;
import java.util.Optional;
import java.util.function.Function;

/**
 * @author <a href="xiaoymin@foxmail.com">xiaoymin@foxmail.com</a>
 * 2024/4/16 20:27
 * @since torchv_server v1.7.1
 */
@Slf4j
public abstract class AbstractFileEmbeddingFacade implements FileEmbeddingFacade {

    @Autowired
    protected DocumentParseEngineService documentParseEngineService;

    /**
     * 下载文件
     * @param convertReq 请求参数
     * @return 文件
     */
    protected File downloadFile(MessageFileConvertReq convertReq) {
        File tmpFile = FileUtil.createTempFile(RandomUtil.randomString(32), "." + convertReq.getFormat(), true);
        log.info("开始下载文件，file:{}", convertReq.getOssUrl());
        HttpUtil.downloadFile(convertReq.getOssUrl(), tmpFile, 300 * 1000);
        log.info("下载文件完成，filePath:{}", tmpFile.getAbsolutePath());
        return tmpFile;
    }

    /**
     * 尝试使用外部解析引擎解析文件。
     * 如果配置了非 DEFAULT 的解析引擎，且文件类型受支持，则提交到外部引擎解析。
     * 如果未配置外部引擎、文件类型不支持、或解析失败，返回 Optional.empty()。
     *
     * @param convertReq         文件转换请求
     * @param tmpFile            已下载的临时文件
     * @param container          知识库配置容器
     * @param elementCode        文件级别的elementCode，用于查询文件级配置（可为 null）
     * @param imageUploadHandler 图片上传处理器（MinerU ZIP 模式使用，可为 null）
     * @return 外部解析结果，empty 表示应回退默认引擎
     */
    protected Optional<ExternalParseResult> tryExternalParse(MessageFileConvertReq convertReq,
                                                              File tmpFile,
                                                              SaasKnowledgeConfigContainer container,
                                                              String elementCode,
                                                              Integer elementId,
                                                              Function<File, String> imageUploadHandler) {
        Optional<UniversalDocumentParseConfig> configOpt = documentParseEngineService.resolveParseConfig(
                elementCode, container.getContainerId(), convertReq.getTenantId());
        if (configOpt.isEmpty()) {
            return Optional.empty();
        }
        UniversalDocumentParseConfig parseConfig = configOpt.get();
        if (!documentParseEngineService.isFileTypeSupported(convertReq.getFormat(), parseConfig)) {
            log.info("文件类型 {} 不在外部解析引擎支持列表中: {}", convertReq.getFormat(), parseConfig.getLayoutDocumentFormats());
            return Optional.empty();
        }

        // 先检查Redis中是否有之前提交但未完成的解析任务（程序异常退出恢复场景）
        if (elementId != null) {
            String existingTaskId = documentParseEngineService.getExternalTaskId(elementId);
            if (StrUtil.isNotBlank(existingTaskId)) {
                log.info("发现未完成的外部解析任务, elementId={}, taskId={}, 使用已有taskId等待结果", elementId, existingTaskId);
                ExternalParseResult result = documentParseEngineService.waitForExternalParseResult(
                        existingTaskId, parseConfig, imageUploadHandler, tmpFile.getName(), elementId);
                documentParseEngineService.removeExternalTask(elementId);
                return Optional.of(result);
            }
        }

        // 提交新的外部解析任务
        ExternalParseResult result = documentParseEngineService.parseWithExternalEngine(tmpFile, parseConfig, imageUploadHandler, elementId);
        // 提交成功后保存taskId到Redis（在parseWithExternalEngine内部轮询前已提交）
        // 注意：parseWithExternalEngine是阻塞的（内部轮询），只有成功完成后才到这里
        // 所以taskId主要用于异常恢复——如果程序在轮询期间崩溃，Redis中的taskId会被恢复Job使用
        if (result.isSuccess() && elementId != null) {
            documentParseEngineService.removeExternalTask(elementId);
        }
        return Optional.of(result)

