/**
 * SQL相关的工具
 * @author <a href="xiaoymin@foxmail.com">xiaoymin@foxmail.com</a>
 * 2024/8/13 10:03
 * @since torchv_server v1.7.10
 */
@Slf4j
public class SQLUtils {

    /**
     * select前缀,忽略大小写
     */
    static final Pattern SELECT_PREFIX = Pattern.compile("(?i)^\\s*SELECT[\\s\\S]*$", Pattern.CASE_INSENSITIVE);
    /**
     * 关键字
     */
    static final String[] KEYWORDS = new String[]{"drop", "update", "delete", "insert", "merge", "truncate", "create", "alter", "grant", "revoke", "commit", "rollback", "savepoint", "rename"};


    /**
     * 检查SQL中是否包含关键字
     * @param sql SQL
     * @param content 关键字内容
     * @return true 包含，false 不包含
     * @since v1.7.11
     */
    public static boolean containsTable(String sql,String content) {
        if (StrUtil.isBlank(sql) || StrUtil.isBlank(content)) {
            return false;
        }
        // 对sql进行切割
        List<String> sqlParts = StrUtil.split(sql, StrUtil.SPACE);
        for (String part : sqlParts) {
            if (StrUtil.contains(content,part)){
                return true;
            }
        }
        return false;
    }

    /**
     * 检查SQL是否是select语句
     * @param sql SQL
     */
    public static String checkSelect(String sql) {
        log.info("checkSelect:{}", sql);
        // 1、必须以select开头
        Assert.isTrue(ReUtil.isMatch(SELECT_PREFIX, sql), "sql statement invalid.");
        // 基于jsqlparser 判断SQL语句是否合法
        try {
            Statement statement = CCJSqlParserUtil.parse(sql);
            if (statement instanceof Select select) {
                log.info("select sql statement");
                return select.getSelectBody().toString();
            } else {
                throw new RuntimeException("sql statement invalid.");
            }
        } catch (JSQLParserException e) {
            log.error(e.getMessage(), e);
            //throw new RuntimeException("sql statement invalid.");
        }
        return sql;
    }

    /**
     * 提取SQL语句
     * @param nl2sqls SQL文本
     * @return SQL列表
     * @since v1.4.4
     */
    public static List<String> extractSql(String nl2sqls){
        Optional<SqlScriptResult> resultOptional = GsonUtils.fromJson(nl2sqls, SqlScriptResult.class);
        if (resultOptional.isPresent()){
            // 这里直接返回SQL语句
            List<SqlScriptValue>  values=resultOptional.get().getSqls();
            if (CollUtil.isNotEmpty(values)){
                return values.stream().map(SqlScriptValue::getSql).toList();
            }else{
                return extractSqlDefault(nl2sqls);
            }
        }
        return extractSqlDefault(nl2sqls);
    }

    public static List<String> extractSqlDefault(String sql){
        List<String> tables=new ArrayList<>();
        try {
            List<String> sqlCollections = StrUtil.split(sql, ';');
            for (String sqlItem : sqlCollections) {
                if (StrUtil.isEmpty(sqlItem)) {
                    continue;
                }
                tables.add(sqlItem);
            }
        } catch (Exception e) {
            log.error(e.getMessage(), e);
        }
        return tables;
    }

    /**
     * 拼接SQL语句的执行结果
     * @param sql sql语句
     * @param results 执行结果
     * @return 文本信息
     * @since v1.7.11
     */
    public static String rowDataText(String sql, List<Map<String, Object>> results) {
        StringBuilder builder = new StringBuilder("\r\n");
        builder.append("```shell").append("\r\n");
        builder.append("console> ").append(sql).append("\r\n");
        if (CollUtil.isNotEmpty(results)) {
            int headerIndex = 0;
            String dataJoin = "         |         ";
            String dataLine = "-------------------------";
            int dataSize = 0;
            // 获取表头
            for (Map<String, Object> data : results) {
                if (headerIndex == 0) {
                    dataSize = data.size();
                    // append头
                    List<String> headerKeys = new ArrayList<>();
                    for (Map.Entry<String, Object> entry : data.entrySet()) {
                        headerKeys.add(entry.getKey());
                    }
                    String headerLine = StrUtil.join(dataJoin, headerKeys);
                    builder.append("+").append(dataLine.repeat(dataSize)).append("+").append("\r\n");
                    builder.append("|         ").append(headerLine).append("         |").append("\r\n");
                    builder.append("+").append(dataLine.repeat(dataSize)).append("+").append("\r\n");
                }
                // append值
                List<String> values = new ArrayList<>();
                for (Map.Entry<String, Object> entry : data.entrySet()) {
                    values.add(Objects.toString(entry.getValue(), "NULL"));
                }
                String valueLine = StrUtil.join(dataJoin, values);
                // builder.append("+").append(dataLine.repeat(dataSize)).append("+").append("\r\n");
                builder.append("|         ").append(valueLine).append("         |").append("\r\n");
                // builder.append("+").append(dataLine.repeat(dataSize)).append("+").append("\r\n");
                headerIndex++;
            }
            builder.append("+").append(dataLine.repeat(dataSize)).append("+").append("\r\n");
            builder.append(results.size()).append(" row in set (0.01 sec)").append("\r\n");
        } else {
            builder.append("Empty Set").append("\r\n");
        }
        builder.append("````").append("\r\n");
        return builder.toString();
    }

    /**
     * 知识库信息转换为文本
     * @param table 表信息
     * @param columns 列信息
     * @return 文本信息
     * @since torchv_server v1.7.10
     */
    public static String toTxt(BusinessTable table, List<BusinessColumn> columns) {
        StringBuilder tableContent = new StringBuilder();
        tableContent.append("# ").append(table.getName()).append("\n");
        tableContent.append(Objects.toString(table.getDescription(), StrUtil.EMPTY)).append("\n");
        if (StrUtil.equalsIgnoreCase(table.getType(), KnowledgeTableTypes.TABLE.name())){
            tableContent.append(getTableSql(table, columns));
        } else if (StrUtil.equalsIgnoreCase(table.getType(), MapSyncNodeType.STRUCTURED.name())){
            tableContent.append(getStructuredTableSql(table, columns));
        } else if (StrUtil.equalsIgnoreCase(table.getType(), KnowledgeTableTypes.VIEW.name())){
            tableContent.append(getViewSql(table, columns));
        }
        tableContent.append(Objects.toString(table.getRemark(), StrUtil.EMPTY));
        return tableContent.toString();
    }



    public static String getTableSql(BusinessTable table, List<BusinessColumn> columns){
        StringBuilder tableContent = new StringBuilder();
        tableContent.append("```sql\n");
        tableContent.append("create table `").append(table.getName()).append("` (\n");
        // 针对列进行排序（倒叙）
        columns.sort(Comparator.comparing(BusinessColumn::getSort));
        for (BusinessColumn column : columns) {
            tableContent.append("\t").append(column.getName()).append("\t")
                    .append(column.getDataType()).append("\t")
                    .append("comment").append("\t")
                    .append("'").append(Objects.toString(column.getDescription(), StrUtil.EMPTY)).append("'").append("\t")
                    .append(",").append("\n");
        }
        tableContent.append(")").append(" COMMENT='").append(Objects.toString(table.getDescription(), StrUtil.EMPTY)).append("';\n");
        tableContent.append("```").append("\n");
        return tableContent.toString();
    }

    /**
     * STRUCTURED 类型（Excel 动态表）的 DDL 文本生成
     * 与 ExcelDynamicTableServiceImpl.buildCreateTableDdl 保持一致
     */
    public static String getStructuredTableSql(BusinessTable table, List<BusinessColumn> columns){
        // 物理表名：excel_{tenantId}_{tableCode}，存储在 dbName 字段
        String physicalName = StrUtil.isNotBlank(table.getDbName()) ? table.getDbName() : table.getName();
        StringBuilder sb = new StringBuilder();
        sb.append("```sql\n");
        sb.append("CREATE TABLE `").append(physicalName).append("` (\n");
        // 系统列
        sb.append("  `_id` BIGINT NOT NULL AUTO_INCREMENT COMMENT '系统主键',\n");
        sb.append("  `_tenant_id` VARCHAR(50) NOT NULL DEFAULT '0' COMMENT '租户ID',\n");
        sb.append("  `_create_time` DATETIME COMMENT '创建时间',\n");
        sb.append("  `_modifier` VARCHAR(100) COMMENT '修改人',\n");
        sb.append("  `_modifier_time` DATETIME COMMENT '修改时间',\n");
        // 用户定义列
        columns.sort(Comparator.comparing(BusinessColumn::getSort));
        for (BusinessColumn column : columns) {
            String typeDef = resolveMysqlTypeDef(column.getDataType(), column.getDataLength());
            sb.append("  `").append(column.getName()).append("` ").append(typeDef);
            if (StrUtil.isNotBlank(column.getDescription())) {
                sb.append(" COMMENT '").append(column.getDescription().replace("'", "\\'")).append("'");
            }
            sb.append(",\n");
        }
        sb.append("  PRIMARY KEY (`_id`)\n");
        sb.append(")");
        // 表注释保留中文名称，便于大模型理解表含义
        if (StrUtil.isNotBlank(table.getName())) {
            sb.append(" COMMENT='").append(table.getName().replace("'", "\\'")).append("'");
        }
        sb.append(";\n");
        sb.append("```\n");
        return sb.toString();
    }

    /**
     * 将前端列类型映射为 MySQL 类型定义
     * 与 ExcelColumnType.toMysqlTypeDef 逻辑保持一致
     */
    private static String resolveMysqlTypeDef(String dataType, Long dataLength) {
        if (dataType == null) return "VARCHAR(500)";
        return switch (dataType.toLowerCase()) {
            case "long" -> "BIGINT";
            case "double" -> "DOUBLE";
            case "datetime" -> "DATETIME";
            case "link" -> "VARCHAR(" + (dataLength != null && dataLength > 0 ? dataLength : 2000) + ")";
            default -> "VARCHAR(" + (dataLength != null && dataLength > 0 ? dataLength : 500) + ")";
        }

