/**
 * XLS/XLSX格式处理，参考{@link DocConvertFormats} 进行引用
 * @author <a href="xiaoymin@foxmail.com">xiaoymin@foxmail.com</a>
 * 2024/4/15 17:01
 * @since torchv_server v1.7.1
 */
@RequiredArgsConstructor
@Service("fileEmbeddingExcelFacade")
@Slf4j
public class FileEmbeddingExcelFacade extends AbstractFileEmbeddingFacade {

    final KnowledgeElementService knowledgeElementService;
    final MaterialService materialService;
    final ModelProviderService modelProviderService;
    final UnstructuredEmbeddingService unstructuredEmbeddingService;
    final SaasKnowledgeConfigContainerService saasKnowledgeConfigContainerService;
    final SaasKnowledgeConfigElementService saasKnowledgeConfigElementService;
    final ExcelParserProperties excelParserProperties;
    final MaterialServiceAdapter materialServiceAdapter;
    final TenantInfoAdapter tenantInfoAdapter;

    @Override
    public boolean convert(MessageFileConvertReq convertReq) {
        Optional<SaasKnowledgeElement> elementOptional = tenantInfoAdapter.findElementById(convertReq.getDataId());
        String creator = elementOptional.map(SaasKnowledgeElement::getCreator).orElse(null);
        if (shouldUseLegacy(elementOptional)) {
            log.info("Legacy excel parser forced by splitMode=SEMANTIC_MD_EXCEL for dataId={}", convertReq.getDataId());
            return convertWithLegacy(convertReq, elementOptional);
        }
        // 尝试使用外部解析引擎
        if (elementOptional.isPresent()) {
            SaasKnowledgeElement element = elementOptional.get();
            String containerId = element.getContainerId();
            Optional<SaasKnowledgeConfigContainer> containerOpt = saasKnowledgeConfigContainerService.queryInfoByContainerId(containerId);
            if (containerOpt.isPresent()) {
                File tmpFile = this.downloadFile(convertReq);
                try {
                    Optional<ExternalParseResult> externalResult = tryExternalParse(convertReq, tmpFile, containerOpt.get(), element.getCode(), element.getId(), null);
                    if (externalResult.isPresent() && externalResult.get().isSuccess()) {
                        log.info("外部解析引擎解析Excel完成，继续embedding流程");
                        UniversalEmbeddingConfig embeddingConfig = resolveEmbeddingConfig(element);
                        UnstructuredEmbeddingTxtFileConvert txtFileConvert = UnstructuredEmbeddingTxtFileConvert.of(element, embeddingConfig, externalResult.get().getMarkdownFile(), true);
                        UnstructuredEmbeddingTxtResult embeddingTxtResult = unstructuredEmbeddingService.embedding(txtFileConvert);
                        KnowledgeEmbeddingStatusReq statusReq = embeddingTxtResult.toEmbeddingStatus();
                        statusReq.setPreviewUrl(convertReq.getOriginalOssUrl());
                        MaterialInfoResp mdFileResponse = materialService.save(externalResult.get().getMarkdownFile(), DigestUtil.md5Hex(externalResult.get().getMarkdownFile()), convertReq.getTenantId());
                        statusReq.setConvertMarkdownFileUrl(mdFileResponse.getFileUrl());
                        knowledgeElementService.updateEmbeddingStatus(element.getId(), statusReq);
                        return true;
                    }
                    if (externalResult.isPresent()) {
                        log.warn("外部解析引擎失败: {}, 回退到默认解析引擎", externalResult.get().getErrorMessage());
                    }
                } finally {
                    FileUtil.del(tmpFile);
                }
            }
        }
        log.info("Advanced excel parser enabled for tenant={} user={}", convertReq.getTenantId(), creator);
        boolean success = convertAdvanced(convertReq, elementOptional);
        if (success) {
            return true;
        }
        log.warn("Advanced excel parser failed for dataId {}, falling back to legacy", convertReq.getDataId());
        return convertWithLegacy(convertReq, elementOptional);
    }

    /**
     * 公开的高级解析入口，便于渐进式替换和灰度。
     */
    public boolean convertAdvanced(MessageFileConvertReq convertReq) {
        Optional<SaasKnowledgeElement> elementOptional = tenantInfoAdapter.findElementById(convertReq.getDataId());
        return convertAdvanced(convertReq, elementOptional);
    }

    private boolean convertAdvanced(MessageFileConvertReq convertReq, Optional<SaasKnowledgeElement> elementOptional) {
        log.info("xls文件转换-高级解析");
        File tmpFile = null;
        File xlsMdFile = null;
        File xlsKvFile = null;
        String ossUrl = null;
        try {
            tmpFile = this.downloadFile(convertReq);
            String format = convertReq.getFormat() == null ? null : convertReq.getFormat().toLowerCase();
            boolean markdownInput = FileMagicUtils.isMarkdown(tmpFile.getName()) || (format != null && FileMagicUtils.isMarkdown("." + format));
            String realFilename = elementOptional.map(SaasKnowledgeElement::getEleName).orElse(tmpFile.getName());
            if (markdownInput) {
                // 直接复用已有markdown产物，补齐kv
                xlsMdFile = tmpFile;
                ossUrl = convertReq.getOssUrl();
                Charset charset = CharacterUtils.detectCharset(xlsMdFile);
                String content = FileUtil.readString(xlsMdFile, charset);
                java.util.List<TableData> tableDataList = MarkdownToTableData.parseMarkdownTables(content, realFilename);
                java.util.List<java.util.List<String>> keyValuePairs = KbsExcelParser.generateKeyValuePairs(tableDataList);
                String kvContent = KbsExcelParser.kvPairsToString(keyValuePairs);
                xlsKvFile = FileUtil.createTempFile(RandomUtil.randomString(32), ".md", true);
                FileUtil.writeUtf8String(kvContent, xlsKvFile);
            } else {
                xlsMdFile = FileUtil.createTempFile(RandomUtil.randomString(32), ".md", true);
                xlsKvFile = FileUtil.createTempFile(RandomUtil.randomString(32), ".md", true);
                ExcelParseOptions options = ExcelParseOptions.builder()
                        .multiTableInOneSheet(excelParserProperties.isMultiTableInOneSheet())
                        .logger(log)
                        .analyzeImages(excelParserProperties.isShouldAnalyzeImageForExcel())
                        .evaluateFormulas(excelParserProperties.isEvaluateFormulas())
                        .tenantId(convertReq.getTenantId())
                        .materialServiceAdapter(materialServiceAdapter)
                        .supportedImageFormats(excelParserProperties.getSupportedImageFormats())
                        .build();
                var tables = KbsExcelParser.parseExcelFile(tmpFile, realFilename, options);
                var parseResult = ExcelParseResult.of(tables);
                FileUtil.writeUtf8String(parseResult.markdownAsString(), xlsMdFile);
                FileUtil.writeUtf8String(parseResult.kvAsString(), xlsKvFile);
                MaterialInfoResp mdFileResponse = materialServiceAdapter.save(xlsMdFile, DigestUtil.md5Hex(xlsMdFile), convertReq.getTenantId());
                ossUrl = mdFileResponse.getFileUrl();
            }

            if (ossUrl == null) {
                ossUrl = convertReq.getOssUrl() != null ? convertReq.getOssUrl() : convertReq.getOriginalOssUrl();
            }

            if (elementOptional.isPresent()) {
                SaasKnowledgeElement element = elementOptional.get();
                knowledgeElementService.updateStatus(element.getId(), ProcessStatusEnum.PROCESSING);
                UniversalEmbeddingConfig embeddingConfig = resolveEmbeddingConfig(element);
                File embeddingFile = excelParserProperties.isPreferKvForEmbedding() && xlsKvFile != null ? xlsKvFile : xlsMdFile;
                boolean markdownFile = embeddingFile != null && embeddingFile.equals(xlsMdFile) && !excelParserProperties.isPreferKvForEmbedding();
                UnstructuredEmbeddingTxtFileConvert txtFileConvert = UnstructuredEmbeddingTxtFileConvert.of(element, embeddingConfig, embeddingFile, markdownFile);
                UnstructuredEmbeddingTxtResult embeddingTxtResult = unstructuredEmbeddingService.embedding(txtFileConvert);
                KnowledgeEmbeddingStatusReq statusReq = embeddingTxtResult.toEmbeddingStatus();
                statusReq.setPreviewUrl(convertReq.getOriginalOssUrl());
                statusReq.setConvertMarkdownFileUrl(ossUrl);
                knowledgeElementService.updateEmbeddingStatus(element.getId(), statusReq);
            }
        } catch (Exception e) {
            log.error("Advanced excel parse failed", e);
            knowledgeElementService.updateEmbeddingStatus(convertReq.getDataId(), KnowledgeEmbeddingStatusReq.fail());
            return false;
        } finally {
            FileUtil.del(tmpFile);
            if (xlsMdFile != null && !xlsMdFile.equals(tmpFile)) {
                FileUtil.del(xlsMdFile);
            }
            FileUtil.del(xlsKvFile);
        }
        return true;
    }



    private boolean shouldUseLegacy(Optional<SaasKnowledgeElement> elementOptional) {
        if (elementOptional.isEmpty()) {
            return false;
        }
        String eleCode = elementOptional.map(SaasKnowledgeElement::getCode).orElse(null);
        if (eleCode == null) {
            return false;
        }

        String tenantId = elementOptional.map(SaasKnowledgeElement::getTenantId).orElse(null);
        if (tenantId == null) {
            return false;
        }
        Result<SaasKnowledgeConfigElementResp> byElementId = saasKnowledgeConfigElementService.getByElementId(eleCode, tenantId);
        if (byElementId == null) {
            return false;
        }
        SaasKnowledgeConfigElementResp data = byElementId.getData();
        if (data == null) {
            return false;
        }
        return KbDocumentShardingMode.SEMANTIC_MD_EXCEL.name().equalsIgnoreCase(data.getSplitMode());
    }

