        File tmpMarkdownFile = null;
        OpenDataLoaderPdfService openDataLoaderPdfService = new OpenDataLoaderPdfService();
        Optional<SaasKnowledgeElement> elementOptional = knowledgeElementService.queryInfoById(convertReq.getDataId());
        if (elementOptional.isEmpty()) {
            // 文件不存在，返回true在MQ队列中删除
            return true;
        }
        SaasKnowledgeElement element = elementOptional.get();
        KnowledgeEmbeddingStatusReq statusReq = new KnowledgeEmbeddingStatusReq();
        statusReq.setPreviewUrl(convertReq.getOriginalOssUrl());
        try {
            // 租户配置,embedding模型
            String containerId = element.getContainerId();
            Optional<SaasKnowledgeConfigContainer> saasKnowledgeConfigContainer = saasKnowledgeConfigContainerService.queryInfoByContainerId(containerId);
            String embeddingModel = saasKnowledgeConfigContainer.get().getEmbeddingModel();
            Optional<UniversalEmbeddingConfig>  universalEmbeddingConfigOptional=modelProviderService.loadEmbedding(embeddingModel,element.getTenantId());
            if (universalEmbeddingConfigOptional.isEmpty()){
                // 转换失败，直接设置为失败
                throw new IllegalArgumentException("未配置embedding模型");
            }
            UniversalEmbeddingConfig embeddingConfig=universalEmbeddingConfigOptional.get();
            // 下载PDF文件
            tmpFile = this.downloadFile(convertReq);
            knowledgeElementService.updateStatus(element.getId(), ProcessStatusEnum.PROCESSING);
            // 尝试使用外部解析引擎
            Optional<ExternalParseResult> externalResult = tryExternalParse(convertReq, tmpFile, saasKnowledgeConfigContainer.get(),
                    element.getCode(), element.getId(), imageFile -> unstructuredAisOSSClient.save(imageFile, convertReq.getTenantId()).getFileUrl());
            if (externalResult.isPresent() && externalResult.get().isSuccess()) {
                tmpMarkdownFile = externalResult.get().getMarkdownFile();
                log.info("外部解析引擎解析完成，继续embedding流程");
            } else {
                if (externalResult.isPresent()) {
                    log.warn("外部解析引擎失败: {}, 回退到默认解析引擎", externalResult.get().getErrorMessage());
                }
                log.info("开始使用OpenDataLoader解析PDF，path:{}", tmpFile.getAbsolutePath());
                tmpMarkdownFile=FileUtil.createTempFile(tmpFile.getName(), ".md", true);
                PdfParseRequest pdfParseRequest = new PdfParseRequest();
                pdfParseRequest.setSourcePdfFile(tmpFile);
                pdfParseRequest.setOutputType(PdfParseOutputType.MARKDOWN);
                pdfParseRequest.setTargetFile(tmpMarkdownFile);
                Optional<ImageParseStrategy> imageParseStrategyOptional =
                        knowledgeImageParseService.resolveStrategy(element.getCode(), containerId, element.getTenantId());
                if (imageParseStrategyOptional.isPresent()) {
                    ImageParseStrategy imageParseStrategy = imageParseStrategyOptional.get();
                    pdfParseRequest.setAppendImageAnalysisToContent(true);
                    pdfParseRequest.setImageProcessingHandler(context -> {
                        String imageOssUrl = unstructuredAisOSSClient.save(context.getImageFile(), convertReq.getTenantId()).getFileUrl();
                        String extractedText = knowledgeImageParseService.parseImage(
                                context.getImageFile(), imageOssUrl, FileUtil.extName(context.getImageFile().getName()), imageParseStrategy);
                        PdfImageProcessResult result = PdfImageProcessResult.onlyUrl(imageOssUrl);
                        result.setExtractedText(extractedText);
                        return result;
                    });
                } else {
                    pdfParseRequest.setImageUploadHandler(PdfImageUploadHandlers.fromOssClient(unstructuredAisOSSClient, convertReq.getTenantId()));
                }
                openDataLoaderPdfService.parse(pdfParseRequest);
                log.info("Markdown文档创建成功，path:{}", tmpMarkdownFile.getAbsolutePath());
            }
            // 上传markdown的文件
            MaterialInfoResp mdFileResponse = materialService.save(tmpMarkdownFile, DigestUtil.md5Hex(tmpMarkdownFile), convertReq.getTenantId());
            String ossUrl = mdFileResponse.getFileUrl();

            UnstructuredEmbeddingTxtFileConvert txtFileConvert = UnstructuredEmbeddingTxtFileConvert.of(element, embeddingConfig, tmpMarkdownFile, true);
            UnstructuredEmbeddingTxtResult embeddingTxtResult = unstructuredEmbeddingService.embedding(txtFileConvert);
            embeddingTxtResult.applyEmbeddingStatus(statusReq);
            if (StrUtil.isBlank(element.getElePreviewUrl())) {
                statusReq.setPreviewUrl(convertReq.getOriginalOssUrl());
            }
            // markdown的oss地址
            statusReq.setConvertMarkdownFileUrl(ossUrl);
            knowledgeElementService.updateEmbeddingStatus(element.getId(), statusReq);
        } catch (Exception e) {
            log.error(e.getMessage(), e);
            statusReq.setStatusEnum(ProcessStatusEnum.FAILURE);
        } finally {
            FileUtil.del(tmpFile);
            FileUtil.del(tmpMarkdownFile);
            // 更新转换状态
            knowledgeElementService.updateEmbeddingStatus(element.getId(), statusReq);
        }
        // 标记文档待摘要（由定时任务延迟触发）

