/**
 * docx/doc格式的转换，提取docx/doc的内容，并且处理为markdown文件  <p>
 * 核心步骤： <p>
 * 1、使用<a href="https://tika.apache.org/">Apache Tika</a>项目，将Docx格式的内容提取为Xhtml格式的文件  <p>
 * 2、解析Xhtml文件，使用{@link XMarkdownContentHandler}将Xhtml文件转换为Markdown格式  <p>
 * 3、提取docx格式中的图片，上传到OSS，并且替换为OSS地址  <p>
 * 4、替换markdown格式中的图片地址，替换为在线的oss地址  <p>
 * 5、上传markdown文档内容到oss，提交docx_markdown格式的文件进行embedding处理  <p>  <p>
 * 参考{@link DocConvertFormats} 进行引用
 * @author <a href="xiaoymin@foxmail.com">xiaoymin@foxmail.com</a>
 * 2024/5/5 11:05
 * @since torchv_server v1.7.3
 */
@AllArgsConstructor
@Service("fileEmbeddingWordFacade")
@Slf4j
public class FileEmbeddingWordFacade extends AbstractFileEmbeddingFacade {

    final KnowledgeElementService knowledgeElementService;
    final MaterialService materialService;
    final ModelProviderService modelProviderService;
    final UnstructuredEmbeddingService unstructuredEmbeddingService;
    final SaasKnowledgeConfigContainerService saasKnowledgeConfigContainerService;
    final KnowledgeElementDetailService knowledgeElementDetailService;
    final SummaryAutoGenerateConfig summaryAutoGenerateConfig;
    final KnowledgeImageParseService knowledgeImageParseService;
    @Override
    public boolean convert(MessageFileConvertReq convertReq) {
        log.info("word文件转换");
        File tmpFile = null;
        // DocConvertFormats formats = DocConvertFormats.bySource(convertReq.getFormat());
        File docMdFile = null;
        try {
            tmpFile = this.downloadFile(convertReq);
            Optional<SaasKnowledgeElement> elementOptional = knowledgeElementService.queryInfoById(convertReq.getDataId());
            if (elementOptional.isEmpty()) {
                log.error("未找到该文件");
                return false;
            }
            // 提交任务
            SaasKnowledgeElement element = elementOptional.get();
            knowledgeElementService.updateStatus(element.getId(), ProcessStatusEnum.PROCESSING);
            // 租户配置,embedding模型
            String containerId = element.getContainerId();
            Optional<SaasKnowledgeConfigContainer> saasKnowledgeConfigContainer = saasKnowledgeConfigContainerService.queryInfoByContainerId(containerId);
            String embeddingModel = saasKnowledgeConfigContainer.get().getEmbeddingModel();
            Optional<UniversalEmbeddingConfig>  universalEmbeddingConfigOptional=modelProviderService.loadEmbedding(embeddingModel,element.getTenantId());
            if (universalEmbeddingConfigOptional.isEmpty()){
                // 转换失败，直接设置为失败
                throw new IllegalArgumentException("未配置embedding模型");
            }
            // 尝试使用外部解析引擎
            Optional<ExternalParseResult> externalResult = tryExternalParse(convertReq, tmpFile, saasKnowledgeConfigContainer.get(),
                    element.getCode(), element.getId(), imageFile -> materialService.save(imageFile, convertReq.getTenantId()).getFileUrl());
            if (externalResult.isPresent() && externalResult.get().isSuccess()) {
                docMdFile = externalResult.get().getMarkdownFile();
                log.info("外部解析引擎解析完成，继续embedding流程");
            } else {
                if (externalResult.isPresent()) {
                    log.warn("外部解析引擎失败: {}, 回退到默认解析引擎", externalResult.get().getErrorMessage());
                }
                Optional<ImageParseStrategy> imageParseStrategyOptional =
                        knowledgeImageParseService.resolveStrategy(element.getCode(), containerId, element.getTenantId());
                // 提取docx中的图片
                List<DocPicture> pictures = TikaAutoUtils.extractPictures(tmpFile);
                log.info("docx中的图片数量:{},file:{}", pictures.size(), tmpFile.getAbsolutePath());
                // 上传oss
                if (CollUtil.isNotEmpty(pictures)) {
                    for (DocPicture picture : pictures) {
                        MaterialInfoResp materialInfoResp = materialService.save(picture.getPicFile(), picture.checkSum(), convertReq.getTenantId());
                        picture.setOssUrl(materialInfoResp.getFileUrl());
                        if (imageParseStrategyOptional.isPresent()) {
                            String imageText = knowledgeImageParseService.parseImage(
                                    picture.getPicFile(), materialInfoResp.getFileUrl(), picture.getSuffix(), imageParseStrategyOptional.get());
                            picture.setOcrText(imageText);
                        }
                        picture.del();
                    }
                }
                docMdFile = TikaAutoUtils.toMarkdownWithHtmlTable(tmpFile, pictures);
            }
            // 上传markdown的文件
            MaterialInfoResp mdFileResponse = materialService.save(docMdFile, DigestUtil.md5Hex(docMdFile), convertReq.getTenantId());
            String ossUrl = mdFileResponse.getFileUrl();
            // 更新状态，转换成功
            log.info("转换成功，ossUrl:{}", ossUrl);

            UnstructuredEmbeddingTxtFileConvert txtFileConvert = UnstructuredEmbeddingTxtFileConvert.of(element, universalEmbeddingConfigOptional.get(), docMdFile, true);
            UnstructuredEmbeddingTxtResult embeddingTxtResult = unstructuredEmbeddingService.embedding(txtFileConvert);
            log.info("embedding结果:{}，embeddingModel:{}", embeddingTxtResult, txtFileConvert.getEmbeddingConfig().getModelName());
            KnowledgeEmbeddingStatusReq statusReq = embeddingTxtResult.toEmbeddingStatus();
            statusReq.setPreviewUrl(convertReq.getOriginalOssUrl());
            statusReq.setConvertMarkdownFileUrl(ossUrl);
            knowledgeElementService.updateEmbeddingStatus(element.getId(), statusReq);

            // 标记文档待摘要（由定时任务延迟触发）

com.torchv.kb.common.metadata.data.PageMetaDataIndexField;
