/**
 * @author <a href="xiaoymin@foxmail.com">xiaoymin@foxmail.com</a>
 * 2024/1/17 20:47
 * @since torchv_server v0.1-beta.1
 */
@Getter
@Setter
public class DataSetChunkInfo {
    public static final String METADATA_TAGS="tag";
    public static final String METADATA_TITLE="title";


    public static final String FIELD_ID = "id";
    public static final String FIELD_CONTENT = "content";
    public static final String FIELD_CATEGORY = "category";
    public static final String FIELD_TIME_STATUS = "timeStatus";
    public static final String FIELD_START_TIME = "startTime";
    public static final String FIELD_END_TIME = "endTime";
    public static final String FIELD_VECTOR = "vector";
    public static final String FIELD_CONTAINER_ID = "containerId";
    public static final String FIELD_DATA_ID = "dataId";
    public static final String FIELD_PARAGRAPH_ID = "paragraphId";
    public static final String FIELD_PAGE = "page";
    public static final String FIELD_TOPIC = "topic";
    public static final String FIELD_YEAR = "year";
    public static final String FIELD_ENABLE = "enable";
    /***
     *  切片创建时间
