     */
    public static final String FIELD_TENANT_ID = "tenantId";

    // 增加embedding brand，用于提高多路召回筛选效率
    // TODO
    public static final String FIELD_EMBEDDING_BRAND = "embedding_brand";
    /**
     * 元数据
     * @since vkb-v0.0.1
     */
    public static final String FIELD_METADATA = "metadata";

    /**
     * 元数据页码(合并后的内容)
     * @since ais-v1.2
     */
    public static final String FIELD_METADATA_PAGES="mergePages";


    public static final String[] SEARCH_FIELDS =
            new String[]{"id", "containerId", "category", "content", "dataId", "paragraphId", "page", "topic", "year", "timeStatus", "startTime",
                    "endTime", "vector", "createTime", "embedding_brand","metadata"};
    /**
     * 主键id
     */
    private String id;
    /**
     * 容器code
     */
    private String containerId;
    /**
     * 类型，ORIGINAL-原始内容，CUSTOM-用户自定义新增内容，META-元数据,QUESTION-QA问答对,参考{@link com.torchv.common.constant.knowledge.DataSetChunkType}
     *
     */
    private String category;
    /**
     * 内容
     */
    private String content;

    /**
     * 是否禁用启用
     */
    private String enable= ToggleStatusEnum.YES.codeStr();

    /**
     * @return enable状态，"1"表示启用，"0"表示禁用
     */
    public String getEnable() {
        return enable == null ? "1" : enable;
    }

    /**
     * 判断是否启用
     * @return true-启用，false-禁用
     */
    public boolean isEnabled() {
        return !"0".equals(getEnable());
    }
    /**
     * 数据集code
     */
    private String dataId;

    /**
     * 段落id
     */
    private String paragraphId;

    /**
