    /**
     * 截止时间
     */
    private Long endTime;
    /**
     * 时间状态，参考{@link DocTimeStatus}
     */
    private Integer timeStatus;

    /**
     * 向量
     */
    private double[] vector;

    private Long createTime;

    private String embeddingBrand;

    /**
     * 租户id
     * @since v1.7.11
     */
    private String tenantId;
    /**
     * 元数据
     */
    @Field(type = FieldType.Object)
    private Map<String, Object> metadata;


    public String getKeyHex() {
        return getKeyHex(this.getPage());
    }

    public String getKeyHex(int page){
        return this.getContainerId() + "_" + this.getDataId() + "_" + page;
    }


    /**
     * 获取标题
     * @return 标题
     */
    public String title(){
       if (this.metadata!=null && this.metadata.containsKey(METADATA_TITLE)){
           return Objects.toString(this.metadata.get(METADATA_TITLE));
       }
       return StrUtil.EMPTY;
    }

    /**
     * 获取全路径标题
     * @return 全路径标题
     */
    public String fullPathTitle(){
        if (this.metadata!=null && this.metadata.containsKey(PageMetaDataIndexField.FIELD_NAME_FULL_PATH)){
            return Objects.toString(this.metadata.get(PageMetaDataIndexField.FIELD_NAME_FULL_PATH));
        }
        return StrUtil.EMPTY;
    }


    public String summary(){
        if (this.metadata!=null && this.metadata.containsKey(PageMetaDataIndexField.FIELD_NAME_SUMMARY)){
            return Objects.toString(this.metadata.get(PageMetaDataIndexField.FIELD_NAME_SUMMARY));
        }
        if (this.metadata!=null && this.metadata.containsKey(PageMetaDataIndexField.FIELD_NAME_GENERATIVE_SUMMARY)){
            return Objects.toString(this.metadata.get(PageMetaDataIndexField.FIELD_NAME_GENERATIVE_SUMMARY));
