     */
    public List<Integer> nearPages(int size){
        List<Integer> pages = new LinkedList<>();
        // 前面的页码
        for (int i=0;i<size;i++){
            int pre = page - i - 1;
            if (pre > 0) {
                pages.add(pre);
            }
        }
        // 后面的页码
        for (int i=0;i<size;i++){
            int next = page + i + 1;
            pages.add(next);
        }
        return pages;
    }

    public List<Integer> roundPages() {
        List<Integer> pages = new LinkedList<>();
        int pre = page - 1;
        if (pre > 0) {
            pages.add(pre);
        }
        pages.add(page);
        pages.add(page + 1);
        return pages;
    }

