 */
@Component
@AllArgsConstructor
@AtomixHandler(command = CommandSpec.RENDER)
public class AtomixRenderCommandHandler extends RenderCommandHandler {

    private static final String WORKSTATION_URL_TEMPLATE = "workstation://page/%s/containerId/%s";
    private static final String KNOWLEDGE_CONTAINER_URL_TEMPLATE = "/knowledge/%s";
    private static final String KNOWLEDGE_DOCUMENT_URL_TEMPLATE = "/knowledge/%s/%s/preview";
    private static final String KNOWLEDGE_FOLDER_URL_TEMPLATE = "/knowledge/%s/%s/folder";
    private static final String KNOWLEDGE_CONTAINER_TYPE = "knowledge";
    private static final String PERSONAL_KNOWLEDGE_CONTAINER_TYPE = "PERSONAL_KNOWLEDGE";

    final KnowledgeElementService knowledgeElementService;
    final KnowledgeContainerService knowledgeContainerService;

    @Override
    public CommandResult<RenderCommandResponse> handle(RenderCommandRequest request, CommandExecutionContext context) {
        List<String> codes = normalizeCodes(request == null ? null : request.getCodes());
        if (CollUtil.isEmpty(codes)) {
            return CommandResult.failure(CommandNames.RENDER, "INVALID_REQUEST", "doc code is required");
        }

        List<RenderCommandResponse.Item> items = new ArrayList<>();
        List<String> failCodes = new ArrayList<>();
        List<String> operationSources = new ArrayList<>();
        for (String code : codes) {
            // 1. 先找出页面确定非空
            Optional<SaasKnowledgeElement> optionalSaasKnowledgeElement = knowledgeElementService.queryInfoByCode(code);
            if (optionalSaasKnowledgeElement.isEmpty()) {
                failCodes.add(code);
                continue;
            }
            SaasKnowledgeElement element = optionalSaasKnowledgeElement.get();
            if (StrUtil.isBlank(element.getCode()) || StrUtil.isBlank(element.getContainerId())) {
                failCodes.add(code);
                continue;
            }
            Optional<SaasKnowledgeContainer> containerOptional = knowledgeContainerService.queryInfoByCode(element.getContainerId());
            String displayPath = buildDisplayPath(element, containerOptional)
                    .orElse(StrUtil.blankToDefault(StrUtil.trim(element.getEleName()), StrUtil.EMPTY));
            items.add(RenderCommandResponse.Item.builder()
                    .code(element.getCode())
                    .spaceCode(element.getContainerId())
                    .title(element.getEleName())
                    .url(buildRenderUrl(element, containerOptional))
                    .build());
            operationSources.add(StrUtil.blankToDefault(StrUtil.trim(displayPath), StrUtil.EMPTY));
        }

        RenderCommandResponse response = RenderCommandResponse.builder()
                .items(items)
                .failCount(failCodes.size())
                .failCodes(failCodes)
                .build();
        if (CollUtil.isEmpty(items)) {
            String message = "documents not found: " + String.join(",", failCodes);
            return CommandResult.<RenderCommandResponse>builder()
                    .success(false)
                    .command(CommandNames.RENDER)
                    .data(response)
                    .meta(Map.of("operation_source", String.join(",", operationSources)))
                    .error(CommandError.builder()
                            .code("NOT_FOUND")
                            .message(message)
                            .details(Map.of("fail_count", failCodes.size(), "fail_codes", failCodes))
                            .build())
                    .build();
        }
        return CommandResult.<RenderCommandResponse>builder()
                .success(true)
                .command(CommandNames.RENDER)
                .data(response)
                .meta(Map.of("operation_source", String.join(",", operationSources)))
                .build();
    }

    private Optional<String> buildDisplayPath(SaasKnowledgeElement element,
                                              Optional<SaasKnowledgeContainer> containerOptional) {
        if (element == null || StrUtil.isBlank(element.getContainerId()) || StrUtil.isBlank(element.getCode())) {
            return Optional.empty();
        }
        if (containerOptional.isEmpty()) {
            return Optional.empty();
        }
        List<String> segments = new ArrayList<>();
        SaasKnowledgeElement current = element;
        while (current != null && StrUtil.isNotBlank(current.getCode()) && !"0".equals(current.getCode())) {
            String currentName = StrUtil.trim(current.getEleName());
            if (StrUtil.isBlank(currentName)) {
                return Optional.empty();
            }
            segments.add(currentName);
            String parentCode = StrUtil.blankToDefault(current.getParentCode(), "0");
            if ("0".equals(parentCode)) {
                break;
            }
            current = knowledgeElementService.queryInfoByCode(parentCode).orElse(null);
        }
        Collections.reverse(segments);
        if (CollUtil.isEmpty(segments)) {
            String elementName = StrUtil.trim(element.getEleName());
            if (StrUtil.isBlank(elementName)) {
                return Optional.empty();
            }
            segments.add(elementName);
        }
        return Optional.of(containerOptional.get().getName() + StrUtil.SLASH + String.join(StrUtil.SLASH, segments));
    }

    private String buildRenderUrl(SaasKnowledgeElement element, Optional<SaasKnowledgeContainer> containerOptional) {
        if (containerOptional.isPresent()) {
            SaasKnowledgeContainer container = containerOptional.get();
            if (isKnowledgeContainer(container)) {
                return buildKnowledgeUrl(element);
            }
        }
        return buildWorkstationUrl(element.getCode(), element.getContainerId());
    }

    private boolean isKnowledgeContainer(SaasKnowledgeContainer container) {
        if (container == null) {
            return false;
        }
        String type = StrUtil.trim(container.getType());
        return StrUtil.equalsIgnoreCase(type, KNOWLEDGE_CONTAINER_TYPE)
                || StrUtil.equalsIgnoreCase(type, PERSONAL_KNOWLEDGE_CONTAINER_TYPE);
    }

    private String buildKnowledgeUrl(SaasKnowledgeElement element) {
        String containerCode = element.getContainerId();
        String pageCode = element.getCode();
        if (StrUtil.isBlank(pageCode) || StrUtil.equals(pageCode, containerCode)) {
            return String.format(KNOWLEDGE_CONTAINER_URL_TEMPLATE, containerCode);
        }
        if (isFolder(element.getCategory())) {
            return String.format(KNOWLEDGE_FOLDER_URL_TEMPLATE, containerCode, pageCode);
        }
        return String.format(KNOWLEDGE_DOCUMENT_URL_TEMPLATE, containerCode, pageCode);
    }

