    @Override
    public String getContent(String tenantId, String dataId, String containerId) {
        log.info("get content from es,tenantId:{},dataId:{},containerId:{}", tenantId, dataId, containerId);
        // String collectName = VectorAssistant.referenceCollectName(tenantId,
        // containerId);
        String collectName = VectorAssistant.referenceCollectName(tenantId);
        log.info("ref-collectName-name:{}", collectName);
        // 构建查询条件
        BoolQuery.Builder builder = QueryBuilders.bool();
        builder.must(
                QueryBuilders.term().field(DataSetChunkInfo.FIELD_CONTAINER_ID).value(containerId).build()._toQuery());
        builder.must(QueryBuilders.term().field(DataSetChunkInfo.FIELD_DATA_ID).value(dataId).build()._toQuery());
        // 考虑到sharding的情况
        if (VectorAssistant.isSharding(tenantId)) {
            builder.must(
                    QueryBuilders.term().field(DataSetChunkInfo.FIELD_TENANT_ID).value(tenantId).build()._toQuery());
        }
        NativeQuery nativeQuery = NativeQuery.builder().withQuery(builder.build()._toQuery())
                .withPageable(Pageable.ofSize(150)).build();
        SearchHits<DataSetReference> dataSearchHits = this.elasticsearchTemplate.search(nativeQuery,
                DataSetReference.class, IndexCoordinates.of(collectName));
        List<SearchHit<DataSetReference>> data = dataSearchHits.getSearchHits();
        Set<DataSetReferenceObject> dataSetReferenceObjects = new HashSet<>();
        for (SearchHit<DataSetReference> ele : data) {
            DataSetReference reference = ele.getContent();
            if (StrUtil.equalsIgnoreCase(reference.getCategory(), DataSetReferenceType.paragraph.getName())) {
                DataSetReferenceObject referenceObject = new DataSetReferenceObject();
                BeanUtils.copyProperties(reference, referenceObject);
                dataSetReferenceObjects.add(referenceObject);
            }
        }
        CollUtil.sort(dataSetReferenceObjects, Comparator.comparing(DataSetReferenceObject::getPage));
        List<String> link = new LinkedList<>();
        for (DataSetReferenceObject referenceObject : dataSetReferenceObjects) {
            link.add(referenceObject.getContent());
        }
        return CollUtil.join(link, "\n");
    }

