    @Override
    public List<DataSetReferenceObject> getReference(List<DataSetScoreChunkInfo> chunkInfos, String tenantId) {
        log.info("根据租户id和片段的段落Pages获取引用对象列表,tenantId:{},chunkSize:{}", tenantId, CollUtil.size(chunkInfos));
        Set<DataSetReferenceObject> dataSetReferenceObjects = new HashSet<>();
        try {
            // 如果没有片段的内容，那么就返回return
            if (CollUtil.isEmpty(chunkInfos)) {
                return new ArrayList<>();
            }
            String collectName = VectorAssistant.referenceCollectName(tenantId);
            log.info("collectName-name:{}", collectName);
            boolean sharding = VectorAssistant.isSharding(tenantId);
            Set<String> keyHexSet = new HashSet<>();
            // 构建查询条件
            BoolQuery.Builder builder = QueryBuilders.bool();
            for (DataSetScoreChunkInfo chunkInfo : chunkInfos) {
                // 已经存在相同的过滤参数的情况下，就不用重复添加了
                if (keyHexSet.contains(chunkInfo.getKeyHex())) {
                    continue;
                }
                keyHexSet.add(chunkInfo.getKeyHex());
                List<Query> queries = new LinkedList<>();
                // sharding模式，必须新增租户id的过滤条件
                if (sharding) {
                    queries.add(QueryBuilders.term().field(DataSetChunkInfo.FIELD_TENANT_ID).value(tenantId).build()
                            ._toQuery());
                }
                queries.add(QueryBuilders.term().field(DataSetChunkInfo.FIELD_CONTAINER_ID)
                        .value(chunkInfo.getContainerId()).build()._toQuery());
                queries.add(QueryBuilders.term().field(DataSetChunkInfo.FIELD_DATA_ID).value(chunkInfo.getDataId())
                        .build()._toQuery());
                queries.add(QueryBuilders.term().field(DataSetChunkInfo.FIELD_PAGE).value(chunkInfo.getPage()).build()
                        ._toQuery());
                builder.should(QueryBuilders.bool().must(queries).build()._toQuery());

            }
            NativeQuery nativeQuery = NativeQuery.builder().withQuery(builder.build()._toQuery())
                    .withPageable(Pageable.ofSize(50)).build();
            SearchHits<DataSetReference> dataSearchHits = this.elasticsearchTemplate.search(nativeQuery,
                    DataSetReference.class, IndexCoordinates.of(collectName));
            List<SearchHit<DataSetReference>> data = dataSearchHits.getSearchHits();
            List<DataSetReference> references = new LinkedList<>();
            // 处理db查询的引用行数
            List<DataSetReference> referenceRows = data.stream().map(SearchHit::getContent).toList();
            applyReferences(referenceRows, references, dataSetReferenceObjects);
            // 针对reference获取不同的内容，获取段落的内容
            applyParagraph(references, dataSetReferenceObjects);
        } catch (Exception e) {
            log.error(e.getMessage(), e);
        }
        return CollUtil.newArrayList(dataSetReferenceObjects.iterator());
    }

