                KnnSearch.Builder knnSearchBuilder = new KnnSearch.Builder().boost(knnAlpha)
                        .field(DataSetChunkInfo.FIELD_VECTOR)
                        .numCandidates(numCandidates).k(topK).queryVector(VectorUtils.toFloatList(searchReq.getVector()))
                        .filter(knnBuilder.build()._toQuery());
                nativeQueryBuilder.withKnnSearches(List.of(knnSearchBuilder.build()));
                // 升级兼容spring boot 3.1.9到3.5.13
                // nativeQueryBuilder.withKnnQuery(knnSearchQueryBuilder.build());
                // 关键词检索的部分不需要了
            } else if (searchReq.getRetrievalModes() == RetrievalModes.HYBRID) {
                // 向量检索 或者混合检索的方式
                BoolQuery.Builder knnBuilder = queryBuilder(searchReq, false);
                // 向量或者混合
                // knn搜索
                /**KnnQuery.Builder knnSearchQueryBuilder = new KnnQuery.Builder().field(DataSetChunkInfo.FIELD_VECTOR)
                        .k(topK)
                        .numCandidates(numCandidates)
                        .boost(knnAlpha)
                        .queryVector(VectorUtils.toFloatList(searchReq.getVector()))
                        .filter(knnBuilder.build()._toQuery());


                 **/
                KnnSearch.Builder knnSearchBuilder = new KnnSearch.Builder().boost(knnAlpha)
                        .field(DataSetChunkInfo.FIELD_VECTOR)
                        .numCandidates(numCandidates).k(topK).queryVector(VectorUtils.toFloatList(searchReq.getVector()))
                        .filter(knnBuilder.build()._toQuery());
                nativeQueryBuilder.withKnnSearches(List.of(knnSearchBuilder.build()));
                // 升级兼容spring boot 3.1.9到3.5.13
                //nativeQueryBuilder.withKnnQuery(knnSearchQueryBuilder.build());
                // 如果是混合检索，那么bm25也需要
                nativeQueryBuilder.withQuery(bm25Builder.build()._toQuery());
            }
            // 创建NativeQuery
            NativeQuery nativeQuery = nativeQueryBuilder.build();
            VectorElastic question = new VectorElastic(VectorUtils.toFloatArray(searchReq.getVector()));
            SearchHits<DataSetChunkInfo> dataSearchHits = this.elasticsearchTemplate.search(nativeQuery,
                    DataSetChunkInfo.class, IndexCoordinates.of(collectName));
            List<SearchHit<DataSetChunkInfo>> data = dataSearchHits.getSearchHits();
            float cosineMinScore = searchReq.isKnowledge() ? searchReq.getConfigObject().getQms()
                    : searchReq.getConfigObject().getRms();
            log.info("检索成功，total-size:{}，cosineMinScore：{}", dataSearchHits.getTotalHits(), cosineMinScore);
            for (SearchHit<DataSetChunkInfo> ele : data) {
                DataSetChunkInfo elasticData = ele.getContent();
                DataSetScoreChunkInfo chunkInfo = DataSetScoreChunkInfo.newChunkInfo(elasticData);
                chunkInfo.setScore(BigDecimal.valueOf(ele.getScore()));
                if (searchReq.getRetrievalModes() == RetrievalModes.VECTOR
                        || searchReq.getRetrievalModes() == RetrievalModes.HYBRID) {
                    VectorElastic eleVector = new VectorElastic(VectorUtils.toFloatArray(elasticData.getVector()));
                    // 二次计算，方便召回重排序
                    float cosineScore = question.cosineElastic(eleVector);
                    chunkInfo.setCosine(BigDecimal.valueOf(cosineScore));
                } else {
                    // 关键词检索，那么cosine为0
                    chunkInfo.setCosine(BigDecimal.ZERO);
                }
                chunkInfos.add(chunkInfo);
            }
            return chunkInfos;
        } catch (Exception e) {
            log.error(e.getMessage(), e);
        }
        return chunkInfos;
    }

    @Override
    public List<DataSetScoreChunkInfo> semanticSearch(SemanticSearchReq searchReq) {
        log.info("semantic search,tenant:{},knowledge:{},query:{}，dims:{}", searchReq.getTenantId(), searchReq.isKnowledge(),
                searchReq.getQuery(),searchReq.getDims());
        // 可选的用法：使用通用RRF方法的另一种调用方式
        int maxTopK=Math.max(searchReq.getSearchTopK(),50);
        // 如果搜索的向量为空，那么使用关键词搜索
        List<DataSetScoreChunkInfo> result ;
        if (searchReq.getVector() == null || ArrayUtil.isEmpty(searchReq.getVector())){
            log.info("搜索向量为空，强制使用关键词搜索");
            searchReq.setRetrievalModes(RetrievalModes.KEYWORD);
            result=this.searchOne(searchReq);
        }else{
            log.info("启用混合搜索，knnAlpha:{}", searchReq.knnAlpha());
            if (searchReq.getRetrievalModes()==RetrievalModes.HYBRID){
                // 混合搜索需要检索两次，然后程序手动做rrf算法的实现
                List<List<DataSetScoreChunkInfo>> resultSets = List.of(RetrievalModes.VECTOR,RetrievalModes.KEYWORD).parallelStream().map(searchReq::copy)
                        .map(this::searchOne).toList();
                log.info("semantic search-size:{}", CollUtil.size(resultSets));
                //List<DataSetScoreChunkInfo> chunkVectorResults = searchOne(searchReq.copy(RetrievalModes.VECTOR));
                //List<DataSetScoreChunkInfo> chunkBm25Results = searchOne(searchReq.copy(RetrievalModes.KEYWORD));
                // 对结果进行RRF（RRF算法是ElasticSearch商业版的功能，只能程序实现）
                // 当前用法：使用便捷的两参数方法
                result=reciprocalRankFusion(resultSets, maxTopK);
            }else{
                result=this.searchOne(searchReq);
            }
        }
        //默认返回结果，进行一次rerank
        //默认做一次重排序
        try {
            RetrieverUtils.rank(searchReq.knnAlpha(), result, searchReq.getQuery(), searchReq.getVector());
        } catch (Exception e) {
            log.error("重排序失败，降级返回原始检索结果, query:{}, topK:{}", searchReq.getQuery(), CollUtil.size(result), e);
        }
        return result;
    }

