    @Override
    public CommandResult<EditCommandResponse> handle(EditCommandRequest request, CommandExecutionContext context) {
        if (request == null) {
            return invalidArgs("empty_request", "edit request is empty");
        }
        String commandPrefix = request.getCommandPrefix();
        String name = requestString(request, "getName");
        String code = requestString(request, "getCode");
        String oldString = requestString(request, "getOldString");
        String newString = requestString(request, "getNewString");
        Boolean replaceAll = requestBoolean(request, "getReplaceAll");
        if (StrUtil.isBlank(name) == StrUtil.isBlank(code)) {
            return invalidArgs("missing_target", "edit requires exactly one of name or code");
        }
        if (oldString == null || newString == null) {
            return invalidArgs("missing_string", "edit requires old_string and new_string");
        }
        if (oldString.isEmpty()) {
            return invalidArgs("empty_old_string", "old_string cannot be empty");
        }
        if (StrUtil.equals(oldString, newString)) {
            return invalidArgs("no_change", "old_string and new_string are identical");
        }
        Mode mode = StrUtil.isNotBlank(name) ? Mode.NAME : Mode.CODE;
        String target = mode == Mode.NAME ? name : code;
        return doSimpleUpdate(
                target,
                mode,
                oldString,
                newString,
                Boolean.TRUE.equals(replaceAll),
                commandPrefix);
    }

    private CommandResult<EditCommandResponse> doSimpleUpdate(String rawTarget,
                                                             Mode mode,
                                                             String oldString,
                                                             String newString,
                                                             boolean replaceAll,
                                                             String commandPrefix) {
        String target = normalizeLocator(rawTarget);
        if (!isValidPath(target)) {
            return forbidden("illegal_path", target);
        }
        ResolvedUpdate resolved = resolveUpdateTarget(target, mode, commandPrefix);
        if (resolved.error != null) {
            return resolved.error;
        }
        if (resolved.container != null && builtinSkillService.isBuiltinSkill(resolved.container.getCode())) {
            return fail(SkillConstants.BUILTIN_SKILL_READONLY_ERROR_CODE,
                    SkillConstants.BUILTIN_SKILL_READONLY_ERROR_MESSAGE,
                    Map.of("path", resolved.displayPath));
        }
        KnowledgeElementResp targetEle = resolved.element;
        KnowledgeElementResp editableEle = targetEle == null ? null : queryElement(targetEle.getCode());
        if (editableEle == null) {
            editableEle = targetEle;
        }
        if (isDirectory(targetEle)) {
            return invalidPatch("update_target_not_file", "Update File target must be a file");
        }
        if (StrUtil.equalsIgnoreCase(editableEle.getCategory(), KnowledgeElementCategory.FILE.getName())) {
            return forbidden("document_not_editable", resolved.displayPath);
        }

        ApplyResult applied = applySimpleEdit(resolveEditableContent(editableEle), oldString, newString, replaceAll);
        if (applied.error != null) {
            return applied.error;
        }

        String oldEtag = editableEle.getEleMd5();
        Result<String> issue = issue(editableEle, applied.content);
        if (issue == null || !ErrorCodeEnum.SUCCESS.getCode().equals(issue.getCode())) {
            return conflict("issue_failed", resolved.displayPath);
        }
        KnowledgeElementResp latest = queryElement(editableEle.getCode());

        EditCommandResponse response = EditCommandResponse.builder()
                .path(resolved.displayPath)
                .code(editableEle.getCode())
                .oldEtag(oldEtag)
                .newEtag(latest == null ? null : latest.getEleMd5())
                .appliedHunks(applied.appliedHunks)
                .build();
        setReplacementCountIfPresent(response, applied.appliedHunks);
        return CommandResult.<EditCommandResponse>builder()
                .success(true)
                .command(CommandNames.EDIT)
                .data(response)
                .meta(Map.of("operation_source", response.getPath()))
                .build();
    }

