    private CommandResult<EditCommandResponse> doAdd(ParsedPatch patch, String commandPrefix) {
        String src = normalizeLocator(patch.addSrc);
        String fileName = StrUtil.trim(patch.fileName);
        if (StrUtil.isBlank(src) || StrUtil.isBlank(fileName)) {
            return invalidPatch("invalid_file_name", "Add File target must be <src>/<file_name[.ext]>");
        }
        if (!isValidPath(src + "/" + fileName)) {
            return forbidden("illegal_path", patch.target);
        }
        if (CollUtil.isEmpty(patch.addLines)) {
            return invalidPatch("empty_add_content", "Add File must include at least one + content line");
        }
        ResolvedSrc resolved = resolveAddSource(src, patch.mode, commandPrefix);
        if (resolved.error != null) {
            return resolved.error;
        }
        if (resolved.container != null && builtinSkillService.isBuiltinSkill(resolved.container.getCode())) {
            return fail(SkillConstants.BUILTIN_SKILL_READONLY_ERROR_CODE,
                    SkillConstants.BUILTIN_SKILL_READONLY_ERROR_MESSAGE,
                    Map.of("path", resolved.displaySrc));
        }
        KnowledgeElementResp exists = findByName(resolved.elements, resolved.parentCode, fileName);
        if (exists != null) {
            Map<String, Object> details = new LinkedHashMap<>();
            details.put("reason", "target_already_exists");
            details.put("path", resolved.displaySrc + "/" + fileName);
            return fail(ERR_CONFLICT, "target already exists", details);
        }

        String content = String.join("\n", patch.addLines);
        Result<KnowledgeElementTreeResp> addResult = addElement(resolved.container, resolved.parentCode, fileName, content);
        if (addResult == null || !ErrorCodeEnum.SUCCESS.getCode().equals(addResult.getCode()) || addResult.getData() == null) {
            return conflict("create_failed", resolved.displaySrc + "/" + fileName);
        }

        String docCode = addResult.getData().getCode();
        KnowledgeElementResp created = queryElement(docCode);
        Result<String> issue = created == null ? null : issue(created, content);
        if (issue == null || !ErrorCodeEnum.SUCCESS.getCode().equals(issue.getCode())) {
            return conflict("issue_failed", resolved.displaySrc + "/" + fileName);
        }
        KnowledgeElementResp latest = queryElement(docCode);

        EditCommandResponse response = EditCommandResponse.builder()
                .path(resolved.displaySrc + "/" + fileName)
                .code(docCode)
                .newEtag(latest == null ? null : latest.getEleMd5())
                .appliedHunks(1)
                .build();
        return CommandResult.<EditCommandResponse>builder()
                .success(true)
                .command(CommandNames.EDIT)
                .data(response)
                .meta(Map.of("operation_source", response.getPath()))
                .build();
    }

    private ParsedPatch parsePatch(String raw, EditPatchMeta reqMeta) {
        if (StrUtil.isBlank(raw)) {
            return ParsedPatch.error(invalidPatch("empty_patch", "patch body is empty"));
        }
        String body = normalizePatch(raw);
        List<String> lines = splitLines(body);
        int begin = findMarker(lines, BEGIN_PATCH);
        int end = findMarker(lines, END_PATCH);
        if (begin < 0 || end < 0 || begin >= end) {
            return ParsedPatch.error(invalidPatch("missing_begin_or_end", "patch must include Begin/End markers"));
        }

        int headerIndex = -1;
        EditPatchOperation operation = null;
        String target = null;
        Mode mode = null;
        for (int i = begin + 1; i < end; i++) {
            String t = lines.get(i).trim();
            if (isDirective(t, MOVE_TO_DIRECTIVE)) {
                return ParsedPatch.error(unsupported("Move to"));
            }
            if (isDirective(t, DELETE_FILE_DIRECTIVE)) {
                return ParsedPatch.error(unsupported("Delete File"));
            }
            if (t.startsWith(UPDATE_FILE_NAME) || t.startsWith(UPDATE_FILE_CODE)
                    || t.startsWith(ADD_FILE_NAME) || t.startsWith(ADD_FILE_CODE)
                    || t.startsWith(UPDATE_FILE_LEGACY) || t.startsWith(ADD_FILE_LEGACY)) {
                if (headerIndex >= 0) {
                    return ParsedPatch.error(invalidPatch("multiple_operations", "patch contains multiple file operations"));
                }
                headerIndex = i;
                if (t.startsWith(UPDATE_FILE_NAME)) {
                    operation = EditPatchOperation.UPDATE_FILE;
                    mode = Mode.NAME;
                    target = t.substring(UPDATE_FILE_NAME.length()).trim();
                } else if (t.startsWith(UPDATE_FILE_CODE)) {
                    operation = EditPatchOperation.UPDATE_FILE;
                    mode = Mode.CODE;
                    target = t.substring(UPDATE_FILE_CODE.length()).trim();
                } else if (t.startsWith(ADD_FILE_NAME)) {
                    operation = EditPatchOperation.ADD_FILE;
                    mode = Mode.NAME;
                    target = t.substring(ADD_FILE_NAME.length()).trim();
                } else if (t.startsWith(ADD_FILE_CODE)) {
                    operation = EditPatchOperation.ADD_FILE;
                    mode = Mode.CODE;
                    target = t.substring(ADD_FILE_CODE.length()).trim();
                } else {
                    return ParsedPatch.error(invalidPatch("missing_src_mode",
                            "Add File/Update File must declare src mode with --name or --code"));
                }
            }
        }
        if (headerIndex < 0 || operation == null || mode == null || StrUtil.isBlank(target)) {
            return ParsedPatch.error(invalidPatch("missing_operation", "patch must contain one Update File or Add File directive"));
        }

        EditPatchMeta meta = buildPatchMeta(body, reqMeta);

        if (operation == EditPatchOperation.UPDATE_FILE) {
            if (meta == null || meta.getOperation() != EditPatchOperation.UPDATE_FILE || CollUtil.isEmpty(meta.getHunks())) {
                return ParsedPatch.error(invalidPatch("empty_patch", "Update File patch has no hunks"));
            }
            CommandResult<EditCommandResponse> hunkStructureError = validateUpdateHunkStructure(meta);
            if (hunkStructureError != null) {
                return ParsedPatch.error(hunkStructureError);
            }
            ParsedPatch patch = new ParsedPatch();
            patch.operation = operation;
            patch.mode = mode;
            patch.target = target;
            patch.meta = meta;
            return patch;
        }

        int slash = target.lastIndexOf('/');
        if (slash <= 0 || slash == target.length() - 1) {
            return ParsedPatch.error(invalidPatch("invalid_file_name", "Add File target must be <src>/<file_name[.ext]>"));
        }
        List<String> addLines = new ArrayList<>();
        for (int i = headerIndex + 1; i < end; i++) {
            String line = lines.get(i);
            if (line.startsWith("+")) {
                addLines.add(line.substring(1));
            } else {
                return ParsedPatch.error(invalidPatch("invalid_add_line", "Add File lines must start with +"));
            }
        }
        if (CollUtil.isEmpty(addLines)) {
            return ParsedPatch.error(invalidPatch("empty_add_content", "Add File must include at least one + content line"));
        }
        ParsedPatch patch = new ParsedPatch();
        patch.operation = operation;
        patch.mode = mode;
        patch.target = target;
        patch.addSrc = target.substring(0, slash);
        patch.fileName = target.substring(slash + 1);
        patch.addLines = addLines;
        patch.meta = meta;
        return patch;
    }

    private ResolvedUpdate resolveUpdateTarget(String locator, Mode mode, String commandPrefix) {
        if (StrUtil.isBlank(locator)) {
            return ResolvedUpdate.error(notFound("target_not_found", locator));
        }
        if (mode == Mode.NAME) {
            return resolveByName(locator, false, commandPrefix);
        }
        return resolveByCode(locator, false, commandPrefix);
    }

    private String requestString(EditCommandRequest request, String getterName) {
        Object value = invokeNoArg(request, getterName);
        return value == null ? null : value.toString();
    }

    private Boolean requestBoolean(EditCommandRequest request, String getterName) {
        Object value = invokeNoArg(request, getterName);
        if (value instanceof Boolean bool) {
            return bool;
        }
        if (value == null) {
            return Boolean.FALSE;
        }
        return Boolean.parseBoolean(value.toString());
    }

    private Object invokeNoArg(Object target, String methodName) {
        if (target == null) {
            return null;
        }
        try {
            return target.getClass().getMethod(methodName).invoke(target);
        } catch (ReflectiveOperationException ignored) {
            return null;
        }
    }

    private void setReplacementCountIfPresent(EditCommandResponse response, Integer count) {
        if (response == null || count == null) {
            return;
        }
        try {
            response.getClass().getMethod("setReplacementCount", int.class).invoke(response, count);
        } catch (ReflectiveOperationException ignored) {
            // Compatible with older ais-atomix response model that only exposes appliedHunks.
        }
    }

    private ResolvedSrc resolveAddSource(String locator, Mode mode, String commandPrefix) {
        if (mode == Mode.NAME) {
            ResolvedUpdate byName = resolveByName(locator, true, commandPrefix);
            if (byName.error != null) {
                return ResolvedSrc.error(byName.error);
            }
            return ResolvedSrc.ok(byName.container, byName.elements, byName.parentCode, byName.displayPath);
        }
        ResolvedUpdate byCode = resolveByCode(locator, true, commandPrefix);
        if (byCode.error == null) {
            return ResolvedSrc.ok(byCode.container, byCode.elements, byCode.parentCode, byCode.displayPath);
        }
        if (!isErrorCode(byCode.error, ERR_NOT_FOUND)) {
            return ResolvedSrc.error(byCode.error);
        }
        ResolvedUpdate byCodeAndName = resolveByCodeAndNamePath(locator, true, commandPrefix);
        if (byCodeAndName.error != null) {
            return ResolvedSrc.error(byCodeAndName.error);
        }
        return ResolvedSrc.ok(byCodeAndName.container, byCodeAndName.elements, byCodeAndName.parentCode, byCodeAndName.displayPath);
    }

    private ResolvedUpdate resolveByDocCode(String docCode, String commandPrefix) {
        KnowledgeElementResp element = queryElement(docCode);
        if (element == null) {
            return ResolvedUpdate.error(notFound("target_not_found", docCode));
        }
        SaasKnowledgeContainer container = listContainers(commandPrefix).stream()
                .filter(c -> StrUtil.equals(c.getCode(), element.getContainerId()))
                .findFirst().orElse(null);
        if (container == null) {
            return ResolvedUpdate.error(forbidden("no_permission", docCode));
        }
        List<KnowledgeElementResp> elements = listElements(container.getCode());
        String display = buildElementDisplay(container, element, toElementMap(elements));
        return ResolvedUpdate.ok(container, elements, element, ROOT_PARENT_CODE, display);
    }

    private ResolvedUpdate resolveByName(String namePath, boolean resolveDirectory, String commandPrefix) {
        List<String> segments = splitPath(namePath);
        if (segments.size() < (resolveDirectory ? 1 : 2)) {
            return ResolvedUpdate.error(notFound("target_not_found", namePath));
        }
        List<SaasKnowledgeContainer> matches = listContainers(commandPrefix).stream()
                .filter(c -> StrUtil.equals(c.getName(), segments.get(0)))
                .collect(Collectors.toList());
        if (matches.size() > 1) {
            return ResolvedUpdate.duplicate(namePath, matches.stream().map(SaasKnowledgeContainer::getCode).collect(Collectors.toList()));
        }
        SaasKnowledgeContainer container = CollUtil.isEmpty(matches) ? null : matches.get(0);
        if (container == null) {
            return ResolvedUpdate.error(notFound("target_not_found", namePath));
        }

        List<KnowledgeElementResp> elements = listElements(container.getCode());
        Map<String, List<KnowledgeElementResp>> parentIndex = toParentIndex(elements);
        String parentCode = ROOT_PARENT_CODE;
        KnowledgeElementResp current = null;

        for (int i = 1; i < segments.size(); i++) {
            String seg = segments.get(i);
            List<KnowledgeElementResp> candidates = parentIndex.getOrDefault(parentCode, Collections.emptyList()).stream()
                    .filter(x -> StrUtil.equals(x.getEleName(), seg))
                    .collect(Collectors.toList());
            if (i < segments.size() - 1 || resolveDirectory) {
                candidates = candidates.stream().filter(this::isDirectory).collect(Collectors.toList());
            }
            if (CollUtil.isEmpty(candidates)) {
                return ResolvedUpdate.error(notFound("target_not_found", namePath));
            }
            if (candidates.size() > 1) {
                return ResolvedUpdate.duplicate(namePath, candidates.stream().map(KnowledgeElementResp::getCode).collect(Collectors.toList()));
            }
            current = candidates.get(0);
            parentCode = current.getCode();
        }

        if (resolveDirectory) {
            String display = buildDirectoryDisplay(container, parentCode, toElementMap(elements));
            return ResolvedUpdate.ok(container, elements, null, parentCode, display);
        }
        if (current == null) {
            return ResolvedUpdate.error(notFound("target_not_found", namePath));
        }
        String display = buildElementDisplay(container, current, toElementMap(elements));
        return ResolvedUpdate.ok(container, elements, current, parentCode, display);
    }

    private ResolvedUpdate resolveByCode(String codePath, boolean resolveDirectory, String commandPrefix) {
        if (!codePath.contains("/") && !resolveDirectory) {
            return resolveByDocCode(codePath, commandPrefix);
        }
        List<String> segments = splitPath(codePath);
        if (segments.size() < 1) {
            return ResolvedUpdate.error(notFound("target_not_found", codePath));
        }
        SaasKnowledgeContainer container = listContainers(commandPrefix).stream()
                .filter(c -> StrUtil.equals(c.getCode(), segments.get(0)))
                .findFirst().orElse(null);
        if (container == null) {
            return ResolvedUpdate.error(notFound("target_not_found", codePath));
        }

        List<KnowledgeElementResp> elements = listElements(container.getCode());
        Map<String, List<KnowledgeElementResp>> parentIndex = toParentIndex(elements);
        String parentCode = ROOT_PARENT_CODE;
        KnowledgeElementResp current = null;

        for (int i = 1; i < segments.size(); i++) {
            String seg = segments.get(i);
            current = parentIndex.getOrDefault(parentCode, Collections.emptyList()).stream()
                    .filter(x -> StrUtil.equals(x.getCode(), seg))
                    .findFirst().orElse(null);
            if (current == null) {
                return ResolvedUpdate.error(notFound("target_not_found", codePath));
            }
            if ((i < segments.size() - 1 || resolveDirectory) && !isDirectory(current)) {
                return ResolvedUpdate.error(notFound("target_not_found", codePath));
            }
            parentCode = current.getCode();
        }

        if (resolveDirectory) {
            String display = buildDirectoryDisplay(container, parentCode, toElementMap(elements));
            return ResolvedUpdate.ok(container, elements, null, parentCode, display);
        }
        if (current == null) {
            return ResolvedUpdate.error(notFound("target_not_found", codePath));
        }
        String display = buildElementDisplay(container, current, toElementMap(elements));
        return ResolvedUpdate.ok(container, elements, current, parentCode, display);
    }

