    private ApplyResult applyPatch(String source, EditPatchMeta meta) {
        List<String> lines = splitLines(source == null ? "" : source.replace("\r\n", "\n").replace('\r', '\n'));
        if (meta == null || CollUtil.isEmpty(meta.getHunks())) {
            return ApplyResult.error(invalidPatch("empty_patch", "Update File patch has no hunks"));
        }

        for (EditPatchHunk hunk : meta.getHunks()) {
            List<String> oldLines = new ArrayList<>();
            List<String> newLines = new ArrayList<>();
            List<EditPatchLine> patchLines = hunk.getLines() == null ? Collections.emptyList() : hunk.getLines();
            for (EditPatchLine line : patchLines) {
                if (line.getType() == EditPatchLineType.CONTEXT) {
                    oldLines.add(line.getContent());
                    newLines.add(line.getContent());
                } else if (line.getType() == EditPatchLineType.DELETE) {
                    oldLines.add(line.getContent());
                } else if (line.getType() == EditPatchLineType.ADD) {
                    newLines.add(line.getContent());
                }
            }

            if (CollUtil.isEmpty(oldLines)) {
                int index = hunk.getOldStartLine() == null ? lines.size() : Math.max(0, Math.min(lines.size(), hunk.getOldStartLine() - 1));
                lines.addAll(index, newLines);
                continue;
            }

            MatchLevel usedLevel = null;
            int index = -1;
            List<String> attempted = new ArrayList<>();
            for (MatchLevel level : MatchLevel.values()) {
                attempted.add(level.code);
                List<Integer> hits = findHits(lines, oldLines, level);
                if (hits.size() > 1) {
                    Map<String, Object> details = new LinkedHashMap<>();
                    details.put("hunk_index", hunk.getIndex());
                    details.put("header", hunk.getHeader());
                    details.put("match_level", level.code);
                    details.put("match_count", hits.size());
                    return ApplyResult.error(fail(ERR_AMBIGUOUS_HUNK, "ambiguous hunk", details));
                }
                if (hits.size() == 1) {
                    usedLevel = level;
                    index = hits.get(0);
                    break;
                }
            }
            if (usedLevel == null || index < 0) {
                Map<String, Object> details = new LinkedHashMap<>();
                details.put("hunk_index", hunk.getIndex());
                details.put("header", hunk.getHeader());
                details.put("attempted_levels", attempted);
                return ApplyResult.error(fail(ERR_HUNK_NOT_FOUND, "hunk not found", details));
            }
            for (int i = 0; i < oldLines.size(); i++) {
                lines.remove(index);
            }
            lines.addAll(index, newLines);
        }
        return ApplyResult.ok(String.join("\n", lines), meta.getHunks().size());
    }

    private ApplyResult applySimpleEdit(String source, String oldString, String newString, boolean replaceAll) {
        String content = ObjectUtil.defaultIfNull(source, "");
        String search = oldString;
        if (StrUtil.isEmpty(newString) && !oldString.endsWith("\n") && content.contains(oldString + "\n")) {
            search = oldString + "\n";
        }
        int count = countOccurrences(content, search);
        if (count == 0) {
            Map<String, Object> details = new LinkedHashMap<>();
            details.put("reason", "old_string_not_found");
            return ApplyResult.error(fail(ERR_STRING_NOT_FOUND, "old_string not found", details));
        }
        if (count > 1 && !replaceAll) {
            Map<String, Object> details = new LinkedHashMap<>();
            details.put("reason", "multiple_matches");
            details.put("match_count", count);
            return ApplyResult.error(fail(ERR_STRING_NOT_UNIQUE, "old_string is not unique", details));
        }

        String updated = replaceAll
                ? content.replace(search, newString)
                : replaceFirstLiteral(content, search, newString);
        if (StrUtil.equals(content, updated)) {
            return ApplyResult.error(invalidArgs("no_change", "replacement produced no changes"));
        }
        return ApplyResult.ok(updated, replaceAll ? count : 1);
    }

    private int countOccurrences(String content, String search) {
        if (StrUtil.isEmpty(search)) {
            return 0;
        }
        int count = 0;
        int index = 0;
        while ((index = content.indexOf(search, index)) >= 0) {
            count++;
            index += search.length();
        }
        return count;
    }

    private String replaceFirstLiteral(String source, String oldString, String newString) {
        int index = source.indexOf(oldString);
        if (index < 0) {
            return source;
        }
        return source.substring(0, index) + newString + source.substring(index + oldString.length());
    }

    private List<Integer> findHits(List<String> lines, List<String> oldLines, MatchLevel level) {
        if (lines.size() < oldLines.size()) {
            return Collections.emptyList();
        }
        List<Integer> hits = new ArrayList<>();
        int max = lines.size() - oldLines.size();
        for (int i = 0; i <= max; i++) {
            boolean ok = true;
            for (int j = 0; j < oldLines.size(); j++) {
                if (!level.match(lines.get(i + j), oldLines.get(j))) {
                    ok = false;
                    break;
                }
            }
            if (ok) {
                hits.add(i);
            }
        }
        return hits;
    }

    private List<SaasKnowledgeContainer> listContainers(String commandPrefix) {
        List<SaasKnowledgeContainer> containers = ObjectUtil.defaultIfNull(knowledgeContainerService.queryAuthKnowledgeBaseUserCode(), Collections.emptyList());
        containers = AtomixContainerFilterUtil.filterContainers(containers, commandPrefix);
        if (StrUtil.equalsIgnoreCase("skill", commandPrefix)) {
            containers = builtinSkillService.mergeBuiltinSkillContainers(containers);
        }
        return containers;
    }

    private List<KnowledgeElementResp> listElements(String containerCode) {
        KnowledgeElementQueryReq req = new KnowledgeElementQueryReq();
        req.setContainerId(containerCode);
        Result<List<KnowledgeElementResp>> result = knowledgeElementService.listAll(req);
        return Optional.ofNullable(result).map(Result::getData).filter(CollUtil::isNotEmpty).orElse(Collections.emptyList());
    }

    private KnowledgeElementResp queryElement(String code) {
        KnowledgeElementResp editElement = Optional.ofNullable(knowledgeElementService.queryByCode(code, true))
                .map(Result::getData)
                .orElse(null);
        KnowledgeElementResp publishedElement = Optional.ofNullable(knowledgeElementService.queryByCode(code, false))
                .map(Result::getData)
                .orElse(null);
        if (editElement == null) {
            return publishedElement;
        }
        if (publishedElement == null) {
            return editElement;
        }
        if (hasReadableContent(editElement)) {
            return editElement;
        }
        if (hasReadableContent(publishedElement)) {
            return publishedElement;
        }
        return editElement;
    }

    private Map<String, List<KnowledgeElementResp>> toParentIndex(List<KnowledgeElementResp> elements) {
        if (CollUtil.isEmpty(elements)) {
            return Collections.emptyMap();
        }
        return elements.stream().collect(Collectors.groupingBy(e -> StrUtil.blankToDefault(e.getParentCode(), ROOT_PARENT_CODE)));
    }

    private Map<String, KnowledgeElementResp> toElementMap(List<KnowledgeElementResp> elements) {
        Map<String, KnowledgeElementResp> map = new HashMap<>();
        List<KnowledgeElementResp> safeElements = elements == null ? Collections.emptyList() : elements;
        for (KnowledgeElementResp e : safeElements) {
            if (e != null && StrUtil.isNotBlank(e.getCode())) {
                map.putIfAbsent(e.getCode(), e);
            }
        }
        return map;
    }

    private String buildElementDisplay(SaasKnowledgeContainer container, KnowledgeElementResp element, Map<String, KnowledgeElementResp> map) {
        List<String> segments = new ArrayList<>();
        segments.add(StrUtil.blankToDefault(container.getName(), container.getCode()));
        List<String> chain = new ArrayList<>();
        KnowledgeElementResp cursor = element;
        while (cursor != null) {
            chain.add(cursor.getEleName());
            if (StrUtil.equals(cursor.getParentCode(), ROOT_PARENT_CODE)) {
                break;
            }
            cursor = map.get(cursor.getParentCode());
        }
        Collections.reverse(chain);
        segments.addAll(chain);
        return String.join("/", segments.stream().filter(StrUtil::isNotBlank).collect(Collectors.toList()));
    }

    private String buildDirectoryDisplay(SaasKnowledgeContainer container, String parentCode, Map<String, KnowledgeElementResp> map) {
        List<String> segments = new ArrayList<>();
        segments.add(StrUtil.blankToDefault(container.getName(), container.getCode()));
        if (StrUtil.equals(parentCode, ROOT_PARENT_CODE)) {
            return String.join("/", segments);
        }
        List<String> chain = new ArrayList<>();
        KnowledgeElementResp cursor = map.get(parentCode);
        while (cursor != null) {
            chain.add(cursor.getEleName());
            if (StrUtil.equals(cursor.getParentCode(), ROOT_PARENT_CODE)) {
                break;
            }
            cursor = map.get(cursor.getParentCode());
        }
        Collections.reverse(chain);
        segments.addAll(chain);
        return String.join("/", segments.stream().filter(StrUtil::isNotBlank).collect(Collectors.toList()));
    }

    private KnowledgeElementResp findByName(List<KnowledgeElementResp> elements, String parentCode, String name) {
        List<KnowledgeElementResp> safeElements = elements == null ? Collections.emptyList() : elements;
        return safeElements.stream()
                .filter(e -> StrUtil.equals(StrUtil.blankToDefault(e.getParentCode(), ROOT_PARENT_CODE), parentCode))
                .filter(e -> StrUtil.equals(e.getEleName(), name))
                .findFirst().orElse(null);
    }

    private Result<KnowledgeElementTreeResp> addElement(SaasKnowledgeContainer container, String parentCode, String fileName, String content) {
        KnowledgeElementAddReq req = new KnowledgeElementAddReq();
        req.setTitle(fileName);
        req.setSpaceCode(container.getCode());
        req.setParentCode(parentCode);
        req.setContent(content);
        req.setContentMarked(content);
        req.setType(KnowledgeElementTypes.PAGE.name());
        req.setEleSuffix(extractSuffix(fileName));
        return knowledgeElementService.add(req, KnowledgeElementTypes.PAGE);
    }

    private Result<String> issue(KnowledgeElementResp ele, String content) {
        KnowledgeElementContentUpdateReq req = new KnowledgeElementContentUpdateReq();
        req.setCode(ele.getCode());
        req.setTitle(StrUtil.blankToDefault(ele.getEleName(), ele.getCode()));
        req.setContent(content);
        req.setContentMarked(content);
        req.setNeverExpire(ObjectUtil.defaultIfNull(ele.getNeverExpire(), DocTimeStatus.NEVER_EXPIRE.getCode()));
        Result<String> result = knowledgeElementService.issue(req, true);

        // 判断是否是 SKILL.md 文件，如果是则更新容器表
        if (result != null && ErrorCodeEnum.SUCCESS.getCode().equals(result.getCode())) {
            handleSkillMdUpdate(ele, content);
        }

        return result;
    }

    private String resolveEditableContent(KnowledgeElementResp ele) {
        if (ele == null) {
            return "";
        }
        if (StrUtil.isNotBlank(ele.getContentMarked())) {
            return ele.getContentMarked();
        }
        if (StrUtil.isNotBlank(ele.getContent())) {
            return ele.getContent();
        }
        if (StrUtil.isNotBlank(ele.getOriginContent())) {
            return ele.getOriginContent();
        }
        if (StrUtil.isNotBlank(ele.getAnswer())) {
            return ele.getAnswer();
        }
        if (ele.getId() != null) {
            Result<String> contentResult = knowledgeElementService.getElementContent(ele.getId());
            String fallback = Optional.ofNullable(contentResult).map(Result::getData).orElse(null);
            if (StrUtil.isNotBlank(fallback)) {
                return fallback;
            }
        }
        return "";
    }

    private boolean hasReadableContent(KnowledgeElementResp ele) {
        if (ele == null) {
            return false;
        }
        return StrUtil.isNotBlank(ele.getContentMarked())
                || StrUtil.isNotBlank(ele.getContent())
                || StrUtil.isNotBlank(ele.getOriginContent());
    }

    private boolean isDirectory(KnowledgeElementResp ele) {
        if (ele == null) {
            return false;
        }
        return StrUtil.equalsIgnoreCase(ele.getCategory(), KnowledgeElementCategory.DIRECTORY.getName())
                || StrUtil.equalsIgnoreCase(ele.getCategory(), KnowledgeElementCategory.FOLDER.getName());
    }

    private String extractSuffix(String fileName) {
        int dot = fileName.lastIndexOf('.');
        if (dot > 0 && dot < fileName.length() - 1) {
            return fileName.substring(dot + 1);
        }
        return "md";
    }

    private String normalizePatch(String patchBody) {
        String normalized = patchBody.replace("\r\n", "\n").replace('\r', '\n');
        String content = normalized;
        String trimmed = content.trim();
        if (trimmed.startsWith("<<'EOF'") || trimmed.startsWith("<<\"EOF\"") || trimmed.startsWith("<<EOF")) {
            List<String> lines = splitLines(content);
            if (lines.size() >= 2 && StrUtil.equals(lines.get(lines.size() - 1).trim(), "EOF")) {
                content = String.join("\n", lines.subList(1, lines.size() - 1));
            }
        }
        content = decodeQuotedPatchBody(content);
        return content.replace("\r\n", "\n").replace('\r', '\n');
    }

    private String decodeQuotedPatchBody(String patchBody) {
        String trimmed = StrUtil.trim(patchBody);
        if (StrUtil.isBlank(trimmed) || trimmed.length() < 2) {
            return patchBody;
        }
        char quote = trimmed.charAt(0);
        if ((quote != '"' && quote != '\'') || trimmed.charAt(trimmed.length() - 1) != quote) {
            return patchBody;
        }
        String inner = trimmed.substring(1, trimmed.length() - 1);
        String decoded = unescapeQuotedString(inner);
        boolean originalHasMarker = patchBody.contains(BEGIN_PATCH) && patchBody.contains(END_PATCH);
        boolean decodedHasMarker = decoded.contains(BEGIN_PATCH) && decoded.contains(END_PATCH);
        boolean looksEscaped = inner.contains("\\n")
                || inner.contains("\\r")
                || inner.contains("\\t")
                || inner.contains("\\u")
                || inner.contains("\\\"")
                || inner.contains("\\'");
        if (decodedHasMarker || (looksEscaped && !originalHasMarker)) {
            return decoded;
        }
        return patchBody;
    }

    private String unescapeQuotedString(String value) {
        StringBuilder out = new StringBuilder(value.length());
        for (int i = 0; i < value.length(); i++) {
            char c = value.charAt(i);
            if (c != '\\') {
                out.append(c);
                continue;
            }
            if (i == value.length() - 1) {
                out.append('\\');
                break;
            }
            char next = value.charAt(++i);
            switch (next) {
                case 'n':
                    out.append('\n');
                    break;
                case 'r':
                    out.append('\r');
                    break;
                case 't':
                    out.append('\t');
                    break;
                case 'b':
                    out.append('\b');
                    break;
                case 'f':
                    out.append('\f');
                    break;
                case '\\':
                    out.append('\\');
                    break;
                case '/':
                    out.append('/');
                    break;
                case '"':
                    out.append('"');
                    break;
                case '\'':
                    out.append('\'');
                    break;
                case 'u':
                    if (i + 4 < value.length()) {
                        String hex = value.substring(i + 1, i + 5);
                        if (hex.matches("[0-9a-fA-F]{4}")) {
                            out.append((char) Integer.parseInt(hex, 16));
                            i += 4;
                            break;
                        }
                    }
                    out.append("\\u");
                    break;
                default:
                    out.append(next);
                    break;
            }
        }
        return out.toString();
    }

    private EditPatchMeta buildPatchMeta(String body, EditPatchMeta reqMeta) {
        EditPatchMeta parsed = EditPatchParser.parse(body);
        if (parsed != null && parsed.getOperation() != null) {
            if (parsed.getOperation() == EditPatchOperation.UPDATE_FILE
                    && CollUtil.isEmpty(parsed.getHunks())
                    && reqMeta != null
                    && !CollUtil.isEmpty(reqMeta.getHunks())) {
                return reqMeta;
            }
            return parsed;
        }
        return reqMeta;
    }

    private CommandResult<EditCommandResponse> validateUpdateHunkStructure(EditPatchMeta meta) {
        List<EditPatchHunk> hunks = meta.getHunks();
        for (int i = 0; i < hunks.size(); i++) {
            EditPatchHunk hunk = hunks.get(i);
            if (hunk == null) {
                return invalidPatch("invalid_hunk", "hunk cannot be null");
            }
            String header = StrUtil.trim(hunk.getHeader());
            if (i > 0 && StrUtil.isBlank(header)) {
                return invalidPatch("missing_hunk_header", "second and subsequent hunks must start with @@");
            }
            if (StrUtil.isNotBlank(header) && !header.startsWith("@@")) {
                return invalidPatch("invalid_hunk_header", "hunk header must start with @@");
            }
            if (CollUtil.isEmpty(hunk.getLines())) {
                return invalidPatch("empty_hunk", "hunk has no body lines");
            }
        }
        return null;
    }

    private int findMarker(List<String> lines, String marker) {
        for (int i = 0; i < lines.size(); i++) {
            if (StrUtil.equals(lines.get(i).trim(), marker)) {
                return i;
            }
        }
        return -1;
    }

    private List<String> splitLines(String content) {
        if (content == null) {
            return Collections.emptyList();
        }
        return new ArrayList<>(List.of(content.split("\n", -1)));
    }

    private String normalizeLocator(String raw) {
        String value = StrUtil.trim(raw);
        if (StrUtil.isBlank(value)) {
            return null;
        }
        value = value.replace("\\", "/");
        while (value.startsWith("/")) {
            value = value.substring(1);
        }
        while (value.endsWith("/")) {
            value = value.substring(0, value.length() - 1);
        }
        return value;
    }

    private boolean sameLocator(String a, String b) {
        return StrUtil.equals(normalizeLocator(a), normalizeLocator(b));
    }

    private List<String> splitPath(String path) {
        String normalized = normalizeLocator(path);
        if (StrUtil.isBlank(normalized)) {
            return Collections.emptyList();
        }
        return StrUtil.split(normalized, '/');
    }

    private boolean isDirective(String line, String directive) {
        if (!line.startsWith(directive)) {
            return false;
        }
        if (line.length() == directive.length()) {
            return true;
        }
        char next = line.charAt(directive.length());
        return next == ':' || Character.isWhitespace(next);
    }

    private boolean isValidPath(String path) {
        String value = StrUtil.trim(path);
        if (StrUtil.isBlank(value)) {
            return false;
        }
        if (value.startsWith("/") || value.startsWith("\\") || WINDOWS_ABS.matcher(value).matches()) {
            return false;
        }
        if (value.contains("\\")) {
            return false;
        }
        List<String> segments = StrUtil.split(value, '/');
        for (String seg : segments) {
            if (StrUtil.isBlank(seg) || StrUtil.equals(seg, ".") || StrUtil.equals(seg, "..")) {
                return false;
            }
        }
        return true;
    }

