        }
        return result;
    }

    @Transactional(rollbackFor = Exception.class)
    @Override
    public Result<List<SaasKnowledgeElement>> addFilesAndReturnElements(KnowledgeElementAddFileReq addFileReq, String tenantId, SysUserInfo sysUserInfo) {
        log.info("批量新增文件");
        AddFilesExecution execution = prepareAddFilesExecution(addFileReq, tenantId, sysUserInfo);
        Result<String> result = this.lockBatchFile(execution.saasKnowledgeElements, tenantId, execution.storageAmount.get(), execution.cacheKeys, addFileReq.getContainerId());
        if (CollUtil.isNotEmpty(execution.saasKnowledgeElements) && ErrorCodeEnum.SUCCESS.getCode().equals(result.getCode())) {
            publishElementBatch(KnowledgeEventType.DOCUMENT_CREATED, tenantId, execution.saasKnowledgeElements, MapSyncAction.UPSERT);
        }
        if (!ErrorCodeEnum.SUCCESS.getCode().equals(result.getCode())) {
            return Result.error(result.getMessage());
        }
        return Result.data(execution.saasKnowledgeElements, result.getMessage());
    }

    private AddFilesExecution prepareAddFilesExecution(KnowledgeElementAddFileReq addFileReq, String tenantId, SysUserInfo sysUserInfo) {
        knowledgeValidationService.validateFileBase(addFileReq, tenantId);
        knowledgePermissionGuardService.assertContainerEditPermission(addFileReq.getContainerId(), sysUserInfo);
        List<String> cacheKeys = new LinkedList<>();
        List<SaasKnowledgeElement> saasKnowledgeElements = new ArrayList<>();
        AtomicLong storageAmount = new AtomicLong(0);
        Integer maxOrder = saasKnowledgeElementMapper.maxOrder(tenantId, addFileReq.getContainerId(), addFileReq.getParentCode());
        AtomicInteger maxOrderAtomic = new AtomicInteger(Objects.requireNonNullElse(maxOrder, 0));
        for (KnowledgeElementAddFileOneReq fileOneReq : addFileReq.getDataSets()) {
            String cacheKey = Cns.PIPELINE_CACHE_PREFIX + tenantId + ":" + fileOneReq.getDataId();
            cacheKeys.add(cacheKey);
            String value = stringRedisTemplate.opsForValue().get(cacheKey);
            Assert.notBlank(value, "knowledge.dataset.file.validation.expireFile");
            saasKnowledgeElements.addAll(fileOneReq.getElementList(addFileReq, maxOrderAtomic, tenantId, value, storageAmount, sysUserInfo));
        }
        Assert.isTrue(billingSubscribeAccountService.validateAvailableStorage(tenantId, storageAmount.get()), "knowledge.preview.upload.limit");
        return new AddFilesExecution(cacheKeys, saasKnowledgeElements, storageAmount);
    }

    private static final class AddFilesExecution {
        private final List<String> cacheKeys;
        private final List<SaasKnowledgeElement> saasKnowledgeElements;
        private final AtomicLong storageAmount;

        private AddFilesExecution(List<String> cacheKeys, List<SaasKnowledgeElement> saasKnowledgeElements, AtomicLong storageAmount) {
            this.cacheKeys = cacheKeys;
            this.saasKnowledgeElements = saasKnowledgeElements;
            this.storageAmount = storageAmount;
        }
    }

    @Override
    public Result<KnowledgeResultInfo> addSingleFile(KnowledgeElementAddSingleFileReq singleFileReq) {
        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        // 校验知识库 请求参数
        knowledgeValidationService.validateFileBase(singleFileReq, sysUserInfo.getTenantId());
        knowledgePermissionGuardService.assertContainerEditPermission(singleFileReq.getContainerId(), sysUserInfo);
        SaasKnowledgeElement saasKnowledgeElement = new SaasKnowledgeElement();
        BeanUtils.copyProperties(singleFileReq, saasKnowledgeElement);
        saasKnowledgeElement.setStartTime(singleFileReq.startTimeInstance());
        saasKnowledgeElement.setEndTime(singleFileReq.endTimeInstance());
        saasKnowledgeElement.setCategory(KnowledgeElementCategory.FILE.name());
        saasKnowledgeElement.setCreateTime(LocalDateTime.now());
        saasKnowledgeElement.setCreator(sysUserInfo.getCode());
        saasKnowledgeElement.setModifier(sysUserInfo.getCode());
        saasKnowledgeElement.setModifierTime(LocalDateTime.now());
        saasKnowledgeElement.setTenantId(sysUserInfo.getTenantId());
        // 唯一编码
        saasKnowledgeElement.setCode(IdUtil.getSnowflakeNextIdStr());
        // 文件md5
        saasKnowledgeElement.setEleMd5(singleFileReq.getEleMd5());
        saasKnowledgeElement.setEleName(singleFileReq.getEleName());
        // 设置状态,默认为待处理，需要向量化操作。
        saasKnowledgeElement.setProcessStatus(ProcessStatusEnum.INIT.getCode());
        saasKnowledgeElement.setProcessCount(0);
        saasKnowledgeElement.setPageCount(1);
        saasKnowledgeElement.setPermissionStatus(ToggleStatusEnum.YES.getCode());
        saasKnowledgeElement.setEleSize(singleFileReq.getEleSize());
        saasKnowledgeElement.setEleSuffix(singleFileReq.getEleSuffix());
        // 处理排序
        try {
            String tenantId = sysUserInfo.getTenantId();
            String parentCode = StrUtil.isBlank(saasKnowledgeElement.getParentCode()) ? "0" : saasKnowledgeElement.getParentCode();
            Integer maxOrder = saasKnowledgeElementMapper.maxOrder(tenantId, saasKnowledgeElement.getContainerId(), parentCode);
            saasKnowledgeElement.setSort(Objects.requireNonNullElse(maxOrder, 0) + KbConst.MOVE_ORDER_LAST_NEXT);
        } catch (Exception e) {
            log.warn("新增知识库元素数据-FileSingle set sort failed, use 0, err:{}", e.getMessage(), e);
            saasKnowledgeElement.setSort(0);
        }

        int ret = saasKnowledgeElementMapper.insert(saasKnowledgeElement);
        if (ret > 0) {
            knowledgeElementConfigService.processElementConfig(saasKnowledgeElement, sysUserInfo);
            publishElementUpsert(KnowledgeEventType.DOCUMENT_CREATED, saasKnowledgeElement, false);

            // 记录日志
            CommonLog.knowledge.action(ActionType.FILE_UPLOAD_SINGLE, "导入知识文件，名称:{}", saasKnowledgeElement.getEleName())
                    .withMetadata("elementId", saasKnowledgeElement.getCode())
                    .withMetadata("elementName", saasKnowledgeElement.getEleName())
                    .withMetadata("containerId", saasKnowledgeElement.getContainerId())
                    .send();
        }
        return ret > 0 ? Result.defaultSuccess(KnowledgeResultInfo.from(saasKnowledgeElement)) : Result.error(i18nMessage.resolveMessage("system.common.add.fail"));
    }

