    @Override
    @Transactional(rollbackFor = Exception.class)
    public Result<KnowledgeElementTreeResp> add(KnowledgeElementAddReq knowledgeElementAddReq, KnowledgeElementTypes types) {
        log.info("新增空间页面数据,Vo:{}", knowledgeElementAddReq.toString());
        String pageCode = IdUtil.getSnowflakeNextIdStr();
        // 获取当前用户信息
        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        knowledgePermissionGuardService.assertContainerEditPermission(knowledgeElementAddReq.getSpaceCode(), sysUserInfo);
        // 生成唯一的MD5值，避免空内容导致的MD5冲突
        String uniqueContent = generateUniqueContent(knowledgeElementAddReq, pageCode, sysUserInfo);
        String eleMd5 = MD5.create().digestHex16(uniqueContent);
        // 创建saasKnowledgeElement对象并从请求Vo中复制属性
        SaasKnowledgeElement saasKnowledgeElement = new SaasKnowledgeElement();
        BeanUtils.copyProperties(knowledgeElementAddReq, saasKnowledgeElement);
        // 模板信息获取
        if (ObjectUtils.isNotEmpty(knowledgeElementAddReq.getTemplateCode())) {
            String templateCode = knowledgeElementAddReq.getTemplateCode();
            String tenantId = UserContextHolder.getTenantId();
            kbPageTemplateService.queryTemplateByCode(tenantId, templateCode).ifPresent(template -> {
                saasKnowledgeElement.setContentMarked(template.getContentMarked());
            });
        }
        saasKnowledgeElement.setCode(pageCode);
        saasKnowledgeElement.setEleMd5(eleMd5);
        // 设置页面类型
        saasKnowledgeElement.setCategory(types.name());
        // 设置描述字段
        String description = MarkdownUtils.cleanAndSub(knowledgeElementAddReq.getContentMarked());
        // 临时复用存储
        saasKnowledgeElement.setConfig(description);
        // 设置修改者和修改时间
        saasKnowledgeElement.setModifier(sysUserInfo.getCode());
        saasKnowledgeElement.setModifierTime(LocalDateTime.now());
        // 设置创建者和创建时间
        saasKnowledgeElement.setCreator(sysUserInfo.getCode());
        saasKnowledgeElement.setCreateTime(LocalDateTime.now());
        saasKnowledgeElement.setTenantId(sysUserInfo.getTenantId());
        saasKnowledgeElement.setContainerId(knowledgeElementAddReq.getSpaceCode());
        // 设置页面状态为待处理 excel类型排除
        if (KnowledgeElementTypes.EXCEL.equals(types)) {
            saasKnowledgeElement.setProcessStatus(ProcessStatusEnum.INIT.getCode());
        } else if (KnowledgeElementTypes.PAGE.equals(types)) {
            WikiStatusEnum wikiStatus = WikiStatusEnum.fromCode(knowledgeElementAddReq.getWikiStatus());
            Assert.notNull(wikiStatus, "文档状态仅支持draft或published");
            if (WikiStatusEnum.PUBLISHED.equals(wikiStatus)) {
                saasKnowledgeElement.setProcessStatus(ProcessStatusEnum.INIT.getCode());
            } else {
                saasKnowledgeElement.setProcessStatus(ProcessStatusEnum.DRAFT.getCode());
            }
        } else {
            saasKnowledgeElement.setProcessStatus(ProcessStatusEnum.DRAFT.getCode());
        }
        // 查询最大的Sort值
        Integer maxOrder = saasKnowledgeElementMapper.maxOrder(saasKnowledgeElement.getTenantId(), saasKnowledgeElement.getContainerId(), saasKnowledgeElement.getParentCode());
        Integer currentOrder = Objects.requireNonNullElse(maxOrder, 0) + KbConst.MOVE_ORDER_LAST_NEXT;
        // 设置排序
        saasKnowledgeElement.setSort(currentOrder);
        // 版本号
        String pageVersionCode = IdUtil.getSnowflakeNextIdStr();
        // 设置标题名称
        saasKnowledgeElement.setEleName(knowledgeElementAddReq.getTitle());
        // Excel直接存储url地址
        if (knowledgeElementAddReq.getContent().endsWith(KnowledgeElementTypes.EXCELJSON.name().toLowerCase())) {
            saasKnowledgeElement.setEleUrl(knowledgeElementAddReq.getContent());
        }
        // 插入页面记录到数据库
        int ret = saasKnowledgeElementMapper.insert(saasKnowledgeElement);
        if (ret > 0) {
            // 插入版本信息
            knowledgeElementVersionService.add(pageVersionCode, saasKnowledgeElement, knowledgeElementAddReq.getAttachments(), sysUserInfo, KnowledgeElementVersionStatus.DEFAULT);
            // 插入文件解析配置
            Optional<SaasKnowledgeConfigContainer> saasKnowledgeConfigContainer = saasKnowledgeConfigContainerService.queryInfoByContainerId(knowledgeElementAddReq.getSpaceCode());
            if (saasKnowledgeConfigContainer.isEmpty()) {
                log.error("未找到知识库配置信息");
                return Result.error(i18nMessage.resolveMessage("system.common.add.fail"));
            }
            SaasKnowledgeConfigElement request = SaasKnowledgeConfigElement.builder()
                    .elementId(saasKnowledgeElement.getCode())
                    .analysisEngine(saasKnowledgeConfigContainer.get().getAnalysisEngine())
                    .analysisMode(saasKnowledgeConfigContainer.get().getAnalysisMode())
                    .ocrEngine(saasKnowledgeConfigContainer.get().getOcrEngine())
                    .multiModalityEngine(saasKnowledgeConfigContainer.get().getMultiModalityEngine())
                    .splitMode(saasKnowledgeConfigContainer.get().getSplitMode())
                    .maxChunkSize(saasKnowledgeConfigContainer.get().getMaxChunkSize())
                    .overlapSize(saasKnowledgeConfigContainer.get().getOverlapSize())
                    .maxChunkLength(saasKnowledgeConfigContainer.get().getMaxChunkLength())
                    .splitDelimiters(saasKnowledgeConfigContainer.get().getSplitDelimiters())
                    .imageOcr(saasKnowledgeConfigContainer.get().getImageOcr())
                    .tenantId(saasKnowledgeConfigContainer.get().getTenantId())
                    .sort(saasKnowledgeConfigContainer.get().getSort())
                    .modifier(UserContextHolder.getCurrentUser().getCode())
                    .creator(UserContextHolder.getCurrentUser().getCode())
                    .modifierTime(LocalDateTime.now())
                    .containerId(saasKnowledgeConfigContainer.get().getContainerId())
                    .engineType(saasKnowledgeConfigContainer.get().getEngineType())
                    .useOriginalContent(Cns.YES)
                    .createTime(LocalDateTime.now())
                    .build();
            saasKnowledgeConfigElementService.save(request);
            // 通用知识库文档列入 草稿状态不列入动态信息
            String spaceCode = knowledgeElementAddReq.getSpaceCode();
            LambdaQueryWrapper<SaasKnowledgeContainer> queryWrapper = new LambdaQueryWrapper<>();
            queryWrapper.eq(SaasKnowledgeContainer::getCode, spaceCode);
            queryWrapper.eq(SaasKnowledgeContainer::getTenantId, sysUserInfo.getTenantId());
            SaasKnowledgeContainer saasKnowledgeContainer = saasKnowledgeContainerMapper.selectOne(queryWrapper);
            if (!ProcessStatusEnum.DRAFT.equals(ProcessStatusEnum.parse(saasKnowledgeElement.getProcessStatus()))
                    && saasKnowledgeContainer.getCategory().equals(KnowledgeCategory.COMMON.name())) {
                // 空间动态信息新增
                SaasKnowledgeElementCacheInfo saasKnowledgeElementCacheInfo = knowledgeElementConfigService.get(saasKnowledgeElement.getContainerId(), saasKnowledgeElement.getTenantId());
                saasKnowledgeElementTrendService.messageTrend(SaasKnowledgeElementTrendAddReq.of(sysUserInfo, saasKnowledgeElement, SaasKnowledgeElementEvent.UPDATED, saasKnowledgeElementCacheInfo));
            }

            CommonLog.knowledge.action(ActionType.CREATE_SINGLE, "新增知识库元素，名称:{}", saasKnowledgeElement.getEleName())
                    .withMetadata("elementCode", saasKnowledgeElement.getCode())
                    .withMetadata("containerCode", saasKnowledgeElement.getContainerId())
                    .send();
            publishElementUpsert(KnowledgeEventType.DOCUMENT_CREATED, saasKnowledgeElement, false);
        }
        // 模板信息获取
        if (ObjectUtils.isNotEmpty(knowledgeElementAddReq.getTemplateCode())) {
            String templateCode = knowledgeElementAddReq.getTemplateCode();
            String tenantId = UserContextHolder.getTenantId();
            kbPageTemplateService.queryTemplateByCode(tenantId, templateCode).ifPresent(template -> {
                saasKnowledgeElement.setContentMarked(template.getContentMarked());
            });
        }
        return Result.data(KnowledgeElementTreeResp.of(saasKnowledgeElement));
    }

    /**
     * 生成唯一的内容字符串，避免空内容导致的MD5冲突
     */
    private String generateUniqueContent(KnowledgeElementAddReq req, String pageCode, SysUserInfo sysUserInfo) {
        StringBuilder contentBuilder = new StringBuilder();

        // 添加页面标题
        if (StrUtil.isNotBlank(req.getTitle())) {
            contentBuilder.append(req.getTitle());
        }

        // 添加页面内容
        if (StrUtil.isNotBlank(req.getContent())) {
            contentBuilder.append(req.getContent());
        }

        // 添加markdown内容
        if (StrUtil.isNotBlank(req.getContentMarked())) {
            contentBuilder.append(req.getContentMarked());
        }

        // 如果内容为空，使用唯一标识符确保MD5不同
        if (contentBuilder.length() == 0) {
            contentBuilder.append("EMPTY_CONTENT_")
                    .append(pageCode)
                    .append("_")
                    .append(sysUserInfo.getTenantId())
                    .append("_")
                    .append(System.currentTimeMillis());
        }

        return contentBuilder.toString();
    }

    @Override
    public Result<KnowledgeResultInfo> addSingle(KnowledgeSingleElementAddFileReq singleFileReq) {
        log.info("新增知识库元素数据Single,Vo:{}", singleFileReq.toString());
        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        // 校验知识库 请求参数
