        knowledgePermissionGuardService.assertContainerEditPermission(singleFileReq.getContainerId(), sysUserInfo);
        SaasKnowledgeElement saasKnowledgeElement = new SaasKnowledgeElement();
        BeanUtils.copyProperties(singleFileReq, saasKnowledgeElement);
        saasKnowledgeElement.setStartTime(singleFileReq.startTimeInstance());
        saasKnowledgeElement.setEndTime(singleFileReq.endTimeInstance());
        KnowledgeElementCategory elementCategory = KnowledgeElementCategory.getKnowledgeCategory(singleFileReq.getCategory());
        saasKnowledgeElement.setCategory(Objects.requireNonNull(elementCategory, "system.common.request.invalid").getName());
        saasKnowledgeElement.setCreateTime(LocalDateTime.now());
        saasKnowledgeElement.setCreator(sysUserInfo.getCode());
        saasKnowledgeElement.setModifier(sysUserInfo.getCode());
        saasKnowledgeElement.setModifierTime(LocalDateTime.now());
        saasKnowledgeElement.setTenantId(UserContextHolder.getTenantId());
        // 唯一编码
        saasKnowledgeElement.setCode(IdUtil.getSnowflakeNextIdStr());
        // 文件md5
        saasKnowledgeElement.setEleMd5(MD5.create().digestHex16(singleFileReq.getName()));
        saasKnowledgeElement.setEleName(singleFileReq.getName());
        // 设置状态,默认为成功状态
        saasKnowledgeElement.setProcessStatus(ProcessStatusEnum.SUCCESS.getCode());
        saasKnowledgeElement.setProcessCount(0);
        saasKnowledgeElement.setPageCount(1);
        saasKnowledgeElement.setPermissionStatus(ToggleStatusEnum.YES.getCode());
        String parentCode = StrUtil.isBlank(saasKnowledgeElement.getParentCode()) ? "0" : saasKnowledgeElement.getParentCode();
        saasKnowledgeElement.setParentCode(parentCode);
        SaasKnowledgeElement existingDirectory = isDirectoryCategory(saasKnowledgeElement.getCategory())
                ? findSameLevelDirectory(sysUserInfo.getTenantId(), saasKnowledgeElement.getContainerId(), parentCode, saasKnowledgeElement.getEleName())
                : null;
        if (existingDirectory != null) {
            log.info("新增知识库元素数据Single命中同级同名目录, containerId:{}, parentCode:{}, name:{}, existCode:{}",
                    saasKnowledgeElement.getContainerId(), parentCode, saasKnowledgeElement.getEleName(), existingDirectory.getCode());
            return Result.defaultSuccess(KnowledgeResultInfo.from(existingDirectory));
        }
        Long count = saasKnowledgeElementMapper.selectCount(Wrappers.lambdaQuery(SaasKnowledgeElement.class)
                .eq(SaasKnowledgeElement::getParentCode, parentCode)
                .eq(SaasKnowledgeElement::getTenantId, sysUserInfo.getTenantId())
                .eq(SaasKnowledgeElement::getContainerId, saasKnowledgeElement.getContainerId())
                .eq(SaasKnowledgeElement::getCategory, saasKnowledgeElement.getCategory())
                .eq(SaasKnowledgeElement::getEleName, saasKnowledgeElement.getEleName()));
        if (count > 0) {
            return Result.error(i18nMessage.resolveMessage("knowledge.element.add.name.exist"));
        }

        // 处理排序
        try {
            String tenantId = sysUserInfo.getTenantId();
            Integer maxOrder = saasKnowledgeElementMapper.maxOrder(tenantId, saasKnowledgeElement.getContainerId(), parentCode);
            saasKnowledgeElement.setSort(Objects.requireNonNullElse(maxOrder, 0) + KbConst.MOVE_ORDER_LAST_NEXT);
        } catch (Exception e) {
            log.warn("新增知识库元素数据Single set sort failed, use 0, err:{}", e.getMessage());
            saasKnowledgeElement.setSort(0);
        }

        int ret = saasKnowledgeElementMapper.insert(saasKnowledgeElement);

        // 记录日志
        if (ret > 0) {
            recordSingleElementTrend(saasKnowledgeElement, sysUserInfo);
            publishElementUpsert(KnowledgeEventType.FOLDER_CREATED, saasKnowledgeElement, false);
            CommonLog.knowledge.action(ActionType.CREATE_SINGLE, "新增文件夹或虚拟文件，名称:{}，类型:{}", saasKnowledgeElement.getEleName(), singleFileReq.getCategory())
                    .withMetadata("elementId", saasKnowledgeElement.getCode())
                    .withMetadata("elementName", saasKnowledgeElement.getEleName())
                    .withMetadata("category", singleFileReq.getCategory())
                    .withMetadata("containerId", saasKnowledgeElement.getContainerId())
                    .send();
        }

        return ret > 0 ? Result.defaultSuccess(KnowledgeResultInfo.from(saasKnowledgeElement)) : Result.error(i18nMessage.resolveMessage("system.common.add.fail"));
    }

