    private void publishElementUpsert(KnowledgeEventType eventType, SaasKnowledgeElement element, boolean cascade) {
        if (element == null || StrUtil.isBlank(element.getTenantId())) {
            return;
        }
        knowledgeMapSyncEventPublisher.publishAfterCommit(knowledgeMapSyncMessageFactory.message(
                element.getTenantId(),
                eventType,
                List.of(knowledgeMapSyncMessageFactory.elementItem(element, MapSyncAction.UPSERT, cascade))
        ));
    }

    private void publishElementDelete(SaasKnowledgeElement element) {
        if (element == null || StrUtil.isBlank(element.getTenantId())) {
            return;
        }
        int count = mapSyncService.deleteTaskByNode(element.getTenantId(), element.getContainerId(), element.getCode());
        log.info("删除元素后清理知识地图同步任务完成，tenantId:{}, containerId:{}, elementCode:{}, deleteCount:{}",
                element.getTenantId(),
                element.getContainerId(),
                element.getCode(),
                count);
    }

    private void publishElementBatch(KnowledgeEventType eventType,
                                     String tenantId,
                                     Collection<SaasKnowledgeElement> elements,
                                     MapSyncAction action) {
        if (StrUtil.isBlank(tenantId) || CollUtil.isEmpty(elements)) {
            return;
        }
        knowledgeMapSyncEventPublisher.publishAfterCommit(knowledgeMapSyncMessageFactory.message(
                tenantId,
                eventType,
                knowledgeMapSyncMessageFactory.elementItems(elements, action, false)
        ));
    }

    private void publishElementBatchByCategory(String tenantId,
                                               Collection<SaasKnowledgeElement> elements,
                                               KnowledgeEventType directoryEventType,
                                               KnowledgeEventType documentEventType,
                                               MapSyncAction action) {
        if (StrUtil.isBlank(tenantId) || CollUtil.isEmpty(elements)) {
            return;
        }
        List<SaasKnowledgeElement> directories = elements.stream()
                .filter(this::isDirectoryElement)
                .toList();
        List<SaasKnowledgeElement> documents = elements.stream()
                .filter(element -> !isDirectoryElement(element))
                .toList();
        publishElementBatch(directoryEventType, tenantId, directories, action);
        publishElementBatch(documentEventType, tenantId, documents, action);
    }

    private boolean isDirectoryElement(SaasKnowledgeElement element) {
        return element != null && StrUtil.equalsAnyIgnoreCase(element.getCategory(), "DIRECTORY", "FOLDER");
    }

    @Transactional(rollbackFor = Exception.class)
    @Override
    public Result<KnowledgeElementResp> addText(KnowledgeElementTxtAddFileReq addFileReq) {
        log.info("新增文本，name:{}", addFileReq.getName());
        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        knowledgeValidationService.validateFileBase(addFileReq, sysUserInfo.getTenantId());
        knowledgePermissionGuardService.assertContainerEditPermission(addFileReq.getContainerId(), sysUserInfo);
        File tmpFile = null;
        File tmpPreviewFile = null;
        String md5_str = MD5.create().digestHex16(addFileReq.getContent());
        String md5_preview_str = MD5.create().digestHex16(addFileReq.getOriginContent());
        LambdaQueryWrapper<SaasKnowledgeElement> lambdaQueryWrapper = Wrappers.lambdaQuery(SaasKnowledgeElement.class)
                .eq(SaasKnowledgeElement::getTenantId, UserContextHolder.getTenantId())
                .eq(SaasKnowledgeElement::getEleMd5, md5_str);
        Assert.isFalse(saasKnowledgeElementMapper.selectCount(lambdaQueryWrapper) > 0, "knowledge.dataset.txt.validation.exists.content");
        String key = Cns.LOCK_KNOWLEDGE_KEY + sysUserInfo.getTenantId();
        RLock rLock = redissonClient.getLock(key);
        try {
            if (rLock.tryLock(10, 10, TimeUnit.SECONDS)) {
                // 上传
                tmpFile = File.createTempFile("custom_" + addFileReq.getName(), ".txt");
                tmpPreviewFile = File.createTempFile("custom_preview_" + addFileReq.getName(), ".txt");
                // 文本类型的情况，把标题也添加进去？
                FileUtil.writeUtf8String(addFileReq.markdownText(), tmpFile);
                FileUtil.writeUtf8String(addFileReq.getOriginContent(), tmpPreviewFile);
                // 记录上传流量日志
                long fileSize = FileUtil.size(tmpFile);
                boolean storageValidate = billingSubscribeAccountService.validateAvailableStorage(sysUserInfo.getTenantId(), fileSize);
                Assert.isTrue(storageValidate, "knowledge.preview.upload.limit");
                // 上传
                MaterialInfoResp materialInfoResp = materialService.save(tmpFile, md5_str, sysUserInfo.getTenantId());
                MaterialInfoResp materialInfoPreviewResp = materialService.save(tmpPreviewFile, md5_preview_str, sysUserInfo.getTenantId());
                SaasKnowledgeElement saasKnowledgeElement = new SaasKnowledgeElement();
                BeanUtils.copyProperties(addFileReq, saasKnowledgeElement);
                saasKnowledgeElement.setStartTime(addFileReq.startTimeInstance());
                saasKnowledgeElement.setEndTime(addFileReq.endTimeInstance());
                // 文件md5
                saasKnowledgeElement.setEleMd5(MD5.create().digestHex16(addFileReq.getContent()));
                saasKnowledgeElement.setEleName(addFileReq.getName());
                saasKnowledgeElement.setEleUrl(materialInfoResp.getFileUrl());
                // 预览地址存储富文本
                saasKnowledgeElement.setElePreviewUrl(materialInfoPreviewResp.getFileUrl());
                saasKnowledgeElement.setEleTokenSize(Long.parseLong(Objects.toString(StrUtil.length(addFileReq.getContent()), "0")));
                saasKnowledgeElement.setEleSuffix("txt");
                saasKnowledgeElement.setEleSize(fileSize);
                saasKnowledgeElement.setCategory(KnowledgeElementCategory.FILE.getName());
                saasKnowledgeElement.setCreateTime(LocalDateTime.now());
                saasKnowledgeElement.setCreator(sysUserInfo.getCode());
                saasKnowledgeElement.setModifier(sysUserInfo.getCode());
                saasKnowledgeElement.setModifierTime(LocalDateTime.now());
                saasKnowledgeElement.setTenantId(sysUserInfo.getTenantId());
                // 唯一编码
                saasKnowledgeElement.setCode(IdUtil.getSnowflakeNextIdStr());
                // 设置状态,默认为待处理状态
                saasKnowledgeElement.setProcessStatus(ProcessStatusEnum.INIT.getCode());
                saasKnowledgeElement.setProcessCount(0);
                saasKnowledgeElement.setPageCount(1);
                int ret = saasKnowledgeElementMapper.insert(saasKnowledgeElement);
                if (ret > 0) {
                    CommonLog.knowledge.action(ActionType.CREATE_SINGLE, "新增文本文件，名称:{}", addFileReq.getName())
                            .withMetadata("elementCode", saasKnowledgeElement.getCode())
                            .withMetadata("containerCode", addFileReq.getContainerId())
                            .send();
                    Optional<SaasKnowledgeConfigContainer> saasKnowledgeConfigContainer = saasKnowledgeConfigContainerService.queryInfoByContainerId(addFileReq.getContainerId());
                    if (saasKnowledgeConfigContainer.isEmpty()) {
                        log.error("未找到知识库配置信息");
                        return Result.error(i18nMessage.resolveMessage("system.common.add.fail"));
                    }

                    SaasKnowledgeConfigElementAddReq request = SaasKnowledgeConfigElementAddReq.builder()
                            .elementId(saasKnowledgeElement.getCode())
                            .analysisEngine(saasKnowledgeConfigContainer.get().getAnalysisEngine())
                            .analysisMode(saasKnowledgeConfigContainer.get().getAnalysisMode())
                            .ocrEngine(saasKnowledgeConfigContainer.get().getOcrEngine())
                            .multiModalityEngine(saasKnowledgeConfigContainer.get().getMultiModalityEngine())
                            .splitMode(saasKnowledgeConfigContainer.get().getSplitMode())
                            .maxChunkSize(saasKnowledgeConfigContainer.get().getMaxChunkSize())
                            .overlapSize(saasKnowledgeConfigContainer.get().getOverlapSize())
                            .maxChunkLength(saasKnowledgeConfigContainer.get().getMaxChunkLength())
                            .splitDelimiters(saasKnowledgeConfigContainer.get().getSplitDelimiters())
                            .imageOcr(saasKnowledgeConfigContainer.get().getImageOcr())
                            .tenantId(saasKnowledgeConfigContainer.get().getTenantId())
                            .sort(saasKnowledgeConfigContainer.get().getSort())
                            .modifier(UserContextHolder.getCurrentUser().getCode())
                            .creator(UserContextHolder.getCurrentUser().getCode())
                            .modifierTime(LocalDateTime.now())
                            .containerId(saasKnowledgeConfigContainer.get().getContainerId())
                            .engineType(saasKnowledgeConfigContainer.get().getEngineType())
                            .createTime(LocalDateTime.now())
                            .build();

                    boolean f = saasKnowledgeConfigElementService.add(request).getCode().equals(ErrorCodeEnum.SUCCESS.getCode());
                    Assert.isTrue(f, "knowledge.dataset.txt.add.fail");
                    // 增加存储流量日志
                    boolean storageResult = knowledgeStorageService.addStorage(KnowledgeStorageRecord.uploadText(sysUserInfo.getTenantId(), saasKnowledgeElement, materialInfoResp));
                    Assert.isTrue(storageResult, "knowledge.dataset.txt.add.fail");
                    // 上传流量账户扣费
                    boolean result = billingSubscribeAccountService.costStorage(sysUserInfo.getTenantId(), fileSize);
                    Assert.isTrue(result, "knowledge.dataset.txt.add.fail");
                    publishElementUpsert(KnowledgeEventType.DOCUMENT_CREATED, saasKnowledgeElement, false);
                }
                return ret > 0 ? Result.data(new SaasKnowledgeElementApplyFunction().apply(saasKnowledgeElement)) : Result.error(i18nMessage.resolveMessage("system.common.add.fail"));
            }
        } catch (InterruptedException | IOException i) {
            log.error(i.getMessage(), i);
            throw new RuntimeException("system.error.inner.exception");
        } finally {
            FileUtil.del(tmpFile);
            // 释放分布式锁
            if (rLock != null && rLock.isLocked()) {
                rLock.unlock();
                log.info("free lock successful...");
            }
        }
        return Result.error(i18nMessage.resolveMessage("knowledge.dataset.txt.add.fail"));
    }

