    private Result<String> updateElementName(SaasKnowledgeElement record, String eleName) {
        String tenantId = UserContextHolder.getTenantId();
        Assert.isTrue(StrUtil.equalsIgnoreCase(tenantId, record.getTenantId()), "system.common.request.invalid");
        knowledgePermissionGuardService.assertElementEditPermission(record);
        SaasKnowledgeElement saasKnowledgeElement = new SaasKnowledgeElement();
        saasKnowledgeElement.setId(record.getId());
        saasKnowledgeElement.setEleName(eleName);
        saasKnowledgeElement.setModifierTime(LocalDateTime.now());
        int ret = saasKnowledgeElementMapper.updateById(saasKnowledgeElement);
        if (ret > 0) {
            SaasKnowledgeElement saasKnowledgeElement1 = saasKnowledgeElementMapper.selectById(saasKnowledgeElement.getId());
            CommonLog.knowledge.update("更新知识库元素，名称:{}", saasKnowledgeElement1.getEleName())
                    .withMetadata("elementCode", saasKnowledgeElement1.getCode())
                    .withMetadata("containerCode", saasKnowledgeElement1.getContainerId())
                    .send();
            if (!StrUtil.equals(record.getEleName(), saasKnowledgeElement1.getEleName())) {
                try {
                    LambdaQueryWrapper<SaasKnowledgeContainer> queryWrapper = Wrappers.lambdaQuery(SaasKnowledgeContainer.class)
                            .eq(SaasKnowledgeContainer::getCode, saasKnowledgeElement1.getContainerId())
                            .eq(SaasKnowledgeContainer::getTenantId, saasKnowledgeElement1.getTenantId());
                    SaasKnowledgeContainer saasKnowledgeContainer = saasKnowledgeContainerMapper.selectOne(queryWrapper, false);
                    if (saasKnowledgeContainer != null && StrUtil.equalsIgnoreCase(saasKnowledgeContainer.getCategory(), KnowledgeCategory.COMMON.name())) {
                        SaasKnowledgeElementCacheInfo cacheInfo = knowledgeElementConfigService.get(saasKnowledgeElement1.getContainerId(), saasKnowledgeElement1.getTenantId());
                        saasKnowledgeElementTrendService.messageTrend(
                                SaasKnowledgeElementTrendAddReq.of(UserContextHolder.getCurrentUser(), saasKnowledgeElement1, SaasKnowledgeElementEvent.UPDATED, cacheInfo));
                    }
                } catch (Exception e) {
                    log.error("更新知识库元素动态失败：elementCode={}", saasKnowledgeElement1.getCode(), e);
                }
            }
            if (StrUtil.equalsIgnoreCase(saasKnowledgeElement1.getCategory(), KnowledgeElementCategory.DIRECTORY.getName())) {
                publishElementUpsert(KnowledgeEventType.FOLDER_RENAMED, saasKnowledgeElement1, true);
            } else {
                publishElementUpsert(KnowledgeEventType.DOCUMENT_UPDATED, saasKnowledgeElement1, false);
            }
        }

        return ret > 0 ? Result.defaultSuccess(i18nMessage.resolveMessage("system.common.update.success")) : Result.error(i18nMessage.resolveMessage("system.common.update.fail"));
    }


    @Override
    public Result<String> enable(KnowledgeElementEnableReq req) {
        String tenantId = UserContextHolder.getTenantId();
        String lockKey = Cns.LOCK_KNOWLEDGE_KEY + tenantId + ":enable:" + req.getId();
        RLock rLock = redissonClient.getLock(lockKey);
        try {
            if (rLock.tryLock(10, 10, TimeUnit.SECONDS)) {
                SaasKnowledgeElement record = saasKnowledgeElementMapper.selectById(req.getId());
                Assert.isTrue(ObjectUtil.isNotEmpty(record) && StrUtil.equalsIgnoreCase(tenantId, record.getTenantId()), "system.common.request.invalid");
                record.setModifierTime(LocalDateTime.now());
                if (StrUtil.isAllNotEmpty(req.getStartTime(), req.getEndTime())) {
                    DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
                    String startTimeStr = req.getStartTime();
                    String endTimeStr = req.getEndTime();
                    LocalDateTime start = null;
                    LocalDateTime end = null;
                    try {
                        if (startTimeStr != null && !startTimeStr.isEmpty()) {
                            start = LocalDateTime.parse(startTimeStr, formatter);
                        }
                        if (endTimeStr != null && !endTimeStr.isEmpty()) {
                            end = LocalDateTime.parse(endTimeStr, formatter);
                        }
                    } catch (DateTimeParseException e) {
                        log.error("时间格式错误，startTime:{}, endTime:{}", startTimeStr, endTimeStr, e);
                    }
                    record.setStartTime(start);
                    record.setEndTime(end);
                } else {
                    if (Objects.equals(record.getEnable(), ToggleStatusEnum.NO.getCode())) {
                        record.setEnable(ToggleStatusEnum.YES.getCode());
                    } else {
                        record.setEnable(ToggleStatusEnum.NO.getCode());
                    }
                }
                if (ObjectUtil.isNotEmpty(req.getNeverExpire())) {
                    record.setNeverExpire(req.getNeverExpire());
                }

                int ret = saasKnowledgeElementMapper.updateById(record);
                if (ret > 0) {
                    try {
                        log.info("开始同步-启用/禁用-状态到ES.enable:{},startTime:{},endTime:{},neverExpire:{}", record.getEnable(), record.getStartTime(), record.getEndTime(), record.getNeverExpire());
                        Map<String, Object> updateFields = new HashMap<>();
                        if (ObjectUtil.isNotEmpty(record.getEnable())) {
                            updateFields.put(DataSetChunkInfo.FIELD_ENABLE, String.valueOf(record.getEnable()));
                        }
                        if (record.getStartTime() != null) {
                            updateFields.put(DataSetChunkInfo.FIELD_START_TIME, record.getStartTime().atZone(ZoneId.systemDefault()).toInstant().toEpochMilli());
                        }
                        if (record.getEndTime() != null) {
                            updateFields.put(DataSetChunkInfo.FIELD_END_TIME, record.getEndTime().atZone(ZoneId.systemDefault()).toInstant().toEpochMilli());
                        }
                        if (record.getNeverExpire() != null) {
                            updateFields.put(DataSetChunkInfo.FIELD_TIME_STATUS, String.valueOf(record.getNeverExpire()));
                        }

                        if (!updateFields.isEmpty()) {
                            try {
                                List<UpdateReference> updateChunks = Arrays.asList(
                                        UpdateReference.builder()
                                                .dataId(record.getCode())
                                                .value(updateFields)
                                                .build()
                                );

                                UniversalEmbeddingConfig embeddingConfig = knowledgeElementEmbeddingQueryService.getEmbeddingConfigByContainerId(record.getContainerId());
                                vectorIndexDelegate.updateChuck(tenantId, updateChunks, embeddingConfig.getVectorDimension());

                                log.info("updateChunk成功更新同步启用/禁用状态到ES，elementCode:{}, 更新字段:{}", record.getCode(), updateFields);

                            } catch (Exception chunkUpdateEx) {
                                log.error("updateChunk更新同步ES失败，elementCode:{}, error:{}", record.getCode(), chunkUpdateEx.getMessage(), chunkUpdateEx);
                            }
                        }
                    } catch (Exception e) {
                        log.error("同步启用/禁用状态到ES失败，数据库已更新ES同步失败，elementId:{}, error:{}", record.getId(), e.getMessage(), e);
                    }
                }
                return ret > 0 ? Result.defaultSuccess(i18nMessage.resolveMessage("system.common.update.success")) : Result.error(i18nMessage.resolveMessage("system.common.update.fail"));
            } else {
                return Result.error(i18nMessage.resolveMessage("system.common.update.fail"));
            }
        } catch (InterruptedException e) {
            log.error("获取锁失败", e);
            Thread.currentThread().interrupt();
            return Result.error(i18nMessage.resolveMessage("system.common.update.fail"));
        } finally {
            if (rLock != null && rLock.isLocked()) {
                rLock.unlock();
            }
        }
    }


    @Transactional(rollbackFor = Exception.class)
    @Override
    public Result<BatchOperationResult> batchEnable(KnowledgeElementEnableReq req) {
        String tenantId = UserContextHolder.getTenantId();
        BatchOperationResult result = new BatchOperationResult();
        result.setSuccessCount(0);
        result.setFailureCount(0);
        result.setSuccessIds(new ArrayList<>());
        result.setFailureDetails(new ArrayList<>());

        if (CollUtil.isEmpty(req.getIds())) {
            return Result.error("ID列表不能为空");
        }

        for (Integer id : req.getIds()) {
            String lockKey = Cns.LOCK_KNOWLEDGE_KEY + tenantId + ":enable:" + id;
            RLock rLock = redissonClient.getLock(lockKey);
            try {
                if (rLock.tryLock(10, 10, TimeUnit.SECONDS)) {
                    SaasKnowledgeElement record = saasKnowledgeElementMapper.selectById(id);
                    if (ObjectUtil.isEmpty(record) || !StrUtil.equalsIgnoreCase(tenantId, record.getTenantId())) {
                        result.getFailureDetails().add(new BatchOperationResult.FailureDetail(id, "记录不存在或无权限"));
                        result.setFailureCount(result.getFailureCount() + 1);
                        continue;
                    }
                    record.setModifierTime(LocalDateTime.now());
                    if (Objects.equals(record.getEnable(), ToggleStatusEnum.NO.getCode())) {
                        record.setEnable(ToggleStatusEnum.YES.getCode());
                    } else {
                        record.setEnable(ToggleStatusEnum.NO.getCode());
                    }
                    int ret = saasKnowledgeElementMapper.updateById(record);
                    if (ret > 0) {
                        try {
                            Map<String, Object> updateFields = new HashMap<>();
                            if (ObjectUtil.isNotEmpty(record.getEnable())) {
                                updateFields.put(DataSetChunkInfo.FIELD_ENABLE, String.valueOf(record.getEnable()));
                            }
                            if (record.getStartTime() != null) {
                                updateFields.put(DataSetChunkInfo.FIELD_START_TIME, record.getStartTime().atZone(ZoneId.systemDefault()).toInstant().toEpochMilli());
                            }
                            if (record.getEndTime() != null) {
                                updateFields.put(DataSetChunkInfo.FIELD_END_TIME, record.getEndTime().atZone(ZoneId.systemDefault()).toInstant().toEpochMilli());
                            }
                            if (record.getNeverExpire() != null) {
                                updateFields.put(DataSetChunkInfo.FIELD_TIME_STATUS, String.valueOf(record.getNeverExpire()));
                            }

                            if (!updateFields.isEmpty()) {
                                List<UpdateReference> updateChunks = Arrays.asList(
                                        UpdateReference.builder()
                                                .dataId(record.getCode())
                                                .value(updateFields)
                                                .build()
                                );
                                UniversalEmbeddingConfig embeddingConfig = knowledgeElementEmbeddingQueryService.getEmbeddingConfigByContainerId(record.getContainerId());
                                vectorIndexDelegate.updateChuck(tenantId, updateChunks, embeddingConfig.getVectorDimension());
                            }
                            result.getSuccessIds().add(id);
                            result.setSuccessCount(result.getSuccessCount() + 1);
                        } catch (Exception e) {
                            log.error("同步ES失败，ID:{}", id, e);
                            result.getFailureDetails().add(new BatchOperationResult.FailureDetail(id, "ES同步失败"));
                            result.setFailureCount(result.getFailureCount() + 1);
                        }
                    } else {
                        result.getFailureDetails().add(new BatchOperationResult.FailureDetail(id, "数据库更新失败"));
                        result.setFailureCount(result.getFailureCount() + 1);
                    }
                } else {
                    result.getFailureDetails().add(new BatchOperationResult.FailureDetail(id, "获取锁超时"));
                    result.setFailureCount(result.getFailureCount() + 1);
                }
            } catch (Exception e) {
                log.error("批量启用/禁用处理失败，ID:{}", id, e);
                result.getFailureDetails().add(new BatchOperationResult.FailureDetail(id, "处理异常: " + e.getMessage()));
                result.setFailureCount(result.getFailureCount() + 1);
            } finally {
                if (rLock != null && rLock.isLocked()) {
                    rLock.unlock();
                }
            }
        }

        String message = String.format("批量操作完成，成功:%d个，失败:%d个", result.getSuccessCount(), result.getFailureCount());
        return Result.data(result, message);
    }

    @Override
    public Result<BatchOperationResult> batchReset(KnowledgeElementResetReq req) {
        if (CollUtil.isEmpty(req.getIds())) {
            return Result.error("ID列表不能为空");
        }
        String tenantId = UserContextHolder.getTenantId();
        BatchOperationResult result = new BatchOperationResult();
        result.setSuccessCount(0);
        result.setFailureCount(0);
        result.setSuccessIds(new ArrayList<>());
        result.setFailureDetails(new ArrayList<>());
        for (Integer id : req.getIds()) {
            try {
                SaasKnowledgeElement saasKnowledgeElement = saasKnowledgeElementMapper.selectById(id);
                if (ObjectUtil.isEmpty(saasKnowledgeElement) || !StrUtil.equalsIgnoreCase(saasKnowledgeElement.getTenantId(), tenantId)) {
                    result.getFailureDetails().add(new BatchOperationResult.FailureDetail(id, "记录不存在或无权限"));
                    result.setFailureCount(result.getFailureCount() + 1);
                    continue;
                }

                // 判断状态,正在处理中的文件不允许删除
                ProcessStatusEnum processStatusEnum = ProcessStatusEnum.parse(saasKnowledgeElement.getProcessStatus());
                // 如果已经是待处理或者成功的状态，那么不用二次重置处理
                if (processStatusEnum == ProcessStatusEnum.SUCCESS || processStatusEnum == ProcessStatusEnum.INIT) {
                    result.getSuccessIds().add(id);
                    result.setSuccessCount(result.getSuccessCount() + 1);
                    continue;
                }
                // 非处理失败的情况下，给一个间隔
                if (processStatusEnum != ProcessStatusEnum.FAILURE) {
                    // 计算一下时间，避免误操作
                    if (ChronoUnit.MINUTES.between(saasKnowledgeElement.getModifierTime(), LocalDateTime.now()) < 0.5) {
                        // 在5分钟内，不允许重置
                        result.getFailureDetails().add(new BatchOperationResult.FailureDetail(id, "操作间隔时间不足5分钟"));
                        result.setFailureCount(result.getFailureCount() + 1);
                        continue;
                    }
                }
                // 更新状态
                SaasKnowledgeElement element = new SaasKnowledgeElement();
                element.setId(id);
                element.setModifierTime(LocalDateTime.now());
                element.setProcessStatus(ProcessStatusEnum.INIT.getCode());

                // 判断文本的元素类型，如果是wiki类型，那么不需要重置地址
                if (!StrUtil.equalsIgnoreCase(saasKnowledgeElement.getCategory(), KnowledgeElementCategory.VIRTUAL_FILE.getName())) {
                    if (StrUtil.isNotBlank(saasKnowledgeElement.getElePreviewUrl())) {
                        // 把原始的地址重置回去
                        element.setEleUrl(saasKnowledgeElement.getElePreviewUrl());
                    }
                }
                int ret = saasKnowledgeElementMapper.updateById(element);
                if (ret > 0) {
                    // 根据数据集code删除索引的数据
                    knowledgeElementDataService.deleteByDataId(tenantId, saasKnowledgeElement.getContainerId(), saasKnowledgeElement.getCode());
                    result.getSuccessIds().add(id);
                    result.setSuccessCount(result.getSuccessCount() + 1);
                } else {
                    result.getFailureDetails().add(new BatchOperationResult.FailureDetail(id, "数据库更新失败"));
                    result.setFailureCount(result.getFailureCount() + 1);
                }

            } catch (Exception e) {
                log.error("批量重置处理失败，ID:{}", id, e);
                result.getFailureDetails().add(new BatchOperationResult.FailureDetail(id, "处理异常: " + e.getMessage()));
                result.setFailureCount(result.getFailureCount() + 1);
            }
        }
        String message = String.format("批量重置完成，成功:%d个，失败:%d个", result.getSuccessCount(), result.getFailureCount());
        return Result.data(result, message);
    }

    public Result<KnowledgeElementResp> buildElementInfo(SaasKnowledgeElement saasKnowledgeElement, Boolean edit) {
        Assert.notNull(saasKnowledgeElement, BizExceptionSupplier.notFoundInstance());
        String tenantId = UserContextHolder.getTenantId();
        Assert.isTrue(StrUtil.equalsIgnoreCase(tenantId, saasKnowledgeElement.getTenantId()), BizExceptionSupplier.authenticationFailedInstance());
        KnowledgeElementResp knowledgeElementResp = new KnowledgeElementResp();
        BeanUtils.copyProperties(saasKnowledgeElement, knowledgeElementResp);
        // 查询用户名称
        Map<String, String> userMap = userService.selectByCode(knowledgeElementResp.userCodes());
        knowledgeElementResp.applyUserName(userMap);
        // 判断是否为QA对
        if (StrUtil.equalsIgnoreCase(knowledgeElementResp.getCategory(), KnowledgeElementCategory.QA.getName())) {
            // 查询答案,相似问列表
            knowledgeElementResp.setAnswer(knowledgeReferenceService.getAnswer(knowledgeElementResp.getCode(), tenantId));
            knowledgeElementResp.setSimilar(knowledgeSimilarService.listSimilar(tenantId, knowledgeElementResp.getCode()));
            // 获取原始文本
            if (StrUtil.isNotBlank(saasKnowledgeElement.getElePreviewUrl())) {
                knowledgeElementResp.setOriginContent(WebUtil.getString(saasKnowledgeElement.getElePreviewUrl()));
            } else {
                knowledgeElementResp.setOriginContent(knowledgeElementResp.getAnswer());
            }
        } else {
            if (KnowledgeElementTypes.PAGE.name().equals(saasKnowledgeElement.getCategory())
                    // 此处excel就是可编辑的EXCELJSON格式
             || KnowledgeElementTypes.EXCEL.name().equals(saasKnowledgeElement.getCategory())){
                // 如果是页面类型的知识库元素，那么查询最新版本
                knowledgeElementVersionService.queryLatestVersionByPageCode(saasKnowledgeElement.getCode(), saasKnowledgeElement.getTenantId(), edit)
                        .ifPresent(version -> {
                            knowledgeElementResp.setContentMarked(version.getContentMarked());
                            knowledgeElementResp.setOriginContent(version.getContent());
                            knowledgeElementResp.setContent(version.getContent());
                        });
            } else {
                try {
                    DataSetFileCategory dataSetFileCategory = DataSetFileCategory.getDataSetFileCategoryBySuffix(knowledgeElementResp.getEleSuffix());
                    if (dataSetFileCategory == DataSetFileCategory.TXT || dataSetFileCategory == DataSetFileCategory.MARKDOWN) {
                        // 如果是md、txt文件，那么下载oss的内容，给到前端
                        URL presignedUrl=materialService.refreshPresignedUrl(saasKnowledgeElement.getEleUrl());
                        log.info("download-url-string:{},pre-signedUrl:{}", saasKnowledgeElement.getEleUrl(),presignedUrl);
                        // knowledgeElementResp.setAnswer(HttpUtil.downloadString(saasKnowledgeElement.getEleUrl(), StandardCharsets.UTF_8));
                        //knowledgeElementResp.setAnswer(WebUtil.getString(saasKnowledgeElement.getEleUrl()));
                        knowledgeElementResp.setAnswer(WebUtil.getString(presignedUrl.toString()));
                        // 获取原始文本
                        if (StrUtil.isNotBlank(saasKnowledgeElement.getElePreviewUrl())) {
                            URL presignedPreviewUrl = materialService.refreshPresignedUrl(saasKnowledgeElement.getElePreviewUrl());
                            log.info("preview-download-url-string:{},pre-signedPreviewUrl:{}", saasKnowledgeElement.getElePreviewUrl(), presignedPreviewUrl);
                            //knowledgeElementResp.setOriginContent(WebUtil.getString(saasKnowledgeElement.getElePreviewUrl()));
                            knowledgeElementResp.setOriginContent(WebUtil.getString(presignedPreviewUrl.toString()));
                        } else {
                            knowledgeElementResp.setOriginContent(knowledgeElementResp.getAnswer());
                        }
                    }
                } catch (Exception e) {
                    log.error(e.getMessage(), e);
                }
            }
        }
        // 设置显示
        if (saasKnowledgeElement.getEleSize() != null && saasKnowledgeElement.getEleSize() > 0) {
            knowledgeElementResp.setEleSizeDisplay(DataSizeUtil.format(saasKnowledgeElement.getEleSize()));
        } else {
            knowledgeElementResp.setEleSizeDisplay("-");
        }
        // 设置online,非edit请求才返回online地址
        if (!edit) {
            // 文件类型，但是不包含PDF，PDF前端单独处理
            log.info("code:{} ,category:{},suffix:{}", saasKnowledgeElement.getCode(), saasKnowledgeElement.getCategory(), saasKnowledgeElement.getEleSuffix());
            if (KnowledgeElementCategory.FILE.name().equalsIgnoreCase(saasKnowledgeElement.getCategory()) || KnowledgeElementCategory.VIRTUAL_FILE.name().equalsIgnoreCase(saasKnowledgeElement.getCategory())) {
                String url = saasKnowledgeElement.onlineUrl();
                if (StrUtil.isNotBlank(url)) {
                    log.info("online-url-string:{}", url);
                    knowledgeElementResp.setOnline(materialService.online(ThreadLocalHolder.getHttpServletRequest(), url));
                }
            }
        }

        return Result.data(knowledgeElementResp);
    }

