    private Result<String> deleteElement(SaasKnowledgeElement saasKnowledgeElement) {
        String tenantId = UserContextHolder.getTenantId();
        Assert.isTrue(StrUtil.equalsIgnoreCase(saasKnowledgeElement.getTenantId(), tenantId), "system.common.request.invalid");
        knowledgePermissionGuardService.assertElementEditPermission(saasKnowledgeElement);
        // 判断状态,正在处理中的文件不允许删除
        ProcessStatusEnum processStatusEnum = ProcessStatusEnum.parse(saasKnowledgeElement.getProcessStatus());
        if (processStatusEnum == ProcessStatusEnum.PROCESSING || processStatusEnum == ProcessStatusEnum.EMBEDDED || processStatusEnum == ProcessStatusEnum.EMBEDDING) {
            // 判断创建日期是否超过2小时，如果超过，那么验证通过，直接删除,否则不允许删除
            if (ChronoUnit.MINUTES.between(saasKnowledgeElement.getCreateTime(), LocalDateTime.now()) < 120) {
                // 在2小时内的知识库，不允许删除
                throw new IllegalArgumentException(i18nMessage.resolveMessage("knowledge.dataset.del.process"));
            }

        }
        // 如果是文件夹，BFS收集所有后代元素并批量删除
        if (StrUtil.equalsIgnoreCase(saasKnowledgeElement.getCategory(), KnowledgeElementCategory.DIRECTORY.getName())) {
            List<Integer> descendantIds = collectAllDescendantIds(tenantId, saasKnowledgeElement.getContainerId(), saasKnowledgeElement.getCode());
            if (CollUtil.isNotEmpty(descendantIds)) {
                // 校验后代元素状态，正在处理中的不允许删除
                List<SaasKnowledgeElement> descendantElements = saasKnowledgeElementMapper.selectBatchIds(descendantIds);
                for (SaasKnowledgeElement descendant : descendantElements) {
                    ProcessStatusEnum descendantStatus = ProcessStatusEnum.parse(descendant.getProcessStatus());
                    if (descendantStatus == ProcessStatusEnum.PROCESSING || descendantStatus == ProcessStatusEnum.EMBEDDED || descendantStatus == ProcessStatusEnum.EMBEDDING) {
                        if (ChronoUnit.MINUTES.between(descendant.getCreateTime(), LocalDateTime.now()) < 120) {
                            throw new IllegalArgumentException(i18nMessage.resolveMessage("knowledge.dataset.del.process"));
                        }
                    }
                }
                // 批量删除所有后代元素
                saasKnowledgeElementMapper.deleteBatchIds(descendantIds);
                // 清理每个后代元素的关联数据
                for (SaasKnowledgeElement descendant : descendantElements) {
                    knowledgeElementDataService.deleteByDataId(tenantId, descendant.getContainerId(), descendant.getCode());
                    if (KnowledgeElementTypes.PAGE.name().equals(descendant.getCategory()) ||
                            KnowledgeElementTypes.EXCEL.name().equals(descendant.getCategory())) {
                        if (KnowledgeElementTypes.EXCELJSON.name().toLowerCase().equals(descendant.getEleSuffix())) {
                            List<SaasKnowledgeElementVersion> versionList = saasKnowledgeElementVersionMapper.selectList(
                                    Wrappers.lambdaQuery(SaasKnowledgeElementVersion.class)
                                            .eq(SaasKnowledgeElementVersion::getPageCode, descendant.getCode())
                                            .eq(SaasKnowledgeElementVersion::getTenantId, tenantId));
                            if (CollUtil.isNotEmpty(versionList)) {
                                List<String> contentList = versionList.stream()
                                        .map(SaasKnowledgeElementVersion::getContent)
                                        .filter(StrUtil::isNotBlank)
                                        .toList();
                                if (CollUtil.isNotEmpty(contentList)) {
                                    int deleteBatch = sopFileService.deleteBatch(contentList);
                                    if (deleteBatch > 0) {
                                        log.info("删除快照文件成功,数量:{}", deleteBatch);
                                    }
                                }
                            }
                        }
                        knowledgeElementVersionService.remove(Wrappers.lambdaQuery(SaasKnowledgeElementVersion.class)
                                .eq(SaasKnowledgeElementVersion::getPageCode, descendant.getCode())
                                .eq(SaasKnowledgeElementVersion::getTenantId, tenantId));
                        saasKnowledgeConfigElementService.remove(Wrappers.lambdaQuery(SaasKnowledgeConfigElement.class)
                                .eq(SaasKnowledgeConfigElement::getElementId, descendant.getCode())
                                .eq(SaasKnowledgeConfigElement::getContainerId, descendant.getContainerId())
                                .eq(SaasKnowledgeConfigElement::getTenantId, tenantId));
                    }
                    publishElementDelete(descendant);
                }
            }
        }
        // 删除元素自身
        int ret = saasKnowledgeElementMapper.deleteById(saasKnowledgeElement.getId());
        // 判断，如果是非文件夹的数据集，那么删除数据集的向量索引内容
        if (ret > 0) {
            // 释放知识库的空间容量大小
            knowledgeContainerCapacityDataService.flushKnowledge(saasKnowledgeElement.getContainerId(), saasKnowledgeElement.getEleSize());
            // 根据数据集code删除索引的数据
            knowledgeElementDataService.deleteByDataId(tenantId, saasKnowledgeElement.getContainerId(), saasKnowledgeElement.getCode());
            if (KnowledgeElementTypes.PAGE.name().equals(saasKnowledgeElement.getCategory()) ||
                    KnowledgeElementTypes.EXCEL.name().equals(saasKnowledgeElement.getCategory())){
                // 可编辑excel去除对象存储内容
                if (KnowledgeElementTypes.EXCELJSON.name().toLowerCase().equals(saasKnowledgeElement.getEleSuffix())){
                    List<SaasKnowledgeElementVersion> versionList = saasKnowledgeElementVersionMapper.selectList(
                            Wrappers.lambdaQuery(SaasKnowledgeElementVersion.class)
                                    .eq(SaasKnowledgeElementVersion::getPageCode, saasKnowledgeElement.getCode())
                                    .eq(SaasKnowledgeElementVersion::getTenantId, tenantId)
                    );
                    if (CollUtil.isNotEmpty(versionList)) {
                        List<String> contentList = versionList.stream()
                                .map(SaasKnowledgeElementVersion::getContent)
                                .filter(StrUtil::isNotBlank)
                                .toList();
                        if (CollUtil.isNotEmpty(contentList)) {
                            int deleteBatch = sopFileService.deleteBatch(contentList);
                            if (deleteBatch > 0) {
                                log.info("删除快照文件成功,数量:{}", deleteBatch);
                            }
                        }
                    }
                }
                // 删除快照文件
                LambdaQueryWrapper<SaasKnowledgeElementVersion> lambdaQueryWrapper = Wrappers.lambdaQuery(SaasKnowledgeElementVersion.class)
                        .eq(SaasKnowledgeElementVersion::getPageCode, saasKnowledgeElement.getCode())
                        .eq(SaasKnowledgeElementVersion::getTenantId, tenantId);
                knowledgeElementVersionService.remove(lambdaQueryWrapper);
                // 删除配置向量
                LambdaQueryWrapper<SaasKnowledgeConfigElement> saasKnowledgeConfigContainerLambdaQueryWrapper = Wrappers.lambdaQuery(SaasKnowledgeConfigElement.class)
                        .eq(SaasKnowledgeConfigElement::getElementId, saasKnowledgeElement.getCode())
                        .eq(SaasKnowledgeConfigElement::getContainerId, saasKnowledgeElement.getContainerId())
                        .eq(SaasKnowledgeConfigElement::getTenantId, saasKnowledgeElement.getTenantId());
                saasKnowledgeConfigElementService.remove(saasKnowledgeConfigContainerLambdaQueryWrapper);
            }
            // 通用知识库文档列入 草稿状态不列入动态信息
            String containerId = saasKnowledgeElement.getContainerId();
            LambdaQueryWrapper<SaasKnowledgeContainer> queryWrapper = new LambdaQueryWrapper<>();
            queryWrapper.eq(SaasKnowledgeContainer::getCode, containerId);
            queryWrapper.eq(SaasKnowledgeContainer::getTenantId, tenantId);
            SaasKnowledgeContainer saasKnowledgeContainer = saasKnowledgeContainerMapper.selectOne(queryWrapper);
            if (!ProcessStatusEnum.DRAFT.equals(ProcessStatusEnum.parse(saasKnowledgeElement.getProcessStatus()))
                    && saasKnowledgeContainer.getCategory().equals(KnowledgeCategory.COMMON.name())) {
                // 空间动态信息新增
                SaasKnowledgeElementCacheInfo saasKnowledgeElementCacheInfo = knowledgeElementConfigService.get(saasKnowledgeElement.getContainerId(), saasKnowledgeElement.getTenantId());
                saasKnowledgeElementTrendService.messageTrend(SaasKnowledgeElementTrendAddReq.of(UserContextHolder.getCurrentUser(), saasKnowledgeElement, SaasKnowledgeElementEvent.DELETED, saasKnowledgeElementCacheInfo));
            }
            publishElementDelete(saasKnowledgeElement);
        }
        if (ret > 0) {
            CommonLog.knowledge.delete("删除知识库元素，名称:{}", saasKnowledgeElement.getEleName())
                    .withMetadata("elementCode", saasKnowledgeElement.getCode())
                    .withMetadata("containerCode", saasKnowledgeElement.getContainerId())
                    .send();
        }
        return ret > 0 ? Result.defaultSuccess(i18nMessage.resolveMessage("system.common.delete.success")) : Result.error(i18nMessage.resolveMessage("system.common.delete.fail"));
    }

    /**
     * BFS逐层收集文件夹下所有后代元素ID（不含文件夹自身）
     */
    private List<Integer> collectAllDescendantIds(String tenantId, String containerId, String folderCode) {
        List<Integer> allIds = new ArrayList<>();
        Queue<String> parentCodes = new LinkedList<>();
        parentCodes.add(folderCode);
        while (!parentCodes.isEmpty()) {
            List<String> currentLevelCodes = new ArrayList<>(parentCodes);
            parentCodes.clear();
            List<SaasKnowledgeElement> children = saasKnowledgeElementMapper.selectList(
                    Wrappers.lambdaQuery(SaasKnowledgeElement.class)
                            .eq(SaasKnowledgeElement::getTenantId, tenantId)
                            .eq(SaasKnowledgeElement::getContainerId, containerId)
                            .in(SaasKnowledgeElement::getParentCode, currentLevelCodes));
            if (CollUtil.isNotEmpty(children)) {
                for (SaasKnowledgeElement child : children) {
                    allIds.add(child.getId());
                    if (StrUtil.equalsIgnoreCase(child.getCategory(), KnowledgeElementCategory.DIRECTORY.getName())) {
                        parentCodes.add(child.getCode());
                    }
                }
            }
        }
        return allIds;
    }

