    @Transactional(rollbackFor = Exception.class)
    @Override
    public Result<String> reset(Integer id) {
        log.info("根据主键id重置知识库元素,id:{}", id);
        String tenantId = UserContextHolder.getTenantId();
        SaasKnowledgeElement saasKnowledgeElement = saasKnowledgeElementMapper.selectById(id);
        Assert.notNull(saasKnowledgeElement, "system.common.request.invalid");
        Assert.isTrue(StrUtil.equalsIgnoreCase(saasKnowledgeElement.getTenantId(), tenantId), "system.common.request.invalid");
        KnowledgeElementCategory category = KnowledgeElementCategory.getKnowledgeCategory(saasKnowledgeElement.getCategory());
        // 判断状态,正在处理中的文件不允许删除
        ProcessStatusEnum processStatusEnum = ProcessStatusEnum.parse(saasKnowledgeElement.getProcessStatus());
        // 如果已经是待处理或者成功的状态，那么不用二次重置处理
        if (processStatusEnum == ProcessStatusEnum.SUCCESS || processStatusEnum == ProcessStatusEnum.INIT) {
            return Result.data("SUCCESS");
        }
        // 非处理失败的情况下，给一个间隔
        if (processStatusEnum != ProcessStatusEnum.FAILURE) {
            // 计算一下时间，避免误操作
            if (ChronoUnit.MINUTES.between(saasKnowledgeElement.getModifierTime(), LocalDateTime.now()) < 0.5) {
                // 在5分钟内，不允许重置
                throw new IllegalArgumentException(i18nMessage.resolveMessage("knowledge.dataset.file.status.reset.process"));
            }
        }
        // 更新状态
        SaasKnowledgeElement element = new SaasKnowledgeElement();
        element.setId(id);
        element.setModifierTime(LocalDateTime.now());
        element.setProcessStatus(ProcessStatusEnum.INIT.getCode());
        // 判断文本的元素类型，如果是wiki类型，那么不需要重置地址,这样在向量化的过程中使用wiki转换过的markdown数据
        if (!StrUtil.equalsIgnoreCase(saasKnowledgeElement.getCategory(), KnowledgeElementCategory.VIRTUAL_FILE.getName())) {
            if (StrUtil.isNotBlank(saasKnowledgeElement.getElePreviewUrl())) {
                // 把原始的地址重置回去
                element.setEleUrl(saasKnowledgeElement.getElePreviewUrl());
            }
        }
        int ret = saasKnowledgeElementMapper.updateById(element);
        if (ret > 0) {
            // 根据数据集code删除索引的数据
            knowledgeElementDataService.deleteByDataId(tenantId, saasKnowledgeElement.getContainerId(), saasKnowledgeElement.getCode());
            CommonLog.knowledge.update("重置知识库状态，名称:{}", saasKnowledgeElement.getEleName())
                    .withMetadata("elementCode", saasKnowledgeElement.getCode())
                    .withMetadata("containerCode", saasKnowledgeElement.getContainerId())
                    .send();
        }
        return ret > 0 ? Result.defaultSuccess(i18nMessage.resolveMessage("knowledge.dataset.file.status.reset"))
                : Result.error(i18nMessage.resolveMessage("knowledge.dataset.file.status.reset.fail"));
    }

