    @Override
    public void updateEmbeddingStatus(Integer id, KnowledgeEmbeddingStatusReq embeddingStatusReq) {
        SaasKnowledgeElement knowledgeElement = new SaasKnowledgeElement();
        knowledgeElement.setId(id);
        knowledgeElement.setModifierTime(LocalDateTime.now());
        if (embeddingStatusReq.getStatusEnum() != null) {
            knowledgeElement.setProcessStatus(embeddingStatusReq.getStatusEnum().getCode());
            // 向量化成功时，自动标记待摘要，一次 updateById 搞定
            if (embeddingStatusReq.getStatusEnum() == ProcessStatusEnum.SUCCESS
                    && summaryAutoGenerateConfig.getEnable()) {
                knowledgeElement.setSummaryStatus(SummaryStatus.PENDING.getCode());
            }
        }
        if (embeddingStatusReq.getPageCount() != null && embeddingStatusReq.getPageCount() > 0) {
            knowledgeElement.setProcessCount(embeddingStatusReq.getPageCount());
            knowledgeElement.setPageCount(embeddingStatusReq.getPageCount());
        }
        if (StrUtil.isNotBlank(embeddingStatusReq.getConvertMarkdownFileUrl())) {
            knowledgeElement.setEleUrl(embeddingStatusReq.getConvertMarkdownFileUrl());
        }
        if (StrUtil.isNotBlank(embeddingStatusReq.getPreviewUrl())) {
            knowledgeElement.setElePreviewUrl(embeddingStatusReq.getPreviewUrl());
        }
        int ret=saasKnowledgeElementMapper.updateById(knowledgeElement);
        if (ret>0){
            if (embeddingStatusReq.getStatusEnum() != null) {
                knowledgeElementProcessService.updateProcessStatus(id, embeddingStatusReq.getStatusEnum());
                if (embeddingStatusReq.getStatusEnum() == ProcessStatusEnum.SUCCESS) {
                    SaasKnowledgeElement latestElement = saasKnowledgeElementMapper.selectById(id);
                    if (latestElement != null) {
                        publishElementUpsert(KnowledgeEventType.EMBEDDING_COMPLETED, latestElement, false);
                    }
                }
            }
        }
    }

