    @Override
    public Result<String> updateOrIssue(KnowledgeElementContentUpdateReq issueReq) {
        Optional<SaasKnowledgeElement> elementOptional = queryInfoByCode(issueReq.getCode());
        Assert.isTrue(elementOptional.isPresent(), "system.common.request.invalid");
        knowledgePermissionGuardService.assertElementEditPermission(elementOptional.get());
        // 页面组件
        String lockKey = KbCacheConst.KB_LOCK_PAGE_UPDATE + issueReq.getCode();
        RLock rLock = redissonClient.getLock(lockKey);
        try {
            rLock.lock();
            // 考虑兼容workstation的cat命令情况，这里不做html转markdown的处理，直接存储原始的html内容
            // 还需要修改embedding解析的逻辑
            // issueReq.html2Markdown();
            if (StrUtil.equalsIgnoreCase(issueReq.getOperateType(), "update")) {
                return this.updateContent(issueReq);
            } else if (StrUtil.equalsIgnoreCase(issueReq.getOperateType(), "issue")) {
                return this.issue(issueReq, true);
            }
        } catch (Exception e) {
            // 如果获取锁失败，记录日志
            log.info("page version number increment。get lock failed...message:{}", e.getMessage(), e);
        } finally {
            // 释放分布式锁
            if (rLock != null && rLock.isHeldByCurrentThread()) {
                rLock.unlock();
                log.info("free comment lock successful...");
            }
        }

        return Result.error(i18nMessage.resolveMessage("system.common.update.fail"));
    }

