    @Override
    public DataSetChunkInfo buildChunkInfo(double[] vector, String chunkText, SaasKnowledgeElement element, int line, Map<String, Integer> chunkMeta) {
        DataSetChunkInfo chunkInfo = new DataSetChunkInfo();
        chunkInfo.setVector(vector);
        chunkInfo.setContent(chunkText);
        chunkInfo.setYear(element.getYear());
        chunkInfo.setContainerId(element.getContainerId());
        chunkInfo.setTopic(element.getTopic());
        DocTimeStatus docTimeStatus = DocTimeStatus.parse(element.getNeverExpire());
        if (docTimeStatus == DocTimeStatus.NEVER_EXPIRE) {
            chunkInfo.setTimeStatus(docTimeStatus.getCode());
            chunkInfo.setStartTime(0L);
            chunkInfo.setEndTime(0L);
        } else if (docTimeStatus == DocTimeStatus.TIME_EXPIRE) {
            chunkInfo.setTimeStatus(docTimeStatus.getCode());
            chunkInfo.setStartTime(element.getStartTime().atZone(ZoneId.systemDefault()).toInstant().toEpochMilli());
            chunkInfo.setEndTime(element.getEndTime().atZone(ZoneId.systemDefault()).toInstant().toEpochMilli());
        }
        chunkInfo.setCategory(DataSetChunkType.ORIGINAL.getName());
        chunkInfo.setCreateTime(LocalDateTime.now().atZone(ZoneId.systemDefault()).toInstant().toEpochMilli());
        chunkInfo.setDataId(element.getCode());
        // i是从下标0开始的，因此需要+1
        String key = Objects.toString(line + 1, "1");
        int page = Integer.parseInt(Objects.toString(chunkMeta.get(key), "1"));
        chunkInfo.setPage(page);
        chunkInfo.setParagraphId(md5.digestHex(chunkInfo.getContainerId() + chunkInfo.getDataId() + page));
        chunkInfo.setId(md5.digestHex(chunkInfo.getParagraphId() + IdUtil.getSnowflakeNextIdStr()));
        return chunkInfo;
    }

    @Override
    public void merge(SaasKnowledgeElement saasKnowledgeElement, List<String> attachmentCodes, SysUserInfo sysUserInfo, KnowledgeElementVersionStatus status) {
        String lockKey = StrUtil.format(KbCacheConst.KB_LOCK_PAGE_VERSION, saasKnowledgeElement.getCode());
        RLock rLock = redissonClient.getLock(lockKey);
        try {
            rLock.lock();
            // 查询指定页面信息，只和页面关联
            LambdaQueryWrapper<SaasKnowledgeElementVersion> lambdaQueryWrapper = Wrappers.lambdaQuery(SaasKnowledgeElementVersion.class)
                    .eq(SaasKnowledgeElementVersion::getTenantId, saasKnowledgeElement.getTenantId())
                    .eq(SaasKnowledgeElementVersion::getPageCode, saasKnowledgeElement.getCode())
                    .eq(SaasKnowledgeElementVersion::getStatus, KnowledgeElementVersionStatus.DEFAULT.getCode());
            lambdaQueryWrapper.select(SaasKnowledgeElementVersion::getId, SaasKnowledgeElementVersion::getCode);
            SaasKnowledgeElementVersion pageVersion = saasKnowledgeElementVersionMapper.selectOne(lambdaQueryWrapper, false);
            SaasKnowledgeElementVersion record = new SaasKnowledgeElementVersion();
            if (pageVersion != null) {
                // 存在，那么直接更新
                record.setAttachmentCode(CollUtil.join(attachmentCodes, StrUtil.COMMA));
                record.setTitle(saasKnowledgeElement.getEleName());
                record.setDescription(saasKnowledgeElement.getConfig());
                // 判断page类型，如果是excel，存储到OSS上面，避免数据太多，超过DB字段的上限。
                // dealContent(kbPage, versionCode, record, sysUserInfo);
                record.setContent(saasKnowledgeElement.getContent());
                record.setContentMarked(saasKnowledgeElement.getContentMarked());
                record.setId(pageVersion.getId());
                record.setModifierTime(LocalDateTime.now());
                record.setModifier(sysUserInfo.getCode());
                saasKnowledgeElementVersionMapper.updateById(record);
            } else {
                // 查询已发布的最大版本号
                LambdaQueryWrapper<SaasKnowledgeElementVersion> queryWrapper = Wrappers.lambdaQuery(SaasKnowledgeElementVersion.class)
                        .eq(SaasKnowledgeElementVersion::getTenantId, saasKnowledgeElement.getTenantId())
                        .eq(SaasKnowledgeElementVersion::getPageCode, saasKnowledgeElement.getCode())
                        .eq(SaasKnowledgeElementVersion::getStatus, KnowledgeElementVersionStatus.ISSUED.getCode());
                queryWrapper.select(SaasKnowledgeElementVersion::getVersionNo);
                List<SaasKnowledgeElementVersion> issuedVersions = saasKnowledgeElementVersionMapper.selectList(queryWrapper);
                int maxVersionNo = issuedVersions.stream()
                        .map(SaasKnowledgeElementVersion::getVersionNo)
                        .max(Integer::compareTo)
                        .orElse(0); // 没有已发布版本则为0
                int newVersionNo = maxVersionNo + 1;
                record.setVersionNo(newVersionNo);
                record.setTitle(saasKnowledgeElement.getEleName());
                record.setDescription(saasKnowledgeElement.getConfig());
                record.setUserCode(sysUserInfo.getCode());
                record.setContent(saasKnowledgeElement.getContent());
                record.setContentMarked(saasKnowledgeElement.getContentMarked());
                record.setPageCode(saasKnowledgeElement.getCode());
                record.setTenantId(sysUserInfo.getTenantId());
                record.setCreator(sysUserInfo.getCode());
                record.setCreateTime(LocalDateTime.now());
                record.setModifier(sysUserInfo.getCode());
                record.setModifierTime(LocalDateTime.now());
                record.setStatus(status.name());
                record.setCode(IdUtil.getSnowflakeNextIdStr());
                if (CollUtil.isNotEmpty(attachmentCodes)) {
                    record.setAttachmentCode(CollUtil.join(attachmentCodes, StrUtil.COMMA));
                }
                log.info("生成一个新的版本号，versionNo:{},versionCode:{}", record.getVersionNo());
                // insert
                int ret = saasKnowledgeElementVersionMapper.insert(record);
                log.info("新增页面版本,ret:{}", ret);
            }
        } catch (Exception e) {
            // 如果获取锁失败，记录日志
            log.info("page version number increment。get lock failed...message:{}", e.getMessage(), e);
        } finally {
            // 释放分布式锁
            if (rLock != null && rLock.isHeldByCurrentThread()) {
                rLock.unlock();
                log.info("free comment lock successful...");
            }
        }
    }

