    /**
     * 对象转换Function
     */
    private static class SaasKnowledgeElementApplyFunction implements Function<SaasKnowledgeElement, KnowledgeElementResp> {

        @Override
        public KnowledgeElementResp apply(SaasKnowledgeElement saasKnowledgeElement) {
            KnowledgeElementResp knowledgeElementResp = new KnowledgeElementResp();
            BeanUtils.copyProperties(saasKnowledgeElement, knowledgeElementResp);
            // 设置显示
            if (saasKnowledgeElement.getEleSize() != null && saasKnowledgeElement.getEleSize() > 0) {
                knowledgeElementResp.setEleSizeDisplay(DataSizeUtil.format(saasKnowledgeElement.getEleSize()));
            } else {
                knowledgeElementResp.setEleSizeDisplay("-");
            }
            ProcessStatusEnum processStatusEnum = ProcessStatusEnum.parse(knowledgeElementResp.getProcessStatus());
            if (processStatusEnum == ProcessStatusEnum.PROCESSING || processStatusEnum == ProcessStatusEnum.EMBEDDED || processStatusEnum == ProcessStatusEnum.EMBEDDING) {
                // 判断处理时间，如果超过2小时，那么默认按失败处理
                if (ChronoUnit.HOURS.between(saasKnowledgeElement.getCreateTime(), LocalDateTime.now()) > 4) {
                    knowledgeElementResp.setProcessStatus(ProcessStatusEnum.FAILURE.getCode());
                }
            }
            // 判断处理进度
            if (processStatusEnum == ProcessStatusEnum.INIT) {
                knowledgeElementResp.setProcessPercent(0);
            } else if (processStatusEnum == ProcessStatusEnum.SUCCESS) {
                knowledgeElementResp.setProcessPercent(100);
            } else {
                if (saasKnowledgeElement.getProcessCount() > 0 && saasKnowledgeElement.getPageCount() > 0) {
                    int per = BigDecimal.valueOf(saasKnowledgeElement.getProcessCount()).divide(BigDecimal.valueOf(saasKnowledgeElement.getPageCount()), 4, RoundingMode.HALF_UP)
                            .multiply(BigDecimal.valueOf(100)).intValue();
                    knowledgeElementResp.setProcessPercent(per);
                } else {
                    knowledgeElementResp.setProcessPercent(0);
                }
            }
            return knowledgeElementResp;
        }
    }

