    @Override
    public Pagination<KnowledgeElementResp> hotPage(Integer pageNo, Integer pageSize, String containerId) {
        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        // 是否租户管理员
        boolean adminRole = false;
        List<String> joinSpaceCodes = null;

        if (StrUtil.isNotBlank(containerId)) {
            // 如果指定了空间，验证用户是否有权限访问该空间
            joinSpaceCodes = Collections.singletonList(containerId);
        } else if (!adminRole) {
            // 如果不是管理员且未指定空间，获取用户有权限的所有空间
            joinSpaceCodes = kbSpaceUserService.userSpaceCodeIndex(sysUserInfo);
        }

        try (Page<SaasKnowledgeElement> page = PageHelper.startPage(pageNo, pageSize)) {
            LambdaQueryWrapper<SaasKnowledgeElement> lambdaQueryWrapper = Wrappers.lambdaQuery(SaasKnowledgeElement.class)
                    .eq(SaasKnowledgeElement::getTenantId, sysUserInfo.getTenantId())
                    // 只查询已发布的页面
                    .eq(SaasKnowledgeElement::getProcessStatus, ProcessStatusEnum.SUCCESS.getCode())
                    .ne(SaasKnowledgeElement::getCategory, KnowledgeElementTypes.FOLDER.name())
                    .ne(SaasKnowledgeElement::getCategory, KnowledgeContainerType.DIRECTORY.name())
                    // 根据热度排序
                    .orderByDesc(SaasKnowledgeElement::getHotNumber);

            // 如果指定了空间编码，直接在主查询中添加条件
            if (StrUtil.isNotBlank(containerId)) {
                lambdaQueryWrapper.eq(SaasKnowledgeElement::getContainerId, containerId);
            } else if (!adminRole && CollUtil.isNotEmpty(joinSpaceCodes)) {
                // 如果是非管理员且有权限的空间列表不为空，添加空间编码条件
                lambdaQueryWrapper.in(SaasKnowledgeElement::getContainerId, joinSpaceCodes);
            }

            // 直接使用lambdaQueryWrapper进行查询
            List<SaasKnowledgeElement> saasKnowledgeElementList = saasKnowledgeElementMapper.selectList(lambdaQueryWrapper);
            List<KnowledgeElementResp> pageTree = new ArrayList<>();
            if (CollUtil.isNotEmpty(saasKnowledgeElementList)) {
                pageTree = new ArrayList<>(saasKnowledgeElementList.stream().map(KnowledgeElementResp::of).toList());
                // 批量填充creatorName和modifierName
                Set<String> userCodes = new HashSet<>();
                for (KnowledgeElementResp resp : pageTree) {
                    userCodes.addAll(resp.userCodes());
                }
                if (!userCodes.isEmpty()) {
                    Map<String, String> userMap = userService.selectByCode(new ArrayList<>(userCodes));
                    for (KnowledgeElementResp resp : pageTree) {
                        resp.applyUserName(userMap);
                    }
                }
            }
            return Pagination.pagination(pageTree, page.getTotal(), pageNo, pageSize);
        }
    }

    @Override
    public Result<String> restore(PageVersionRestoreReq issueReq) {
        // 记录发布空间页面的日志
        String code = issueReq.getCode();
        log.info("根据code恢复页面版本当前页面快照编码,code:{}", code);
        SaasKnowledgeElementVersion saasKnowledgeElementVersion = knowledgeElementVersionService.getVersionByCode(issueReq.getVersionNo(), issueReq.getCode());
        // 恢复标题
        issueReq.setTitle(saasKnowledgeElementVersion.getTitle());
        // 获取当前用户信息
        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        // 根据代码和租户ID查询页面信息
        Optional<SaasKnowledgeElement> kbPageOptional = this.queryByCode(issueReq.getPageCode(), sysUserInfo.getTenantId());
        // 如果查询不到页面信息，抛出非法参数异常
        if (kbPageOptional.isEmpty()) {
            throw new IllegalArgumentException("system.common.request.invalid");
        }
        // 获取查询到的页面信息
        SaasKnowledgeElement record = kbPageOptional.get();
        // 创建一个新对象用于更新页面状态
        SaasKnowledgeElement update = new SaasKnowledgeElement();
        if (StrUtil.isNotBlank(issueReq.getTitle())) {
            update.setEleName(issueReq.getTitle());
        }
        update.setId(record.getId());
        update.setModifier(sysUserInfo.getCode());
        update.setModifierTime(LocalDateTime.now());
        SaasKnowledgeElementIssueContext issueContext = new SaasKnowledgeElementIssueContext();
        // 如果是已经发布的状态。新增一个版本作为当前页面版本的草稿状态。
        issueReq.applyPublish(issueContext, update);
        // 设置最新的内容
        update.setContent(issueReq.getContent());
        update.setContentMarked(issueReq.getContentMarked());
        // 可编辑excel兼容性修改
        if (issueReq.getContent().endsWith(KnowledgeElementTypes.EXCELJSON.name().toLowerCase())){
            update.setEleUrl(issueReq.getContent());
        }
        update.setProcessStatus(ProcessStatusEnum.INIT.getCode());
        // 执行页面状态更新操作
        int ret = saasKnowledgeElementMapper.updateById(update);
        // 记录更新结果
        log.info("恢复空间页面结果:{}", ret > 0);
        // 如果更新成功，进行向量化处理
        if (ret > 0) {
            CommonLog.knowledge.update("恢复页面版本，版本号:{}", issueReq.getVersionNo())
                    .withMetadata("pageCode", code)
                    .withMetadata("versionNo", issueReq.getVersionNo())
                    .withMetadata("title", issueReq.getTitle())
                    .withMetadata("containerId", record.getContainerId())
                    .send();
            issueReq.updateIssue(update, record);
            // todo 处理附件
            // 更新版本信息
            this.issuePage(issueContext, update, sysUserInfo, issueReq.getAttachments());
            // 如果原来记录中原本就是发布状态,并且当前页面不需要审核，则更新动态信息
            // 空间动态信息新增
//            SaasKnowledgeElementCacheInfo saasKnowledgeElementCacheInfo = this.get(update.getContainerId(), update.getTenantId());
//            saasKnowledgeElementTrendService.messageTrend(SaasKnowledgeElementTrendAddReq.of(UserContextHolder.getCurrentUser(), update, SaasKnowledgeElementEvent.DELETED, saasKnowledgeElementCacheInfo));
            if (issueContext.getVersionStatus() == KnowledgeElementVersionStatus.ISSUED) {
                // 删除旧的es索引
                boolean re = knowledgeElementDataService.deleteByDataId(update.getTenantId(), update.getContainerId(), issueReq.getPageCode());
                log.info("数据库删除成功,ret:{},向量删除:{}", ret, re);
            }
        }
        // 返回成功结果
        return Result.success("SUCCESS");
    }

    @Override
    public void issuePage(SaasKnowledgeElementIssueContext issueContext, SaasKnowledgeElement saasKnowledgeElement, SysUserInfo sysUserInfo, List<String> attachmentCodes) {
        // 判断是否为新版本
        if (issueContext.isStartVersion()) {
            // 新增一个版本
            this.merge(saasKnowledgeElement, attachmentCodes, sysUserInfo, issueContext.getVersionStatus());
        } else {
            // 更新
