            BeanUtils.copyProperties(saasKnowledgeElement, knowledgeElementContentUpdateReq);
            this.update(saasKnowledgeElement, knowledgeElementContentUpdateReq, sysUserInfo, issueContext.getVersionStatus());
        }
    }


