    /**
     * 文件名比较方法，支持中英文和数字混合排序
     * 排序规则：
     * - sortType=1(正序/A-Z): 英文A-Z → 中文拼音A-Z → 数字0-9
     * - sortType=0(倒序/Z-A): 数字9-0 → 中文拼音Z-A → 英文Z-A
     *
     * @param fileName1 第一个文件名
     * @param fileName2 第二个文件名
     * @param sortType  排序类型（1=正序A-Z, 0=倒序Z-A）
     * @return 比较结果
     */
    private int compareFileName(String fileName1, String fileName2, Integer sortType) {
        if (fileName1 == null && fileName2 == null) {
            return 0;
        }
        if (fileName1 == null) {
            return sortType == 0 ? -1 : 1;
        }
        if (fileName2 == null) {
            return sortType == 0 ? 1 : -1;
        }

        String name1 = fileName1.trim();
        String name2 = fileName2.trim();

        // 判断文件名的类型（英文、中文、数字开头）
        int type1 = getFileNameType(name1);
        int type2 = getFileNameType(name2);

        int result;

        if (sortType == 1) {
            // 正序：英文(1) < 中文(2) < 数字(3) < 其他(4)
            if (type1 != type2) {
                result = Integer.compare(type1, type2);
            } else {
                result = compareByType(name1, name2, type1);
            }
        } else {
            // 倒序：数字(3) < 中文(2) < 英文(1) < 其他(4)
            if (type1 != type2) {
                // 数字和中文、英文的顺序需要反转
                if (type1 == 3 || type2 == 3) {
                    result = Integer.compare(type2, type1);
                } else {
                    result = Integer.compare(type1, type2);
                }
            } else {
                result = -compareByType(name1, name2, type1);
            }
        }

        return result;
    }

    /**
     * 获取文件名类型
     *
     * @param fileName 文件名
     * @return 1=英文开头, 2=中文开头, 3=数字开头, 4=其他
     */
    private int getFileNameType(String fileName) {
        if (fileName == null || fileName.isEmpty()) {
            return 4;
        }
        char firstChar = fileName.charAt(0);
        if ((firstChar >= 'A' && firstChar <= 'Z') || (firstChar >= 'a' && firstChar <= 'z')) {
            return 1; // 英文
        } else if (firstChar >= '\u4e00' && firstChar <= '\u9fa5') {
            return 2; // 中文
        } else if (firstChar >= '0' && firstChar <= '9') {
            return 3; // 数字
        } else {
            return 4; // 其他
        }
    }

    /**
     * 根据类型比较文件名
     *
     * @param name1 文件名1
     * @param name2 文件名2
     * @param type  类型
     * @return 比较结果
     */
    private int compareByType(String name1, String name2, int type) {
        if (type == 1) {
            // 英文：忽略大小写比较
            return name1.toUpperCase().compareTo(name2.toUpperCase());
        } else if (type == 3) {
            // 数字：提取开头的数字部分按数值比较
            return compareNumericPrefix(name1, name2);
        } else {
            // 中文和其他：直接字符串比较
            return name1.compareTo(name2);
        }
    }

    /**
     * 比较数字开头的文件名
     * 提取开头的连续数字，按数值大小比较
     *
     * @param name1 文件名1
     * @param name2 文件名2
     * @return 比较结果
     */
    private int compareNumericPrefix(String name1, String name2) {
        // 提取开头的连续数字
        String numStr1 = extractLeadingNumber(name1);
        String numStr2 = extractLeadingNumber(name2);

        try {
            // 按数值比较
            Long num1 = Long.parseLong(numStr1);
            Long num2 = Long.parseLong(numStr2);
            int numCompare = num1.compareTo(num2);

            if (numCompare != 0) {
                return numCompare;
            }

            // 数字相同，比较剩余部分
            String rest1 = name1.substring(numStr1.length());
            String rest2 = name2.substring(numStr2.length());
            return rest1.compareTo(rest2);
        } catch (NumberFormatException e) {
            // 数字太大，降级为字符串比较
            return name1.compareTo(name2);
        }
    }

    /**
     * 提取文件名开头的连续数字
     *
     * @param fileName 文件名
     * @return 数字字符串
     */
    private String extractLeadingNumber(String fileName) {
        if (fileName == null || fileName.isEmpty()) {
            return "0";
        }

        StringBuilder numStr = new StringBuilder();
        for (int i = 0; i < fileName.length(); i++) {
            char c = fileName.charAt(i);
            if (c >= '0' && c <= '9') {
                numStr.append(c);
            } else {
                break;
            }
        }

        return numStr.length() > 0 ? numStr.toString() : "0";
    }

    /**
     * 从文件名中提取数字前缀（已废弃，保留用于兼容）
     * 匹配模式：数字 + 分隔符（如点、横线、下划线等）
     *
     * @param fileName 文件名
     * @return 提取的数字，如果没有则返回null
     * @deprecated 使用新的排序逻辑，此方法已不再使用
     */
    @Deprecated
    private Integer extractNumberPrefix(String fileName) {
        if (fileName == null || fileName.trim().isEmpty()) {
            return null;
        }

        // 匹配开头的数字，后面跟着分隔符（. - _ 空格等）
        java.util.regex.Pattern pattern = java.util.regex.Pattern.compile("^(\\d+)[.\\-_\\s]+");
        java.util.regex.Matcher matcher = pattern.matcher(fileName.trim());

        if (matcher.find()) {
            try {
                return Integer.parseInt(matcher.group(1));
            } catch (NumberFormatException e) {
                log.debug("解析文件名数字前缀失败: {}", fileName, e);
                return null;
            }
        }

        return null;
    }

    /**
     * 查询所有知识库元素列表，包括所有子级，排序规则与list接口保持一致
     *
     * @param knowledgeElementQueryReq 查询条件Vo
     * @return 所有知识库元素列表（包括所有层级）
     */
    @Override
    public Result<List<KnowledgeElementResp>> listAllWithSort(KnowledgeElementQueryReq knowledgeElementQueryReq) {
        log.info("根据条件查询所有知识库元素列表（包括所有层级）");
        log.info("QueryReq:{}", knowledgeElementQueryReq.toString());

        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        // 查询全部列表的
        DepartmentUserOrgPermissions orgPermissions = kbDepartmentUserService.listAccessibleDepartmentCodes(sysUserInfo);

        LambdaQueryWrapper<SaasKnowledgeElement> lambdaQueryWrapper = Wrappers.lambdaQuery(SaasKnowledgeElement.class)
                .eq(SaasKnowledgeElement::getTenantId, sysUserInfo.getTenantId());

        // 查询条件
        lambdaQueryWrapper.eq(StrUtil.isNotBlank(knowledgeElementQueryReq.getContainerId()), SaasKnowledgeElement::getContainerId, knowledgeElementQueryReq.getContainerId());
        // 注意：这里不限制parentCode，要查询所有层级
        if (StrUtil.isNotBlank(knowledgeElementQueryReq.getCategory())) {
            List<String> category = StrUtil.split(knowledgeElementQueryReq.getCategory(), StrUtil.COMMA);
            lambdaQueryWrapper.in(SaasKnowledgeElement::getCategory, category);
        }
        lambdaQueryWrapper.like(StrUtil.isNotBlank(knowledgeElementQueryReq.getEleName()), SaasKnowledgeElement::getEleName, knowledgeElementQueryReq.getEleName());

        // 草稿状态只能自己可见
        lambdaQueryWrapper.and(l -> {
            l.ne(SaasKnowledgeElement::getProcessStatus, ProcessStatusEnum.DRAFT.getCode()).or(lf -> {
                lf.eq(SaasKnowledgeElement::getProcessStatus, ProcessStatusEnum.DRAFT.getCode());
                lf.eq(SaasKnowledgeElement::getCreator, Objects.toString(sysUserInfo.getCode()));
            });
        });

        // 过滤权限
        ElementSearchCondition searchCondition = ElementSearchCondition.from(sysUserInfo.getTenantId(), knowledgeElementQueryReq.getContainerId(), null, orgPermissions.permissionCodesToList());
        List<String> visibleCodes = saasKnowledgeElementMapper.listVisibleCodes(searchCondition);
        if (CollUtil.isNotEmpty(visibleCodes)) {
            lambdaQueryWrapper.and(lf -> lf.eq(SaasKnowledgeElement::getPermissionStatus, ToggleStatusEnum.YES.getCode()).or(l1 -> {
                l1.eq(SaasKnowledgeElement::getPermissionStatus, ToggleStatusEnum.NO.getCode());
                l1.in(SaasKnowledgeElement::getCode, visibleCodes);
            }));
        } else {
            lambdaQueryWrapper.eq(SaasKnowledgeElement::getPermissionStatus, ToggleStatusEnum.YES.getCode());
        }

        // 设定排序规则
        SortRules sortRule = SortRules.parse(knowledgeElementQueryReq.getSortRule());
        if (sortRule == SortRules.SORT_NUMBER) {
            lambdaQueryWrapper.orderByAsc(SaasKnowledgeElement::getSort);
        } else if (sortRule == SortRules.SORT_CREATE_TIME) {
            if (knowledgeElementQueryReq.getSortType() == 0) {
                lambdaQueryWrapper.orderByAsc(SaasKnowledgeElement::getCreateTime);
            } else {
                lambdaQueryWrapper.orderByDesc(SaasKnowledgeElement::getCreateTime);
            }
        } else if (sortRule == SortRules.SORT_MODIFY_TIME) {
            if (knowledgeElementQueryReq.getSortType() == 0) {
                lambdaQueryWrapper.orderByAsc(SaasKnowledgeElement::getModifierTime);
            } else {
                lambdaQueryWrapper.orderByDesc(SaasKnowledgeElement::getModifierTime);
            }
        }
        String permissionType = saasKnowledgeContainerPermissionService.getHighestPermission(knowledgeElementQueryReq.getContainerId(), sysUserInfo);
        log.info("当前用户在容器中的最高权限:{}", permissionType);
        // 如果是没权限的角色，那么需要判断当前的知识库是否设置为公开，如果是公开的情况下，那么给予只读角色
        Optional<SaasKnowledgeContainer> containerOptional = knowledgeContainerQueryService.queryInfoByCode(knowledgeElementQueryReq.getContainerId());
        if (containerOptional.isEmpty()) {
            return Result.data(new ArrayList<>());
        }
        boolean canFilter = true;
        SaasKnowledgeContainer saasKnowledgeContainer = containerOptional.get();
        if (KbKnowledgeBaseContainerVisibilityRange.publicRead(saasKnowledgeContainer.getVisibilityRange())) {
            // 公开可读
            canFilter = false;
        } else {
            // 非公开可读，那么必须有权限才可以查看
            if (!StrUtil.equalsIgnoreCase(KbKnowledgeBaseContainerPermissionTypes.NO_PERMISSION.getCode(), permissionType)) {
                // 公开可读
                canFilter = false;
            }
        }
        List<SaasKnowledgeElement> saasKnowledgeElementInfos = saasKnowledgeElementMapper.selectList(lambdaQueryWrapper);
        if (canFilter) {
            List<String> elementCodes = saasKnowledgeElementInfos.stream().map(SaasKnowledgeElement::getCode).toList();
            ElementFilterSearchCondition searchFilterCondition = ElementFilterSearchCondition.from(sysUserInfo.getTenantId(), knowledgeElementQueryReq.getContainerId(), elementCodes, orgPermissions.permissionCodesToList());
            List<String> visibleFilterCodes = saasKnowledgeElementMapper.listVisibleFilterCodes(searchFilterCondition);
            if (CollUtil.isNotEmpty(visibleFilterCodes)) {
                saasKnowledgeElementInfos = saasKnowledgeElementInfos.stream().filter(e -> visibleFilterCodes.contains(e.getCode())).toList();
            }
        }
        // 对于文件名排序，在内存中进行排序
        if (sortRule == SortRules.SORT_TITLE) {
            saasKnowledgeElementInfos.sort((a, b) -> compareFileName(a.getEleName(), b.getEleName(), knowledgeElementQueryReq.getSortType()));
        }

        // 构建树形结构并保持每一级的排序
        List<KnowledgeElementResp> result = buildTreeStructureWithSort(saasKnowledgeElementInfos, knowledgeElementQueryReq);

        return Result.data(result);
    }

