    /**
     * 构建树形结构并保持每一级的排序
     */
    private List<KnowledgeElementResp> buildTreeStructureWithSort(List<SaasKnowledgeElement> elements, KnowledgeElementQueryReq queryReq) {
        if (CollectionUtil.isEmpty(elements)) {
            return new ArrayList<>();
        }

        // 转换为响应对象
        List<KnowledgeElementResp> allElements = elements.stream()
                .map(new SaasKnowledgeElementApplyFunction())
                .collect(Collectors.toList());

        // 批量填充creatorName和modifierName
        Set<String> userCodes = new HashSet<>();

        // key-code value:parentCode
        Map<String, String> elementRootMap = new HashMap<>();
        for (KnowledgeElementResp resp : allElements) {
            userCodes.addAll(resp.userCodes());
            elementRootMap.put(resp.getCode(), resp.getParentCode());
        }
        if (!userCodes.isEmpty()) {
            Map<String, String> userMap = userService.selectByCode(new ArrayList<>(userCodes));
            for (KnowledgeElementResp resp : allElements) {
                resp.applyUserName(userMap);
            }
        }
        log.info("批量填充creatorName和modifierName{}", allElements);
        // 创建映射：parentCode -> 子元素列表
        Map<String, List<KnowledgeElementResp>> parentChildMap = new HashMap<>();
        Map<String, KnowledgeElementResp> rootMap = new LinkedHashMap<>();

        for (KnowledgeElementResp element : allElements) {
            String parentCode = StrUtil.isBlank(element.getParentCode()) ? "0" : element.getParentCode();
            parentChildMap.computeIfAbsent(parentCode, k -> new ArrayList<>()).add(element);
            if (!elementRootMap.containsKey(element.getParentCode())) {
                rootMap.put(element.getCode(), element);
                //parentChildMap.computeIfAbsent(element.getCode(), k -> new ArrayList<>()).add(element);
            }
        }

        // 对每一级的子元素进行排序
        SortRules sortRule = SortRules.parse(queryReq.getSortRule());
        for (List<KnowledgeElementResp> children : parentChildMap.values()) {
            sortElementList(children, sortRule, queryReq.getSortType());
        }

        // 递归构建树形结构
        //List<KnowledgeElementResp> rootElements = parentChildMap.getOrDefault("0", new ArrayList<>());

        List<KnowledgeElementResp> rootElements = new ArrayList<>(rootMap.values());
        sortElementList(rootElements, sortRule, queryReq.getSortType());
        for (KnowledgeElementResp element : rootElements) {
            buildChildren(element, parentChildMap);
        }

        return rootElements;
    }

    /**
     * 递归构建子元素
     */
    private void buildChildren(KnowledgeElementResp parent, Map<String, List<KnowledgeElementResp>> parentChildMap) {
        List<KnowledgeElementResp> children = parentChildMap.get(parent.getCode());
        if (CollectionUtil.isNotEmpty(children)) {
            parent.setChildrens(children);
            for (KnowledgeElementResp child : children) {
                buildChildren(child, parentChildMap);
            }
        }
    }

    /**
     * 对元素列表进行排序
     */
    private void sortElementList(List<KnowledgeElementResp> elements, SortRules sortRule, Integer sortType) {
        if (CollectionUtil.isEmpty(elements)) {
            return;
        }

        switch (sortRule) {
            case SORT_NUMBER:
                elements.sort(Comparator.comparing(KnowledgeElementResp::getSort, Comparator.nullsLast(Comparator.naturalOrder())));
                break;
            case SORT_CREATE_TIME:
                if (sortType == 0) {
                    elements.sort(Comparator.comparing(KnowledgeElementResp::getCreateTime, Comparator.nullsLast(Comparator.naturalOrder())));
                } else {
                    elements.sort(Comparator.comparing(KnowledgeElementResp::getCreateTime, Comparator.nullsLast(Comparator.reverseOrder())));
                }
                break;
            case SORT_MODIFY_TIME:
                if (sortType == 0) {
                    elements.sort(Comparator.comparing(KnowledgeElementResp::getModifierTime, Comparator.nullsLast(Comparator.naturalOrder())));
                } else {
                    elements.sort(Comparator.comparing(KnowledgeElementResp::getModifierTime, Comparator.nullsLast(Comparator.reverseOrder())));
                }
                break;
            case SORT_TITLE:
                elements.sort((a, b) -> compareFileName(a.getEleName(), b.getEleName(), sortType));
                break;
            default:
                // 默认按排序号排序
                elements.sort(Comparator.comparing(KnowledgeElementResp::getSort, Comparator.nullsLast(Comparator.naturalOrder())));
                break;
        }
    }

