    public ExcelImportResultResp importData(String tableCode, MultipartFile file, List<BusinessColumn> columns) {
        // 直接使用传入的列定义，跳过 business_table / business_column 查询
        // 适用于建表确认编排场景（元数据在同一事务中尚未提交，不可查询）
        SysUserInfo currentUser = UserContextHolder.getCurrentUser();
        String tenantId = currentUser.getTenantId();
        String physicalName = excelDynamicTableService.resolvePhysicalTableName(tenantId, tableCode);

        // 创建导入任务记录
        ExcelImportTask task = new ExcelImportTask();
        task.setTenantId(tenantId);
        task.setCode(IdUtil.getSnowflakeNextIdStr());
        task.setTableCode(tableCode);
        task.setFileName(file.getOriginalFilename());
        task.setOssKey("");
        task.setImportMode(ExcelImportMode.OVERWRITE.getCode());
        task.setStatus(ExcelImportStatus.PROCESSING.getCode());
        task.setTotalRows(0);
        task.setSuccessRows(0);
        task.setFailRows(0);
        task.setSort(0);
        task.setCreator(currentUser.getCode());
        task.setCreateTime(LocalDateTime.now());
        task.setModifier(currentUser.getCode());
        task.setModifierTime(LocalDateTime.now());
        excelImportTaskMapper.insert(task);

        // 覆盖模式清空表数据（DELETE 是 DML，不会隐式提交）
        jdbcTemplate.execute("DELETE FROM `" + physicalName + "`");

        List<ExcelImportResultResp.FailRowDetail> failDetails = new ArrayList<>();
        int totalRows = 0;
        int successRows = 0;

        try {
            String originalFilename = file.getOriginalFilename() == null ? "" : file.getOriginalFilename().toLowerCase();
            try (Workbook workbook = openWorkbook(file, originalFilename)) {
                Sheet sheet = workbook.getSheetAt(0);
                Row headerRow = sheet.getRow(0);
                Assert.notNull(headerRow, "Excel表头行为空");

                Map<String, Integer> headerIndexMap = new LinkedHashMap<>();
                for (int c = 0; c < headerRow.getLastCellNum(); c++) {
                    Cell cell = headerRow.getCell(c);
                    if (cell != null) {
                        String colName = DATA_FORMATTER.formatCellValue(cell).trim();
                        if (!colName.isEmpty()) {
                            headerIndexMap.put(colName, c);
                        }
                    }
                }

                // 校验表头
                List<String> missingCols = columns.stream()
                        .map(BusinessColumn::getName)
                        .filter(name -> !headerIndexMap.containsKey(name))
                        .toList();
                if (!missingCols.isEmpty()) {
                    throw new IllegalArgumentException(
                            "Excel表头与表结构不匹配，缺失列: " + String.join(", ", missingCols));
                }

                List<String> colNames = columns.stream().map(BusinessColumn::getName).toList();
                String insertSql = buildInsertSql(physicalName, colNames, ExcelImportMode.OVERWRITE);

                int lastRowNum = sheet.getLastRowNum();
                List<Object[]> batchArgs = new ArrayList<>();
                for (int r = 1; r <= lastRowNum; r++) {
                    Row row = sheet.getRow(r);
                    if (row == null) continue;
                    totalRows++;
                    try {
                        Object[] args = buildRowArgs(row, columns, headerIndexMap, tenantId);
                        batchArgs.add(args);
                        if (batchArgs.size() >= BATCH_SIZE) {
                            jdbcTemplate.batchUpdate(insertSql, batchArgs);
                            successRows += batchArgs.size();
                            batchArgs.clear();
                        }
                    } catch (Exception e) {
                        ExcelImportResultResp.FailRowDetail detail = new ExcelImportResultResp.FailRowDetail();
                        detail.setRowIndex(r + 1);
                        detail.setReason(e.getMessage());
                        failDetails.add(detail);
                        log.warn("第{}行数据校验失败: {}", r + 1, e.getMessage());
                    }
                }
                if (!batchArgs.isEmpty()) {
                    jdbcTemplate.batchUpdate(insertSql, batchArgs);
                    successRows += batchArgs.size();
                }
            }

            String finalStatus = failDetails.isEmpty()
                    ? ExcelImportStatus.SUCCESS.getCode()
                    : (successRows > 0 ? ExcelImportStatus.PARTIAL_FAIL.getCode() : ExcelImportStatus.FAIL.getCode());
            updateTask(task.getId(), finalStatus, totalRows, successRows, failDetails);
            log.info("Excel导入完成(编排模式), tableCode:{}, total:{}, success:{}, fail:{}", tableCode, totalRows, successRows, failDetails.size());
        } catch (Exception e) {
            log.error("Excel导入异常(编排模式), tableCode:{}", tableCode, e);
            updateTask(task.getId(), ExcelImportStatus.FAIL.getCode(), totalRows, successRows, failDetails);
            throw new RuntimeException("Excel导入失败: " + e.getMessage(), e);
        }

        ExcelImportResultResp resp = new ExcelImportResultResp();
        resp.setTaskCode(task.getCode());
        resp.setStatus(failDetails.isEmpty() ? ExcelImportStatus.SUCCESS.getCode()
                : (successRows > 0 ? ExcelImportStatus.PARTIAL_FAIL.getCode() : ExcelImportStatus.FAIL.getCode()));
        resp.setTotalRows(totalRows);
        resp.setSuccessRows(successRows);
        resp.setFailRows(failDetails.size());
        resp.setFailDetails(failDetails);
        return resp;
    }

