public String createTableAndImport(ExcelSchemaConfirmReq req, MultipartFile file) {
        String tenantId = UserContextHolder.getTenantId();
        SysUserInfo currentUser = UserContextHolder.getCurrentUser();

        // 1. 建表 DDL（隐式提交，无法回滚，只创建物理表）
        String tableCode = excelDynamicTableService.createTable(req);
        String physicalName = excelDynamicTableService.resolvePhysicalTableName(tenantId, tableCode);

        // 构建列定义（从 req 转为 BusinessColumn，供 importData 直接使用）
        List<BusinessColumn> columns = buildBusinessColumns(req.getColumns(), tenantId, tableCode);

        try {
            // 以下所有 DML 操作在同一事务中，任一失败则全部回滚
            doImportAndPublish(req, file, tableCode, physicalName, columns, tenantId, currentUser);
        } catch (Exception e) {
            // DDL 隐式提交不受事务回滚影响，直接 DROP 物理表确保清理
            // DML（business_table / business_column / import_task / 数据行）由 @Transactional 自动回滚
            log.error("建表导入流程失败，清理物理表, tableCode:{}", tableCode, e);
            try {
                jdbcTemplate.execute("DROP TABLE IF EXISTS `" + physicalName + "`");
            } catch (Exception dropEx) {
                log.error("DROP TABLE 失败, physicalName:{}", physicalName, dropEx);
            }
            throw e;
        }

        return tableCode;
    }

    /**
     * 在同一事务中完成：元数据写入 → 数据导入 → 发布。
     * 任一步骤失败，@Transactional 自动回滚所有 DML。
     */
    @Transactional(rollbackFor = Exception.class)
    void doImportAndPublish(ExcelSchemaConfirmReq req, MultipartFile file,
                            String tableCode, String physicalName,
                            List<BusinessColumn> columns, String tenantId, SysUserInfo currentUser) {
        // 1. 写入 business_table / business_column 元数据
        String belongDs = resolveBelongDs(req.getContainerId());
        excelDynamicTableService.insertTableMetadata(
                tenantId, tableCode, physicalName, belongDs,
                req.getContainerId(), req.getTableName(), req.getTableDescription(),
                req.getColumns(), currentUser);

        // 2. 导入数据（直接传入列定义，跳过 DB 查询）
        ExcelImportResultResp importResult = excelImportService.importData(tableCode, file, columns);
        log.info("数据导入完成, tableCode:{}, success:{}, fail:{}", tableCode, importResult.getSuccessRows(), importResult.getFailRows());

        // 3. 发布到知识元素
        BusinessTable businessTable = businessTableMapper.selectOne(
                Wrappers.lambdaQuery(BusinessTable.class)
                        .eq(BusinessTable::getCode, tableCode)
                        .eq(BusinessTable::getTenantId, tenantId), false);
        Assert.notNull(businessTable, "表不存在或无权限");

        BusinessTableIssueReq issueReq = new BusinessTableIssueReq();
        issueReq.setId(businessTable.getId());
        Result<String> issueResult = businessTableService.issue(issueReq);
        log.info("自动发布完成, tableCode:{}, result:{}", tableCode, issueResult.getMessage());
    }

    private String resolveBelongDs(String containerId) {
        com.torchv.repository.chat.entity.SaasKnowledgeContainer container =
                com.baomidou.mybatisplus.core.toolkit.Wrappers.lambdaQuery(
                        com.torchv.repository.chat.entity.SaasKnowledgeContainer.class)
                        .eq(com.torchv.repository.chat.entity.SaasKnowledgeContainer::getCode, containerId)
                        .one();
        Assert.notNull(container, "知识库容器不存在");
        return container.getCode();
    }

    private List<BusinessColumn> buildBusinessColumns(List<ExcelColumnDefReq> reqColumns, String tenantId, String tableCode) {
        return reqColumns.stream().map(reqCol -> {
            BusinessColumn col = new BusinessColumn();
            col.setTenantId(tenantId);
            col.setBelongTable(tableCode);
            col.setName(reqCol.getName());
            col.setDataType(reqCol.getDataType());
            col.setDataLength(reqCol.getDataLength());
            col.setDescription(reqCol.getDescription());
            return col;
        }).toList()

