/**
 * 从知识库配置中解析外部解析引擎配置。
 * 优先级：文件级别 > 知识库级别。
 */
public Optional<UniversalDocumentParseConfig> resolveParseConfig(String elementCode, String containerId, String tenantId) {
    return documentParseConfigQueryService.resolve(elementCode, containerId, tenantId);
}

/**
 * 校验文件类型是否在解析引擎支持的文档格式列表中。
 * "image" 在列表中代表所有图片类型。
 */
public boolean isFileTypeSupported(String format, UniversalDocumentParseConfig parseConfig) {
    if (StrUtil.isBlank(format) || parseConfig == null || StrUtil.isBlank(parseConfig.getLayoutDocumentFormats())) {
        return false;
    }
    String lowerFormat = format.toLowerCase();
    String[] supportedFormats = parseConfig.getLayoutDocumentFormats().toLowerCase().split(",");
    for (String supported : supportedFormats) {
        supported = supported.trim();
        if ("image".equalsIgnoreCase(supported) && IMAGE_EXTENSIONS.contains(lowerFormat)) {
            return true;
        }
        if (supported.equalsIgnoreCase(lowerFormat)) {
            return true;
        }
    }
    return false;
}

// ==================== 限流检查 ====================

/**
 * 检查指定文件/知识库的外部解析引擎是否允许提交。
 * 先查询配置，再做QPS检查。无外部引擎配置时直接放行。
 *
 * @return true=允许提交，false=限流中，应跳过等待下一轮
 */
public boolean checkSubmitPermit(String elementCode, String containerId, String tenantId) {
    Optional<UniversalDocumentParseConfig> configOpt = resolveParseConfig(elementCode, containerId, tenantId);
    if (configOpt.isEmpty()) {
        return true;
    }
    return tryAcquireSubmitPermit(configOpt.get());
}

/**
 * 非阻塞检查当前解析引擎的提交QPS是否允许。
 * 用于Job提交MQ前的源头限流，与消费端的限流共用同一份Redis令牌桶。
 *
 * @param parseConfig 解析引擎配置
 * @return true=允许提交，false=限流中，应跳过等待下一轮
 */
public boolean tryAcquireSubmitPermit(UniversalDocumentParseConfig parseConfig) {
    if (parseConfig == null) {
        return true;
    }
    String engineType = parseConfig.getEngineType();
    DocumentParseProviders provider = DocumentParseProviders.of(engineType);
    Optional<ExternalParseEngineHandler> handlerOpt = engineRegistry.getHandler(provider);
    if (handlerOpt.isEmpty()) {
        return true;
    }
    String rateLimiterKey = handlerOpt.get().buildRateLimiterKey(parseConfig);
    if (rateLimiterKey == null) {
        return true;
    }
    int qps = (parseConfig.getSubmitQps() != null && parseConfig.getSubmitQps() > 0) ? parseConfig.getSubmitQps() : 2;
    com.torchv.unstructured.engine.rate.SubmitRateLimiter limiter = createSubmitRateLimiter(rateLimiterKey, qps);
    return limiter.tryAcquire(100, TimeUnit.MILLISECONDS);
}

// ==================== 外部解析任务 taskId 管理（用于异常恢复） ====================

private static final String TASK_KEY_PREFIX = "doc_parse:external_task:";
private static final long TASK_TTL_SECONDS = 7200; // 2小时
private static final String HEARTBEAT_FIELD = "heartbeat";
private static final long HEARTBEAT_EXPIRE_MILLIS = 120_000; // 心跳超过2分钟未更新，认为进程已死亡

/**
 * 保存外部解析任务的taskId到Redis，用于异常恢复。
 */
public void saveExternalTaskId(Integer elementId, String taskId, String engineType, String elementCode, String containerId, String tenantId) {
    String key = TASK_KEY_PREFIX + elementId;
    try {
        stringRedisTemplate.opsForHash().put(key, "taskId", taskId);
        stringRedisTemplate.opsForHash().put(key, "engineType", engineType);
        stringRedisTemplate.opsForHash().put(key, "elementCode", elementCode);
        stringRedisTemplate.opsForHash().put(key, "containerId", containerId);
        stringRedisTemplate.opsForHash().put(key, "tenantId", tenantId);
        stringRedisTemplate.opsForHash().put(key, HEARTBEAT_FIELD, String.valueOf(System.currentTimeMillis()));
        stringRedisTemplate.expire(key, TASK_TTL_SECONDS, TimeUnit.SECONDS);
        log.info("保存外部解析任务taskId, elementId={}, taskId={}, engineType={}", elementId, taskId, engineType);
    } catch (Exception e) {
        log.warn("保存外部解析任务taskId失败, elementId={}: {}", elementId, e.getMessage());
    }
}

/**
 * 更新轮询心跳时间戳（每次轮询查询时调用）。
 * 恢复Job通过检查心跳是否过期来判断轮询进程是否存活。
 */
public void updateHeartbeat(Integer elementId) {
    String key = TASK_KEY_PREFIX + elementId;
    try {
        stringRedisTemplate.opsForHash().put(key, HEARTBEAT_FIELD, String.valueOf(System.currentTimeMillis()));
    } catch (Exception e) {
        log.warn("更新外部解析任务心跳失败, elementId={}: {}", elementId, e.getMessage());
    }
}

/**
 * 检查心跳是否已过期（轮询进程是否已死亡）。
 * @return true=心跳过期，进程可能已死亡，可安全恢复；false=心跳正常，进程仍在轮询
 */
public boolean isHeartbeatExpired(Integer elementId) {
    String key = TASK_KEY_PREFIX + elementId;
    try {
        Object heartbeatObj = stringRedisTemplate.opsForHash().get(key, HEARTBEAT_FIELD);
        if (heartbeatObj == null) {
            return true;
        }
        long lastHeartbeat = Long.parseLong(heartbeatObj.toString());
        boolean expired = (System.currentTimeMillis() - lastHeartbeat) > HEARTBEAT_EXPIRE_MILLIS;
        if (expired) {
            log.info("外部解析任务心跳已过期, elementId={}, lastHeartbeat={}ms ago", elementId,
                    System.currentTimeMillis() - lastHeartbeat);
        }
        return expired;
    } catch (Exception e) {
        log.warn("检查外部解析任务心跳失败, elementId={}: {}", elementId, e.getMessage());
        return true;
    }
}

/**
 * 获取已保存的外部解析任务taskId。
 */
public String getExternalTaskId(Integer elementId) {
    String key = TASK_KEY_PREFIX + elementId;
    try {
        Object taskId = stringRedisTemplate.opsForHash().get(key, "taskId");
        return taskId != null ? taskId.toString() : null;
    } catch (Exception e) {
        log.warn("获取外部解析任务taskId失败, elementId={}: {}", elementId, e.getMessage());
        return null;
    }
}

/**
 * 获取已保存的外部解析任务的引擎类型。
 */
public String getExternalTaskEngineType(Integer elementId) {
    String key = TASK_KEY_PREFIX + elementId;
    try {
        Object engineType = stringRedisTemplate.opsForHash().get(key, "engineType");
        return engineType != null ? engineType.toString() : null;
    } catch (Exception e) {
        return null;
    }
}

/**
 * 删除已保存的外部解析任务记录（解析完成或失败后清理）。
 */
public void removeExternalTask(Integer elementId) {
    String key = TASK_KEY_PREFIX + elementId;
    try {
        stringRedisTemplate.delete(key);
        log.info("删除外部解析任务记录, elementId={}", elementId);
    } catch (Exception e) {
        log.warn("删除外部解析任务记录失败, elementId={}: {}", elementId, e.getMessage());
    }
}

// ==================== 核心解析流程（委托给引擎处理器） ====================

/**
 * 使用外部解析引擎解析文件。
 * 统一的异步提交 + 轮询 + 结果处理流程。
 * 任何异常/超时都返回失败结果，由调用方决定是否回退到默认引擎。
 *
 * @param file              待解析的文件
 * @param parseConfig       解析引擎配置
 * @param imageUploadHandler 图片上传处理器（MinerU ZIP 模式使用）
 * @param elementId         文件元素ID（用于保存taskId到Redis，支持异常恢复）
 * @return 解析结果
 */
public ExternalParseResult parseWithExternalEngine(File file, UniversalDocumentParseConfig parseConfig,
                                                    Function<File, String> imageUploadHandler, Integer elementId) {
    DocumentParseProviders provider = DocumentParseProviders.of(parseConfig.getEngineType());
    log.info("使用外部解析引擎解析文件, engineType={}, provider={}, file={}", parseConfig.getEngineType(), provider, file.getName());

    Optional<ExternalParseEngineHandler> handlerOpt = engineRegistry.getHandler(provider);
    if (handlerOpt.isEmpty()) {
        log.warn("不支持的解析引擎类型: {}, 回退到默认引擎", parseConfig.getEngineType());
        return ExternalParseResult.failure("不支持的解析引擎类型: " + parseConfig.getEngineType());
    }

    try {
        ExternalParseEngineHandler handler = handlerOpt.get();
        TaskPollHandler pollHandler = buildHeartbeatPollHandler(elementId);

        // taskId保存回调：在阻塞等待之前保存到Redis，确保崩溃后可恢复
        java.util.function.Consumer<String> taskIdSaveCallback = taskId -> {
            if (elementId != null) {
                saveExternalTaskId(elementId, taskId, parseConfig.getEngineType(), null, null, null);
            }
        };

        ExternalParseResult result = handler.parseAndSubmit(file, parseConfig, imageUploadHandler, pollHandler, taskIdSaveCallback);

        // 解析完成后清理Redis任务记录
        if (elementId != null && result.isSuccess()) {
            removeExternalTask(elementId);
        }
        return result;
    } catch (Exception e) {
        log.error("外部解析引擎调用异常, engineType={}, file={}", parseConfig.getEngineType(), file.getName(), e);
        return ExternalParseResult.failure("外部解析引擎调用异常: " + e.getMessage());
    }
}

/**
 * 使用已有的taskId阻塞等待外部解析引擎结果（轮询直到完成或超时）。
 * 用于恢复场景：Redis中有taskId，不需要重新提交，直接轮询等待结果。
 */
public ExternalParseResult waitForExternalParseResult(String taskId, UniversalDocumentParseConfig parseConfig,
                                                       Function<File, String> imageUploadHandler, String originalFileName,
                                                       Integer elementId) {
    DocumentParseProviders provider = DocumentParseProviders.of(parseConfig.getEngineType());
    log.info("使用已有taskId等待外部引擎结果, taskId={}, provider={}", taskId, provider);

    Optional<ExternalParseEngineHandler> handlerOpt = engineRegistry.getHandler(provider);
    if (handlerOpt.isEmpty()) {
        return ExternalParseResult.failure("不支持的解析引擎类型: " + parseConfig.getEngineType());
    }

    try {
        TaskPollHandler pollHandler = buildHeartbeatPollHandler(elementId);
        ExternalParseResult result = handlerOpt.get().waitForResult(taskId, parseConfig, imageUploadHandler, originalFileName, pollHandler);

        if (elementId != null && result.isSuccess()) {
            removeExternalTask(elementId);
        }
        return result;
    } catch (Exception e) {
        log.error("等待外部解析引擎结果异常, taskId={}, engineType={}: {}", taskId, parseConfig.getEngineType(), e.getMessage(), e);
        return ExternalParseResult.failure("等待外部解析引擎结果异常");
    }
}

/**
 * 根据已保存的taskId查询外部解析引擎的结果（单次查询，不阻塞轮询）。
 * 用于异常恢复Job场景：快速检查任务是否已完成。
 */
public ExternalParseResult queryExternalParseResult(String taskId, UniversalDocumentParseConfig parseConfig,
                                                     Function<File, String> imageUploadHandler, String originalFileName) {
    DocumentParseProviders provider = DocumentParseProviders.of(parseConfig.getEngineType());

    Optional<ExternalParseEngineHandler> handlerOpt = engineRegistry.getHandler(provider);
    if (handlerOpt.isEmpty()) {
        return null;
    }

    try {
        return handlerOpt.get().queryResult(taskId, parseConfig, originalFileName);
    } catch (Exception e) {
        log.error("查询外部解析引擎结果异常, taskId={}, engineType={}: {}", taskId, parseConfig.getEngineType(), e.getMessage(), e);
        return null;
    }
}

// ==================== 内部方法 ====================

/**
 * 构建带心跳更新的轮询回调。
 * 每次轮询时更新Redis中的心跳时间戳，用于恢复Job判断进程是否存活。
 */
private TaskPollHandler buildHeartbeatPollHandler(Integer elementId) {
    return (tid, status) -> {
        if (elementId != null) {
            updateHeartbeat(elementId);
        }
    };
}

private com.torchv.unstructured.engine.rate.SubmitRateLimiter createSubmitRateLimiter(String key, int qps) {
    try {
        return new RedisSubmitRateLimiter(stringRedisTemplate, "doc_parse:rate_limit:" + key, qps);
    } catch (Exception e) {
        log.warn("创建 Redis 限流器失败, 回退到进程内限流: {}", e.getMessage());
        return new com.torchv.unstructured.engine.rate.InMemorySubmitRateLimiter(qps);
    }
}

幂等性检查：如果文件已处理到终态，跳过重复消费，避免重复切片embedding入库
        Optional<SaasKnowledgeElement> elementOpt = knowledgeElementService.queryInfoById(convertReq.getDataId());
        if (elementOpt.isPresent()) {
            Integer status = elementOpt.get().getProcessStatus();
            if (status != null && (status == ProcessStatusEnum.SUCCESS.getCode()
                    || status == ProcessStatusEnum.EMBEDDED.getCode()
                    || status == ProcessStatusEnum.EMBEDDING.getCode())) {
                log.info("文件已完成处理，跳过重复消费, elementId={}, status={}", convertReq.getDataId(), status);
                return true;
            }
        }
        //

（全局条件，需停止整批）
        if (!fileParsingConcurrencyGuard.isHeapHealthy()) {
            log.info("堆内存使用率过高，暂停提交文件转换任务 elementId={}", knowledgeElement.getId());
            return false;
        }

        // 闸门2：文件大小检查，超大文件直接标记为不支持，避免消费端OOM
        if (!fileParsingConcurrencyGuard.isFileSizeAllowed(knowledgeElement.getEleSize())) {
            log.info("文件大小超过限制，标记为UN_ISSUE elementId={}, size={}",
                    knowledgeElement.getId(), knowledgeElement.getEleSize());
            knowledgeElementService.updateElementStatus(knowledgeElement, ProcessStatusEnum.UN_ISSUE);
            return true;
        }

        // 闸门3：外部解析引擎QPS检查（引擎粒度限流，仅跳过当前文件，不影响其他文件）
        if (!documentParseEngineService.checkSubmitPermit(knowledgeElement.getCode(), knowledgeElement.getContainerId(), knowledgeElement.getTenantId())) {
            log.info("外部解析引擎QPS限流，跳过本次提交 elementId={}", knowledgeElement.getId());
            return true;
        }

        MessageFileConvertReq convertReq = MessageFileConvertReq.of(knowledgeElement);
        EmbeddingQueueCapacityAcquireResult acquireResult =
                embeddingQueueCapacityGuardService.tryAcquire(knowledgeElement.getId(), knowledgeElement.getEleSize());
        if (acquireResult == EmbeddingQueueCapacityAcquireResult.LIMIT_EXCEEDED) {
            return false;
        }
        if (acquireResult == EmbeddingQueueCapacityAcquireResult.ALREADY_RESERVED) {
            return true;
        }
        if (acquireResult == EmbeddingQueueCapacityAcquireResult.SKIPPED) {
            log.warn("文件向量化容量保护跳过（配置关闭/参数异常/Redis降级），继续提交 elementId={}, fileSize={}",
                    knowledgeElement.getId(), knowledgeElement.getEleSize());
        }
        boolean acquired = acquireResult == EmbeddingQueueCapacityAcquireResult.ACQUIRED;
        if (rabbitMessageService.sendConvertMsg(convertReq)) {
            knowledgeElementService.updateElementStatus(knowledgeElement, ProcessStatusEnum.CONVERT);
            return true;
        }
        log.warn("MQ消息发送失败，elementId={}，将在下一轮Job重试", knowledgeElement.getId());
        if (acquired) {
            embeddingQueueCapacityGuardService.release(knowledgeElement.getId());
        }
        return true;
    }

    @Override
    public void submitLargeFileAsyncQWen(SaasKnowledgeElement knowledgeElement) {
        // 查询chunkCount的数量，是否都已经处理完成了
        List<SaasTaskEmbedding> taskEmbeddings =
                taskEmbeddingService.listTask(knowledgeElement.getTenantId(), knowledgeElement.getContainerId(), knowledgeElement.getCode(), TaskEmbeddingStatus.SUCCEEDED);
        if (CollUtil.size(taskEmbeddings) == knowledgeElement.getChunkCount()) {
            // 如果chunk大小和embedding都成功了，那么可以开始处理了
            knowledgeElementService.updateStatus(knowledgeElement.getId(), ProcessStatusEnum.EMBEDDED);
            // 发送MQ消息，开始做入库的动作，不用MQ，会阻塞
            MessageEmbeddingReq embeddingReq = new MessageEmbeddingReq();
            embeddingReq.setChunkCount(knowledgeElement.getChunkCount());
            embeddingReq.setDataId(knowledgeElement.getCode());
            embeddingReq.setContainerId(knowledgeElement.getContainerId());
            embeddingReq.setPkId(knowledgeElement.getId());
            embeddingReq.setTenantId(knowledgeElement.getTenantId());
            rabbitMessageService.sendEmbeddingMsg(embeddingReq);
        }
    }

    @Override
    public void recoverStuckConvertFiles() {
        // 恢复卡在 CONVERT 状态超过 10 分钟的文件（可能是程序异常退出导致外部引擎解析结果未被消费）
        // 每次Job只处理一批（不使用while循环），避免超出SchedulerLock的lockAtMostFor导致并发执行
        LocalDateTime threshold = LocalDateTime.now().minusMinutes(10);
        int size = 1000;
        Pagination<SaasKnowledgeElement> pagination = knowledgeElementService.listStuckFiles(1, size, ProcessStatusEnum.CONVERT, threshold);
        if (pagination == null || CollUtil.isEmpty(pagination.getData())) {
            return;
        }
        log.info("恢复CONVERT文件: 本轮处理{}个文件", pagination.getData().size());
        for (SaasKnowledgeElement element : pagination.getData()) {
            recoverSingleConvertFile(element);
        }
    }

    private void recoverSingleConvertFile(SaasKnowledgeElement element) {
        Integer elementId = element.getId();
        String taskId = documentParseEngineService.getExternalTaskId(elementId);
        if (StrUtil.isBlank(taskId)) {
            // 没有保存taskId（可能是taskId已过期或旧代码提交的），重置为INIT重新提交
            log.info("恢复CONVERT文件: 无taskId记录，重置为INIT, elementId={}", elementId);
            embeddingQueueCapacityGuardService.release(elementId);
            knowledgeElementService.updateElementStatus(element, ProcessStatusEnum.INIT);
            return;
        }

        // 检查心跳：如果心跳未过期，说明有进程仍在轮询，跳过恢复避免重复提交
        if (!documentParseEngineService.isHeartbeatExpired(elementId)) {
            log.debug("恢复CONVERT文件: 心跳正常，有进程在轮询，跳过, elementId={}, taskId={}", elementId, taskId);
            return;
        }

        // 心跳已过期（进程可能已死亡），尝试查询外部引擎结果
        log.info("恢复CONVERT文件: 心跳已过期，查询外部引擎结果, elementId={}, taskId={}", elementId, taskId);
        try {
            Optional<UniversalDocumentParseConfig> configOpt = documentParseEngineService.resolveParseConfig(
                    element.getCode(), element.getContainerId(), element.getTenantId());
            if (configOpt.isEmpty()) {
                // 配置已变更或删除，清理taskId并重置
                log.info("恢复CONVERT文件: 解析引擎配置已变更，重置为INIT, elementId={}", elementId);
                documentParseEngineService.removeExternalTask(elementId);
                embeddingQueueCapacityGuardService.release(elementId);
                knowledgeElementService.updateElementStatus(element, ProcessStatusEnum.INIT);
                return;
            }

            ExternalParseResult result = documentParseEngineService.queryExternalParseResult(
                    taskId, configOpt.get(), null, element.getEleName());
            if (result != null && result.isSuccess()) {
                // 外部引擎已解析完成，清理taskId，重置为INIT让正常流程处理后续embedding
                log.info("恢复CONVERT文件: 外部引擎已有结果，重置为INIT, elementId={}", elementId);
                documentParseEngineService.removeExternalTask(elementId);
                embeddingQueueCapacityGuardService.release(elementId);
                knowledgeElementService.updateElementStatus(element, ProcessStatusEnum.INIT);
            } else if (result != null && !result.isSuccess()) {
                // 外部引擎任务失败，清理taskId，重置为INIT重新提交
                log.info("恢复CONVERT文件: 外部引擎任务失败，重置为INIT, elementId={}, error={}", elementId, result.getErrorMessage());
                documentParseEngineService.removeExternalTask(elementId);
                embeddingQueueCapacityGuardService.release

