带文档概览上下文的批量摘要生成
     * 参考Anthropic Contextual Embeddings方案，提供文档全局上下文以提升摘要质量
     *
     * @param tenantId 租户ID
     * @param chunks 批量切片信息
     * @param documentOverview 文档概览（前2000字）
     * @param modelCode 模型编码
     * @param elementCode 文档编码
     * @param temperature 温度参数
     * @param topP 核采样参数
     * @return 批量摘要生成响应
     */
    @SummaryCall
    public SummaryGenerationResponse generateBatchSummaryWithContext(
            String tenantId, List<ChunkInfo> chunks, String documentOverview,
            String modelCode, String elementCode, Float temperature, Float topP) {
        try {
            if (chunks == null || chunks.isEmpty()) {
                return SummaryGenerationResponse.failed("切片列表不能为空");
            }

            if (chunks.size() > 10) {
                log.warn("批量处理切片数量过多，已截断：{} -> {}", chunks.size(), 10);
                chunks = chunks.subList(0, 10);
            }

            SaasKnowledgeSummaryConfig summaryConfig = knowledgeElementDetailService.getSummaryConfig(elementCode, null, tenantId);

            // 使用带上下文的提示词构建器
            BatchSummaryGenerationPromptBuilder promptBuilder = new BatchSummaryGenerationPromptBuilder();
            String prompt = promptBuilder.buildBatchPromptWithContext(chunks, documentOverview, summaryConfig.getPrompt());

            // 获取模型配置
            Optional<ModelSetting> modelSettingOptional = modelProviderService.load(modelCode, tenantId);
            if (modelSettingOptional.isEmpty()) {
                return SummaryGenerationResponse.failed("未找到可用的模型配置");
            }

            // 获取LLM供应商
            LLMSupplier llmSupplier = applicationContext.getBean(modelSettingOptional.get().supplierClazz());
            if (!llmSupplier.available()) {
                return SummaryGenerationResponse.failed("LLM供应商不可用");
            }

            // 构建请求参数
            ChainCompletionParameter parameter = new ChainCompletionParameter();
            parameter.setModelSetting(modelSettingOptional.get());
            parameter.setTemperature(temperature != null ? temperature : 0.3f);
            parameter.setTop_p(topP != null ? topP : 0.8f);

            // 添加消息
            BotMessage userMessage = BotMessage.newMessage(BotRole.USER, prompt);
            parameter.addMessage(userMessage);

            // 同步调用LLM
            var response = llmSupplier.completion(parameter);
            if (response != null && response.getChoices() != null && !response.getChoices().isEmpty()) {
                String result = response.firstMessage();
                return parseBatchLLMResponse(result);
            } else {
                return SummaryGenerationResponse.failed("LLM调用失败");
            }

        } catch (Exception e) {
            log.error("带上下文的批量生成摘要失败: {}", e.getMessage(), e);
            return SummaryGenerationResponse.failed("带上下文的批量生成摘要失败: " + e.getMessage());
        }
    }

