    @Transactional(rollbackFor = Exception.class)
    @Override
    public Result<String> batchAdd(BusinessTableBatchAddReq batchAddReq) {
        log.info("批量新增数据表,dsId:{},size:{}", batchAddReq.getDsId(), CollUtil.size(batchAddReq.getNames()));
        SysUserInfo sysUser = UserContextHolder.getCurrentUser();
        String tenantId = sysUser.getTenantId();
        BusinessDataSource businessDataSource = businessDatasourceDynamicService.checkDataSource(batchAddReq.getDsId());
        Assert.isTrue(StrUtil.equalsIgnoreCase(businessDataSource.getTenantId(), tenantId), "system.common.request.invalid");
        List<String> tableNames = batchAddReq.getNames().stream().map(StrUtil::trim).distinct().toList();
        Assert.notEmpty(tableNames, "表名称列表不能为空");
        Map<String, DataBaseTable> tableMap = businessDatasourceDynamicService.mapTables(businessDataSource, tableNames);
        Assert.isTrue(tableMap.size() == tableNames.size(), "system.common.request.invalid");
        Map<String, List<DatabaseColumn>> columnMap = businessDatasourceDynamicService.mapColumns(businessDataSource, tableNames);
        LocalDateTime now = LocalDateTime.now();
        List<BusinessTable> businessTables = new ArrayList<>();
        List<BusinessColumn> businessColumns = new ArrayList<>();
        tableNames.forEach(tableName -> {
            DataBaseTable dataBaseTable = tableMap.get(tableName);
            Assert.notNull(dataBaseTable, "system.common.request.invalid");
            List<DatabaseColumn> columns = columnMap.get(tableName);
            Assert.notEmpty(columns, "system.common.request.invalid");
            BusinessTable table = this.buildBusinessTable(businessDataSource, batchAddReq.getContainerId(), tableName, tenantId, sysUser, dataBaseTable, now);
            businessTables.add(table);
            for (int i = 0; i < columns.size(); i++) {
                businessColumns.add(this.buildBusinessColumn(columns.get(i), table, i + 1, now));
            }
        });
        Assert.isTrue(this.saveBatch(businessTables), "新增失败");
        Assert.isTrue(businessColumnService.saveBatch(businessColumns), "新增失败");
        return Result.defaultSuccess("新增成功");
    }

