        log.info("批量删除数据表,pageSize:{}", CollectionUtil.size(ids));
        if (CollectionUtil.isEmpty(ids)) {
            return Result.error("请求数据非法");
        }
        String tenantId = UserContextHolder.getTenantId();
        LambdaQueryWrapper<BusinessTable> lambdaQueryWrapper = Wrappers.lambdaQuery(BusinessTable.class).eq(BusinessTable::getTenantId, tenantId)
                .in(BusinessTable::getId, ids).select(BusinessTable::getCode, BusinessTable::getId);
        List<BusinessTable> tables = businessTableMapper.selectList(lambdaQueryWrapper);
        Assert.isTrue(NumberUtil.equals(CollUtil.size(tables), CollUtil.size(ids)), "请求数据非法");
        int ret = businessTableMapper.deleteBatchIds(ids);
        if (ret == CollUtil.size(ids)) {
            // 删除列信息
            List<String> tableCodes = tables.stream().map(BusinessTable::getCode).toList();
            businessColumnService.deleteColumns(tenantId, tableCodes);
            // 删除知识库文件
            knowledgeElementService.deleteByCode(tenantId, tables.get(0).getContainerId(), tableCodes);
        }
        return ret > 0 ? Result.defaultSuccess("删除成功") : Result.error("删除失败");
    }

