    @Override
    public UnstructuredEmbeddingTxtResult embedding(UnstructuredEmbeddingTxtFileConvert txtFile) {
        UnstructuredEmbeddingTxtResult embeddingTxtResult = new UnstructuredEmbeddingTxtResult();
        embeddingTxtResult.setSuccess(true);

        // 获取知识库配置信息
        Optional<SaasKnowledgeConfigElement> configOptional = saasKnowledgeConfigElementService.queryByElementId(txtFile.getDataId());
        if (configOptional.isEmpty()) {
            log.warn("知识库配置不存在，dataPkId: {}", txtFile.getDataPkId());
            embeddingTxtResult.setSuccess(false);
            return embeddingTxtResult;
        }

        SaasKnowledgeConfigElement config = configOptional.get();
        // 构建元数据内容
        PageMetaDataIndexField dataIndexField=kbPageMetadataQueryService.buildMetaDataIndexField(txtFile.getElement());
        txtFile.applyMetaData(dataIndexField);
        // 设置状态为向量中
        knowledgeElementService.updateStatus(txtFile.getDataPkId(), ProcessStatusEnum.EMBEDDING);

        List<String> pageText = new ArrayList<>();
        SplitTypes splitTypes = SplitTypes.of(config.getSplitMode());

        try {
            if (splitTypes.name().equals(SplitTypes.PAGE.name()) && txtFile.isPdf() && ObjectUtil.isNotEmpty(txtFile.getPageContentList())) {
                pageText = txtFile.getPageContentList();
                int pageCount = this.embeddingByPageText(txtFile, pageText, true);
                embeddingTxtResult.setPageCount(pageCount);
                embeddingTxtResult.setSuccess(pageCount > 0);
                knowledgeElementService.updateStatus(txtFile.getDataPkId(), ProcessStatusEnum.EMBEDDED);
                return embeddingTxtResult;
            }

            long fileSize = FileUtil.size(txtFile.getTxtFile());
            int pageCount;
            if (fileSize <= STREAM_READ_THRESHOLD_BYTES) {
                String fileContent = getFromFile(txtFile);
                if (StrUtil.isBlank(fileContent)) {
                    log.warn("文件内容为空，dataPkId: {}", txtFile.getDataPkId());
                    embeddingTxtResult.setSuccess(true);
                    return embeddingTxtResult;
                }
                PieceContentCovertReq req = PieceContentCovertReq.of(config, fileContent, txtFile.isMarkdownFile());
                pageText = pieceContentService.piece(req);
                pageCount = this.embeddingByPageText(txtFile, pageText, true);
            } else {
                pageCount = this.embeddingByStreamingFile(txtFile, config);
            }
            if (pageCount == 0) {
                log.warn("分割后内容为空，dataPkId: {}", txtFile.getDataPkId());
                embeddingTxtResult.setSuccess(false);
            }
            embeddingTxtResult.setPageCount(pageCount);
        } catch (EmbeddingServiceException e) {
            log.error("Embedding服务连续失败超过阈值，标记文件为失败：dataPkId={}, 失败次数={}",
                    txtFile.getDataPkId(), e.getConsecutiveFailures(), e);
            embeddingTxtResult.setSuccess(false);
            embeddingTxtResult.setPageCount(0);
            knowledgeElementService.updateStatus(txtFile.getDataPkId(), ProcessStatusEnum.FAILURE);
        }

        knowledgeElementService.updateStatus(txtFile.getDataPkId(), ProcessStatusEnum.EMBEDDED);
        return embeddingTxtResult;
    }

    private int embeddingByPageText(UnstructuredEmbeddingTxtFileConvert txtFile, List<String> pageText, boolean updateProgress) {
        int pageCount = pageText.size();
        if (pageCount == 0) {
            return 0;
        }
        int multipleOf = CommonUtils.multipleOf(pageCount);
        int embeddingMaxLines = txtFile.getEmbeddingConfig().maxLines();
        List<UnstructuredEmbeddingChunkConvert> embeddingContents = new ArrayList<>();
        int consecutiveFailures = 0;
        boolean anySuccess = false;
        for (int i = 0; i < pageText.size(); i++) {
            int page = i + 1;
            String pageContent = pageText.get(i);
            if (updateProgress && (i % multipleOf == 0 || page == pageCount)) {
                knowledgeElementService.updateProcessCount(txtFile.getDataPkId(), page, pageCount);
                log.info("更新处理进度，dataPkId: {}, 当前页: {}/{}", txtFile.getDataPkId(), page, pageCount);
            }
            embeddingContents.add(txtFile.toChunkConvert(pageContent, page));
            if (embeddingContents.size() >= embeddingMaxLines) {
                boolean success = this.embeddingContent(txtFile, embeddingContents);
                embeddingContents.clear();
                if (success) {
                    consecutiveFailures = 0;
                    anySuccess = true;
                } else {
                    consecutiveFailures++;
                    if (consecutiveFailures >= embeddingFailureThreshold) {
                        throw new EmbeddingServiceException(consecutiveFailures);
                    }
                }
            }
        }
        if (CollUtil.isNotEmpty(embeddingContents)) {
            boolean success = this.embeddingContent(txtFile, embeddingContents);
            embeddingContents.clear();
            if (success) {
                anySuccess = true;
            } else {
                consecutiveFailures++;
                if (consecutiveFailures >= embeddingFailureThreshold) {
                    throw new EmbeddingServiceException(consecutiveFailures);
                }
            }
        }
        // 所有批次都失败了，标记为失败
        if (!anySuccess && pageCount > 0) {
            throw new EmbeddingServiceException(consecutiveFailures);
        }
        return pageCount;
    }

    private int embeddingByStreamingFile(UnstructuredEmbeddingTxtFileConvert txtFile, SaasKnowledgeConfigElement config) {
        if (txtFile == null || !FileUtil.exist(txtFile.getTxtFile())) {
            log.warn("文件不存在，file: {}", txtFile == null ? null : txtFile.getTxtFile().getAbsolutePath());
            return 0;
        }
        Charset fileCharset = CharacterUtils.detectCharset(txtFile.getTxtFile());
        log.info("流式切片读取文件,file:{},charset:{}，fileSize:{}", txtFile.getTxtFile().getAbsolutePath(), fileCharset, FileUtil.size(txtFile.getTxtFile()));
        int segmentLimit = this.resolveStreamSegmentSize(config);
        int maxSegmentLength = segmentLimit * STREAM_SEGMENT_MAX_MULTIPLE;
        int totalPageCount = 0;
        int consecutiveFailures = 0;
        boolean anySuccess = false;
        try (BufferedReader reader = FileUtil.getReader(txtFile.getTxtFile(), fileCharset)) {
            StringBuilder segmentContent = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                segmentContent.append(line).append('\n');
                if (segmentContent.length() >= segmentLimit && (StrUtil.isBlank(line) || segmentContent.length() >= maxSegmentLength)) {
                    boolean success = this.embeddingSegment(txtFile, config, segmentContent.toString(), totalPageCount);
                    segmentContent.setLength(0);
                    if (success) {
                        totalPageCount += 1;
                        anySuccess = true;
                        consecutiveFailures = 0;
                    } else {
                        consecutiveFailures++;
                        if (consecutiveFailures >= embeddingFailureThreshold) {
                            throw new EmbeddingServiceException(consecutiveFailures);
                        }
                    }
                }
            }
            if (segmentContent.length() > 0) {
                boolean success = this.embeddingSegment(txtFile, config, segmentContent.toString(), totalPageCount);
                if (success) {
                    anySuccess = true;
                }
            }
        } catch (IOException e) {
            log.error("流式读取文件失败,file:{},error:{}", txtFile.getTxtFile().getAbsolutePath(), e.getMessage(), e);
            return 0;
        }
        if (!anySuccess && totalPageCount > 0) {
            throw new EmbeddingServiceException(consecutiveFailures);
        }
        if (totalPageCount > 0) {
            knowledgeElementService.updateProcessCount(txtFile.getDataPkId(), totalPageCount, totalPageCount);
        }
        return totalPageCount;
    }

    private boolean embeddingSegment(UnstructuredEmbeddingTxtFileConvert txtFile, SaasKnowledgeConfigElement config, String segmentContent, int pageOffset) {
        if (StrUtil.isBlank(segmentContent)) {
            return false;
        }
        PieceContentCovertReq req = PieceContentCovertReq.of(config, segmentContent, txtFile.isMarkdownFile());
        List<String> segmentPageText = pieceContentService.piece(req);
        if (CollUtil.isEmpty(segmentPageText)) {
            return false;
        }
        int embeddingMaxLines = txtFile.getEmbeddingConfig().maxLines();
        List<UnstructuredEmbeddingChunkConvert> embeddingContents = new ArrayList<>();
        int localPageCount = 0;
        for (String pageContent : segmentPageText) {
            localPageCount++;
            int currentPage = pageOffset + localPageCount;
            embeddingContents.add(txtFile.toChunkConvert(pageContent, currentPage));
            if (embeddingContents.size() >= embeddingMaxLines) {
                this.embeddingContent(txtFile, embeddingContents);
                embeddingContents.clear();
            }
            if (currentPage % 20 == 0) {
                knowledgeElementService.updateProcessCount(txtFile.getDataPkId(), currentPage, currentPage);
                log.info("流式切片进度，dataPkId: {}, 当前分片: {}", txtFile.getDataPkId(), currentPage);
            }
        }
        if (CollUtil.isNotEmpty(embeddingContents)) {
            this.embeddingContent(txtFile, embeddingContents);
            embeddingContents.clear();
        }
        return localPageCount > 0;
    }

    private int resolveStreamSegmentSize(SaasKnowledgeConfigElement config) {
        int chunkSize = config.getMaxChunkSize() == null || config.getMaxChunkSize() <= 0 ? 1024 : config.getMaxChunkSize();
        int segmentSize = chunkSize * 20;
        return Math.max(segmentSize, STREAM_SEGMENT_DEFAULT_SIZE);
    }

    private String getFromFile(UnstructuredEmbeddingTxtFileConvert txtFile) {
        if (txtFile == null || !FileUtil.exist(txtFile.getTxtFile())) {
            log.warn("文件不存在，file: {}", txtFile == null ? null : txtFile.getTxtFile().getAbsolutePath());
            return null;
        }
        // 检测文本文件的字符集
        Charset fileCharset = CharacterUtils.detectCharset(txtFile.getTxtFile());
        log.info("file:{},charset:{}，fileSize:{}", txtFile.getTxtFile().getAbsolutePath(), fileCharset,FileUtil.size(txtFile.getTxtFile()));
        return FileUtil.readString(txtFile.getTxtFile(), fileCharset);
    }

    public boolean embeddingContent(UnstructuredEmbeddingTxtFileConvert txtFile,List<UnstructuredEmbeddingChunkConvert> chunkConverts) {
        if (CollUtil.isEmpty(chunkConverts)) {
            log.warn("chunkConverts is empty, nothing to do");
            return false;
        }
        List<String> chunkContents=new LinkedList<>();
        // 批量处理
        for (UnstructuredEmbeddingChunkConvert chunkConvert : chunkConverts) {
            chunkContents.add(chunkConvert.getPageContent());
        }
        UniversalEmbeddingConfig embeddingConfig=txtFile.getEmbeddingConfig();
        UniversalEmbeddingResponse embeddingResults = embeddingVectorService.universalEmbedding(embeddingConfig, chunkContents);
        if (embeddingResults==null || CollUtil.isEmpty(embeddingResults.getAllEmbeddings())) {
            log.warn("embeddingResults is empty, embedding failed,chunkContentSize:{}", chunkContents.size());
            return false;
        }
        List<DataSetChunkInfo> chunkInfos = new ArrayList<>();
        for (int i=0;i<embeddingResults.getAllEmbeddings().size();i++){
            UnstructuredEmbeddingChunkConvert chunkConvert=chunkConverts.get(i);
            String category = DataSetReferenceType.paragraph.name();
            // 批量请求embedding
            if (StrUtil.equalsIgnoreCase(chunkConvert.getCategory(), DataSetReferenceType.table.getName())) {
                category=DataSetReferenceType.table.name();
            }
            double[] vector=embeddingResults.getAllEmbeddings().get(i);
            //String question=block.get(i);
            DataSetChunkInfo chunkInfo = new DataSetChunkInfo();
            chunkInfo.setId(IdUtil.getSnowflakeNextIdStr());
            chunkInfo.setTenantId(txtFile.getTenantId());
            //chunkInfo.setCategory(DataSetChunkType.ORIGINAL.getName());
            chunkInfo.setCategory(category);
            chunkInfo.setContainerId(chunkConvert.getContainerId());
            chunkInfo.setDataId(chunkConvert.getDataId());
            chunkInfo.setPage(chunkConvert.getPage());
            chunkInfo.setParagraphId(DigestUtil.md5Hex(chunkInfo.getContainerId() + chunkInfo.getDataId() + chunkInfo.getPage()));
            chunkInfo.setContent(chunkConvert.getPageContent());
            chunkInfo.setVector(vector);
            chunkInfo.setYear(0);
            chunkInfo.setTopic("DEFAULT");
            chunkInfo.setTimeStatus(chunkConvert.getTimeExpire());
            chunkInfo.setStartTime(chunkConvert.getStartTime());
            chunkInfo.setEndTime(chunkConvert.getEndTime());
            chunkInfo.setCreateTime(LocalDateTime.now().atZone(ZoneId.systemDefault()).toInstant().toEpochMilli());
            // 设置元数据
            chunkInfo.setMetadata(txtFile.getMetadata());
            chunkInfos.add(chunkInfo);
        }
        // 存储分片信息
        vectorIndexDelegate.saveChunks(chunkInfos, txtFile.getTenantId());
        return true

