        String cachePromptValue = stringRedisTemplate.opsForValue().get(cacheId);
        if (StrUtil.isNotBlank(cachePromptValue)) {
            log.info("prompt cache.value:{}", cachePromptValue);
            Optional<PromptInfoResp> promptInfoRespOptional = GsonUtils.fromJson(cachePromptValue, PromptInfoResp.class);
            if (promptInfoRespOptional.isPresent()) {
                return promptInfoRespOptional.get();
            }
        }
        PromptInfoResp resp = this.queryPrompt(tenantId);
        if (resp != null) {
            stringRedisTemplate.opsForValue().set(cacheId, GsonUtils.GSON.toJson(resp), 1, TimeUnit.DAYS);
        }
        return resp;
    }

