    /**
     * 同步更新租户的模型配置
     * @param tenantId 租户ID
     * @param config Prompt配置
     */
    private void syncTenantModelConfig(String tenantId, PromptConfigReq config) {
        // 校验参数
        if (StrUtil.isBlank(tenantId) || config == null) {
            log.warn("同步租户模型配置失败，参数为空,tenantId:{},config:{}", tenantId, config);
            return;
        }

        // 只有当字段不为空时才更新
        String embeddingModel = config.getEmbeddingModel();
        String rankerModelName = config.getRankerModelName();

        if (StrUtil.isBlank(embeddingModel) && StrUtil.isBlank(rankerModelName)) {
            log.info("无需更新租户模型配置，embeddingModel和rankerModelName均为空");
            return;
        }

        try {
            // 构建更新条件
            LambdaQueryWrapper<SaasTenantInfo> lambdaQueryWrapper = Wrappers.lambdaQuery(SaasTenantInfo.class)
                .eq(SaasTenantInfo::getCode, tenantId);

            // 创建新的实体对象用于更新（遵循规范：禁止在查询对象上直接修改）
            SaasTenantInfo saasTenantInfo = new SaasTenantInfo();

            // 只更新非空字段
            if (StrUtil.isNotBlank(embeddingModel)) {
                saasTenantInfo.setEmbeddingModel(embeddingModel);
            }
            if (StrUtil.isNotBlank(rankerModelName)) {
                saasTenantInfo.setRerankerModel(rankerModelName);
            }

            // 设置修改时间
            saasTenantInfo.setModifiedTime(new Date());

            // 执行更新
            int updateRet = saasTenantInfoMapper.update(saasTenantInfo, lambdaQueryWrapper);

            if (updateRet > 0) {
                log.info("同步更新租户模型配置成功,tenantId:{},embeddingModel:{},rerankerModel:{}",
                    tenantId, embeddingModel, rankerModelName);
            } else {
                log.warn("同步更新租户模型配置失败，未找到租户记录,tenantId:{}", tenantId);
            }
        } catch (Exception e) {
            // 捕获异常，避免影响主流程
            log.error("同步更新租户模型配置异常,tenantId:{},embeddingModel:{},rerankerModel:{}",
                tenantId, embeddingModel, rankerModelName, e);
