    @Override
    public Pagination<KnowledgeElementDetailResp> listParagraphByContainerId(KnowledgeElementDetailQueryReq queryReq,
            Integer page, Integer size) {
        List<KnowledgeElementDetailResp> details = new LinkedList<>();
        // 根据容器id、数据id查询所有的段落列表
        String tenantId = UserContextHolder.getTenantId();
        long total = 0L;
        try {
            UniversalEmbeddingConfig embeddingConfig=knowledgeElementEmbeddingQueryService.getEmbeddingConfig(queryReq.getCode());
            if (embeddingConfig==null){
                return Pagination.empty(page,size);
            }
            Pagination<DataSetChunkInfo> dataSetReferencePagination = vectorIndexDelegate
                    .getChunkPage(queryReq.toChunkSearch(tenantId,embeddingConfig.getVectorDimension()), page, size);
            if (dataSetReferencePagination != null) {
                total = dataSetReferencePagination.getTotal();
                for (DataSetChunkInfo chunkInfo : dataSetReferencePagination.getData()) {
                    details.add(KnowledgeElementDetailResp.from(chunkInfo));
                }
            }
        } catch (Exception e) {
            // 有可能数据还未导入，捕获该异常
            log.error(e.getMessage(), e);
        }
        return Pagination.pagination(details, total, page, size);
    }
    @Override
    public Result<SummaryGenerationResponse> generateSummary(KnowledgeElementSummaryReq summaryReq) {
        String tenantId = UserContextHolder.getTenantId();

        try {
            // 获取嵌入配置
            UniversalEmbeddingConfig embeddingConfig = knowledgeElementEmbeddingQueryService.getEmbeddingConfig(summaryReq.getCode());

            if (embeddingConfig == null) {
                return Result.customFail("请选择知识库");
            }
            if (StrUtil.isBlank(summaryReq.getModelCode())){
                SaasKnowledgeSummaryConfig summaryConfig = getSummaryConfig(summaryReq.getCode(), summaryReq.getContainerId(), tenantId);
                if (StrUtil.isBlank(summaryConfig.getModelCode())){
                    summaryReq.setModelCode(modelProviderService.availableModel(tenantId));
                }else {
                    summaryReq.setModelCode(summaryConfig.getModelCode());
                }
                summaryReq.setTemperature(summaryConfig.getTemperature());
                summaryReq.setTopP(summaryConfig.getTopP());
                summaryReq.setPrompt(summaryConfig.getPrompt());
            }
            Integer dim = embeddingConfig.getVectorDimension();

            // 查询chunk数据
            Optional<DataSetChunkInfo> chunkById = vectorIndexDelegate.getChunkById(ChunkIdInfoReq.build(tenantId, summaryReq.getContainerId(), summaryReq.getParagraphId(), dim));
            if (chunkById.isPresent()){
                DataSetChunkInfo dataSetChunkInfo = chunkById.get();
                SummaryGenerationResponse summaryGenerationResponse = processChunk(dataSetChunkInfo, summaryReq, dim,tenantId);
                return Result.success(summaryGenerationResponse);
            }
            return Result.customFail("未找到该段落");
        } catch (Exception e) {
            log.error("生成摘要失败: {}", e.getMessage(), e);
            return Result.customFail("生成摘要失败: " + e.getMessage());
        }
    }

