    @Override
    public Result<KnowledgeElementSummaryResp> generateSummaryAsync(KnowledgeElementSummaryReq summaryReq) {
        try {
            SaasKnowledgeElement element = knowledgeElementMapper.selectOne(Wrappers.lambdaQuery(SaasKnowledgeElement.class)
                    .eq(SaasKnowledgeElement::getCode, summaryReq.getCode())
                    .eq(SaasKnowledgeElement::getContainerId, summaryReq.getContainerId()));
            String tenantId = element.getTenantId();
            // 获取嵌入配置
            UniversalEmbeddingConfig embeddingConfig = knowledgeElementEmbeddingQueryService.getEmbeddingConfig(summaryReq.getCode(), tenantId);
            if (embeddingConfig == null) {
                return Result.customFail("请选择知识库");
            }
            if (StrUtil.isBlank(summaryReq.getModelCode())){
                SaasKnowledgeSummaryConfig summaryConfig = getSummaryConfig(summaryReq.getCode(), summaryReq.getContainerId(), tenantId);
                if (StrUtil.isBlank(summaryConfig.getModelCode())){
                    summaryReq.setModelCode(modelProviderService.availableModel(tenantId));
                }else {
                    summaryReq.setModelCode(summaryConfig.getModelCode());
                }
                summaryReq.setTemperature(summaryConfig.getTemperature());
                summaryReq.setTopP(summaryConfig.getTopP());
                summaryReq.setPrompt(summaryConfig.getPrompt());
            }else {
                Assert.notNull(summaryReq.getTopP(), "topP不能为空");
                Assert.notNull(summaryReq.getTemperature(), "temperature不能为空");
                Assert.notNull(summaryReq.getPrompt(), "summaryPrompt不能为空");
                String expandConfigJson = GsonUtils.toJSONString(SaasKnowledgeExpandConfig.builder()
                        .summaryConfig(SaasKnowledgeSummaryConfig.builder()
                                .topP(summaryReq.getTopP())
                                .prompt(summaryReq.getPrompt())
                                .modelCode(summaryReq.getModelCode())
                                .temperature(summaryReq.getTemperature())
                                .build())
                        .build());
                saasKnowledgeConfigElementMapper.update(Wrappers.lambdaUpdate(SaasKnowledgeConfigElement.class)
                        .set(SaasKnowledgeConfigElement::getExpandConfig, expandConfigJson)
                        .set(SaasKnowledgeConfigElement::getModifierTime, LocalDateTime.now())
                        .eq(SaasKnowledgeConfigElement::getElementId, summaryReq.getCode())
                        .eq(SaasKnowledgeConfigElement::getTenantId, tenantId)
                        .eq(SaasKnowledgeConfigElement::getContainerId, summaryReq.getContainerId()));
            }

            // 查询所有chunk数据
            KnowledgeElementDetailQueryReq queryReq = summaryReq.toDetailQueryReq();
            List<DataSetChunkInfo> chunkList = vectorIndexDelegate
                    .getChunkList(queryReq.toChunkSearch(tenantId, embeddingConfig.getVectorDimension()));

            log.info("查询到{}个chunk数据，提交异步摘要任务", chunkList.size());
//            if (CollUtil.isEmpty(chunkList)) {
//                return Result.customFail("未找到可处理的切片数据");
//            }

            // 创建文档级任务编码
            String taskCode = IdUtil.getSnowflakeNextIdStr();
            // 创建单个文档级异步任务
            SaasKnowledgeSummaryAsyncTask asyncTask = SaasKnowledgeSummaryAsyncTask.builder()
                    .code(taskCode)
                    .tenantId(tenantId)
                    .containerId(summaryReq.getContainerId())
                    .elementCode(summaryReq.getCode())
                    .modelCode(summaryReq.getModelCode())
                    .priority(calculatePriority(summaryReq))
                    .status(TaskStatus.PENDING.getCode())
                    .temperature(summaryReq.getTemperature())
                    .topP(summaryReq.getTopP())
                    .elementUpdatedTime(element.getModifierTime())
                    .build();

            // 保存异步任务
            boolean saved = summaryAsyncTaskService.save(asyncTask);
            if (!saved) {
                return Result.customFail("保存异步任务失败");
            }

            // 发送任务到RabbitMQ队列
            try {
                MessageSummaryTaskReq mqReq = new MessageSummaryTaskReq();
                mqReq.setTaskCode(taskCode);
                mqReq.setTenantId(tenantId);
                mqReq.setContainerId(summaryReq.getContainerId());
                mqReq.setElementCode(summaryReq.getCode());
                mqReq.setModelCode(summaryReq.getModelCode());
                mqReq.setTemperature(summaryReq.getTemperature());
                mqReq.setTopP(summaryReq.getTopP());
                mqReq.setElementUpdatedTime(element.getModifierTime() != null ?
                        element.getModifierTime().toString() : null);
                rabbitMessageService.sendSummaryTaskMsg(mqReq);
                log.info("摘要任务已发送到MQ队列：taskCode={}, modelCode={}", taskCode, summaryReq.getModelCode());
            } catch (Exception e) {
                log.error("发送摘要任务到MQ失败：taskCode={}", taskCode, e);
            }

            return Result.success(KnowledgeElementSummaryResp.builder()
                    .taskId(taskCode)
                    .totalChunks(chunkList.size())
                    .processedChunks(0)
                    .status(TaskStatus.PENDING.getDesc())
                    .createTime(LocalDateTime.now())
                    .updateTime(LocalDateTime.now())
                    .message("摘要任务已提交到异步队列，将在系统空闲时处理")
                    .build());

        } catch (Exception e) {
            log.error("提交异步摘要任务失败: {}", e.getMessage(), e);
            return Result.customFail("提交摘要任务失败：" + e.getMessage());
        }
    }

