/**
 * 摘要任务消息消费者
 * 支持QPM池化控制、文档概览、自适应延迟
 *
 * @author <a href="xiaoymin@foxmail.com">xiaoymin@foxmail.com</a>
 * @since torchv_server v1.13.0
 */
@Slf4j
@Component
@RequiredArgsConstructor
public class SummaryTaskMessageConsumer {

    private final SummaryAsyncTaskService summaryAsyncTaskService;
    private final SummaryLLMService summaryLLMService;
    private final KnowledgeElementEmbeddingQueryService knowledgeElementEmbeddingQueryService;
    private final KnowledgeElementService knowledgeElementService;
    private final DynamicQMPPoolService dynamicQMPPoolService;
    private final ModelProviderService modelProviderService;

    @Value("${ais.summary.batch.chunk-size:5}")
    private Integer batchChunkSize;

    @Value("${ais.summary.batch.min-delay-ms:200}")
    private Long minBatchDelayMs;

    @Value("${ais.summary.batch.max-delay-ms:3000}")
    private Long maxBatchDelayMs;

    /** 中文混合文本，1 token ≈ 3字符的保守估计 */
    private static final double CHARS_PER_TOKEN = 3.0;

    /** 上下文预算中全局上下文的最大占比 */
    private static final double GLOBAL_CONTEXT_RATIO_SHORT = 0.5;
    private static final double GLOBAL_CONTEXT_RATIO_LONG = 0.3;

    /** 安全余量：输入预算的 60% 供上下文使用，其余留给 batch 内容和输出 */
    private static final double CONTEXT_BUDGET_RATIO = 0.6;

    /** 每个 chunk 输出预估 token（摘要 + 标签 JSON） */
    private static final int OUTPUT_TOKENS_PER_CHUNK = 180;

    /**
     * 处理摘要任务消息
     */
    @RabbitListener(
            concurrency = "${ais.rabbit.listener.sync-concurrency:1}",
            queuesToDeclare = {@Queue("${ais.bot.message.summary-task}")}
    )
    public void processSummaryTask(MessageSummaryTaskReq messageReq,
                                    Message rabbitMessage,
                                    Channel channel) {
        long deliveryTag = rabbitMessage.getMessageProperties().getDeliveryTag();
        String taskCode = messageReq.getTaskCode();

        try {
            log.info("开始处理摘要任务消息 - taskCode: {}, elementCode: {}",
                    taskCode, messageReq.getElementCode());

            // 注册任务开始
            dynamicQMPPoolService.registerSummaryTaskStart();

            // 查询任务信息
            SaasKnowledgeSummaryAsyncTask task = summaryAsyncTaskService.getByCode(taskCode);
            if (task == null) {
                log.warn("任务不存在，跳过处理：taskCode={}", taskCode);
                channel.basicAck(deliveryTag, false);
                return;
            }

            // 更新任务状态为执行中
            summaryAsyncTaskService.updateTaskStatus(taskCode, TaskStatus.EXECUTING.getCode(), null);

            log.info("开始处理文档摘要任务：taskCode={}, elementCode={}, 当前活跃任务数={}",
                    taskCode, task.getElementCode(), dynamicQMPPoolService.getActiveSummaryTasks());

            // 获取嵌入配置
            UniversalEmbeddingConfig embeddingConfig = knowledgeElementEmbeddingQueryService
                    .getEmbeddingConfig(task.getElementCode(), task.getTenantId());
            Integer dims = embeddingConfig.getVectorDimension();

            // 查询文档的所有切片
            List<ChunkInfo> chunks = queryDocumentChunks(task, dims);

            if (CollUtil.isEmpty(chunks)) {
                log.warn("文档无切片数据：elementCode={}", task.getElementCode());
                summaryAsyncTaskService.updateTaskStatus(taskCode, TaskStatus.COMPLETED.getCode(), "文档无切片数据");
                knowledgeElementService.updateSummaryStatus(task.getElementCode(), SummaryStatus.COMPLETED.getCode());
                channel.basicAck(deliveryTag, false);
                return;
            }

            // 计算模型上下文预算
            int contextTokenBudget = estimateContextTokenBudget(task);
            log.info("模型上下文预算：modelCode={}, contextBudget={} tokens", task.getModelCode(), contextTokenBudget);

            // 分批处理切片（每批动态构建滑动上下文）
            int failedBatches = processChunksInBatches(task, chunks, contextTokenBudget, dims);

            // 更新任务状态
            if (failedBatches == 0) {
                summaryAsyncTaskService.updateTaskStatus(taskCode, TaskStatus.COMPLETED.getCode(), null);
                knowledgeElementService.updateSummaryStatus(task.getElementCode(), SummaryStatus.COMPLETED.getCode());
            } else {
                summaryAsyncTaskService.updateTaskStatus(taskCode, TaskStatus.PARTIALLY_FAILED.getCode(),
                        String.format("%d/%d 批次处理失败", failedBatches, getBatchCount(chunks)));
                knowledgeElementService.updateSummaryStatus(task.getElementCode(), SummaryStatus.COMPLETED.getCode());
                log.warn("文档摘要部分批次失败：taskCode={}, 失败批次={}", taskCode, failedBatches);
            }

            log.info("文档摘要任务处理完成：taskCode={}, 总切片数={}", taskCode, chunks.size());

            // 手动确认消息
            channel.basicAck(deliveryTag, false);

        } catch (Exception e) {
            log.error("处理摘要任务消息失败：taskCode={}", taskCode, e);

            // 更新任务状态为失败
            summaryAsyncTaskService.updateTaskStatus(taskCode, TaskStatus.FAILED.getCode(), e.getMessage());

            try {
                // 拒绝消息（不重新入队）
                channel.basicNack(deliveryTag, false, false);
            } catch (Exception ackException) {
                log.error("消息确认失败：taskCode={}", taskCode, ackException);
            }
        } finally {
            // 注册任务结束
            dynamicQMPPoolService.registerSummaryTaskEnd();
        }
    }

    /**
     * 查询文档切片
     */
    private List<ChunkInfo> queryDocumentChunks(SaasKnowledgeSummaryAsyncTask task, Integer dims) {
        try {
            VectorIndexDelegate vectorIndexDelegate = SpringBeansUtil.getBean(VectorIndexDelegate.class);

            KnowledgeElementDetailQueryReq queryReq = new KnowledgeElementDetailQueryReq();
            queryReq.setCode(task.getElementCode());
            queryReq.setContainerId(task.getContainerId());

            List<DataSetChunkInfo> chunkList = vectorIndexDelegate.getChunkList(
                    queryReq.toChunkSearch(task.getTenantId(), dims));

            return chunkList.stream()
                    .map(chunk -> ChunkInfo.builder()
                            .id(chunk.getId())
                            .content(chunk.getContent())
                            .order(chunk.getPage())
                            .build())
                    .sorted(Comparator.comparing(ChunkInfo::getOrder))
                    .collect(Collectors.toList());

        } catch (Exception e) {
            log.error("查询文档切片失败：elementCode={}", task.getElementCode(), e);
            return Collections.emptyList();
        }
    }

    /**
     * 估算模型可用上下文预算（tokens）
     */
    private int estimateContextTokenBudget(SaasKnowledgeSummaryAsyncTask task) {
        try {
            var modelSettingOpt = modelProviderService.load(task.getModelCode(), task.getTenantId());
            if (modelSettingOpt.isPresent()) {
                int totalTokens = modelSettingOpt.get().getContextNumber() * 1000;
                return (int) (totalTokens * CONTEXT_BUDGET_RATIO);
            }
        } catch (Exception e) {
            log.warn("获取模型配置失败，使用默认上下文窗口：modelCode={}", task.getModelCode(), e);
        }
        return (int) (16000 * CONTEXT_BUDGET_RATIO);
    }

    /**
     * 为当前批次构建滑动上下文窗口
     *
     * 双层上下文：全局（文档头部）+ 局部（当前批次前后相邻切片）
     * 长文档（≥20切片）偏重局部，短文档偏重全局
     */
    private String buildSlidingContext(List<ChunkInfo> allChunks, List<ChunkInfo> batch,
                                       int batchStartIdx, int contextTokenBudget) {
        int contextCharBudget = (int) (contextTokenBudget * CHARS_PER_TOKEN);
        boolean isLongDoc = allChunks.size() >= 20;

        int batchContentLen = batch.stream().mapToInt(c -> c.getContent().length()).sum();
        int outputReserve = batch.size() * OUTPUT_TOKENS_PER_CHUNK * 2;
        int remainingBudget = contextCharBudget - batchContentLen - outputReserve;
        if (remainingBudget <= 0) {
            remainingBudget = 2000;
        }

        double globalRatio = isLongDoc ? GLOBAL_CONTEXT_RATIO_LONG : GLOBAL_CONTEXT_RATIO_SHORT;
        int globalBudget = (int) (remainingBudget * globalRatio);
        int localBudget = remainingBudget - globalBudget;
        int localEachSide = Math.max(2, localBudget / 2);

        StringBuilder ctx = new StringBuilder();

        ctx.append("=== 文档概述 ===\n");
        int globalUsed = 0;
        for (ChunkInfo chunk : allChunks) {
            if (globalUsed + chunk.getContent().length() > globalBudget) break;
            ctx.append(chunk.getContent()).append("\n");
            globalUsed += chunk.getContent().length();
        }

        int batchEndIdx = batchStartIdx + batch.size();
        ctx.append("\n=== 上文切片 ===\n");
        int localUsed = 0;
        for (int i = batchStartIdx - 1; i >= 0 && localUsed < localEachSide; i--) {
            String content = allChunks.get(i).getContent();
            ctx.append(content).append("\n");
            localUsed += content.length();
        }

        ctx.append("\n=== 下文切片 ===\n");
        localUsed = 0;
        for (int i = batchEndIdx; i < allChunks.size() && localUsed < localEachSide; i++) {
            String content = allChunks.get(i).getContent();
            ctx.append(content).append("\n");
            localUsed += content.length();
        }

        log.debug("滑动上下文：全局{}字, 局部预算{}字/side, 总{}字", globalUsed, localEachSide, ctx.length());
        return ctx.toString();
    }

    /**
     * 分批处理切片（滑动上下文窗口）
     *
     * @param task               摘要任务
     * @param chunks             全部切片（已排序）
     * @param contextTokenBudget 模型上下文预算（tokens）
     * @param dims               向量维度
     * @return 失败的批次数
     */
    private int processChunksInBatches(SaasKnowledgeSummaryAsyncTask task,
                                         List<ChunkInfo> chunks,
                                         int contextTokenBudget,
                                         Integer dims) {
        int optimalBatchSize = calculateOptimalBatchSize(chunks, contextTokenBudget);
        List<List<ChunkInfo>> batches = CollUtil.split(chunks, optimalBatchSize);

        log.info("文档切片分批处理：总切片数={}, 批次数={}, 批次大小={}, 上下文预算={} tokens",
                chunks.size(), batches.size(), optimalBatchSize, contextTokenBudget);

        int failedBatches = 0;
        int batchStartIdx = 0;

        for (int i = 0; i < batches.size(); i++) {
            List<ChunkInfo> batch = batches.get(i);
            log.info("处理第 {}/{} 批，切片数={}", i + 1, batches.size(), batch.size());

            // 获取QPM许可
            boolean permitAcquired = dynamicQMPPoolService.tryAcquireSummaryPermit(
                    task.getModelCode(), task.getTenantId(), 30000);

            if (!permitAcquired) {
                log.warn("获取QPM许可超时，等待后重试：batch={}/{}", i + 1, batches.size());
                try {
                    Thread.sleep(5000);
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    throw new RuntimeException("等待QPM许可被中断", e);
                }
                i--;
                continue;
            }

            try {
                // 为当前批次构建滑动上下文
                String batchContext = buildSlidingContext(chunks, batch, batchStartIdx, contextTokenBudget);

                SummaryGenerationResponse response = summaryLLMService.generateBatchSummaryWithContext(
                        task.getTenantId(), batch, batchContext, task.getModelCode(),
                        task.getElementCode(),
                        task.getTemperature() != null ? task.getTemperature().floatValue() / 100f : null,
                        task.getTopP() != null ? task.getTopP().floatValue() / 100f : null);

                if (response.isSuccess() && CollUtil.isNotEmpty(response.getResults())) {
                    if (isDocumentUpdated(task)) {
                        summaryAsyncTaskService.updateTaskStatus(task.getCode(),
                                TaskStatus.CANCELED.getCode(), "文档已更新");
                        log.info("文档已更新，停止处理：elementCode={}", task.getElementCode());
                        return failedBatches;
                    }

                    updateChunksBatch(task.getTenantId(), task.getContainerId(),
                            task.getElementCode(), response.getResults(), dims);
                } else {
                    log.warn("批量摘要生成失败：批次={}, 错误={}", i + 1, response.getErrorMessage());
                    failedBatches++;
                }

            } catch (Exception e) {
                log.error("处理第 {} 批失败", i + 1, e);
                failedBatches++;
            }

            batchStartIdx += batch.size();

            if (i < batches.size() - 1) {
                try {
                    long delay = calculateAdaptiveDelay(task.getModelCode(), task.getTenantId());
                    if (delay > 0) {
                        Thread.sleep(delay);
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    log.warn("批次间延迟被中断：{}", e.getMessage());
                    break;
                }
            }
        }

        return failedBatches;
    }

    /**
     * 计算批次数（用于日志）
     */
    private int getBatchCount(List<ChunkInfo> chunks) {
        return (int) Math.ceil((double) chunks.size() / calculateOptimalBatchSize(chunks, 9600));
    }

    /**
     * 动态批次大小，根据内容长度和模型上下文窗口共同决定上限
     */
    private int calculateOptimalBatchSize(List<ChunkInfo> chunks, int contextTokenBudget) {
        int baseSize = batchChunkSize != null ? batchChunkSize : 5;

        int avgLength = chunks.stream()
                .mapToInt(chunk -> chunk.getContent().length())
                .sum() / chunks.size();

        int maxByOutput = Math.max(2, contextTokenBudget / (OUTPUT_TOKENS_PER_CHUNK * (int) CHARS_PER_TOKEN));

        if (avgLength < 500) {
            return Math.min(baseSize + 2, Math.min(maxByOutput, 8));
        } else if (avgLength < 1000) {
            return Math.min(baseSize, Math.min(maxByOutput, 6));
        } else if (avgLength < 2000) {
            return Math.min(Math.max(baseSize - 1, 3), Math.min(maxByOutput, 5));
        } else {
            return Math.min(Math.max(baseSize - 2, 2), Math.min(maxByOutput, 3));
        }
    }

    /**
     * 批次间固定最小延迟，QPM 限流由 Redis 集中控制
     */
    private long calculateAdaptiveDelay(String modelCode, String tenantId) {
        return minBatchDelayMs;
    }

