            List<String> dataIds = saasKnowledgeContainerPermissionService.getDataIds(highestPermissions, sysUserInfo, chainRequest.getPermissionCodes());
            if (CollUtil.isNotEmpty(dataIds)) {
                chainRequest.setDataIds(dataIds);
