            chainContext.getSearchContext().applyEmbeddingModel(knowledgeEmbeddingChangeService.getKnowledgeEmbeddingModelList(containerIds,chainContext.getTenantId()));
        }else{
            // 不进行embedding处理，直接大模型回复
            chainContext.getSearchContext().setEnableEmbedding(false);
            chainContext.getSearchContext().setEnableReRanker(false);
            // 如果知识库没有绑定，那么不查询知识库，直接让大模型回答
            chainContext.getSearchContext().setRagSearch(false);
        }
        log.info("openapi-containerIds-size:{}", CollUtil.size(containerIds));
