    private static final String META_TAG_FIELD = DataSetChunkInfo.FIELD_METADATA + StrUtil.DOT + PageMetaDataIndexField.FIELD_NAME_TAG;
    private static final String META_CREATED_FIELD = DataSetChunkInfo.FIELD_METADATA + StrUtil.DOT + PageMetaDataIndexField.FIELD_NAME_CREATED;

    // BM25 多字段检索权重配置：字段路径 -> 权重
    // content 是顶层字段，title/fullPathInfo/summary 在 metadata 对象内
    private static final Map<String, Float> BM25_FIELD_WEIGHTS = Map.of(
            DataSetChunkInfo.FIELD_CONTENT, 50f,
            PageMetaDataIndexField.buildMetaFieldName(PageMetaDataIndexField.FIELD_NAME_TITLE), 20f,
            PageMetaDataIndexField.buildMetaFieldName(PageMetaDataIndexField.FIELD_NAME_FULL_PATH), 30f,
