    @Override
    public String getContent(String tenantId, String dataId, String containerId) {
        log.info("get content from es,tenantId:{},dataId:{},containerId:{}", tenantId, dataId, containerId);
        // String collectName = VectorAssistant.referenceCollectName(tenantId,
        // containerId);
        String collectName = VectorAssistant.referenceCollectName(tenantId);
        log.info("ref-collectName-name:{}", collectName);
        // 构建查询条件
        BoolQuery.Builder builder = QueryBuilders.bool();
        builder.must(
                QueryBuilders.term().field(DataSetChunkInfo.FIELD_CONTAINER_ID).value(containerId).build()._toQuery());
        builder.must(QueryBuilders.term().field(DataSetChunkInfo.FIELD_DATA_ID).value(dataId).build()._toQuery());
        // 考虑到sharding的情况
        if (VectorAssistant.isSharding(tenantId)) {
            builder.must(
                    QueryBuilders.term().field(DataSetChunkInfo.FIELD_TENANT_ID).value(tenantId).build()._toQuery());
        }
        NativeQuery nativeQuery = NativeQuery.builder().withQuery(builder.build()._toQuery())
                .withPageable(Pageable.ofSize(150)).build();
        SearchHits<DataSetReference> dataSearchHits = this.elasticsearchTemplate.search(nativeQuery,
                DataSetReference.class, IndexCoordinates.of(collectName));
        List<SearchHit<DataSetReference>> data = dataSearchHits.getSearchHits();
        Set<DataSetReferenceObject> dataSetReferenceObjects = new HashSet<>();
        for (SearchHit<DataSetReference> ele : data) {
            DataSetReference reference = ele.getContent();
            if (StrUtil.equalsIgnoreCase(reference.getCategory(), DataSetReferenceType.paragraph.getName())) {
                DataSetReferenceObject referenceObject = new DataSetReferenceObject();
                BeanUtils.copyProperties(reference, referenceObject);
                dataSetReferenceObjects.add(referenceObject);
            }
        }
        CollUtil.sort(dataSetReferenceObjects, Comparator.comparing(DataSetReferenceObject::getPage));
        List<String> link = new LinkedList<>();
        for (DataSetReferenceObject referenceObject : dataSetReferenceObjects) {
            link.add(referenceObject.getContent());
        }
        return CollUtil.join(link, "\n");
    }

    @Override
    public Optional<DataSetReference> getReferenceById(String tenantId, String containerId, String id) {
        String collectName = VectorAssistant.referenceCollectName(tenantId);
        log.info("get reference by id,tenantId:{},id:{},collectName:{}", tenantId, id, collectName);
        NativeQuery nativeQuery = NativeQuery.builder()
                .withQuery(QueryBuilders.term().field(DataSetChunkInfo.FIELD_ID).value(id).build()._toQuery()).build();
        IndexCoordinates indexCoordinates = IndexCoordinates.of(collectName);
        SearchHit<DataSetReference> referenceSearchHit = this.elasticsearchTemplate.searchOne(nativeQuery,
                DataSetReference.class, indexCoordinates);
        if (referenceSearchHit != null) {
            return Optional.of(referenceSearchHit.getContent());
        }
        return Optional.empty();
    }

    @Override
    public Optional<DataSetChunkInfo> getChunkById(ChunkIdInfoReq req) {
        log.info("get chunk by id request,tenantId:{},dims:{}", req.getTenantId(),req.getDims());
        String collectName = VectorAssistant.chunkCollectName(req.getTenantId(),req.getDims());
        log.info("get chunk by id,tenantId:{},id:{},collectName:{}", req.getTenantId(), req.getId(), collectName);
        NativeQuery nativeQuery = NativeQuery.builder()
                .withQuery(QueryBuilders.term().field(DataSetChunkInfo.FIELD_ID).value(req.getId()).build()._toQuery()).build();
        IndexCoordinates indexCoordinates = IndexCoordinates.of(collectName);
        SearchHit<DataSetChunkInfo> referenceSearchHit = this.elasticsearchTemplate.searchOne(nativeQuery,
                DataSetChunkInfo.class, indexCoordinates);
        if (referenceSearchHit != null) {
            return Optional.of(referenceSearchHit.getContent());
        }
        return Optional.empty();
    }

    @Override
    public List<DataSetReferenceObject> getReference(List<DataSetScoreChunkInfo> chunkInfos, String tenantId) {
        log.info("根据租户id和片段的段落Pages获取引用对象列表,tenantId:{},chunkSize:{}", tenantId, CollUtil.size(chunkInfos));
        Set<DataSetReferenceObject> dataSetReferenceObjects = new HashSet<>();
        try {
            // 如果没有片段的内容，那么就返回return
            if (CollUtil.isEmpty(chunkInfos)) {
                return new ArrayList<>();
            }
            String collectName = VectorAssistant.referenceCollectName(tenantId);
            log.info("collectName-name:{}", collectName);
            boolean sharding = VectorAssistant.isSharding(tenantId);
            Set<String> keyHexSet = new HashSet<>();
            // 构建查询条件
            BoolQuery.Builder builder = QueryBuilders.bool();
            for (DataSetScoreChunkInfo chunkInfo : chunkInfos) {
                // 已经存在相同的过滤参数的情况下，就不用重复添加了
                if (keyHexSet.contains(chunkInfo.getKeyHex())) {
                    continue;
                }
                keyHexSet.add(chunkInfo.getKeyHex());
                List<Query> queries = new LinkedList<>();
                // sharding模式，必须新增租户id的过滤条件
                if (sharding) {
                    queries.add(QueryBuilders.term().field(DataSetChunkInfo.FIELD_TENANT_ID).value(tenantId).build()
                            ._toQuery());
                }
                queries.add(QueryBuilders.term().field(DataSetChunkInfo.FIELD_CONTAINER_ID)
                        .value(chunkInfo.getContainerId()).build()._toQuery());
                queries.add(QueryBuilders.term().field(DataSetChunkInfo.FIELD_DATA_ID).value(chunkInfo.getDataId())
                        .build()._toQuery());
                queries.add(QueryBuilders.term().field(DataSetChunkInfo.FIELD_PAGE).value(chunkInfo.getPage()).build()
                        ._toQuery());
                builder.should(QueryBuilders.bool().must(queries).build()._toQuery());

            }
            NativeQuery nativeQuery = NativeQuery.builder().withQuery(builder.build()._toQuery())
                    .withPageable(Pageable.ofSize(50)).build();
            SearchHits<DataSetReference> dataSearchHits = this.elasticsearchTemplate.search(nativeQuery,
                    DataSetReference.class, IndexCoordinates.of(collectName));
            List<SearchHit<DataSetReference>> data = dataSearchHits.getSearchHits();
            List<DataSetReference> references = new LinkedList<>();
            // 处理db查询的引用行数
            List<DataSetReference> referenceRows = data.stream().map(SearchHit::getContent).toList();
            applyReferences(referenceRows, references, dataSetReferenceObjects);
            // 针对reference获取不同的内容，获取段落的内容
            applyParagraph(references, dataSetReferenceObjects);
        } catch (Exception e) {
            log.error(e.getMessage(), e);
        }
        return CollUtil.newArrayList(dataSetReferenceObjects.iterator());
    }

    private HighlightQuery highlight(){
        // 创建高亮显示
        List<HighlightField> fields = new ArrayList<>();
        HighlightFieldParameters fieldParameters = HighlightFieldParameters.builder()
                // 高亮起始标签
                .withPreTags("<strong>")
                // 高亮结束标签
                .withPostTags("</strong>")
                // 返回片段长度
                .withFragmentSize(250)
                // 返回完整字段内容
                .withNumberOfFragments(5)
                .build();
        fields.add(new HighlightField(DataSetChunkInfo.FIELD_CONTENT, fieldParameters));
        Highlight highlight = new Highlight(fields);
        return new HighlightQuery(highlight, DataSetChunkInfo.class);
    }

