    @Override
    public List<DataSetTermInfo> termSearch(SemanticTermSearchReq termSearchReq) {
        log.info("term search,tenant:{},query:{}", termSearchReq.getTenantId(), termSearchReq.getQuery());
        List<DataSetTermInfo> chunkInfos = new LinkedList<>();
        try {
            // 设置查询的boost
            // float knnAlpha = searchReq.getConfigObject().getRagAlpha();
            // 默认召回200个 扩大召回topK
            int topK=Math.max(termSearchReq.getSearchTopK(),200);
            int numCandidates= ElasticStoreUtils.calculateNumCandidates(topK);
            String collectName = ElasticStoreUtils.INDEX_TERM_NAME;
            log.info(" 术语库 topK::{},num:{},collectionName:{}",topK,numCandidates,collectName);
            // 创建
            NativeQueryBuilder nativeQueryBuilder = NativeQuery.builder()
                    .withPageable(Pageable.ofSize(topK)).withSearchType(null)
                    .withFields(DataSetTermInfo.SEARCH_FIELDS);
            BoolQuery.Builder boolBuilder = QueryBuilders.bool();
            //  需要增加租户id的过滤条件
            boolBuilder.must(QueryBuilders.term().field(DataSetTermInfo.FIELD_TENANT_ID).value(termSearchReq.getTenantId()) .build()._toQuery());
            // 必须是启用状态
            boolBuilder.must(QueryBuilders.term().field(DataSetTermInfo.FIELD_STATUS).value(ToggleStatusEnum.YES.getCode()).build()._toQuery());
            // 关键词match
            boolBuilder.must(QueryBuilders.match().field(DataSetTermInfo.FIELD_CONTENT).query(termSearchReq.getQuery()).boost(1.0f).build()._toQuery());
            // 指定术语库,多个术语库
            if (CollUtil.isNotEmpty(termSearchReq.getContainerId())) {
                TermsQueryField termsQueryField = new TermsQueryField.Builder()
                        .value(termSearchReq.getContainerId().stream().map(FieldValue::of).toList()).build();
                boolBuilder.must(QueryBuilders.terms().field(DataSetTermInfo.FIELD_CONTAINER_ID).terms(termsQueryField)
                        .build()._toQuery());
            }
            // 指定了文档id集合 add since v1.3
            if (CollUtil.isNotEmpty(termSearchReq.getDataIds())) {
                TermsQueryField termsQueryField = new TermsQueryField.Builder()
                        .value(termSearchReq.getDataIds().stream().map(FieldValue::of).toList()).build();
                boolBuilder.must(QueryBuilders.terms().field(DataSetTermInfo.FIELD_DATA_ID).terms(termsQueryField)
                        .build()._toQuery());
            }
            nativeQueryBuilder.withQuery(boolBuilder.build()._toQuery());
            // 创建NativeQuery
            NativeQuery nativeQuery = nativeQueryBuilder.build();
            SearchHits<DataSetTermInfo> dataSearchHits = this.elasticsearchTemplate.search(nativeQuery,
                    DataSetTermInfo.class, IndexCoordinates.of(collectName));
            List<SearchHit<DataSetTermInfo>> data = dataSearchHits.getSearchHits();
            log.info("术语库检索成功，total-size:{}", dataSearchHits.getTotalHits());
            for (int i=0;i<data.size();i++) {
                SearchHit<DataSetTermInfo> ele = data.get(i);
                DataSetTermInfo elasticData = ele.getContent();
                chunkInfos.add(elasticData);
                if (i>=termSearchReq.getSearchTopK()-1){
                    break;
                }
            }
            return chunkInfos;
        } catch (Exception e) {
            log.error(e.getMessage(), e);
        }
        return new ArrayList<>();
    }

    @Override
    public List<DataSetChunkInfo> nearPageChunk(NearPageChunkSearchReq searchReq) {
        try {
            String tenantId=searchReq.getTenantId();
            List<DataSetScoreChunkInfo> chunkInfos=searchReq.getChunkInfos();
            // 如果没有片段的内容，那么就返回return
            if (CollUtil.isEmpty(chunkInfos)) {
                return new ArrayList<>();
            }
            String collectName = VectorAssistant.chunkCollectName(tenantId,searchReq.getDims());
            log.info("collectName-chunk-name:{}", collectName);
            boolean sharding = VectorAssistant.isSharding(tenantId);
            Set<String> keyHexSet = new HashSet<>();
            // 构建查询条件
            BoolQuery.Builder builder = QueryBuilders.bool();
            for (DataSetScoreChunkInfo chunkInfo : chunkInfos) {
                // 已经存在相同的过滤参数的情况下，就不用重复添加了
                if (keyHexSet.contains(chunkInfo.getKeyHex())) {
                    continue;
                }
                keyHexSet.add(chunkInfo.getKeyHex());
                List<Query> queries = new LinkedList<>();
                // sharding模式，必须新增租户id的过滤条件
                if (sharding) {
                    queries.add(QueryBuilders.term().field(DataSetChunkInfo.FIELD_TENANT_ID).value(tenantId).build()._toQuery());
                }
                queries.add(QueryBuilders.term().field(DataSetChunkInfo.FIELD_CONTAINER_ID).value(chunkInfo.getContainerId()).build()._toQuery());
                queries.add(QueryBuilders.term().field(DataSetChunkInfo.FIELD_DATA_ID).value(chunkInfo.getDataId()).build()._toQuery());
                // 获取临近页码(+-2)
                List<Integer> nearPages=chunkInfo.nearPages(searchReq.getNearPageSize());
                if (CollUtil.isEmpty(nearPages)){
                    continue;
                }
                //构建多个页码
                TermsQueryField termsQueryField = new TermsQueryField.Builder().value(nearPages.stream().map(FieldValue::of).toList()).build();
                queries.add(QueryBuilders.terms().field(DataSetChunkInfo.FIELD_PAGE).terms(termsQueryField).build()._toQuery());
                builder.should(QueryBuilders.bool().must(queries).build()._toQuery());
            }
            NativeQuery nativeQuery = NativeQuery.builder().withQuery(builder.build()._toQuery()).withPageable(Pageable.ofSize(200)).build();
            SearchHits<DataSetChunkInfo> dataSearchHits = this.elasticsearchTemplate.search(nativeQuery,
                    DataSetChunkInfo.class, IndexCoordinates.of(collectName));
            List<SearchHit<DataSetChunkInfo>> data = dataSearchHits.getSearchHits();
            // 处理db查询的引用行数
            return data.stream().map(SearchHit::getContent).toList();
        } catch (Exception e) {
            log.error(e.getMessage(), e);
        }
        return List.of();
    }

