 * 负责扫描待生成摘要的文档，创建任务并发送到RabbitMQ
 *
 * @author <a href="xiaoymin@foxmail.com">xiaoymin@foxmail.com</a>
 * @since torchv_server v1.13.0
 */
@Slf4j
@Component
@RequiredArgsConstructor
public class SummaryAsyncTaskScheduler {

    private final KnowledgeElementService knowledgeElementService;
    private final KnowledgeElementDetailService knowledgeElementDetailService;
    private final SummaryAsyncTaskService summaryAsyncTaskService;
    private final RabbitMessageService rabbitMessageService;
    private final DynamicQMPPoolService dynamicQMPPoolService;

    /**
     * 最大重试次数
     */
    private static final int MAX_RETRY_COUNT = 3;

    @Value("${ais.llm.monitor.scheduler.enable:true}")
    private Boolean schedulerEnable;

    @Value("${ais.llm.monitor.scheduler.batch-size:5}")
    private Integer batchSize;

    @Value("${ais.llm.monitor.scheduler.queue-max-size:30}")
    private Integer queueMaxSize;

    /**
     * 调度执行待处理的摘要任务
     * 每1分钟执行一次
     */
    @Scheduled(fixedDelay = 60000, initialDelay = 30000)
    @SchedulerLock(name = "processSummaryTasks", lockAtMostFor = "50s", lockAtLeastFor = "10s")
    public void processPendingTasks() {
        if (!schedulerEnable) {
            return;
        }

        try {
            // 1. 处理待生成摘要的文档
            processPendingSummaryDocs();

            // 2. 处理PENDING状态的孤儿任务（重启后MQ消息丢失的恢复）
            processOrphanedPendingTasks();

            // 3. 处理失败重试任务
            processFailedRetryTasks();

        } catch (Exception e) {
            log.error("摘要任务调度失败", e);
        }
    }

    /**
     * 处理待生成摘要的文档
     */
    private void processPendingSummaryDocs() {
        // 扫描待生成摘要的文档
        List<SaasKnowledgeElement> pendingDocs = knowledgeElementService.listPendingSummaryDocs(batchSize * 2);

        if (CollUtil.isEmpty(pendingDocs)) {
            log.debug("没有待生成摘要的文档");
            return;
        }

        log.info("扫描到 {} 个待生成摘要的文档", pendingDocs.size());

        for (SaasKnowledgeElement doc : pendingDocs) {
            try {
                processDocForSummary(doc);
            } catch (Exception e) {
                log.error("处理文档摘要失败：elementCode={}", doc.getCode(), e);
            }
        }
    }

    /**
     * 处理单个文档的摘要生成
     */
    private void processDocForSummary(SaasKnowledgeElement doc) {
        // 前置检查1：文档是否存在
        Optional<SaasKnowledgeElement> latestDocOpt = knowledgeElementService.queryByCode(doc.getCode(), doc.getTenantId());
        if (latestDocOpt.isEmpty()) {
            // 文档已删除，清除状态
            log.info("文档已删除，清除摘要状态：elementCode={}", doc.getCode());
            knowledgeElementService.updateSummaryStatus(doc.getCode(), SummaryStatus.NONE.getCode());
            return;
        }

        SaasKnowledgeElement element = latestDocOpt.get();

        // 前置检查2：文档是否已完成解析
        if (element.getProcessStatus() == null || element.getProcessStatus() != ProcessStatusEnum.SUCCESS.getCode()) {
            log.debug("文档未完成解析，跳过：elementCode={}, processStatus={}", element.getCode(), element.getProcessStatus());
            return;
        }

        // 前置检查3：是否已有任务在处理
        if (summaryAsyncTaskService.isSummaryTaskRunning(element.getCode())) {
            log.debug("文档已有任务在处理，跳过：elementCode={}", element.getCode());
            return;
        }

        // 检查是否需要重新生成（文档已更新）
        SaasKnowledgeSummaryAsyncTask lastTask = summaryAsyncTaskService.getLastTaskByElementCode(element.getCode());
        if (lastTask != null) {
            LocalDateTime taskTime = lastTask.getCreatedTime();

            if (element.getModifierTime() != null && element.getModifierTime().isAfter(taskTime)) {
                // 文档已更新，取消旧任务
                log.info("文档已更新，取消旧任务：elementCode={}", element.getCode());
                cancelPendingTasks(element.getCode());
            } else if (TaskStatus.COMPLETED.getCode().equals(lastTask.getStatus())) {
                // 已有完成的任务，跳过
                log.debug("文档已有完成的摘要任务，跳过：elementCode={}", element.getCode());
                knowledgeElementService.updateSummaryStatus(element.getCode(), SummaryStatus.COMPLETED.getCode());
                return;
            }
        }

        // 检查系统负载
        if (!dynamicQMPPoolService.tryAcquireSummaryPermit(
                element.getContainerId(), element.getTenantId(), 0)) {
            log.debug("系统负载较高，暂不处理：elementCode={}", element.getCode());
            return;
        }

        // 检查队列消息数量
        int currentQueueSize = rabbitMessageService.getSummaryTaskQueueSize();
        if (currentQueueSize >= queueMaxSize) {
            log.debug("队列消息数量已达上限：{}/{}", currentQueueSize, queueMaxSize);
            return;
        }

        // 创建任务
        createAndSendSummaryTask(element);
    }

    /**
     * 创建并发送摘要任务
     */
    private void createAndSendSummaryTask(SaasKnowledgeElement element) {
        // 更新文档状态为生成中
        knowledgeElementService.updateSummaryStatus(element.getCode(), SummaryStatus.PROCESSING.getCode());

        // 创建任务
        KnowledgeElementSummaryReq req = KnowledgeElementSummaryReq.builder()
                .containerId(element.getContainerId())
                .code(element.getCode())
                .build();

        var result = knowledgeElementDetailService.generateSummaryAsync(req);
        if (result != null && result.getCode() == 8200) {
            log.info("创建摘要任务成功：elementCode={}", element.getCode());
        } else {
            log.warn("创建摘要任务失败：elementCode={}, message={}", element.getCode(), result != null ? result.getMessage() : "null");
            // 恢复状态
            knowledgeElementService.updateSummaryStatus(element.getCode(), SummaryStatus.PENDING.getCode());
        }
    }

    /**
     * 取消待执行的任务
     */
    private void cancelPendingTasks(String elementCode) {
        List<SaasKnowledgeSummaryAsyncTask> tasks = summaryAsyncTaskService.selectTasksByElementCode(elementCode);
        if (CollUtil.isEmpty(tasks)) {
            return;
        }

        for (SaasKnowledgeSummaryAsyncTask task : tasks) {
            if (TaskStatus.PENDING.getCode().equals(task.getStatus()) ||
                TaskStatus.EXECUTING.getCode().equals(task.getStatus())) {
                summaryAsyncTaskService.updateTaskStatus(task.getCode(), TaskStatus.CANCELED.getCode(), "文档已更新");
            }
        }
    }

    /**
     * 处理PENDING状态的孤儿任务
     * 程序重启后MQ消息可能丢失，扫描DB中PENDING任务重新发送到队列。
     * 重要：仅在消费者有空闲容量时才发送，避免MQ队列积压导致重复消费。
     */
    private void processOrphanedPendingTasks() {
        // 检查消费者容量：如果活跃任务已达上限，不发送新任务到MQ
        int activeTasks = dynamicQMPPoolService.getActiveSummaryTasks();
        int maxConcurrent = 10; // 与 DynamicQMPPoolService.maxConcurrentSummaryTasks 对齐
        if (activeTasks >= maxConcurrent) {
            log.debug("消费者已达上限（{}/{}），跳过孤儿任务恢复", activeTasks, maxConcurrent);
            return;
        }

        // 检查MQ队列存量：如果队列已有消息堆积，等待消费后再发
        int queueSize = rabbitMessageService.getSummaryTaskQueueSize();
        if (queueSize > 0) {
            log.debug("MQ队列已有{}条消息等待消费，跳过孤儿任务发送", queueSize);
            return;
        }

        List<SaasKnowledgeSummaryAsyncTask> pendingTasks = summaryAsyncTaskService.selectPendingTasks(batchSize);

        if (CollUtil.isEmpty(pendingTasks)) {
            return;
        }

        int sentCount = 0;
        int availableSlots = maxConcurrent - activeTasks;
        for (SaasKnowledgeSummaryAsyncTask task : pendingTasks) {
            if (sentCount >= availableSlots) {
                break;
            }
            // 仅处理创建超过2分钟的任务，避免重复发送刚创建的任务
            if (task.getCreatedTime() != null
                    && task.getCreatedTime().isAfter(LocalDateTime.now().minusMinutes(2))) {
                continue;
            }

            try {
                // 检查文档是否还存在
                Optional<SaasKnowledgeElement> elementOpt = knowledgeElementService.queryByCode(task.getElementCode(), task.getTenantId());
                if (elementOpt.isEmpty()) {
                    log.info("文档已删除，取消任务：taskCode={}", task.getCode());
                    summaryAsyncTaskService.updateTaskStatus(task.getCode(), TaskStatus.CANCELED.getCode(), "文档已删除");
                    continue;
                }

                SaasKnowledgeElement element = elementOpt.get();

                // 检查文档解析状态
                if (element.getProcessStatus() == null || element.getProcessStatus() != ProcessStatusEnum.SUCCESS.getCode()) {
                    continue;
                }

                // 检查文档是否已更新
                if (task.getElementUpdatedTime() != null && element.getModifierTime() != null
                        && element.getModifierTime().isAfter(task.getElementUpdatedTime())) {
                    log.info("文档已更新，取消旧任务：taskCode={}, elementCode={}", task.getCode(), task.getElementCode());
                    summaryAsyncTaskService.updateTaskStatus(task.getCode(), TaskStatus.CANCELED.getCode(), "文档已更新");
                    continue;
                }

                // 仅在有空闲槽位时发送
                MessageSummaryTaskReq mqReq = new MessageSummaryTaskReq();
                mqReq.setTaskCode(task.getCode());
                mqReq.setTenantId(task.getTenantId());
                mqReq.setContainerId(task.getContainerId());
                mqReq.setElementCode(task.getElementCode());
                mqReq.setModelCode(task.getModelCode());
                mqReq.setTemperature(task.getTemperature());
                mqReq.setTopP(task.getTopP());
                mqReq.setElementUpdatedTime(task.getElementUpdatedTime() != null ?
                        task.getElementUpdatedTime().toString() : null);

                rabbitMessageService.sendSummaryTaskMsg(mqReq);
                sentCount++;
                log.info("重新发送PENDING孤儿任务到MQ：taskCode={}", task.getCode());

            } catch (Exception e) {
                log.error("重新发送PENDING孤儿任务失败：taskCode={}", task.getCode(), e);
            }
        }

        if (sentCount > 0) {
            log.info("孤儿任务恢复：扫描{}个PENDING，发送{}个到MQ（空闲槽位={}）",
                    pendingTasks.size(), sentCount, availableSlots);
        }
    }

    /**
     * 处理失败重试任务
     */
    private void processFailedRetryTasks() {
        // 扫描失败且可重试的任务
        List<SaasKnowledgeSummaryAsyncTask> failedTasks = summaryAsyncTaskService.selectFailedTasksForRetry(batchSize, MAX_RETRY_COUNT);

        if (CollUtil.isEmpty(failedTasks)) {
            return;
        }

        log.info("扫描到 {} 个失败重试任务", failedTasks.size());

        for (SaasKnowledgeSummaryAsyncTask task : failedTasks) {
            try {
                processFailedTask(task);
            } catch (Exception e) {
                log.error("处理失败任务重试失败：taskCode={}", task.getCode(), e);
            }
        }
    }

    /**
     * 处理单个失败任务
     */
    private void processFailedTask(SaasKnowledgeSummaryAsyncTask task) {
        // 检查文档是否还存在
        Optional<SaasKnowledgeElement> elementOpt = knowledgeElementService.queryByCode(task.getElementCode(), task.getTenantId());
        if (elementOpt.isEmpty()) {
            // 文档已删除，标记任务为最终失败
            log.info("文档已删除，标记任务为最终失败：taskCode={}", task.getCode());
            summaryAsyncTaskService.updateTaskStatus(task.getCode(), TaskStatus.FINAL_FAILED.getCode(), "文档已删除");
            knowledgeElementService.updateSummaryStatus(task.getElementCode(), SummaryStatus.NONE.getCode());
            return;
        }

        // 重置任务状态为待执行
        summaryAsyncTaskService.updateTaskStatus(task.getCode(), TaskStatus.PENDING.getCode(), null);
        summaryAsyncTaskService.incrementRetryCount(task.getCode());
        log.info("重置失败任务状态：taskCode={}, retryCount={}", task.getCode(), task.getRetryCount() + 1);
    }

