    @Transactional(rollbackFor = Exception.class)
    @Override
    public Result<String> importWebs(KnowledgeElementBatchWebReq webReq) {
        log.info("批量导入web集合");
        webReq.validateWebUrl();
        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        // 校验知识库文件
        knowledgeValidationService.validateFileBase(webReq, sysUserInfo.getTenantId());
        // 每个网页按1KB计算
        long totalSpace = webReq.getUrls().size() * 1024L;
        // 校验上传流量空间
        Assert.isTrue(billingSubscribeAccountService.validateAvailableStorage(sysUserInfo.getTenantId(), totalSpace), "knowledge.preview.upload.limit");
        List<SaasKnowledgeElement> saasKnowledgeElements = webReq.of(sysUserInfo);
        Result<String> result = this.lockBatchFile(saasKnowledgeElements, sysUserInfo.getTenantId(), totalSpace, new ArrayList<>(), webReq.getContainerId());

        // 记录日志
        CommonLog.knowledge.action(ActionType.IMPORT_BATCH, "批量导入Web知识文件，数量:{}", webReq.getUrls().size()).send();

        return result;
    }

    @Transactional(rollbackFor = Exception.class)
    @Override
    public Result<List<KnowledgeElementImportResp>> importFiles(KnowledgeElementBatchFileReq batchFileReq, MultipartFile[] multipartFiles) {
        Assert.notEmpty(multipartFiles, "system.common.request.invalid");
        log.info("批量导入paas层接口文件，数量:{}", multipartFiles.length);
        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        // 校验知识库文件
        knowledgeValidationService.validateFileBase(batchFileReq, sysUserInfo.getTenantId());
        FileValidationResult fileValidationResult = knowledgeValidationService.files(multipartFiles);
        // 总流量
        long totalSpace = fileValidationResult.getTotalSpace().get();
        // 校验上传流量空间
        Assert.isTrue(billingSubscribeAccountService.validateAvailableStorage(sysUserInfo.getTenantId(), totalSpace), "knowledge.preview.upload.limit");
        List<SaasKnowledgeElement> saasKnowledgeElements = new ArrayList<>();
        for (MultipartFile file : multipartFiles) {
            FileMetadata fileMetadata = fileValidationResult.fileMeta(file);
            // 上传
            MaterialInfoResp material = materialService.save(file, fileMetadata.getMd5(), sysUserInfo.getTenantId());
            saasKnowledgeElements.add(batchFileReq.of(file, sysUserInfo, fileValidationResult, material.getFileUrl()));
        }
        Result<String> result = this.lockBatchFile(saasKnowledgeElements, sysUserInfo.getTenantId(), totalSpace, new ArrayList<>(), batchFileReq.getContainerId());

        // 记录日志
        CommonLog.knowledge.action(ActionType.IMPORT_BATCH, "批量导入知识文件，数量:{}", multipartFiles.length).send();
        if (!ErrorCodeEnum.SUCCESS.getCode().equals(result.getCode())) {
            return Result.error(result.getMessage());
        }
        List<KnowledgeElementImportResp> importResps = saasKnowledgeElements.stream().map(KnowledgeElementImportResp::from).toList();
        return Result.data(importResps, result.getMessage());
    }

