    @Transactional(rollbackFor = Exception.class)
    @Override
    public void addKnowledge(BusinessTable table, List<BusinessColumn> columns, SysUserInfo sysUserInfo, String containerId) {
        // 将当前的表格信息+字段列表信息，全部保存成txt文本，方便后续向量化处理
        String tableContent = SQLUtils.toTxt(table, columns);
        // 插入一条知识文件信息，类型是Table
        SaasKnowledgeElement element = new SaasKnowledgeElement();
        File tableFile = null;
        try {
            tableFile = File.createTempFile("table_source", ".txt");
            FileUtil.writeString(tableContent, tableFile, StandardCharsets.UTF_8);
            // 上传文件
            String md5_str = MD5.create().digestHex16(tableContent);
            MaterialInfoResp materialInfoResp = materialService.save(tableFile, md5_str, sysUserInfo.getTenantId());
            // 上传成功
            String ossUrl = materialInfoResp.getFileUrl();
            element.setNeverExpire(DocTimeStatus.NEVER_EXPIRE.getCode());
            element.setContainerId(table.getContainerId());
            element.setElePreviewUrl(ossUrl);
            element.setEleUrl(ossUrl);
            element.setTenantId(sysUserInfo.getTenantId());
            element.setEleSuffix("txt");
            element.setEleName(table.getName());
            element.setEleMd5(md5_str);
            element.setEleSize(FileUtil.size(tableFile));
            // 没有预览功能，该值为空
            element.setEleTokenSize(0L);
            element.setCreateTime(LocalDateTime.now());
            element.setCreator(Objects.toString(sysUserInfo.getId()));
            element.setModifierTime(LocalDateTime.now());
            element.setModifier(Objects.toString(sysUserInfo.getId()));
            element.setProcessStatus(ProcessStatusEnum.INIT.getCode());
            element.setParentCode("0");
            // 关联表信息的code
            element.setCode(table.getCode());
            element.setPageCount(1);
            element.setProcessCount(0);
            element.setYear(0);
            element.setCategory(KnowledgeElementCategory.TABLE.name());
            element.setTopic("DEFAULT");
            element.setChunkCount(0);
            // 批量导入文本信息
            this.lockBatchFile(CollUtil.newArrayList(element), sysUserInfo.getTenantId(), element.getEleSize(), new ArrayList<>(), containerId);
        } catch (IOException e) {
            throw new RuntimeException(e);
        } finally {
            FileUtil.del(tableFile);
        }
    }

