    @Override
    public void callback(DataSetChunkCallbackReq callbackReq) {
        // 判断process类型
        if (callbackReq.getBasic() == null) {
            return;
        }
        try {
            LambdaQueryWrapper<SaasKnowledgeElement> lambdaQueryWrapper = Wrappers.lambdaQuery(SaasKnowledgeElement.class).eq(SaasKnowledgeElement::getTenantId, callbackReq.getBasic().getTenantId())
                    .eq(SaasKnowledgeElement::getContainerId, callbackReq.getBasic().getContainerId())
                    .eq(SaasKnowledgeElement::getCode, callbackReq.getBasic().getDataId());
            SaasKnowledgeElement knowledgeElement = new SaasKnowledgeElement();
            knowledgeElement.setModifierTime(LocalDateTime.now());
            knowledgeElement.setProcessCount(callbackReq.getProcessPage());
            knowledgeElement.setPageCount(callbackReq.getTotalPage());
            knowledgeElement.setChunkCount(callbackReq.getChunkCounter());
            if (StrUtil.isNotBlank(callbackReq.getMessage())) {
                knowledgeElement.setErrorMessage(callbackReq.getMessage());
            }
            ProcessStatusEnum processStatusEnum = ProcessStatusEnum.parseByName(callbackReq.getProcessStatus());
            if (processStatusEnum != null) {
                knowledgeElement.setProcessStatus(processStatusEnum.getCode());
            }
            saasKnowledgeElementMapper.update(knowledgeElement, lambdaQueryWrapper);
            if (processStatusEnum != null) {
                // callback使用code查询对应element id
                SaasKnowledgeElement dbElement = saasKnowledgeElementMapper.selectOne(lambdaQueryWrapper);
                if (dbElement != null) {
                    knowledgeElementProcessService.updateProcessStatus(dbElement.getId(), processStatusEnum);
                }
            }
        } catch (Exception e) {
            log.error(e.getMessage());
        }
    }

    @Override
    public DataSetChunkSubmitModel buildChunkParams(SaasKnowledgeElement knowledgeElement, String callbackUrl) {
        // 定时任务只处理文件类型和网页类型
        Assert.isTrue(StrUtil.equalsIgnoreCase(knowledgeElement.getCategory(), KnowledgeElementCategory.FILE.getName())
                || StrUtil.equalsIgnoreCase(knowledgeElement.getCategory(), KnowledgeElementCategory.WEB.getName())
                || StrUtil.equalsIgnoreCase(knowledgeElement.getCategory(), KnowledgeElementCategory.VIRTUAL_FILE.getName()), "system.common.request.invalid");
        DataSetChunkSubmitModel submitModel = new DataSetChunkSubmitModel();
        submitModel.setCallbackUrl(callbackUrl);
        submitModel.setOssUrl(knowledgeElement.getEleUrl());
        submitModel.setDataId(knowledgeElement.getCode());
        submitModel.setTenantId(knowledgeElement.getTenantId());
        submitModel.setTimeStatus(knowledgeElement.getNeverExpire());
        if (knowledgeElement.getStartTime() != null && knowledgeElement.getEndTime() != null) {
            submitModel.setStartTime(knowledgeElement.getStartTime().atZone(ZoneId.systemDefault()).toInstant().toEpochMilli());
            submitModel.setEndTime(knowledgeElement.getEndTime().atZone(ZoneId.systemDefault()).toInstant().toEpochMilli());
        }
        submitModel.setYear(knowledgeElement.getYear());
        submitModel.setFileName(knowledgeElement.getEleName());
        submitModel.setFileType(knowledgeElement.getEleSuffix());
        submitModel.setContainerId(knowledgeElement.getContainerId());
        // 判断是否为网页
        if (StrUtil.equalsIgnoreCase(knowledgeElement.getCategory(), KnowledgeElementCategory.WEB.getName())) {
            Optional<DataSetWebConfig> webConfig = GsonUtils.fromJson(knowledgeElement.getConfig(), DataSetWebConfig.class);
            webConfig.ifPresent(submitModel::apply);
            // webConfig.ifPresent(w -> submitModel.setSelector(w.getSelector()));
        }
        // 租户配置,embedding模型
        // SaasTenantInfoCacheResp cacheResp = tenantInfoService.getByCode(knowledgeElement.getTenantId());

        Optional<SaasKnowledgeConfigContainer> saasKnowledgeConfigContainer = saasKnowledgeConfigContainerService.queryInfoByContainerId(knowledgeElement.getContainerId());
        if (saasKnowledgeConfigContainer.isPresent()) {
            submitModel.setEmbedding(saasKnowledgeConfigContainer.get().getEmbeddingModel());
        } else {
            log.error("containerId:{} not found", knowledgeElement.getContainerId());
            throw new BizException(ErrorCodeEnum.SYSTEM_ERROR);
        }

        return submitModel;
    }

