    @Override
    public void updateConvert(MessageFileConvertReq convertReq, KnowledgeFileConvertResult convertResult) {
        SaasKnowledgeElement element = new SaasKnowledgeElement();
        element.setId(convertReq.getDataId());
        element.setModifierTime(LocalDateTime.now());
        if (convertResult.getStatusEnum() == ProcessStatusEnum.CONVERT_SUCCESS) {
            // 转换成功，才更新相关信息
            element.setEleUrl(convertResult.getOssUrl());
            element.setEleSuffix(convertResult.getTargetFormat());
            // preview地址设置为老的地址
            element.setElePreviewUrl(convertReq.getOssUrl());
            element.setProcessStatus(convertResult.getStatusEnum().getCode());
        } else if (convertResult.getStatusEnum() == ProcessStatusEnum.PROCESSING) {
            // Process的状态，代表提交处理成功，此时，不更新processStatus的状态
            // 转换成功，才更新相关信息
            element.setEleUrl(convertResult.getOssUrl());
            element.setEleSuffix(convertResult.getTargetFormat());
            // preview地址设置为老的地址
            element.setElePreviewUrl(convertReq.getOssUrl());
        } else {
            // 其它状态，可能是失败等状态信息
            element.setProcessStatus(convertResult.getStatusEnum().getCode());
        }
        LambdaQueryWrapper<SaasKnowledgeElement> lambdaQueryWrapper =
                Wrappers.lambdaQuery(SaasKnowledgeElement.class).eq(SaasKnowledgeElement::getId, convertReq.getDataId()).eq(SaasKnowledgeElement::getTenantId, convertReq.getTenantId());
        saasKnowledgeElementMapper.update(element, lambdaQueryWrapper);
        // PROCESSING分支不更新processStatus，其余分支均需写Redis
        if (convertResult.getStatusEnum() != ProcessStatusEnum.PROCESSING) {
            knowledgeElementProcessService.updateProcessStatus(convertReq.getDataId(), convertResult.getStatusEnum());
        }
    }

    /**
     * 分页查询-知识库元素列表数据
     *
     * @param knowledgeElementQueryReq 查询条件Vo
     * @param pageNo                   当前页码
     * @param pageSize                 每页页码大小
     * @return 知识库元素列表
     */
    @Override
    public Pagination<KnowledgeElementResp> list(KnowledgeElementQueryReq knowledgeElementQueryReq, Integer pageNo, Integer pageSize) {
        if (StrUtil.isNotBlank(knowledgeElementQueryReq.getPageCode())) {
            return listWithPath(knowledgeElementQueryReq, pageNo, pageSize);
        }
        log.info("分页查询知识库元素列表,pageNo:{},pageSize:{}", pageNo, pageSize);
        log.info("分页QueryReq:{}", knowledgeElementQueryReq.toString());
        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        // 查询全部列表的
        DepartmentUserOrgPermissions orgPermissions = kbDepartmentUserService.listAccessibleDepartmentCodes(sysUserInfo);

        LambdaQueryWrapper<SaasKnowledgeElement> lambdaQueryWrapper = Wrappers.lambdaQuery(SaasKnowledgeElement.class).eq(SaasKnowledgeElement::getTenantId, sysUserInfo.getTenantId());
        // 查询条件
        lambdaQueryWrapper.eq(StrUtil.isNotBlank(knowledgeElementQueryReq.getContainerId()), SaasKnowledgeElement::getContainerId, knowledgeElementQueryReq.getContainerId());
        lambdaQueryWrapper.eq(StrUtil.isNotBlank(knowledgeElementQueryReq.getParentCode()), SaasKnowledgeElement::getParentCode, knowledgeElementQueryReq.getParentCode());
        if (StrUtil.isNotBlank(knowledgeElementQueryReq.getCategory())) {
            List<String> category = StrUtil.split(knowledgeElementQueryReq.getCategory(), StrUtil.COMMA);
            lambdaQueryWrapper.in(SaasKnowledgeElement::getCategory, category);
        }
        lambdaQueryWrapper.like(StrUtil.isNotBlank(knowledgeElementQueryReq.getEleName()), SaasKnowledgeElement::getEleName, knowledgeElementQueryReq.getEleName());
        // 草稿状态只能自己可见
        lambdaQueryWrapper.and(l -> {
            l.ne(SaasKnowledgeElement::getProcessStatus, ProcessStatusEnum.DRAFT.getCode()).or(lf -> {
                lf.eq(SaasKnowledgeElement::getProcessStatus, ProcessStatusEnum.DRAFT.getCode());
                lf.eq(SaasKnowledgeElement::getCreator, Objects.toString(sysUserInfo.getCode()));
            });
        });
        // 过滤权限，因为parentCode不为空，那么查询出当前用户不可见的文档编码，然后在进行过滤
        ElementSearchCondition searchCondition = ElementSearchCondition.from(sysUserInfo.getTenantId(), knowledgeElementQueryReq.getContainerId(), knowledgeElementQueryReq.getParentCode(), orgPermissions.permissionCodesToList());
        List<String> visibleCodes = saasKnowledgeElementMapper.listVisibleCodes(searchCondition);
        if (CollUtil.isNotEmpty(visibleCodes)) {
            // 继承的权限文档全部可见，然后可见的文档也可见
            log.info("过滤掉不可见的权限code列表，size:{}", visibleCodes.size());
            lambdaQueryWrapper.and(lf -> lf.eq(SaasKnowledgeElement::getPermissionStatus, ToggleStatusEnum.YES.getCode()).or(l1 -> {
                l1.eq(SaasKnowledgeElement::getPermissionStatus, ToggleStatusEnum.NO.getCode());
                l1.in(SaasKnowledgeElement::getCode, visibleCodes);
            }));

            ///lambdaQueryWrapper.notIn(SaasKnowledgeElement::getCode,notVisibleCodes);
        } else {
            // 没有任何可见的文档
            log.info("没有权限，查询继承下来的文档");
            lambdaQueryWrapper.eq(SaasKnowledgeElement::getPermissionStatus, ToggleStatusEnum.YES.getCode());
        }
        //创建者/修改者过滤
        if (StrUtil.isNotBlank(knowledgeElementQueryReq.getUserName())) {
            List<String> userCodesByName = queryUserCodesByNameLike(knowledgeElementQueryReq.getUserName(), sysUserInfo.getTenantId());
            if (CollUtil.isEmpty(userCodesByName)) {
                return Pagination.pagination(Collections.emptyList(), 0, pageNo, pageSize);
            }
            lambdaQueryWrapper.and(w -> w.in(SaasKnowledgeElement::getCreator, userCodesByName)
                    .or().in(SaasKnowledgeElement::getModifier, userCodesByName));
        }

        // 启用/禁用过滤
        if (ObjectUtil.isNotEmpty(knowledgeElementQueryReq.getEnable())) {
            lambdaQueryWrapper.eq(SaasKnowledgeElement::getEnable, knowledgeElementQueryReq.getEnable());
        }
        // 生效时间范围过滤
        String effectStart = knowledgeElementQueryReq.getEffectTimeStart();
        String effectEnd = knowledgeElementQueryReq.getEffectTimeEnd();
        if (StrUtil.isNotBlank(effectStart) || StrUtil.isNotBlank(effectEnd)) {
            lambdaQueryWrapper.and(w -> w.eq(SaasKnowledgeElement::getNeverExpire, 1)
                    .or(or -> {
                        if (StrUtil.isNotBlank(effectStart) && StrUtil.isNotBlank(effectEnd)) {
                            or.ge(SaasKnowledgeElement::getStartTime, effectStart)
                                    .le(SaasKnowledgeElement::getEndTime, effectEnd);
                        } else if (StrUtil.isNotBlank(effectStart)) {
                            or.ge(SaasKnowledgeElement::getStartTime, effectStart);
                        } else if (StrUtil.isNotBlank(effectEnd)) {
                            or.le(SaasKnowledgeElement::getEndTime, effectEnd);
                        }
                    })
            );
        }
        // 创建时间范围过滤
        lambdaQueryWrapper.ge(StrUtil.isNotEmpty(knowledgeElementQueryReq.getCreateTimeStart()), SaasKnowledgeElement::getCreateTime, knowledgeElementQueryReq.getCreateTimeStart());
        lambdaQueryWrapper.le(StrUtil.isNotEmpty(knowledgeElementQueryReq.getCreateTimeEnd()), SaasKnowledgeElement::getCreateTime, knowledgeElementQueryReq.getCreateTimeEnd());
        // 修改时间范围过滤
        lambdaQueryWrapper.ge(StrUtil.isNotEmpty(knowledgeElementQueryReq.getModifyTimeStart()), SaasKnowledgeElement::getModifierTime, knowledgeElementQueryReq.getModifyTimeStart());
        lambdaQueryWrapper.le(StrUtil.isNotEmpty(knowledgeElementQueryReq.getModifyTimeEnd()), SaasKnowledgeElement::getModifierTime, knowledgeElementQueryReq.getModifyTimeEnd());
        //处理状态过滤
        if (ObjectUtil.isNotEmpty(knowledgeElementQueryReq.getProcessStatus())) {
            lambdaQueryWrapper.eq(SaasKnowledgeElement::getProcessStatus, knowledgeElementQueryReq.getProcessStatus());
            lambdaQueryWrapper.ne(SaasKnowledgeElement::getCategory, KnowledgeElementCategory.DIRECTORY.name());
        }

        // 设定排序规则
        SortRules sortRule = SortRules.parse(knowledgeElementQueryReq.getSortRule());
        if (sortRule == SortRules.SORT_NUMBER) {
            lambdaQueryWrapper.orderByAsc(SaasKnowledgeElement::getSort);
        } else if (sortRule == SortRules.SORT_CREATE_TIME) {
            // 判断倒序还是顺序
            if (knowledgeElementQueryReq.getSortType() == 0) {
                lambdaQueryWrapper.orderByAsc(SaasKnowledgeElement::getCreateTime);
            } else {
                lambdaQueryWrapper.orderByDesc(SaasKnowledgeElement::getCreateTime);
            }
        } else if (sortRule == SortRules.SORT_MODIFY_TIME) {
            // 判断倒序还是顺序
            if (knowledgeElementQueryReq.getSortType() == 0) {
                lambdaQueryWrapper.orderByAsc(SaasKnowledgeElement::getModifierTime);
            } else {
                lambdaQueryWrapper.orderByDesc(SaasKnowledgeElement::getModifierTime);
            }
        } else if (sortRule == SortRules.SORT_TITLE) {
            // 对于文件名排序，不在数据库层排序，而在内存中进行自定义排序
            // 这样可以支持按数字前缀排序的需求
        }

        List<SaasKnowledgeElement> saasKnowledgeElementInfos;
        List<KnowledgeElementResp> knowledgeElementRespInfos;
        long count;

        if (sortRule == SortRules.SORT_TITLE) {
            // 文件名排序需要在内存中进行，所以先查询所有数据
            saasKnowledgeElementInfos = saasKnowledgeElementMapper.selectList(lambdaQueryWrapper);
            count = saasKnowledgeElementInfos.size();

            // 按照文件名进行自定义排序（支持数字前缀排序）
            saasKnowledgeElementInfos.sort((a, b) -> compareFileName(a.getEleName(), b.getEleName(), knowledgeElementQueryReq.getSortType()));

            // 手动分页
            int startIndex = (pageNo - 1) * pageSize;
            int endIndex = Math.min(startIndex + pageSize, saasKnowledgeElementInfos.size());
            if (startIndex < saasKnowledgeElementInfos.size()) {
                saasKnowledgeElementInfos = saasKnowledgeElementInfos.subList(startIndex, endIndex);
            } else {
                saasKnowledgeElementInfos = new ArrayList<>();
            }

            knowledgeElementRespInfos = new ArrayList<>();
        } else {
            // 其他排序规则使用数据库分页
            try (Page<SaasKnowledgeElement> saasKnowledgeElementPageNo = PageHelper.startPage(pageNo, pageSize)) {
                saasKnowledgeElementInfos = saasKnowledgeElementMapper.selectList(lambdaQueryWrapper);
                knowledgeElementRespInfos = new ArrayList<>();
                count = saasKnowledgeElementPageNo.getTotal();
            }
        }
        if (CollectionUtil.isNotEmpty(saasKnowledgeElementInfos)) {
            knowledgeElementRespInfos.addAll(saasKnowledgeElementInfos.stream().map(new SaasKnowledgeElementApplyFunction()).toList());
            // 批量填充creatorName和modifierName
            Set<String> userCodes = new HashSet<>();
            for (KnowledgeElementResp resp : knowledgeElementRespInfos) {
                userCodes.addAll(resp.userCodes());
            }
            if (!userCodes.isEmpty()) {
                Map<String, String> userMap = userService.selectByCode(new ArrayList<>(userCodes));
                for (KnowledgeElementResp resp : knowledgeElementRespInfos) {
                    resp.applyUserName(userMap);
                }
            }
        }
        return Pagination.pagination(knowledgeElementRespInfos, count, pageNo, pageSize);
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public Result moveEle(KnowledgeElementMoveReq req) {
        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        Assert.notNull(sysUserInfo, "system.common.request.invalid");
        Assert.isTrue(StrUtil.isNotBlank(req.getTargetContainerId()), "目标知识库不能为空");
        Assert.isTrue(StrUtil.isNotBlank(req.getContainerId()), "来源知识库不能为空");
        Assert.isFalse(req.getPageCodeList().contains(req.getTargetPageCode()), "文件夹无法移动到自己下面");
        knowledgePermissionGuardService.assertContainerEditPermission(req.getTargetContainerId(), sysUserInfo);

        // 组装待处理根code列表
        List<String> rootCodes = new ArrayList<>();
        if (CollUtil.isNotEmpty(req.getPageCodeList())) {
            rootCodes.addAll(req.getPageCodeList());
        } else if (StrUtil.isNotBlank(req.getPageCode())) {
            rootCodes.add(req.getPageCode());
        }
        Assert.isTrue(CollUtil.isNotEmpty(rootCodes), "至少选择一个需要处理的页面/文件夹");
        String tenantId = sysUserInfo.getTenantId();
        boolean moveOpt = req.isDelCurrentEle(); // true-移动, false-复制
        boolean ensurePublished = req.isEnsurePublished();
        String sourceContainerId = req.getContainerId();
        String targetContainerId = req.getTargetContainerId();
        // 查询容器存在
        Assert.isTrue(knowledgeContainerQueryService.queryInfoByCode(sourceContainerId).isPresent(), "来源知识库不存在");
        Assert.isTrue(knowledgeContainerQueryService.queryInfoByCode(targetContainerId).isPresent(), "目标知识库不存在");
        // 构建整棵子树元素列表(包含所有子级)
        List<SaasKnowledgeElement> sourceAllElements = new ArrayList<>();
        Set<String> visitedCodes = new HashSet<>();
        for (String code : rootCodes) {
            Optional<SaasKnowledgeElement> elementOpt = queryInfoByCode(code);
            if (elementOpt.isEmpty()) {
                log.warn("根元素不存在，跳过 code:{}", code);
                continue;
            }
            SaasKnowledgeElement rootEle = elementOpt.get();
            // 校验来源容器&租户
            if (!StrUtil.equals(rootEle.getContainerId(), sourceContainerId) || !StrUtil.equals(rootEle.getTenantId(), tenantId)) {
                log.warn("元素不属于来源容器或租户不匹配，跳过 code:{}", code);
                continue;
            }
            boolean isDir = StrUtil.equalsIgnoreCase(rootEle.getCategory(), KnowledgeElementCategory.DIRECTORY.getName());
            boolean copyMode = !moveOpt; // 复制模式
            // 复制模式且不包含子文件夹且根为目录 => 仅复制根目录和其直接文件(排除子文件夹)
            if (copyMode && !req.isSubfolder() && isDir) {
                // 根目录
                if (visitedCodes.add(rootEle.getCode())) {
                    sourceAllElements.add(rootEle);
                }
                // 直接子级(不包含目录类型)
                List<SaasKnowledgeElement> directChildren = saasKnowledgeElementMapper.selectList(
                        Wrappers.lambdaQuery(SaasKnowledgeElement.class)
                                .eq(SaasKnowledgeElement::getTenantId, tenantId)
                                .eq(SaasKnowledgeElement::getContainerId, sourceContainerId)
                                .eq(SaasKnowledgeElement::getParentCode, rootEle.getCode())
                                .ne(SaasKnowledgeElement::getCategory, KnowledgeElementCategory.DIRECTORY.getName())
                );
                for (SaasKnowledgeElement child : directChildren) {
                    if (visitedCodes.add(child.getCode())) {
                        sourceAllElements.add(child);
                    }
                }
            } else {
                // 整棵子树
                Queue<SaasKnowledgeElement> queue = new ArrayDeque<>();
                queue.add(rootEle);
                while (!queue.isEmpty()) {
                    SaasKnowledgeElement current = queue.poll();
                    if (visitedCodes.add(current.getCode())) { // 只第一次加入，避免重复
                        sourceAllElements.add(current);
                        List<SaasKnowledgeElement> children = saasKnowledgeElementMapper.selectList(
                                Wrappers.lambdaQuery(SaasKnowledgeElement.class)
                                        .eq(SaasKnowledgeElement::getTenantId, tenantId)
                                        .eq(SaasKnowledgeElement::getContainerId, sourceContainerId)
                                        .eq(SaasKnowledgeElement::getParentCode, current.getCode())
                        );
                        if (CollUtil.isNotEmpty(children)) {
                            children.forEach(queue::add);
                        }
                    }
                }
            }
        }
        if (CollUtil.isEmpty(sourceAllElements)) {
            return Result.error("未找到可处理的元素");
        }
        // 权限过滤逻辑
        boolean sameContainer = StrUtil.equals(sourceContainerId, targetContainerId);
        List<SaasKnowledgeElement> permittedElements = new ArrayList<>();
        Set<String> skippedParentCode = new HashSet<>();
        List<String> skippedCodes = new ArrayList<>();
        for (SaasKnowledgeElement ele : sourceAllElements) {
            try {
                // 查询来源容器对该元素的权限
                Result<String> srcPermRet = knowledgeContainerQueryService.queryPermissionByCode(sourceContainerId, ele.getCode());
                String srcPerm = srcPermRet.getData();
                if (!hasMoveOrCopySourcePermission(srcPerm, sameContainer, moveOpt)) {
                    skippedCodes.add(ele.getCode());
                    skippedParentCode.add(ele.getParentCode());
                    continue;
                }
                permittedElements.add(ele);
            } catch (Exception ex) {
                log.warn("权限校验异常, elementCode:{}, msg:{}", ele.getCode(), ex.getMessage());
                skippedCodes.add(ele.getCode());
            }
        }
        if (CollUtil.isEmpty(permittedElements)) {
            return Result.error("没有元素符合操作权限要求");
        }
        // 构建原始父子映射，后续用于保护父级
        Map<String, String> parentMap = sourceAllElements.stream().collect(Collectors.toMap(SaasKnowledgeElement::getCode, SaasKnowledgeElement::getParentCode));
        // 计算需要保护的所有祖先（权限不足的元素向上递归）
        Set<String> protectedParentCodes = new HashSet<>();
        for (String skipped : skippedCodes) {
            String cur = skipped;
            // 向上递归，直到根 0 或不存在
            while (parentMap.containsKey(cur)) {
                String p = parentMap.get(cur);
                if (StrUtil.isBlank(p) || StrUtil.equals(p, "0")) {
                    break;
                }
                protectedParentCodes.add(p);
                cur = p;
            }
        }
        sourceAllElements = permittedElements; // 使用过滤后的集合
        // 统计需要占用的容量(复制时占用目标；移动时源释放目标占用)
        long totalSize = sourceAllElements.stream().mapToLong(e -> e.getEleSize() == null ? 0L : e.getEleSize()).sum();
        log.info("即将{}元素数量:{}, 总大小:{}, 跳过(权限不足):{}", moveOpt ? "移动" : "复制", sourceAllElements.size(), totalSize, skippedCodes);
        if (totalSize > 0) {
            knowledgeContainerCapacityDataService.validateContainerCapacity(targetContainerId, totalSize);
        }
        // 查询目标容器配置
        Optional<SaasKnowledgeConfigContainer> targetConfigOpt = saasKnowledgeConfigContainerService.queryInfoByContainerId(targetContainerId);
        if (targetConfigOpt.isEmpty()) {
            return Result.error("目标知识库缺少配置");
        }
        SaasKnowledgeConfigContainer targetConfig = targetConfigOpt.get();
        // 查询各父级在目标的最大排序, root parent = "0"
        Map<String, AtomicInteger> parentSortSeed = new HashMap<>();
        Function<String, Integer> nextSortFunc = (parentCode) -> {
            AtomicInteger seed = parentSortSeed.get(parentCode);
            if (seed == null) {
                Integer maxOrder = saasKnowledgeElementMapper.maxOrder(tenantId, targetContainerId, parentCode);
                seed = new AtomicInteger(Objects.requireNonNullElse(maxOrder, 0));
                parentSortSeed.put(parentCode, seed);
            }
            return seed.addAndGet(KbConst.MOVE_ORDER_LAST_NEXT);
        };
        // oldCode -> newCode 映射
        Map<String, String> codeMapping = new HashMap<>();
        // 按层次顺序(父在前)构建新元素列表
        List<SaasKnowledgeElement> newElements = new ArrayList<>();
        // 需要新增的解析配置
        List<SaasKnowledgeConfigElement> newConfigElements = new ArrayList<>();
        // 新页面的版本(仅保留当前状态,不拷贝历史) attachments需要
        List<Runnable> pageVersionTasks = new ArrayList<>();
        // 仅根元素记录删除动态(移动时)
        Set<String> rootSet = new HashSet<>(rootCodes);

        // 判断是否仅重命名单一根目录
        boolean onlyRenameRootDirectory = false;
        if (StrUtil.isNotEmpty(req.getEleName()) && rootCodes.size() == 1) {
            String singleRootCode = rootCodes.get(0);
            Optional<SaasKnowledgeElement> singleRootOpt = sourceAllElements.stream().filter(e -> StrUtil.equals(e.getCode(), singleRootCode)).findFirst();
            if (singleRootOpt.isPresent() && StrUtil.equalsIgnoreCase(singleRootOpt.get().getCategory(), KnowledgeElementCategory.DIRECTORY.getName())) {
                onlyRenameRootDirectory = true;
            }
        }
        boolean multiSelect = rootCodes.size() > 1;
        boolean hasEleName = StrUtil.isNotBlank(req.getEleName());
        Optional<SaasKnowledgeElement> rootElementOpt = sourceAllElements.stream().filter(e -> e.getCode().equals(rootCodes.get(0))).findFirst();
        boolean rootIsDirectory = rootElementOpt.map(e -> StrUtil.equalsIgnoreCase(e.getCategory(), KnowledgeElementCategory.DIRECTORY.getName())).orElse(false);
        // 场景2：单个目录且指定新名称，需要级联子元素追加“ 副本”
        boolean scenarioFolderRenameCascade = !multiSelect && hasEleName && rootIsDirectory;
        // 场景1：单个文件指定新名称，只重命名自身
        boolean scenarioSingleFileRename = !multiSelect && hasEleName && !rootIsDirectory;
        // 场景3：多选且未指定新名称，对所有被复制/移动的元素追加“副本”
        boolean scenarioMultiSelectCascade = multiSelect && !hasEleName;
        final String COPY_SUFFIX = " 副本";


        for (SaasKnowledgeElement source : sourceAllElements) {
            // 父级存在但未被复制（权限不足），且不是根，则跳过，避免孤儿节点
            if (!rootSet.contains(source.getCode()) && StrUtil.isNotBlank(source.getParentCode()) && !codeMapping.containsKey(source.getParentCode()) && !rootSet.contains(source.getParentCode())) {
                // 父节点不是根且未复制，则跳过该子节点
                continue;
            }
            SaasKnowledgeElement target = new SaasKnowledgeElement();
            BeanUtils.copyProperties(source, target);
            target.setId(null);
            String newCode = IdUtil.getSnowflakeNextIdStr();
            target.setCode(newCode);
            codeMapping.put(source.getCode(), newCode);
            String newParentCode;
            if (rootSet.contains(source.getCode())) {
                newParentCode = StrUtil.isBlank(req.getTargetPageCode()) ? "0" : req.getTargetPageCode();
            } else if (codeMapping.containsKey(source.getParentCode())) {
                newParentCode = codeMapping.get(source.getParentCode());
            } else {
                // 理论上已在前面 continue 过滤，这里兜底
                newParentCode = StrUtil.isBlank(req.getTargetPageCode()) ? "0" : req.getTargetPageCode();
            }
            target.setParentCode(newParentCode);

            target.setContainerId(targetContainerId);
            target.setTenantId(tenantId);
            //target.setCreateTime(LocalDateTime.now());
            target.setModifierTime(LocalDateTime.now());
            //target.setCreator(sysUserInfo.getCode());
            target.setModifier(sysUserInfo.getCode());
            target.setPermissionStatus(1);

            // 排序：根及每个父级下递增
            target.setSort(nextSortFunc.apply(newParentCode));

            if (ensurePublished && isPublishableElementCategory(source.getCategory())) {
                target.setProcessStatus(ProcessStatusEnum.INIT.getCode());
            } else if (!ProcessStatusEnum.DRAFT.equals(ProcessStatusEnum.parse(source.getProcessStatus()))) {
                target.setProcessStatus(ProcessStatusEnum.INIT.getCode());
            }

            // 收藏关注等清零
            target.setFollowers(0);
            target.setCollectCount(0);
            target.setLikesCount(0);
            target.setHotNumber(0);
            target.setReadCount(0);
            target.setProcessCount(0);

            // 重命名
            String originalName = source.getEleName();
            String finalName = originalName;
            boolean isRoot = rootSet.contains(source.getCode());
            if (scenarioSingleFileRename) {
                if (isRoot) {
                    finalName = req.getEleName();
                }
            } else if (scenarioFolderRenameCascade) {
                if (isRoot) {
                    finalName = req.getEleName(); // 根目录用新名称
                } else {
                    finalName = originalName + COPY_SUFFIX; // 子层级统一追加“ 副本”
                }
            } else if (scenarioMultiSelectCascade) {
                finalName = originalName + COPY_SUFFIX; // 多选全部追加“ 副本”
            } else if (hasEleName) {
                if (onlyRenameRootDirectory) {
                    if (isRoot) {
                        finalName = req.getEleName();
                    }
                } else {
                    finalName = req.getEleName();
                }
            }
            target.setEleName(finalName);

            newElements.add(target);
            // 构建解析配置(保持默认容器配置，可覆盖文件级别fileConfig参数)
            SaasKnowledgeConfigElement cfg = SaasKnowledgeConfigElement.builder()
                    .elementId(newCode)
                    .analysisEngine(targetConfig.getAnalysisEngine())
                    .analysisMode(targetConfig.getAnalysisMode())
                    .ocrEngine(targetConfig.getOcrEngine())
                    .multiModalityEngine(targetConfig.getMultiModalityEngine())
                    .splitMode(targetConfig.getSplitMode())
                    .maxChunkSize(targetConfig.getMaxChunkSize())
                    .overlapSize(targetConfig.getOverlapSize())
                    .maxChunkLength(targetConfig.getMaxChunkLength())
                    .splitDelimiters(targetConfig.getSplitDelimiters())
                    .imageOcr(targetConfig.getImageOcr())
                    .tenantId(targetConfig.getTenantId())
                    .sort(targetConfig.getSort())
                    .modifier(sysUserInfo.getCode())
                    .creator(sysUserInfo.getCode())
                    .modifierTime(LocalDateTime.now())
                    .containerId(targetContainerId)
                    .engineType(targetConfig.getEngineType())
                    .useOriginalContent(Cns.YES)
                    .createTime(LocalDateTime.now())
                    .build();
            newConfigElements.add(cfg);
            // 页面版本(只保留当前状态,不拷贝历史)
            if (StrUtil.equalsIgnoreCase(source.getCategory(), KnowledgeElementTypes.PAGE.name())
                    || StrUtil.equalsIgnoreCase(source.getCategory(), KnowledgeElementTypes.EXCEL.name())) {
                pageVersionTasks.add(() -> {
                    Optional<SaasKnowledgeElementVersion> latestOpt = knowledgeElementVersionService
                            .queryLatestVersionByPageCode(source.getCode(), tenantId, ensurePublished);
                    if (latestOpt.isEmpty() && ensurePublished) {
                        latestOpt = knowledgeElementVersionService.queryLatestVersionAnyStatusByPageCode(source.getCode(), tenantId);
                    }
                    SaasKnowledgeElementVersion latest = latestOpt.orElse(null);
                    String pageVersionCode = IdUtil.getSnowflakeNextIdStr();
                    SaasKnowledgeElementVersion record = new SaasKnowledgeElementVersion();
                    record.setCode(pageVersionCode);
                    record.setPageCode(newCode);
                    record.setTenantId(tenantId);
                    record.setCreator(sysUserInfo.getCode());
                    record.setCreateTime(LocalDateTime.now());
                    record.setModifier(sysUserInfo.getCode());
                    record.setUserCode(sysUserInfo.getCode());
                    record.setModifierTime(LocalDateTime.now());
                    record.setVersionNo(1);
                    record.setStatus(ensurePublished
                            ? KnowledgeElementVersionStatus.ISSUED.getCode()
                            : KnowledgeElementVersionStatus.DEFAULT.getCode());
                    if (latest != null) {
                        if (!ensurePublished) {
                            record.setStatus(KnowledgeElementVersionStatus.ISSUED.getCode());
                        }
                        record.setTitle(StrUtil.blankToDefault(target.getEleName(), latest.getTitle()));
                        record.setDescription(latest.getDescription());
                        record.setContent(latest.getContent());
                        record.setContentMarked(latest.getContentMarked());
                        record.setAttachmentCode(latest.getAttachmentCode());
                    } else {
                        record.setTitle(target.getEleName());
                        record.setDescription(source.getConfig());
                        record.setContent(source.getContent());
                        record.setContentMarked(source.getContentMarked());
                    }
                    saasKnowledgeElementVersionMapper.insert(record);
                });
            }
        }
        // 保存
        boolean saveOk = this.saveBatch(newElements);
        if (!saveOk) {
            return Result.error("元素新增失败");
        }
        // ===== QA元素内容复制补偿逻辑开始 =====
        try {
            // 只处理成功保存后的 QA 类型元素(复制与移动均执行)
            // 构建新元素快速索引，避免在新元素列表中多次线性查找
            Map<String, SaasKnowledgeElement> newElementIndex = newElements.stream()
                    .collect(Collectors.toMap(SaasKnowledgeElement::getCode, e -> e));
            int qaTotal = 0;            // 原始QA总数
            int qaAnswerCopied = 0;     // 成功复制答案数量
            int qaSimilarCopied = 0;    // 成功复制相似问数量(按QA计数,非问题条数)
            int qaSkipped = 0;          // 跳过的QA(找不到新元素或无数据)
            List<String> qaErrorCodes = new ArrayList<>(); // 复制失败的QA编码
            long startCopyTs = System.currentTimeMillis();

            for (SaasKnowledgeElement source : sourceAllElements) {
                if (!StrUtil.equalsIgnoreCase(source.getCategory(), KnowledgeElementCategory.QA.getName())) {
                    continue;
                }
                qaTotal++;
                String newCode = codeMapping.get(source.getCode());
                if (StrUtil.isBlank(newCode)) {
                    qaSkipped++;
                    continue;
                }
                SaasKnowledgeElement newEle = newElementIndex.get(newCode);
                if (newEle == null) {
                    qaSkipped++;
                    continue;
                }
                // 复制答案
                try {
                    String answer = null;
                    try {
                        answer = knowledgeReferenceService.getAnswer(source.getCode(), tenantId);
                    } catch (Exception ex) {
                        log.warn("获取QA答案失败, sourceCode:{}, msg:{}", source.getCode(), ex.getMessage());
                    }
                    if (StrUtil.isNotBlank(answer)) {
                        // 避免重复添加: 如果新元素本身已经有答案(极少出现),再判断是否相同
                        String newAnswerExist = null;
                        try {
                            newAnswerExist = knowledgeReferenceService.getAnswer(newEle.getCode(), tenantId);
                        } catch (Exception ignore) {
                        }
                        if (StrUtil.isBlank(newAnswerExist) || !StrUtil.equals(newAnswerExist, answer)) {
                            knowledgeReferenceService.addDefaultReference(DataSetReferenceType.assist, newEle, sysUserInfo, answer);
                            qaAnswerCopied++;
                        } else {
                            log.debug("QA答案已存在且相同, 跳过重复写入, newCode:{}", newCode);
                        }
                    } else {
                        log.debug("源QA答案为空, 跳过写入, sourceCode:{}", source.getCode());
                    }
                } catch (Exception ex) {
                    log.error("复制QA答案失败, newCode:{}, msg:{}", newCode, ex.getMessage(), ex);
                    qaErrorCodes.add(source.getCode());
                    throw ex; // 保持事务一致性, 触发整体回滚
                }
                // 复制相似问
                try {
                    List<String> similarList = null;
                    try {
                        similarList = knowledgeSimilarService.listSimilar(tenantId, source.getCode());
                    } catch (Exception ex) {
                        log.warn("获取QA相似问失败, sourceCode:{}, msg:{}", source.getCode(), ex.getMessage());
                    }
                    if (CollUtil.isNotEmpty(similarList)) {
                        // 使用新增/覆盖模式, merge内部已做去重
                        knowledgeSimilarService.mergeSimilar(tenantId, newCode, similarList, true);
                        qaSimilarCopied++;
                    } else {
                        log.debug("源QA无相似问, 跳过写入, sourceCode:{}", source.getCode());
                    }
                } catch (Exception ex) {
                    log.error("复制QA相似问失败, newCode:{}, msg:{}", newCode, ex.getMessage(), ex);
                    qaErrorCodes.add(source.getCode());
                    throw ex;
                }
            }
            long costMs = System.currentTimeMillis() - startCopyTs;
            log.info("QA复制补偿完成: total={}, answerCopied={}, similarCopied={}, skipped={}, errors={}, costMs={}", qaTotal, qaAnswerCopied, qaSimilarCopied, qaSkipped, qaErrorCodes, costMs);
        } catch (Exception qaEx) {
            log.error("QA内容复制过程中出现异常，触发回滚: {}", qaEx.getMessage(), qaEx);
            throw qaEx;
        }
        // ===== QA元素内容复制End =====

        // ===== 为新元素添加复制/移动动态记录开始 =====
        try {
            SaasKnowledgeElementCacheInfo cacheInfo = knowledgeElementConfigService.get(targetContainerId, tenantId);
            List<SaasKnowledgeElementTrendAddReq> newElementTrends = new ArrayList<>();
            for (SaasKnowledgeElement newElement : newElements) {
                // 为每个新元素创建一条新的动态记录
                SaasKnowledgeElementTrendAddReq trendReq = SaasKnowledgeElementTrendAddReq.of(
                        sysUserInfo,
                        newElement,
                        moveOpt ? SaasKnowledgeElementEvent.MOVED:SaasKnowledgeElementEvent.COPIED,
                        cacheInfo
                );
                newElementTrends.add(trendReq);
            }
            // 批量插入新元素的动态
            if (CollUtil.isNotEmpty(newElementTrends)) {
                saasKnowledgeElementTrendService.messageTrendBatch(newElementTrends);
                log.info("为新元素添加动态记录完成，总计:{}条", newElementTrends.size());
            }
        } catch (Exception trendEx) {
            log.error("添加新元素动态记录过程中出现异常: {}", trendEx.getMessage(), trendEx);
        }
        // ===== 为新元素添加复制/移动动态记录结束 =====

        // 保存解析配置
        if (CollUtil.isNotEmpty(newConfigElements)) {
            saasKnowledgeConfigElementService.saveBatch(newConfigElements);
        }
        // 页面版本插入
        pageVersionTasks.forEach(Runnable::run);

        List<SaasKnowledgeElement> deletedSourceElements = new ArrayList<>();
        // 移动操作需要删除原元素并释放容量与写动态
        if (moveOpt) {
            long releasedSize = 0L;
            SaasKnowledgeElementCacheInfo cacheInfo = knowledgeElementConfigService.get(sourceContainerId, tenantId);
            // 根删除动态
            for (String rootCode : rootCodes) {
                Optional<SaasKnowledgeElement> rootOpt = queryInfoByCode(rootCode);
                rootOpt.ifPresent(r -> saasKnowledgeElementTrendService.messageTrend(
                        SaasKnowledgeElementTrendAddReq.of(sysUserInfo, r, SaasKnowledgeElementEvent.DELETED, cacheInfo)));
            }
            // 过滤真正需要删除的元素：排除受保护父级
            List<SaasKnowledgeElement> elementsToDelete = sourceAllElements.stream()
                    .filter(e -> !protectedParentCodes.contains(e.getCode()))
                    .collect(Collectors.toList());
            deletedSourceElements = elementsToDelete;
            for (SaasKnowledgeElement src : elementsToDelete) {
                if (src.getEleSize() != null) {
                    releasedSize += src.getEleSize();
                }
                // 删除版本与配置
                if (StrUtil.equalsIgnoreCase(src.getCategory(), KnowledgeElementTypes.PAGE.name())
                        || StrUtil.equalsIgnoreCase(src.getCategory(), KnowledgeElementTypes.EXCEL.name())) {
                    LambdaQueryWrapper<SaasKnowledgeElementVersion> vqw = Wrappers.lambdaQuery(SaasKnowledgeElementVersion.class)
                            .eq(SaasKnowledgeElementVersion::getPageCode, src.getCode())
                            .eq(SaasKnowledgeElementVersion::getTenantId, tenantId);
                    saasKnowledgeElementVersionMapper.delete(vqw);
                }
                LambdaQueryWrapper<SaasKnowledgeConfigElement> cqw = Wrappers.lambdaQuery(SaasKnowledgeConfigElement.class)
                        .eq(SaasKnowledgeConfigElement::getElementId, src.getCode())
                        .eq(SaasKnowledgeConfigElement::getContainerId, sourceContainerId)
                        .eq(SaasKnowledgeConfigElement::getTenantId, tenantId);
                saasKnowledgeConfigElementService.remove(cqw);
                // ===== 移动模式QA旧元素关联数据清理开始 =====
                if (StrUtil.equalsIgnoreCase(src.getCategory(), KnowledgeElementCategory.QA.getName())) {
                    try {
                        knowledgeReferenceService.remove(Wrappers.lambdaQuery(SaasKnowledgeReference.class)
                                .eq(SaasKnowledgeReference::getTenantId, tenantId)
                                .eq(SaasKnowledgeReference::getDataId, src.getCode())
                                .eq(SaasKnowledgeReference::getCategory, DataSetReferenceType.assist.getName()));
                    } catch (Exception ex) {
                        log.warn("移动清理QA引用失败 code:{} msg:{}", src.getCode(), ex.getMessage());
                    }
                    try {
                        knowledgeSimilarService.remove(Wrappers.lambdaQuery(SaasKnowledgeSimilar.class)
                                .eq(SaasKnowledgeSimilar::getTenantId, tenantId)
                                .eq(SaasKnowledgeSimilar::getCode, src.getCode()));
                    } catch (Exception ex) {
                        log.warn("移动清理QA相似问失败 code:{} msg:{}", src.getCode(), ex.getMessage());
                    }
                }
                // ===== 移动模式QA旧元素关联数据清理结束 =====
                // 删除主记录
                saasKnowledgeElementMapper.delete(Wrappers.lambdaQuery(SaasKnowledgeElement.class)
                        .eq(SaasKnowledgeElement::getTenantId, tenantId)
                        .eq(SaasKnowledgeElement::getContainerId, sourceContainerId)
                        .eq(SaasKnowledgeElement::getCode, src.getCode()));
                // 删除索引
                try {
                    knowledgeElementDataService.deleteByDataId(tenantId, sourceContainerId, src.getCode());
                } catch (Exception e) {
                    log.warn("删除向量索引失败 code:{} err:{}", src.getCode(), e.getMessage());
                }
            }
            // 释放容量
            if (releasedSize > 0) {
                try {
                    knowledgeContainerCapacityDataService.flushKnowledge(sourceContainerId, releasedSize);
                } catch (Exception e) {
                    log.error("释放来源知识库容量失败:{}", e.getMessage(), e);
                }
            }
        }
        if (moveOpt) {
            publishElementBatchByCategory(tenantId, newElements, KnowledgeEventType.FOLDER_MOVED, KnowledgeEventType.DOCUMENT_MOVED, MapSyncAction.UPSERT);
        } else {
            publishElementBatch(KnowledgeEventType.DOCUMENT_COPIED, tenantId, newElements, MapSyncAction.UPSERT);
        }
        if (moveOpt) {
            publishElementBatchByCategory(tenantId, deletedSourceElements, KnowledgeEventType.FOLDER_DELETED, KnowledgeEventType.DOCUMENT_DELETED, MapSyncAction.DELETE);
        }

        String codesString = newElements.stream()
                .map(SaasKnowledgeElement::getCode)
                .filter(Objects::nonNull)
                .collect(Collectors.joining(","));
        String eleNames = newElements.stream()
                .map(SaasKnowledgeElement::getEleName)
                .filter(Objects::nonNull)
                .collect(Collectors.joining(","));
        if (moveOpt){
            CommonLog.knowledge.action(ActionType.PAGE_MOVE, "页面移动" + "，名称:{}", eleNames)
                    .withMetadata("elementCode", codesString)
                    .withMetadata("containerCode", targetContainerId)
                    .send();
        } else {
            CommonLog.knowledge.action(ActionType.PAGE_COPY, "页面复制，名称:{}", eleNames)
                    .withMetadata("elementCode", codesString)
                    .withMetadata("containerCode", targetContainerId)
                    .send();
        }

        String msg = (moveOpt ? "移动" : "复制") + "成功！";
        if (CollUtil.isNotEmpty(skippedCodes)) {
            msg += " 部分页面权限不足已跳过";
        }
        return Result.success(msg);
    }

    private boolean isPublishableElementCategory(String category) {
        return StrUtil.equalsIgnoreCase(category, KnowledgeElementTypes.PAGE.name())
                || StrUtil.equalsIgnoreCase(category, KnowledgeElementTypes.EXCEL.name());
    }


    private Pagination<KnowledgeElementResp> listWithPath(KnowledgeElementQueryReq knowledgeElementQueryReq, Integer pageNo, Integer pageSize) {
        log.info("分页查询知识库元素列表,pageNo:{},pageSize:{}", pageNo, pageSize);
        log.info("分页QueryReq:{}", knowledgeElementQueryReq.toString());
        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        SaasKnowledgeElement saasKnowledgeElementNode = saasKnowledgeElementMapper.selectOne(Wrappers.lambdaQuery(SaasKnowledgeElement.class).select(SaasKnowledgeElement::getParentCode, SaasKnowledgeElement::getCode).eq(SaasKnowledgeElement::getTenantId, sysUserInfo.getTenantId()).eq(SaasKnowledgeElement::getCode, knowledgeElementQueryReq.getPageCode()));
        if (saasKnowledgeElementNode == null) {
            log.info("没有找到对应的知识库元素");
            return Pagination.empty(pageNo, pageSize);
        }
        String permissionType = saasKnowledgeContainerPermissionService.getHighestPermission(knowledgeElementQueryReq.getContainerId(), sysUserInfo);
        log.info("当前用户在容器中的最高权限:{}", permissionType);
        // 如果是没权限的角色，那么需要判断当前的知识库是否设置为公开，如果是公开的情况下，那么给予只读角色
        Optional<SaasKnowledgeContainer> containerOptional = knowledgeContainerQueryService.queryInfoByCode(knowledgeElementQueryReq.getContainerId());
        if (containerOptional.isEmpty()) {
            return Pagination.empty(pageNo, pageSize);
        }
        boolean canFilter = true;
        SaasKnowledgeContainer saasKnowledgeContainer = containerOptional.get();
        if (KbKnowledgeBaseContainerVisibilityRange.publicRead(saasKnowledgeContainer.getVisibilityRange())) {
            // 公开可读
            canFilter = false;
        } else {
            // 非公开可读，那么必须有权限才可以查看
            if (!StrUtil.equalsIgnoreCase(KbKnowledgeBaseContainerPermissionTypes.NO_PERMISSION.getCode(), permissionType)) {
                // 公开可读
                canFilter = false;
            }
        }
        String parentCode = saasKnowledgeElementNode.getParentCode();
        // 查询全部列表的
        DepartmentUserOrgPermissions orgPermissions = kbDepartmentUserService.listAccessibleDepartmentCodes(sysUserInfo);
        List<KnowledgeElementResp> respInfos = new ArrayList<>();
        while (StrUtil.isNotBlank(parentCode)) {
            LambdaQueryWrapper<SaasKnowledgeElement> lambdaQueryWrapper = Wrappers.lambdaQuery(SaasKnowledgeElement.class).eq(SaasKnowledgeElement::getTenantId, sysUserInfo.getTenantId());
            // 查询条件
            lambdaQueryWrapper.eq(StrUtil.isNotBlank(knowledgeElementQueryReq.getContainerId()), SaasKnowledgeElement::getContainerId, knowledgeElementQueryReq.getContainerId());
            lambdaQueryWrapper.eq(StrUtil.isNotBlank(parentCode), SaasKnowledgeElement::getParentCode, parentCode);
            if (StrUtil.isNotBlank(knowledgeElementQueryReq.getCategory())) {
                List<String> category = StrUtil.split(knowledgeElementQueryReq.getCategory(), StrUtil.COMMA);
                lambdaQueryWrapper.in(SaasKnowledgeElement::getCategory, category);
            }
            lambdaQueryWrapper.like(StrUtil.isNotBlank(knowledgeElementQueryReq.getEleName()), SaasKnowledgeElement::getEleName, knowledgeElementQueryReq.getEleName());
            // 草稿状态只能自己可见
            lambdaQueryWrapper.and(l -> {
                l.ne(SaasKnowledgeElement::getProcessStatus, ProcessStatusEnum.DRAFT.getCode()).or(lf -> {
                    lf.eq(SaasKnowledgeElement::getProcessStatus, ProcessStatusEnum.DRAFT.getCode());
                    lf.eq(SaasKnowledgeElement::getCreator, Objects.toString(sysUserInfo.getCode()));
                });
            });
            // 过滤权限，因为parentCode不为空，那么查询出当前用户不可见的文档编码，然后在进行过滤
            ElementSearchCondition searchCondition = ElementSearchCondition.from(sysUserInfo.getTenantId(), knowledgeElementQueryReq.getContainerId(), parentCode, orgPermissions.permissionCodesToList());
            List<String> visibleCodes = saasKnowledgeElementMapper.listVisibleCodes(searchCondition);
            if (CollUtil.isNotEmpty(visibleCodes)) {
                // 继承的权限文档全部可见，然后可见的文档也可见
                log.info("过滤掉不可见的权限code列表，size:{}", visibleCodes.size());
                lambdaQueryWrapper.and(lf -> lf.eq(SaasKnowledgeElement::getPermissionStatus, ToggleStatusEnum.YES.getCode()).or(l1 -> {
                    l1.eq(SaasKnowledgeElement::getPermissionStatus, ToggleStatusEnum.NO.getCode());
                    l1.in(SaasKnowledgeElement::getCode, visibleCodes);
                }));

                ///lambdaQueryWrapper.notIn(SaasKnowledgeElement::getCode,notVisibleCodes);
            } else {
                // 没有任何可见的文档
                log.info("没有权限，查询继承下来的文档");
                lambdaQueryWrapper.eq(SaasKnowledgeElement::getPermissionStatus, ToggleStatusEnum.YES.getCode());
            }
            // 设定排序规则
            SortRules sortRule = SortRules.parse(knowledgeElementQueryReq.getSortRule());
            if (sortRule == SortRules.SORT_NUMBER) {
                lambdaQueryWrapper.orderByAsc(SaasKnowledgeElement::getSort);
            } else if (sortRule == SortRules.SORT_CREATE_TIME) {
                // 判断倒序还是顺序
                if (knowledgeElementQueryReq.getSortType() == 0) {
                    lambdaQueryWrapper.orderByAsc(SaasKnowledgeElement::getCreateTime);
                } else {
                    lambdaQueryWrapper.orderByDesc(SaasKnowledgeElement::getCreateTime);
                }
            } else if (sortRule == SortRules.SORT_MODIFY_TIME) {
                // 判断倒序还是顺序
                if (knowledgeElementQueryReq.getSortType() == 0) {
                    lambdaQueryWrapper.orderByAsc(SaasKnowledgeElement::getModifierTime);
                } else {
                    lambdaQueryWrapper.orderByDesc(SaasKnowledgeElement::getModifierTime);
                }
            } else if (sortRule == SortRules.SORT_TITLE) {
                // 对于文件名排序，不在数据库层排序，而在内存中进行自定义排序
                // 这样可以支持按数字前缀排序的需求
            }

            List<SaasKnowledgeElement> saasKnowledgeElementInfos;
            List<KnowledgeElementResp> knowledgeElementRespInfos;

            if (sortRule == SortRules.SORT_TITLE) {
                // 文件名排序需要在内存中进行，所以先查询所有数据
                saasKnowledgeElementInfos = saasKnowledgeElementMapper.selectList(lambdaQueryWrapper);

                // 按照文件名进行自定义排序（支持数字前缀排序）
                saasKnowledgeElementInfos.sort((a, b) -> compareFileName(a.getEleName(), b.getEleName(), knowledgeElementQueryReq.getSortType()));

                // 手动分页
                int startIndex = (pageNo - 1) * pageSize;
                int endIndex = Math.min(startIndex + pageSize, saasKnowledgeElementInfos.size());
                if (startIndex < saasKnowledgeElementInfos.size()) {
                    saasKnowledgeElementInfos = saasKnowledgeElementInfos.subList(startIndex, endIndex);
                } else {
                    saasKnowledgeElementInfos = new ArrayList<>();
                }

                knowledgeElementRespInfos = new ArrayList<>();
            } else {
                // 其他排序规则使用数据库分页
                try (Page<SaasKnowledgeElement> saasKnowledgeElementPageNo = PageHelper.startPage(pageNo, pageSize)) {
                    saasKnowledgeElementInfos = saasKnowledgeElementMapper.selectList(lambdaQueryWrapper);
                    knowledgeElementRespInfos = new ArrayList<>();
                }
            }
            if (CollectionUtil.isNotEmpty(saasKnowledgeElementInfos)) {
                if (canFilter) {
                    // 说明要做过滤，这判断你这个人是否可以看
                    // 过滤权限，因为parentCode不为空，那么查询出当前用户不可见的文档编码，然后在进行过滤
                    List<String> elementCodes = saasKnowledgeElementInfos.stream().map(SaasKnowledgeElement::getCode).toList();
                    ElementFilterSearchCondition searchFilterCondition = ElementFilterSearchCondition.from(sysUserInfo.getTenantId(), knowledgeElementQueryReq.getContainerId(), elementCodes, orgPermissions.permissionCodesToList());
                    List<String> visibleFilterCodes = saasKnowledgeElementMapper.listVisibleFilterCodes(searchFilterCondition);
                    if (CollUtil.isNotEmpty(visibleFilterCodes)) {
                        knowledgeElementRespInfos.addAll(saasKnowledgeElementInfos.stream().filter(s -> visibleFilterCodes.contains(s.getCode())).map(new SaasKnowledgeElementApplyFunction()).toList());
                    }
                } else {
                    knowledgeElementRespInfos.addAll(saasKnowledgeElementInfos.stream().map(new SaasKnowledgeElementApplyFunction()).toList());
                }
                // 批量填充creatorName和modifierName
                Set<String> userCodes = new HashSet<>();
                for (KnowledgeElementResp resp : knowledgeElementRespInfos) {
                    userCodes.addAll(resp.userCodes());
                }
                if (!userCodes.isEmpty()) {
                    Map<String, String> userMap = userService.selectByCode(new ArrayList<>(userCodes));
                    for (KnowledgeElementResp resp : knowledgeElementRespInfos) {
                        resp.applyUserName(userMap);
                    }
                }
            }
            if (CollUtil.isNotEmpty(respInfos)) {
                String parentCode1 = respInfos.get(0).getParentCode();
                for (KnowledgeElementResp info : knowledgeElementRespInfos) {
                    if (StrUtil.equals(info.getCode(), parentCode1)) {
                        info.setChildrens(respInfos);
                        break;
                    }
                }
            }
            if (CollUtil.isNotEmpty(knowledgeElementRespInfos)) {
                respInfos = knowledgeElementRespInfos;
            }
            if (StrUtil.equalsIgnoreCase(parentCode, "0")) {
                break;
            }
            SaasKnowledgeElement saasKnowledgeElement = saasKnowledgeElementMapper.selectOne(Wrappers.lambdaQuery(SaasKnowledgeElement.class).eq(SaasKnowledgeElement::getCode, parentCode));
            parentCode = saasKnowledgeElement.getParentCode();
        }
        long totalCount = respInfos.size();

        return Pagination.pagination(respInfos, totalCount, pageNo, pageSize);
    }

    /**
     * 递归获取父级名称链
     *
     * @param code     当前节点编码
     * @param tenantId 租户ID
     * @return 父级名称链
     */
    private String buildParentNamesRecursively(String code, String tenantId) {
        if (StrUtil.isBlank(code) || "0".equals(code)) {
            return "";
        }

        SaasKnowledgeElement element = saasKnowledgeElementMapper.getByCodeAndTenantId(code, tenantId);
        if (element == null) {
            return "";
        }

        String currentName = element.getCode() + "#" + element.getEleName();
        String parentCode = element.getParentCode();

        if (StrUtil.isBlank(parentCode) || "0".equals(parentCode)) {
            return currentName;
        }

        String parentNames = buildParentNamesRecursively(parentCode, tenantId);
        if (StrUtil.isBlank(parentNames)) {
            return currentName;
        }

        return parentNames + "," + currentName;
    }

    @Override
    public Result<List<KnowledgeElementResp>> queryParentName(String code) {
        List<KnowledgeElementResp> results = new ArrayList<>();

        if (StrUtil.isBlank(code) || StrUtil.equalsIgnoreCase(code, "0")) {
            return Result.data(results);
        }

        // 使用新的递归方法
        String parentNames = buildParentNamesRecursively(code, UserContextHolder.getTenantId());

        if (StrUtil.isNotBlank(parentNames)) {
            List<String> arr = StrUtil.split(parentNames, ",");
            for (String names : arr) {
                if (StrUtil.isNotBlank(names)) {
                    List<String> nameInfo = StrUtil.split(names, "#");
                    if (nameInfo.size() >= 2) {
                        KnowledgeElementResp resp = new KnowledgeElementResp();
                        resp.setCode(nameInfo.get(0));
                        resp.setEleName(nameInfo.get(1));
                        results.add(resp);
                    }
                }
            }
        }

        return Result.data(results);
    }

