    /**
     * 批量新增文件
     *
     * @param saasKnowledgeElements 知识库元素列表
     * @param tenantId              租户
     * @param fileSpace             文件占用空间
     * @param cacheKeys             缓存keys
     * @return 是否新增成功
     */
    @Transactional(rollbackFor = Exception.class)
    protected Result<String> lockBatchFile(List<SaasKnowledgeElement> saasKnowledgeElements, String tenantId, Long fileSpace, List<String> cacheKeys, String containerId) {
        String key = Cns.LOCK_KNOWLEDGE_KEY + tenantId;
        RLock rLock = redissonClient.getLock(key);
        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        try {
            // 校验知识库空间大小
            // /kl/api/saas/element/addFiles
            knowledgeContainerCapacityDataService.validateContainerCapacity(saasKnowledgeElements.get(0).getContainerId(), fileSpace);
            if (rLock.tryLock(10, 10, TimeUnit.SECONDS)) {
                boolean ret = this.saveBatch(saasKnowledgeElements);
                if (ret) {
                    boolean result = knowledgeStorageService.addStorages(saasKnowledgeElements.stream().map(KnowledgeStorageRecord::uploadFile).collect(Collectors.toList()));
                    Assert.isTrue(result, "knowledge.dataset.file.validation.expireFile");
                    // 扣费
                    // 上传流量账户扣费
                    result = billingSubscribeAccountService.costStorage(tenantId, fileSpace);
                    Assert.isTrue(result, "knowledge.dataset.file.validation.expireFile");
                    // 清除缓存
                    if (CollUtil.isNotEmpty(cacheKeys)) {
                        stringRedisTemplate.delete(cacheKeys);
                    }
                    // 新增文件解析配置
                    Optional<SaasKnowledgeConfigContainer> saasKnowledgeConfigContainer = saasKnowledgeConfigContainerService.queryInfoByContainerId(containerId);
                    if (saasKnowledgeConfigContainer.isEmpty()) {
                        log.error("未找到知识库配置信息");
                        return Result.error(i18nMessage.resolveMessage("system.common.add.fail"));
                    }
                    List<SaasKnowledgeConfigElement> saasKnowledgeConfigElements = new ArrayList<>();
                    // 构建批量动态记录请求列表
                    List<SaasKnowledgeElementTrendAddReq> trendAddReqs = new ArrayList<>();
                    for (SaasKnowledgeElement saasKnowledgeElement : saasKnowledgeElements) {
                        SaasKnowledgeConfigElement request = SaasKnowledgeConfigElement.builder()
                                .elementId(saasKnowledgeElement.getCode())
                                .analysisEngine(saasKnowledgeConfigContainer.get().getAnalysisEngine())
                                .analysisMode(saasKnowledgeConfigContainer.get().getAnalysisMode())
                                .ocrEngine(saasKnowledgeConfigContainer.get().getOcrEngine())
                                .multiModalityEngine(saasKnowledgeConfigContainer.get().getMultiModalityEngine())
                                .splitMode(saasKnowledgeConfigContainer.get().getSplitMode())
                                .maxChunkSize(saasKnowledgeConfigContainer.get().getMaxChunkSize())
                                .overlapSize(saasKnowledgeConfigContainer.get().getOverlapSize())
                                .maxChunkLength(saasKnowledgeConfigContainer.get().getMaxChunkLength())
                                .splitDelimiters(saasKnowledgeConfigContainer.get().getSplitDelimiters())
                                .imageOcr(saasKnowledgeConfigContainer.get().getImageOcr())
                                .tenantId(saasKnowledgeConfigContainer.get().getTenantId())
                                .sort(saasKnowledgeConfigContainer.get().getSort())
                                .modifier(UserContextHolder.getCurrentUser().getCode())
                                .creator(UserContextHolder.getCurrentUser().getCode())
                                .modifierTime(LocalDateTime.now())
                                .containerId(saasKnowledgeConfigContainer.get().getContainerId())
                                .engineType(saasKnowledgeConfigContainer.get().getEngineType())
                                .useOriginalContent(Cns.YES)
                                .createTime(LocalDateTime.now())
                                .build();
                        FileConfig fileConfig = saasKnowledgeElement.getFileConfig();
                        if (fileConfig != null && request != null) {
                            // 设置分析引擎
                            if (StrUtil.isNotBlank(fileConfig.getAnalysisEngine())) {
                                request.setAnalysisEngine(fileConfig.getAnalysisEngine());
                            }
                            // 设置分析模式
                            if (StrUtil.isNotBlank(fileConfig.getAnalysisMode())) {
                                request.setAnalysisMode(fileConfig.getAnalysisMode());
                            }
                            // 设置引擎类型
                            if (StrUtil.isNotBlank(fileConfig.getEngineType())) {
                                request.setEngineType(fileConfig.getEngineType());
                            }
                            if (StrUtil.equalsIgnoreCase(EngineTypesEnum.OCR.name(), fileConfig.getEngineType())) {
                                // 设置OCR引擎
                                if (StrUtil.isNotBlank(fileConfig.getOcrEngine())) {
                                    request.setOcrEngine(fileConfig.getOcrEngine());
                                }
                            } else if (StrUtil.equalsIgnoreCase(EngineTypesEnum.VLM.name(), fileConfig.getEngineType())) {
                                // 设置多模态引擎
                                if (StrUtil.isNotBlank(fileConfig.getMultiModalityEngine())) {
                                    request.setMultiModalityEngine(fileConfig.getMultiModalityEngine());
                                }
                            }
                        }
                        saasKnowledgeConfigElements.add(request);
                        // 批量更新知识库动态配置
                        // 草稿状态不列入动态信息
                        if (!ProcessStatusEnum.DRAFT.equals(ProcessStatusEnum.parse(saasKnowledgeElement.getProcessStatus()))) {
                            // 获取空间动态信息
                            SaasKnowledgeElementCacheInfo saasKnowledgeElementCacheInfo = knowledgeElementConfigService.get(
                                    saasKnowledgeElement.getContainerId(),
                                    saasKnowledgeElement.getTenantId()
                            );
                            // 使用 UPLOAD 事件创建动态记录请求
                            SaasKnowledgeElementTrendAddReq trendAddReq = SaasKnowledgeElementTrendAddReq.of(
                                    sysUserInfo,
                                    saasKnowledgeElement,
                                    SaasKnowledgeElementEvent.UPLOAD,
                                    saasKnowledgeElementCacheInfo
                            );

                            trendAddReqs.add(trendAddReq);
                        }
                    }

                    // 批量插入动态记录
                    if (CollectionUtil.isNotEmpty(trendAddReqs)) {
                        saasKnowledgeElementTrendService.messageTrendBatch(trendAddReqs);
                        log.info("批量更新知识库动态配置完成，实际处理数量:{}", trendAddReqs.size());
                    } else {
                        log.info("批量更新知识库动态配置完成，无需处理的记录");
                    }

                    saasKnowledgeConfigElementService.saveBatch(saasKnowledgeConfigElements);

                }
                return ret ? Result.success(i18nMessage.resolveMessage("system.common.insert.success")) : Result.error(i18nMessage.resolveMessage("knowledge.dataset.file.save.fail"));
            }
        } catch (InterruptedException e) {
            log.error(e.getMessage());
            throw new RuntimeException("system.error.inner.exception");
        } finally {
            // 释放分布式锁
            if (rLock != null && rLock.isLocked()) {
                rLock.unlock();
                log.info("free addFiles lock successful...");
            }
        }
        return Result.error("knowledge.dataset.file.validation.expireFile");
    }

    @Transactional(rollbackFor = Exception.class)
    @Override
    public Result<String> addFiles(KnowledgeElementAddFileReq addFileReq) {
        log.info("批量新增文件");
        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        String tenantId = sysUserInfo.getTenantId();
        AddFilesExecution execution = prepareAddFilesExecution(addFileReq, tenantId, sysUserInfo);
        Result<String> result = this.lockBatchFile(execution.saasKnowledgeElements, tenantId, execution.storageAmount.get(), execution.cacheKeys, addFileReq.getContainerId());
        if (CollUtil.isNotEmpty(execution.saasKnowledgeElements) && ErrorCodeEnum.SUCCESS.getCode().equals(result.getCode())) {
            publishElementBatch(KnowledgeEventType.DOCUMENT_CREATED, tenantId, execution.saasKnowledgeElements, MapSyncAction.UPSERT);
        }

        // 记录日志
        List<SaasKnowledgeElement> saasKnowledgeElements = execution.saasKnowledgeElements;
        if (CollUtil.isNotEmpty(saasKnowledgeElements)) {
            CommonLog.knowledge.action(ActionType.FILE_UPLOAD_BATCH, "批量导入知识文件，数量:{}", saasKnowledgeElements.size())
                    .withMetadata("containerId", addFileReq.getContainerId())
                    .withMetadata("fileCount", saasKnowledgeElements.size())
                    .send();
        }
        return result;
    }

    @Transactional(rollbackFor = Exception.class)
    @Override
    public Result<String> addFiles(KnowledgeElementAddFileReq addFileReq, String tenantId, SysUserInfo sysUserInfo) {
        AddFilesExecution execution = prepareAddFilesExecution(addFileReq, tenantId, sysUserInfo);
        Result<String> result = this.lockBatchFile(execution.saasKnowledgeElements, tenantId, execution.storageAmount.get(), execution.cacheKeys, addFileReq.getContainerId());
        if (CollUtil.isNotEmpty(execution.saasKnowledgeElements) && ErrorCodeEnum.SUCCESS.getCode().equals(result.getCode())) {
            publishElementBatch(KnowledgeEventType.DOCUMENT_CREATED, tenantId, execution.saasKnowledgeElements, MapSyncAction.UPSERT);
        }
        return result;
    }

    @Transactional(rollbackFor = Exception.class)
    @Override
    public Result<List<SaasKnowledgeElement>> addFilesAndReturnElements(KnowledgeElementAddFileReq addFileReq, String tenantId, SysUserInfo sysUserInfo) {
        log.info("批量新增文件");
        AddFilesExecution execution = prepareAddFilesExecution(addFileReq, tenantId, sysUserInfo);
        Result<String> result = this.lockBatchFile(execution.saasKnowledgeElements, tenantId, execution.storageAmount.get(), execution.cacheKeys, addFileReq.getContainerId());
        if (CollUtil.isNotEmpty(execution.saasKnowledgeElements) && ErrorCodeEnum.SUCCESS.getCode().equals(result.getCode())) {
            publishElementBatch(KnowledgeEventType.DOCUMENT_CREATED, tenantId, execution.saasKnowledgeElements, MapSyncAction.UPSERT);
        }
        if (!ErrorCodeEnum.SUCCESS.getCode().equals(result.getCode())) {
            return Result.error(result.getMessage());
        }
        return Result.data(execution.saasKnowledgeElements, result.getMessage());
    }

    private AddFilesExecution prepareAddFilesExecution(KnowledgeElementAddFileReq addFileReq, String tenantId, SysUserInfo sysUserInfo) {
        knowledgeValidationService.validateFileBase(addFileReq, tenantId);
        knowledgePermissionGuardService.assertContainerEditPermission(addFileReq.getContainerId(), sysUserInfo);
        List<String> cacheKeys = new LinkedList<>();
        List<SaasKnowledgeElement> saasKnowledgeElements = new ArrayList<>();
        AtomicLong storageAmount = new AtomicLong(0);
        Integer maxOrder = saasKnowledgeElementMapper.maxOrder(tenantId, addFileReq.getContainerId(), addFileReq.getParentCode());
        AtomicInteger maxOrderAtomic = new AtomicInteger(Objects.requireNonNullElse(maxOrder, 0));
        for (KnowledgeElementAddFileOneReq fileOneReq : addFileReq.getDataSets()) {
            String cacheKey = Cns.PIPELINE_CACHE_PREFIX + tenantId + ":" + fileOneReq.getDataId();
            cacheKeys.add(cacheKey);
            String value = stringRedisTemplate.opsForValue().get(cacheKey);
            Assert.notBlank(value, "knowledge.dataset.file.validation.expireFile");
            saasKnowledgeElements.addAll(fileOneReq.getElementList(addFileReq, maxOrderAtomic, tenantId, value, storageAmount, sysUserInfo));
        }
        Assert.isTrue(billingSubscribeAccountService.validateAvailableStorage(tenantId, storageAmount.get()), "knowledge.preview.upload.limit");
        return new AddFilesExecution(cacheKeys, saasKnowledgeElements, storageAmount);
    }

    private static final class AddFilesExecution {
        private final List<String> cacheKeys;
        private final List<SaasKnowledgeElement> saasKnowledgeElements;
        private final AtomicLong storageAmount;

        private AddFilesExecution(List<String> cacheKeys, List<SaasKnowledgeElement> saasKnowledgeElements, AtomicLong storageAmount) {
            this.cacheKeys = cacheKeys;
            this.saasKnowledgeElements = saasKnowledgeElements;
            this.storageAmount = storageAmount;
        }
    }

    @Override
    public Result<KnowledgeResultInfo> addSingleFile(KnowledgeElementAddSingleFileReq singleFileReq) {
        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        // 校验知识库 请求参数
        knowledgeValidationService.validateFileBase(singleFileReq, sysUserInfo.getTenantId());
        knowledgePermissionGuardService.assertContainerEditPermission(singleFileReq.getContainerId(), sysUserInfo);
        SaasKnowledgeElement saasKnowledgeElement = new SaasKnowledgeElement();
        BeanUtils.copyProperties(singleFileReq, saasKnowledgeElement);
        saasKnowledgeElement.setStartTime(singleFileReq.startTimeInstance());
        saasKnowledgeElement.setEndTime(singleFileReq.endTimeInstance());
        saasKnowledgeElement.setCategory(KnowledgeElementCategory.FILE.name());
        saasKnowledgeElement.setCreateTime(LocalDateTime.now());
        saasKnowledgeElement.setCreator(sysUserInfo.getCode());
        saasKnowledgeElement.setModifier(sysUserInfo.getCode());
