    @Transactional(rollbackFor = Exception.class)
    @Override
    public Result<String> batchDelete(List<Integer> ids) {
        log.info("批量删除知识库元素,数量:{},ID列表:{}", ids.size(), ids);
        if (CollUtil.isEmpty(ids)) {
            return Result.error("删除ID列表不能为空");
        }
        List<SaasKnowledgeElement> elementsToDelete = saasKnowledgeElementMapper.selectBatchIds(ids);
        Assert.notNull(elementsToDelete, "system.common.request.invalid");
        String tenantId = UserContextHolder.getTenantId();
        SysUserInfo currentUser = UserContextHolder.getCurrentUser();

        // 验证所有元素的权限和删除条件
        StringBuilder validationErrors = new StringBuilder();
        List<SaasKnowledgeElement> validElements = new ArrayList<>();

        for (SaasKnowledgeElement element : elementsToDelete) {
            try {
                // 1. 权限验证
                if (!StrUtil.equalsIgnoreCase(element.getTenantId(), tenantId)) {
                    validationErrors.append("ID[").append(element.getId()).append("]数据无效; ");
                    continue;
                }
                knowledgePermissionGuardService.assertElementEditPermission(element);
                // 2. 文件夹检查
                if (StrUtil.equalsIgnoreCase(element.getCategory(), KnowledgeElementCategory.DIRECTORY.getName())) {
                    LambdaQueryWrapper<SaasKnowledgeElement> lambdaQueryWrapper = Wrappers.lambdaQuery(SaasKnowledgeElement.class)
                            .eq(SaasKnowledgeElement::getTenantId, tenantId)
                            .eq(SaasKnowledgeElement::getContainerId, element.getContainerId())
                            .eq(SaasKnowledgeElement::getParentCode, element.getCode());
                    if (saasKnowledgeElementMapper.exists(lambdaQueryWrapper)) {
                        validationErrors.append("ID[").append(element.getId()).append("]文件夹[").append(element.getEleName()).append("]下存在文件,不允许删除; ");
                        continue;
                    }
                } else {
                    // 3. 状态检查
                    ProcessStatusEnum processStatusEnum = ProcessStatusEnum.parse(element.getProcessStatus());
                    if (processStatusEnum == ProcessStatusEnum.PROCESSING || processStatusEnum == ProcessStatusEnum.EMBEDDED || processStatusEnum == ProcessStatusEnum.EMBEDDING) {
                        if (ChronoUnit.MINUTES.between(element.getCreateTime(), LocalDateTime.now()) < 120) {
                            validationErrors.append("ID[").append(element.getId()).append("]正在处理中,不允许删除; ");
                            continue;
                        }
                    }
                }
                validElements.add(element);
            } catch (Exception e) {
                log.error("验证元素失败,ID:{}", element.getId(), e);
                validationErrors.append("ID[").append(element.getId()).append("]验证失败: ").append(e.getMessage()).append("; ");
            }
        }
        if (CollUtil.isEmpty(validElements)) {
            return Result.error("没有符合删除条件的元素: " + validationErrors.toString());
        }

        List<Integer> validIds = validElements.stream().map(SaasKnowledgeElement::getId).toList();
        int deletedCount = saasKnowledgeElementMapper.deleteBatchIds(validIds);
        if (deletedCount > 0) {
            long totalSizeReleased = 0L;
            List<String> deletedNames = new ArrayList<>();
            Map<String, List<SaasKnowledgeElement>> containerElementsMap = new HashMap<>();
            for (SaasKnowledgeElement element : validElements) {
                try {
                    // 统计释放的空间大小
                    if (element.getEleSize() != null) {
                        totalSizeReleased += element.getEleSize();
                    }
                    deletedNames.add(element.getEleName());
                    containerElementsMap.computeIfAbsent(element.getContainerId(), k -> new ArrayList<>()).add(element);

                    // 删除向量索引数据
                    knowledgeElementDataService.deleteByDataId(tenantId, element.getContainerId(), element.getCode());

                    if (KnowledgeElementTypes.PAGE.name().equals(element.getCategory())) {
                        // 删除快照文件
                        LambdaQueryWrapper<SaasKnowledgeElementVersion> versionQueryWrapper = Wrappers.lambdaQuery(SaasKnowledgeElementVersion.class)
                                .eq(SaasKnowledgeElementVersion::getPageCode, element.getCode())
                                .eq(SaasKnowledgeElementVersion::getTenantId, tenantId);
                        knowledgeElementVersionService.remove(versionQueryWrapper);
                        // 删除配置向量
                        LambdaQueryWrapper<SaasKnowledgeConfigElement> configQueryWrapper = Wrappers.lambdaQuery(SaasKnowledgeConfigElement.class)
                                .eq(SaasKnowledgeConfigElement::getElementId, element.getCode())
                                .eq(SaasKnowledgeConfigElement::getContainerId, element.getContainerId())
                                .eq(SaasKnowledgeConfigElement::getTenantId, element.getTenantId());
                        saasKnowledgeConfigElementService.remove(configQueryWrapper);
                    }
                } catch (Exception e) {
                    log.error("清理元素数据失败,ID:{},名称:{}", element.getId(), element.getEleName(), e);
                }
            }

            // 批量释放知识库空间容量
            if (totalSizeReleased > 0) {
                try {
                    for (Map.Entry<String, List<SaasKnowledgeElement>> entry : containerElementsMap.entrySet()) {
                        String containerId = entry.getKey();
                        long containerSizeReleased = entry.getValue().stream()
                                .mapToLong(e -> e.getEleSize() != null ? e.getEleSize() : 0L)
                                .sum();
                        if (containerSizeReleased > 0) {
                            knowledgeContainerCapacityDataService.flushKnowledge(containerId, containerSizeReleased);
                        }
                    }
                } catch (Exception e) {
                    log.error("释放知识库容量失败,总大小:{}", totalSizeReleased, e);
                }
            }
            // 空间动态信息新增
            try {
                for (Map.Entry<String, List<SaasKnowledgeElement>> entry : containerElementsMap.entrySet()) {
                    String containerId = entry.getKey();
                    List<SaasKnowledgeElement> containerElements = entry.getValue();

                    boolean needUpdateTrend = containerElements.stream().anyMatch(element -> {
                        LambdaQueryWrapper<SaasKnowledgeContainer> queryWrapper = new LambdaQueryWrapper<>();
                        queryWrapper.eq(SaasKnowledgeContainer::getCode, containerId);
                        queryWrapper.eq(SaasKnowledgeContainer::getTenantId, tenantId);
                        SaasKnowledgeContainer container = saasKnowledgeContainerMapper.selectOne(queryWrapper);
                        return container != null
                                && !ProcessStatusEnum.DRAFT.equals(ProcessStatusEnum.parse(element.getProcessStatus()))
                                && container.getCategory().equals(KnowledgeCategory.COMMON.name());
                    });
                    if (needUpdateTrend) {
                        SaasKnowledgeElement representativeElement = containerElements.get(0);
                        SaasKnowledgeElementCacheInfo cacheInfo = knowledgeElementConfigService.get(containerId, tenantId);
                        // 批量操作
                        representativeElement.setEleName(String.format("批量删除%d个文件: %s等", containerElements.size(),
                                containerElements.stream().limit(3).map(SaasKnowledgeElement::getEleName).collect(Collectors.joining(", "))));

                        saasKnowledgeElementTrendService.messageTrend(SaasKnowledgeElementTrendAddReq.of(currentUser, representativeElement, SaasKnowledgeElementEvent.DELETED, cacheInfo));
                    }
                }
            } catch (Exception e) {
                log.error("更新批量删除动态失败", e);
            }
            publishElementBatchByCategory(tenantId, validElements, KnowledgeEventType.FOLDER_DELETED, KnowledgeEventType.DOCUMENT_DELETED, MapSyncAction.DELETE);

            log.info("批量删除完成,成功删除{}个元素,释放空间{}bytes,删除列表:{}", deletedCount, totalSizeReleased, deletedNames);
            CommonLog.knowledge.action(ActionType.DELETE_BATCH, "批量删除知识库元素，数量:{}", deletedCount)
                    .withMetadata("successCount", String.valueOf(deletedCount))
                    .withMetadata("totalCount", String.valueOf(ids.size()))
                    .withMetadata("sizeReleased", String.valueOf(totalSizeReleased))
                    .withMetadata("elementNames", String.join(",", deletedNames.subList(0, Math.min(5, deletedNames.size()))))
                    .send();
        }
        if (deletedCount == ids.size()) {
            return Result.defaultSuccess(i18nMessage.resolveMessage("system.common.delete.success"));
        } else if (deletedCount > 0) {
            String message = String.format("部分删除成功: 成功%d个,失败%d个。失败详情: %s", deletedCount, ids.size() - deletedCount, validationErrors.toString());
            return Result.error(message);
        } else {
            return Result.error("批量删除失败: " + validationErrors.toString());
        }
    }

