    }

    @Override
    public Result<String> updateContent(KnowledgeElementContentUpdateReq issueReq) {
        // 获取当前用户信息
        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        // 根据页面代码和租户ID查询页面信息
        Optional<SaasKnowledgeElement> saasKnowledgeElementOptional = this.queryByCode(issueReq.getCode(), sysUserInfo.getTenantId());
        if (saasKnowledgeElementOptional.isEmpty()) {
            throw new IllegalArgumentException("system.common.request.invalid");
        }
        // 获取查询到的页面记录
        SaasKnowledgeElement record = saasKnowledgeElementOptional.get();
        // 创建一个新的KbPage对象用于更新
        SaasKnowledgeElement saasKnowledgeElement = issueReq.update(record);
        // 草稿状态更新标题
        // 更新标题和过期时间
        issueReq.updatePageTitle(saasKnowledgeElement);
        int ret = saasKnowledgeElementMapper.updateById(saasKnowledgeElement);
        if (ret > 0) {
            // 版本存在两种情况，一种是当前的页面本身就是待处理状态，那么就一直更新当前版本的内容，版本号不更新
            if (Objects.equals(record.getProcessStatus(), ProcessStatusEnum.DRAFT.getCode())) {
                // 草稿状态更新版本信息
                this.update(record, issueReq, sysUserInfo, KnowledgeElementVersionStatus.DEFAULT);
            } else if (Objects.equals(record.getProcessStatus(), ProcessStatusEnum.SUCCESS.getCode())) {
                // 更新一下标题、过期时间、样式 作为版本副本
                issueReq.updatePageTitle(saasKnowledgeElement);
                // 如果是已经发布的状态 新增一个版本作为当前页面版本的草稿状态
                this.merge(saasKnowledgeElement, issueReq.getAttachments(), sysUserInfo, KnowledgeElementVersionStatus.DEFAULT);
            }
            // 通用知识库文档列入 草稿状态不列入动态信息
            String containerId = saasKnowledgeElement.getContainerId();
            LambdaQueryWrapper<SaasKnowledgeContainer> queryWrapper = new LambdaQueryWrapper<>();
            queryWrapper.eq(SaasKnowledgeContainer::getCode, containerId);
            queryWrapper.eq(SaasKnowledgeContainer::getTenantId, sysUserInfo.getTenantId());
            SaasKnowledgeContainer saasKnowledgeContainer = saasKnowledgeContainerMapper.selectOne(queryWrapper);
            if (!ProcessStatusEnum.DRAFT.equals(ProcessStatusEnum.parse(record.getProcessStatus()))
                    && saasKnowledgeContainer.getCategory().equals(KnowledgeCategory.COMMON.name())) {
                // 空间动态信息新增
                SaasKnowledgeElementCacheInfo saasKnowledgeElementCacheInfo = knowledgeElementConfigService.get(saasKnowledgeElement.getContainerId(), saasKnowledgeElement.getTenantId());
                saasKnowledgeElementTrendService.messageTrend(SaasKnowledgeElementTrendAddReq.of(UserContextHolder.getCurrentUser(), saasKnowledgeElement, SaasKnowledgeElementEvent.UPDATED, saasKnowledgeElementCacheInfo));
            }
            // 记录协作者信息
            LambdaQueryWrapper<SaasKnowledgeElementVersion> versionQueryWrapper = Wrappers.lambdaQuery(SaasKnowledgeElementVersion.class)
                .eq(SaasKnowledgeElementVersion::getTenantId, sysUserInfo.getTenantId())
                .eq(SaasKnowledgeElementVersion::getPageCode, issueReq.getCode())
                .eq(SaasKnowledgeElementVersion::getStatus, KnowledgeElementVersionStatus.DEFAULT.getCode());
            versionQueryWrapper.select(SaasKnowledgeElementVersion::getCode);
            SaasKnowledgeElementVersion defaultVersion = saasKnowledgeElementVersionMapper.selectOne(versionQueryWrapper, false);
            if (defaultVersion != null) {
                saveOrUpdateVersionAuthor(issueReq.getCode(), defaultVersion.getCode(), saasKnowledgeElement.getContainerId(), sysUserInfo);
            }
        }
        return i18nMessage.update(ret);
    }

    @Override
    public Result<String> issue(KnowledgeElementContentUpdateReq issueReq, boolean isIssue) {
        // 记录发布空间页面的日志
        String code = issueReq.getCode();
        log.info("当前更新的页面变为为,code:{}", code);
        // 获取当前用户信息
        SysUserInfo sysUserInfo = UserContextHolder.getCurrentUser();
        // 根据页面代码和租户ID查询页面信息
        Optional<SaasKnowledgeElement> saasKnowledgeElementOptional = this.queryByCode(issueReq.getCode(), sysUserInfo.getTenantId());
        if (saasKnowledgeElementOptional.isEmpty()) {
            throw new IllegalArgumentException("system.common.request.invalid");
        }
        // 获取查询到的页面记录
        SaasKnowledgeElement data = saasKnowledgeElementOptional.get();
        // 确保 DEFAULT 版本存在
        ensureDefaultVersionExists(data, issueReq, sysUserInfo);
        Long contentSize = 0L;
        // 发布逻辑：更新状态为已发布
        if (isIssue) {
            data.setProcessStatus(ProcessStatusEnum.INIT.getCode());
            data.setModifierTime(LocalDateTime.now());
            data.setModifier(sysUserInfo.getCode());
            data.setEleName(issueReq.getTitle());
            if (DocTimeStatus.NEVER_EXPIRE.getCode() == issueReq.getNeverExpire()) {
                data.setNeverExpire(issueReq.getNeverExpire());
            } else {
                data.setNeverExpire(issueReq.getNeverExpire());
                DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
                String startTimeStr = issueReq.getStartTime();
                String endTimeStr = issueReq.getEndTime();
                LocalDateTime start = null;
                LocalDateTime end = null;
                try {
                    if (startTimeStr != null && !startTimeStr.isEmpty()) {
                        start = LocalDateTime.parse(startTimeStr, formatter);
                    }
                    if (endTimeStr != null && !endTimeStr.isEmpty()) {
                        end = LocalDateTime.parse(endTimeStr, formatter);
                    }
                } catch (DateTimeParseException e) {
                    // 这里可以记录日志或抛出自定义异常
                    log.error("时间格式错误", e);
                }
                data.setStartTime(start);
                data.setEndTime(end);
            }
            // 在发布时计算文件大小
            contentSize = calculateContentSize(issueReq.getContentMarked());
            data.setEleSize(contentSize);
        }
        // 如果是发布状态，那么需要更新版本信息
        if (isIssue && contentSize > 0) {
            // 校验容器大小
            knowledgeContainerCapacityDataService.validateContainerCapacity(data.getContainerId(), contentSize);
        }
        Integer versionNo = null;
        if (isIssue) {
            LambdaQueryWrapper<SaasKnowledgeElementVersion> defaultVersionQuery = Wrappers.lambdaQuery(SaasKnowledgeElementVersion.class)
                    .eq(SaasKnowledgeElementVersion::getPageCode, data.getCode())
                    .eq(SaasKnowledgeElementVersion::getStatus, KnowledgeElementVersionStatus.DEFAULT.getCode())
                    .eq(SaasKnowledgeElementVersion::getTenantId, data.getTenantId())
                    .orderByDesc(SaasKnowledgeElementVersion::getVersionNo)
                    .last("limit 1");
            SaasKnowledgeElementVersion defaultVersion = saasKnowledgeElementVersionMapper.selectOne(defaultVersionQuery);
            if (defaultVersion != null) {
                versionNo = defaultVersion.getVersionNo();
            }
        }
        // 更新数据库
        int ret = saasKnowledgeElementMapper.updateById(data);
        if (ret > 0) {
            // 更新页面内容数据
            SaasKnowledgeElementVersion updateEntity = new SaasKnowledgeElementVersion();
            updateEntity.setContentMarked(issueReq.getContentMarked());
            updateEntity.setContent(issueReq.getContent());
            updateEntity.setStatus(KnowledgeElementVersionStatus.ISSUED.getCode());
            LambdaQueryWrapper<SaasKnowledgeElementVersion> queryWrapper = new LambdaQueryWrapper<>();
            queryWrapper.eq(SaasKnowledgeElementVersion::getPageCode, data.getCode())
                    .eq(SaasKnowledgeElementVersion::getStatus, KnowledgeElementVersionStatus.DEFAULT.getCode())
                    .eq(SaasKnowledgeElementVersion::getTenantId, data.getTenantId());
            queryWrapper.select(SaasKnowledgeElementVersion::getCode);
            SaasKnowledgeElementVersion defaultVersion = saasKnowledgeElementVersionMapper.selectOne(queryWrapper, false);
            saasKnowledgeElementVersionMapper.update(updateEntity, queryWrapper);
            // 清理旧es数据
            boolean re = knowledgeElementDataService.deleteByDataId(sysUserInfo.getTenantId(), data.getContainerId(), code);
            log.info("数据库删除成功,ret:{},向量删除:{}", ret, re);
            // 记录操作日志
            CommonLog.knowledge.action(ActionType.CREATE_SINGLE, "发布知识页面，标题:{}，版本:{}", data.getEleName(), versionNo)
                    .withMetadata("elementId", data.getCode())
                    .withMetadata("containerId", data.getContainerId())
                    .send();
            // 空间动态信息新增
            // 通用知识库文档列入 草稿状态不列入动态信息
            String containerId = data.getContainerId();
            LambdaQueryWrapper<SaasKnowledgeContainer> saasKnowledgeContainerLambdaQueryWrapper = new LambdaQueryWrapper<>();
            saasKnowledgeContainerLambdaQueryWrapper.eq(SaasKnowledgeContainer::getCode, containerId);
            saasKnowledgeContainerLambdaQueryWrapper.eq(SaasKnowledgeContainer::getTenantId, sysUserInfo.getTenantId());
            SaasKnowledgeContainer saasKnowledgeContainer = saasKnowledgeContainerMapper.selectOne(saasKnowledgeContainerLambdaQueryWrapper);
            if (saasKnowledgeContainer.getCategory().equals(KnowledgeCategory.COMMON.name())) {
                SaasKnowledgeElementCacheInfo saasKnowledgeElementCacheInfo = knowledgeElementConfigService.get(data.getContainerId(), data.getTenantId());
                // 第一次发布是发布后续是修改
                LambdaQueryWrapper<SaasKnowledgeElementVersion> saasKnowledgeElementVersionLambdaQueryWrapper = new LambdaQueryWrapper<>();
                saasKnowledgeElementVersionLambdaQueryWrapper.eq(SaasKnowledgeElementVersion::getPageCode, data.getCode());
                saasKnowledgeElementVersionLambdaQueryWrapper.eq(SaasKnowledgeElementVersion::getTenantId, sysUserInfo.getTenantId());
                int size = saasKnowledgeElementVersionMapper.selectList(saasKnowledgeElementVersionLambdaQueryWrapper).size();
                if (size > 1) {
                    saasKnowledgeElementTrendService.messageTrend(SaasKnowledgeElementTrendAddReq.of(UserContextHolder.getCurrentUser(), data,
                            SaasKnowledgeElementEvent.UPDATED, saasKnowledgeElementCacheInfo));
                } else {
                    saasKnowledgeElementTrendService.messageTrend(SaasKnowledgeElementTrendAddReq.of(UserContextHolder.getCurrentUser(), data,
                            SaasKnowledgeElementEvent.ISSUED, saasKnowledgeElementCacheInfo));
                }

            }
            // 记录协作者信息
            if (defaultVersion != null) {
                saveOrUpdateVersionAuthor(data.getCode(), defaultVersion.getCode(), data.getContainerId(), sysUserInfo);
            }
            publishElementUpsert(KnowledgeEventType.DOCUMENT_PUBLISHED, data, false);
        }
        return i18nMessage.update(ret);
    }

    /**
     * 计算内容大小（带详细调试信息）
     *
     * @param content 原始内容
     * @return 内容大小（字节）
     */
    private Long calculateContentSize(String content) {
        if (StrUtil.isBlank(content)) {
            log.info("内容为空，返回大小: 0");
            return 0L;
        }

        // 字符数量
        int charCount = content.length();

        // UTF-8字节数
        byte[] utf8Bytes = content.getBytes(StandardCharsets.UTF_8);
        long utf8Size = utf8Bytes.length;

        // 默认编码字节数（用于对比）
        byte[] defaultBytes = content.getBytes();
        long defaultSize = defaultBytes.length;

        // 详细日志
        log.info("=== 内容大小计算详情 ===");
        log.info("字符数量: {}", charCount);
        log.info("UTF-8字节数: {} ({} KB)", utf8Size, utf8Size / 1024.0);
        log.info("默认编码字节数: {} ({} KB)", defaultSize, defaultSize / 1024.0);
        log.info("内容类型分析:");
        log.info("- 是否包含HTML标签: {}", content.contains("<") && content.contains(">"));
        log.info("- 是否包含中文: {}", content.matches(".*[\u4e00-\u9fa5].*"));
        log.info("- 内容开头100字符: {}",
                content.length() > 100 ? content.substring(0, 100) : content);

        return utf8Size;
    }

    /**
     * 确保存在 DEFAULT 版本（UPSERT 逻辑）
     * 如果不存在则创建，存在则不处理
     */
    private void ensureDefaultVersionExists(SaasKnowledgeElement data,
                                            KnowledgeElementContentUpdateReq issueReq,
                                            SysUserInfo sysUserInfo) {
        // 检查是否存在 DEFAULT 版本
        LambdaQueryWrapper<SaasKnowledgeElementVersion> checkWrapper = new LambdaQueryWrapper<>();
        checkWrapper.eq(SaasKnowledgeElementVersion::getPageCode, data.getCode())
                .eq(SaasKnowledgeElementVersion::getStatus, KnowledgeElementVersionStatus.DEFAULT.getCode())
                .eq(SaasKnowledgeElementVersion::getTenantId, data.getTenantId());

        Long count = saasKnowledgeElementVersionMapper.selectCount(checkWrapper);

        // 如果不存在 DEFAULT 版本，则创建一个
        if (count == 0) {
            // 查询已发布的最大版本号
            LambdaQueryWrapper<SaasKnowledgeElementVersion> queryWrapper = Wrappers.lambdaQuery(SaasKnowledgeElementVersion.class)
                    .eq(SaasKnowledgeElementVersion::getTenantId, data.getTenantId())
                    .eq(SaasKnowledgeElementVersion::getPageCode, issueReq.getCode())
                    .eq(SaasKnowledgeElementVersion::getStatus, KnowledgeElementVersionStatus.ISSUED.getCode());
            queryWrapper.select(SaasKnowledgeElementVersion::getVersionNo);
            List<SaasKnowledgeElementVersion> issuedVersions = saasKnowledgeElementVersionMapper.selectList(queryWrapper);
            int maxVersionNo = issuedVersions.stream()
                    .map(SaasKnowledgeElementVersion::getVersionNo)
                    .max(Integer::compareTo)
                    .orElse(0); // 没有已发布版本则为0
            int newVersionNo = maxVersionNo + 1;
            SaasKnowledgeElementVersion record = new SaasKnowledgeElementVersion();
            record.setVersionNo(newVersionNo);
            record.setTitle(issueReq.getTitle());
            record.setDescription(data.getConfig());
            record.setUserCode(sysUserInfo.getCode());
            record.setContent(issueReq.getContent());
            record.setContentMarked(issueReq.getContentMarked());
            record.setPageCode(issueReq.getCode());
            record.setTenantId(sysUserInfo.getTenantId());
            record.setCreator(sysUserInfo.getCode());
            record.setCreateTime(LocalDateTime.now());
            record.setModifier(sysUserInfo.getCode());
            record.setModifierTime(LocalDateTime.now());
            record.setStatus(KnowledgeElementVersionStatus.DEFAULT.getCode());
            record.setCode(IdUtil.getSnowflakeNextIdStr());
            if (CollUtil.isNotEmpty(issueReq.getAttachments())) {
                record.setAttachmentCode(CollUtil.join(issueReq.getAttachments(), StrUtil.COMMA));
            }
            log.info("生成一个新的版本号，versionNo:{},versionCode:{}", record.getVersionNo());
            // insert
            int ret = saasKnowledgeElementVersionMapper.insert(record);
            log.info("频繁发布新增默认版本,结果ret:{}", ret);
        }
    }

