    private void saveOrUpdateVersionAuthor(String pageCode, String versionCode, String spaceCode, SysUserInfo sysUserInfo) {
        LambdaQueryWrapper<com.torchv.repository.chat.entity.SaasKnowledgeElementVersionAuthor> queryWrapper =
