        return fileCounts.stream()
                .filter(item -> StrUtil.isNotBlank(item.getContainerId()))
                .collect(Collectors.toMap(ContainerFileCount::getContainerId, item -> ObjectUtil.defaultIfNull(item.getFileCount(), 0L), (existing, replacement) -> existing));
    }

