        if (CollUtil.isNotEmpty(visibleCodes)) {
            lambdaQueryWrapper.and(lf -> lf.eq(SaasKnowledgeElement::getPermissionStatus, ToggleStatusEnum.YES.getCode()).or(l1 -> {
                l1.eq(SaasKnowledgeElement::getPermissionStatus, ToggleStatusEnum.NO.getCode());
                l1.in(SaasKnowledgeElement::getCode, visibleCodes);
            }));
        } else {
            lambdaQueryWrapper.eq(SaasKnowledgeElement::getPermissionStatus, ToggleStatusEnum.YES.getCode());
        }

        String permissionType = saasKnowledgeContainerPermissionService.getHighestPermission(containerId, sysUserInfo);
        log.info("当前用户在容器中的最高权限:{}", permissionType);
        // 如果是没权限的角色，那么需要判断当前的知识库是否设置为公开，如果是公开的情况下，那么给予只读角色
        Optional<SaasKnowledgeContainer> containerOptional = knowledgeContainerQueryService.queryInfoByCode(containerId);
        if (containerOptional.isEmpty()) {
            return null;
        }
        boolean canFilter = true;
        SaasKnowledgeContainer saasKnowledgeContainer = containerOptional.get();
        if (KbKnowledgeBaseContainerVisibilityRange.publicRead(saasKnowledgeContainer.getVisibilityRange())) {
            // 公开可读
            canFilter = false;
        } else {
            // 非公开可读，那么必须有权限才可以查看
            if (!StrUtil.equalsIgnoreCase(KbKnowledgeBaseContainerPermissionTypes.NO_PERMISSION.getCode(), permissionType)) {
                // 公开可读
                canFilter = false;
            }
        }
        List<SaasKnowledgeElement> saasKnowledgeElementInfos = saasKnowledgeElementMapper.selectList(lambdaQueryWrapper);
        if (canFilter) {
            List<String> elementCodes = saasKnowledgeElementInfos.stream().map(SaasKnowledgeElement::getCode).toList();
            ElementFilterSearchCondition searchFilterCondition = ElementFilterSearchCondition.from(sysUserInfo.getTenantId(), containerId, elementCodes, orgPermissions.permissionCodesToList());
            List<String> visibleFilterCodes = saasKnowledgeElementMapper.listVisibleFilterCodes(searchFilterCondition);
            if (CollUtil.isNotEmpty(visibleFilterCodes)) {
                saasKnowledgeElementInfos = saasKnowledgeElementInfos.stream().filter(e -> visibleFilterCodes.contains(e.getCode())).toList();
            }
        }
        return saasKnowledgeElementInfos.size();
    }

    /**
     * 构建树形结构并保持每一级的排序
     */
    private List<KnowledgeElementResp> buildTreeStructureWithSort(List<SaasKnowledgeElement> elements, KnowledgeElementQueryReq queryReq) {
        if (CollectionUtil.isEmpty(elements)) {
            return new ArrayList<>();
        }

        // 转换为响应对象
        List<KnowledgeElementResp> allElements = elements.stream()
                .map(new SaasKnowledgeElementApplyFunction())
                .collect(Collectors.toList());

        // 批量填充creatorName和modifierName
        Set<String> userCodes = new HashSet<>();

        // key-code value:parentCode
        Map<String, String> elementRootMap = new HashMap<>();
        for (KnowledgeElementResp resp : allElements) {
            userCodes.addAll(resp.userCodes());
            elementRootMap.put(resp.getCode(), resp.getParentCode());
        }
        if (!userCodes.isEmpty()) {
            Map<String, String> userMap = userService.selectByCode(new ArrayList<>(userCodes));
            for (KnowledgeElementResp resp : allElements) {
                resp.applyUserName(userMap);
            }
        }
        log.info("批量填充creatorName和modifierName{}", allElements);
        // 创建映射：parentCode -> 子元素列表
        Map<String, List<KnowledgeElementResp>> parentChildMap = new HashMap<>();
        Map<String, KnowledgeElementResp> rootMap = new LinkedHashMap<>();

        for (KnowledgeElementResp element : allElements) {
            String parentCode = StrUtil.isBlank(element.getParentCode()) ? "0" : element.getParentCode();
            parentChildMap.computeIfAbsent(parentCode, k -> new ArrayList<>()).add(element);
            if (!elementRootMap.containsKey(element.getParentCode())) {
                rootMap.put(element.getCode(), element);
                //parentChildMap.computeIfAbsent(element.getCode(), k -> new ArrayList<>()).add(element);
            }
        }

        // 对每一级的子元素进行排序
        SortRules sortRule = SortRules.parse(queryReq.getSortRule());
        for (List<KnowledgeElementResp> children : parentChildMap.values()) {
            sortElementList(children, sortRule, queryReq.getSortType());
        }

        // 递归构建树形结构
        //List<KnowledgeElementResp> rootElements = parentChildMap.getOrDefault("0", new ArrayList<>());

        List<KnowledgeElementResp> rootElements = new ArrayList<>(rootMap.values());
        sortElementList(rootElements, sortRule, queryReq.getSortType());
        for (KnowledgeElementResp element : rootElements) {
            buildChildren(element, parentChildMap);
        }

        return rootElements;
    }

    /**
     * 递归构建子元素
     */
    private void buildChildren(KnowledgeElementResp parent, Map<String, List<KnowledgeElementResp>> parentChildMap) {
        List<KnowledgeElementResp> children = parentChildMap.get(parent.getCode());
        if (CollectionUtil.isNotEmpty(children)) {
            parent.setChildrens(children);
            for (KnowledgeElementResp child : children) {
                buildChildren(child, parentChildMap);
            }
        }
    }

    /**
     * 对元素列表进行排序
     */
    private void sortElementList(List<KnowledgeElementResp> elements, SortRules sortRule, Integer sortType) {
        if (CollectionUtil.isEmpty(elements)) {
            return;
        }

        switch (sortRule) {
            case SORT_NUMBER:
                elements.sort(Comparator.comparing(KnowledgeElementResp::getSort, Comparator.nullsLast(Comparator.naturalOrder())));
                break;
            case SORT_CREATE_TIME:
                if (sortType == 0) {
                    elements.sort(Comparator.comparing(KnowledgeElementResp::getCreateTime, Comparator.nullsLast(Comparator.naturalOrder())));
                } else {
                    elements.sort(Comparator.comparing(KnowledgeElementResp::getCreateTime, Comparator.nullsLast(Comparator.reverseOrder())));
                }
                break;
            case SORT_MODIFY_TIME:
                if (sortType == 0) {
                    elements.sort(Comparator.comparing(KnowledgeElementResp::getModifierTime, Comparator.nullsLast(Comparator.naturalOrder())));
                } else {
                    elements.sort(Comparator.comparing(KnowledgeElementResp::getModifierTime, Comparator.nullsLast(Comparator.reverseOrder())));
                }
                break;
            case SORT_TITLE:
                elements.sort((a, b) -> compareFileName(a.getEleName(), b.getEleName(), sortType));
                break;
            default:
                // 默认按排序号排序
                elements.sort(Comparator.comparing(KnowledgeElementResp::getSort, Comparator.nullsLast(Comparator.naturalOrder())));
                break;
        }
    }

    private List<String> queryUserCodesByNameLike(String nameLike, String tenantId) {
        if (StrUtil.isBlank(nameLike)) {
            return Collections.emptyList();
        }
        // 查询昵称/真实姓名/登录名任意匹配
        LambdaQueryWrapper<com.torchv.repository.user.entity.SysUser> qw = Wrappers.lambdaQuery(com.torchv.repository.user.entity.SysUser.class)
                .eq(com.torchv.repository.user.entity.SysUser::getTenantId, tenantId)
                .and(w -> w.like(com.torchv.repository.user.entity.SysUser::getNickName, nameLike)
                        .or().like(com.torchv.repository.user.entity.SysUser::getRealName, nameLike)
                        .or().like(com.torchv.repository.user.entity.SysUser::getLoginUsername, nameLike));
        qw.select(com.torchv.repository.user.entity.SysUser::getCode);
        List<com.torchv.repository.user.entity.SysUser> users = userService.list(qw);
        if (CollUtil.isEmpty(users)) {
            return Collections.emptyList();
        }
        return users.stream().map(com.torchv.repository.user.entity.SysUser::getCode).distinct().toList();
    }



    /**
     * 更新KbPageVersion表中content字段里的图片宽高信息
     * @param pageCode 页面编码
     * @return 更新结果
     */
    @Override
    public Result<String> updateImageDimensions(String pageCode, String containerId, String tenantId) {
        try {
            log.info("更新页面图片尺寸信息，pageCode: {},containerId:{}", pageCode,containerId);

            if (StrUtil.isEmpty(tenantId)){
                tenantId = UserContextHolder.getTenantId();
            }


            // 查询页面信息
            SaasKnowledgeElement kbPage = saasKnowledgeElementMapper.selectOne(Wrappers.lambdaQuery(SaasKnowledgeElement.class)
                    .eq(StrUtil.isNotEmpty(tenantId), SaasKnowledgeElement::getTenantId, tenantId)
                    .eq(StrUtil.isNotEmpty(pageCode), SaasKnowledgeElement::getCode, pageCode), false);
            if (StrUtil.isNotEmpty(pageCode) && ObjectUtil.isEmpty(kbPage)) {
                return Result.error("页面不存在");
            }

            List<SaasKnowledgeElement> kbPages = saasKnowledgeElementMapper.selectList(Wrappers.lambdaQuery(SaasKnowledgeElement.class)
                    .eq(StrUtil.isNotEmpty(tenantId), SaasKnowledgeElement::getTenantId, tenantId)
                    .eq(StrUtil.isNotEmpty(containerId), SaasKnowledgeElement::getContainerId, containerId)
                    .eq(SaasKnowledgeElement::getCategory, "PAGE")
                    .eq(StrUtil.isNotEmpty(pageCode), SaasKnowledgeElement::getCode, pageCode));

            if (ObjectUtil.isEmpty(kbPages)) {
                return Result.error("没有KbPage需要更新");
            }

            List<String> codeList = kbPages.stream()
                    .map(SaasKnowledgeElement::getCode)
                    .filter(StrUtil::isNotEmpty)
                    .collect(Collectors.toList());

            if (ObjectUtil.isEmpty(codeList)) {
                return Result.error("没有需要更新图片宽高的页面codeList");
            }


            LambdaQueryWrapper<SaasKnowledgeElementVersion> lambdaQueryWrapper = Wrappers.lambdaQuery(SaasKnowledgeElementVersion.class)
                    .eq(SaasKnowledgeElementVersion::getTenantId, tenantId)
                    .in(SaasKnowledgeElementVersion::getPageCode, codeList)
                    .eq(SaasKnowledgeElementVersion::getStatus, "ISSUED")
                    .like(SaasKnowledgeElementVersion::getContent, "image");
            lambdaQueryWrapper.orderByDesc(SaasKnowledgeElementVersion::getVersionNo);
            List<SaasKnowledgeElementVersion> eleVersions = saasKnowledgeElementVersionMapper.selectList(lambdaQueryWrapper);


            if (ObjectUtil.isEmpty(eleVersions)) {
                return Result.error("没有需要更新图片宽高的页面");
            }

            List successList = new ArrayList<>();

            List contentEmpty = new ArrayList<>();
            List errList = new ArrayList<>();

            for (SaasKnowledgeElementVersion version : eleVersions) {
                String content = version.getContent();
                if (StrUtil.isEmpty(content)) {
                    contentEmpty.add(version.getCode());
                    continue;
                }

                // 解析JSON内容
                JsonNode rootNode;
                try {
                    rootNode = ObjectMapperUtil.readTree(content);
                } catch (Exception e) {
                    log.error("解析JSON内容失败，pageCode: {}", pageCode, e);
                    errList.add(version.getCode());
                    continue;
                }

                // 统计更新前的图片数量
                int totalImages = countImageNodesWithDimensions(rootNode);

                // 处理图片尺寸信息
                try {
                    processNode(rootNode);
                } catch (Exception e) {
                    errList.add(version.getCode());
                }

                // 统计更新后的图片数量（已添加宽高信息的）
                int updatedImages = countUpdatedImages(rootNode);

                // 将处理后的JSON转换回字符串
                String updatedContent = ObjectMapperUtil.toJson(rootNode);

                // 更新数据库中的内容
                SaasKnowledgeElementVersion updateVersion = new SaasKnowledgeElementVersion();
                updateVersion.setId(version.getId());
                updateVersion.setContent(updatedContent);
                updateVersion.setModifierTime(LocalDateTime.now());

                int result = saasKnowledgeElementVersionMapper.updateById(updateVersion);
                if (result > 0) {
                    successList.add(version.getCode());
                    log.info("成功更新页面图片尺寸信息，version—code:{},pageCode: {}，总共图片数: {}，更新图片数: {}",version.getCode(), pageCode, totalImages, updatedImages);
                } else {
                    log.error("更新页面图片尺寸信息失败，version—code:{},pageCode: {}", version.getCode(),pageCode);
                }
                Thread.sleep(100);
            }
            if (!contentEmpty.isEmpty() || !errList.isEmpty()){
                return Result.success("部分更新失败：内容为空:"+contentEmpty+"。内容解析异常:"+errList);
            } else {
                return Result.success("更新成功:"+successList.size());
            }
        } catch (Exception e) {
            log.error("更新页面图片尺寸信息异常，pageCode: {}", pageCode, e);
            return Result.error("更新过程中发生异常: " + e.getMessage());
        }
    }




    // 递归遍历JSON节点并统计图片数量（包括已有的和需要更新的）
    private int countImageNodesWithDimensions(JsonNode node) {
        int count = 0;
        if (node.isArray()) {
            for (int i = 0; i < node.size(); i++) {
                count += countImageNodesWithDimensions(node.get(i));
            }
        } else if (node.isObject()) {
            JsonNode typeNode = node.get("type");
            if (typeNode != null && typeNode.asText().equals("image")) {
                // 找到图片节点，计数加1
                count++;
            }
            // 递归处理所有字段
            Iterator<Map.Entry<String, JsonNode>> fields = node.fields();
            while (fields.hasNext()) {
                Map.Entry<String, JsonNode> entry = fields.next();
                count += countImageNodesWithDimensions(entry.getValue());
            }
        }
        return count;
    }

    // 递归遍历JSON节点并统计更新的图片数量
    private int countUpdatedImages(JsonNode node) {
        int count = 0;
        if (node.isArray()) {
            for (int i = 0; i < node.size(); i++) {
                count += countUpdatedImages(node.get(i));
            }
        } else if (node.isObject()) {
            JsonNode typeNode = node.get("type");
            if (typeNode != null && typeNode.asText().equals("image")) {
                // 找到图片节点，检查是否添加了宽高信息
                JsonNode attrsNode = node.get("attrs");
                if (attrsNode != null && attrsNode.has("width") && attrsNode.has("height")) {
                    count++;
                }
            }
            // 递归处理所有字段
            Iterator<Map.Entry<String, JsonNode>> fields = node.fields();
            while (fields.hasNext()) {
                Map.Entry<String, JsonNode> entry = fields.next();
                count += countUpdatedImages(entry.getValue());
            }
        }
        return count;
    }

    // 递归处理JSON节点，获取图片尺寸并添加到attrs中
    private void processNode(JsonNode node) throws Exception {
        if (node.isArray()) {
            for (int i = 0; i < node.size(); i++) {
                processNode(node.get(i));
            }
        } else if (node.isObject()) {
            JsonNode typeNode = node.get("type");
            if (typeNode != null && typeNode.asText().equals("image")) {
                // 找到图片节点，获取src属性
                JsonNode attrsNode = node.get("attrs");
                if (attrsNode != null && attrsNode.has("src")) {
                    String src = attrsNode.get("src").asText();
                    if (src != null && !src.isEmpty() && !"null".equals(src)) {
                        try {
                            // 获取图片尺寸
                            int[] dimensions = getImageDimensions(src);
                            if (dimensions != null) {
                                // 在attrs中添加width和height属性
                                ((com.fasterxml.jackson.databind.node.ObjectNode) attrsNode)
                                        .put("width", dimensions[0])
                                        .put("height", dimensions[1]);
                            }
                        } catch (Exception e) {
                            log.warn("获取图片尺寸失败，src: {}", src, e);
                            throw e;
                        }
                    }
                }
            }
            // 递归处理所有字段
            Iterator<Map.Entry<String, JsonNode>> fields = node.fields();
            while (fields.hasNext()) {
                Map.Entry<String, JsonNode> entry = fields.next();
                processNode(entry.getValue());
            }
        }
    }


    // 添加一个处理图片尺寸的新方法
    private String processImageDimensions(String content) {
        try {
            if (StrUtil.isEmpty( content)) {
                return content;
            }
            JsonNode rootNode = ObjectMapperUtil.readTree(content);
            processNode(rootNode);
            return ObjectMapperUtil.toJson(rootNode);
        } catch (Exception e) {
            log.error("处理图片尺寸信息失败", e);
            // 如果处理失败，返回原始内容
            return content;
        }
    }


    /**
     * 获取图片的宽度和高度
     * @param src 图片地址
     * @return int[]{width, height} 或 null
     */
    private int[] getImageDimensions(String src) throws Exception {
        // 尝试从Redis获取缓存的图片尺寸 - 使用URL的MD5作为键
        String cacheKey = "image:dimensions:" + cn.hutool.crypto.digest.DigestUtil.md5Hex(src);
        try {
            Object cachedValue = redisTemplate.opsForValue().get(cacheKey);
            if (cachedValue != null) {
                // 处理Redis反序列化后的类型问题
                if (cachedValue instanceof int[]) {
                    log.debug("从Redis缓存获取图片尺寸，src: {}", src);
                    return (int[]) cachedValue;
                } else if (cachedValue instanceof List) {
                    // Redis可能将数组反序列化为List，转换回来
                    List<?> list = (List<?>) cachedValue;
                    if (list.size() == 2 && list.get(0) instanceof Number && list.get(1) instanceof Number) {
                        log.debug("从Redis缓存获取图片尺寸（转换List），src: {}", src);
                        return new int[]{((Number) list.get(0)).intValue(), ((Number) list.get(1)).intValue()};
                    }
                }
            }
        } catch (Exception e) {
            log.warn("从Redis获取图片尺寸缓存失败，src: {}", src, e);
            // Redis不可用时，继续直接获取
        }

        BufferedImage image = null;
        File tempFile = null;
        try {
            if (src.startsWith("data:")) {
                // 处理base64图片
                String base64Data = src.substring(src.indexOf(",") + 1);
                byte[] imageBytes = Base64.getDecoder().decode(base64Data);
                image = ImageIO.read(new java.io.ByteArrayInputStream(imageBytes));
            } else {
                // 处理HTTP/HTTPS或相对路径图片
                String fullUrl;
                if (src.startsWith("http://") || src.startsWith("https://")) {
                    fullUrl = src;
                } else {
                    fullUrl = materialService.convertUrlToRealUrl(src);
                }

                // 创建临时文件下载图片
                tempFile = FileUtil.createTempFile(RandomUtil.randomString(16), getExtensionFromUrl(src), true);
                // 使用Hutool的HttpUtil下载文件
                HttpUtil.downloadFile(fullUrl, tempFile, 30 * 1000);

                // 从下载的文件创建BufferedImage
                image = ImageIO.read(tempFile);
            }

            if (image != null) {
                int[] dimensions = new int[]{image.getWidth(), image.getHeight()};
                // 将图片尺寸缓存到Redis，设置30分钟过期
                try {
                    redisTemplate.opsForValue().set(cacheKey, dimensions, java.time.Duration.ofMinutes(30));
                    log.debug("图片尺寸已缓存到Redis，src: {}", src);
                } catch (Exception e) {
                    log.warn("将图片尺寸缓存到Redis失败，src: {}", src, e);
                }

                return dimensions;
            }
        } catch (Exception e) {
            log.warn("读取图片失败，src: {}", src, e);
            throw e;
        } finally {
            // 释放图片资源
            if (image != null) {
                image.flush();
            }
            // 删除临时文件
            if (tempFile != null) {
                FileUtil.del(tempFile);
            }
        }
        return null;
    }

    /**
     * 从URL获取文件扩展名
     * @param url URL
     * @return 扩展名
     */
    private String getExtensionFromUrl(String url) {
        try {
            if (url.contains("?")) {
                url = url.substring(0, url.indexOf("?"));
            }
            if (url.contains("#")) {
                url = url.substring(0, url.indexOf("#"));
            }
            String extension = FileUtil.extName(url);
            if (StrUtil.isBlank(extension)) {
                // 默认png扩展名
                return ".png";
            }
            return "." + extension;
        } catch (Exception e) {
            log.warn("获取文件扩展名失败，url: {}", url, e);
            return ".png"; // 默认png
        }
    }

    static boolean hasMoveOrCopySourcePermission(String sourcePermission, boolean sameContainer, boolean moveOpt) {
        if (sameContainer || !moveOpt) {
            return hasEditOrManagePermission(sourcePermission);
        }
        return StrUtil.equalsIgnoreCase(sourcePermission, KbKnowledgeBaseContainerPermissionTypes.MANAGE.getCode());
    }

    private static boolean hasEditOrManagePermission(String permission) {
        return StrUtil.equalsIgnoreCase(permission, KbKnowledgeBaseContainerPermissionTypes.EDIT.getCode())
                || StrUtil.equalsIgnoreCase(permission, KbKnowledgeBaseContainerPermissionTypes.MANAGE.getCode());
    }

